class CancipTextPromptModal extends Modal {
  private inputComponent: TextComponent | null = null;
  private settled = false;

  constructor(
    app: App,
    private readonly titleText: string,
    private readonly initialValue: string,
    private readonly onSubmitValue: (value: string | null) => void
  ) {
    super(app);
  }

  onOpen(): void {
    this.setTitle(this.titleText);
    const row = new Setting(this.contentEl)
      .setName(this.titleText)
      .addText((text) => {
        this.inputComponent = text;
        text.setValue(this.initialValue);
        text.inputEl.addEventListener("keydown", (event) => {
          if (event.key === "Enter") {
            event.preventDefault();
            this.submit(text.getValue());
          }
          if (event.key === "Escape") {
            event.preventDefault();
            this.close();
          }
        });
      });
    row.addButton((button) => {
      button
        .setButtonText("OK")
        .setCta()
        .onClick(() => this.submit(this.inputComponent?.getValue() ?? ""));
    });
    window.setTimeout(() => this.inputComponent?.inputEl.focus(), 20);
  }

  onClose(): void {
    if (!this.settled) this.onSubmitValue(null);
    this.contentEl.empty();
  }

  private submit(value: string): void {
    this.settled = true;
    this.onSubmitValue(value);
    this.close();
  }
}

function promptTextModal(app: App, title: string, initialValue: string): Promise<string | null> {
  return new Promise((resolve) => {
    new CancipTextPromptModal(app, title, initialValue, resolve).open();
  });
}

class CancipHtmlPromptModal extends Modal {
  private inputEl: HTMLTextAreaElement | null = null;
  private settled = false;

  constructor(
    app: App,
    private readonly titleText: string,
    private readonly placeholderText: string,
    private readonly submitText: string,
    private readonly cancelText: string,
    private readonly onSubmitValue: (value: string | null) => void
  ) {
    super(app);
  }

  onOpen(): void {
    this.setTitle(this.titleText);
    this.modalEl.addClass("obcc-html-prompt-modal");
    const stopOuterTouch = (event: Event) => event.stopPropagation();
    this.modalEl.addEventListener("pointerdown", stopOuterTouch);
    this.modalEl.addEventListener("touchstart", stopOuterTouch);
    this.modalEl.addEventListener("touchmove", stopOuterTouch, { passive: true });
    this.inputEl = this.contentEl.createEl("textarea", {
      cls: "obcc-html-prompt-input",
      attr: {
        rows: "7",
        placeholder: this.placeholderText,
        "aria-label": this.titleText
      }
    });
    this.inputEl.addEventListener("keydown", (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        this.close();
        return;
      }
      if (event.key === "Enter" && (event.ctrlKey || event.metaKey)) {
        event.preventDefault();
        this.submit();
      }
    });
    const actions = this.contentEl.createDiv({ cls: "modal-button-container" });
    const cancel = actions.createEl("button", { text: this.cancelText, attr: { type: "button" } });
    cancel.addEventListener("click", () => this.close());
    const submit = actions.createEl("button", { cls: "mod-cta", text: this.submitText, attr: { type: "button" } });
    submit.addEventListener("click", () => this.submit());
    window.setTimeout(() => this.inputEl?.focus(), 20);
  }

  onClose(): void {
    if (!this.settled) this.onSubmitValue(null);
    this.contentEl.empty();
  }

  private submit(): void {
    const value = this.inputEl?.value.trim() ?? "";
    if (!value) {
      this.inputEl?.focus();
      return;
    }
    this.settled = true;
    this.onSubmitValue(value);
    this.close();
  }
}

