class CancipModelEditModal extends Modal {
  private modelInput: TextComponent | null = null;
  private profileSelect: HTMLSelectElement | null = null;
  private settled = false;

  constructor(
    app: App,
    private readonly input: ModelEditModalInput,
    private readonly onSubmitValue: (value: ModelEditModalResult | null) => void
  ) {
    super(app);
  }

  onOpen(): void {
    this.containerEl.addClass("obcc-model-edit-modal-container");
    this.modalEl.addClass("obcc-model-edit-modal");
    const stopOuterTouch = (event: Event) => event.stopPropagation();
    this.modalEl.addEventListener("pointerdown", stopOuterTouch);
    this.modalEl.addEventListener("touchstart", stopOuterTouch);
    this.setTitle(this.input.title);
    new Setting(this.contentEl)
      .setName(this.input.profileLabel)
      .addDropdown((dropdown) => {
        this.profileSelect = dropdown.selectEl;
        for (const profile of this.input.profiles) {
          dropdown.addOption(profile.id, profile.name || profile.id);
        }
        dropdown.setValue(this.input.initialProfileId || this.input.profiles[0]?.id || "");
      });
    new Setting(this.contentEl)
      .setName(this.input.modelLabel)
      .addText((text) => {
        this.modelInput = text;
        text.setValue(this.input.initialModel);
        text.inputEl.addEventListener("keydown", (event) => {
          if (event.key === "Enter") {
            event.preventDefault();
            this.submit();
          }
          if (event.key === "Escape") {
            event.preventDefault();
            this.close();
          }
        });
      });
    const actions = this.contentEl.createDiv({ cls: "obcc-model-edit-actions" });
    const cancel = actions.createEl("button", { text: this.input.cancelLabel, attr: { type: "button" } });
    cancel.addEventListener("click", () => this.close());
    const save = actions.createEl("button", { text: this.input.saveLabel, attr: { type: "button" } });
    save.addClass("mod-cta");
    save.addEventListener("click", () => this.submit());
    window.setTimeout(() => this.modelInput?.inputEl.focus(), 20);
  }

  onClose(): void {
    if (!this.settled) this.onSubmitValue(null);
    this.contentEl.empty();
  }

  private submit(): void {
    const model = this.modelInput?.getValue().trim() ?? "";
    const profileId = this.profileSelect?.value || this.input.initialProfileId || this.input.profiles[0]?.id || "";
    if (!model || !profileId) return;
    this.settled = true;
    this.onSubmitValue({ model, profileId });
    this.close();
  }
}

function promptModelEditModal(app: App, input: ModelEditModalInput): Promise<ModelEditModalResult | null> {
  return new Promise((resolve) => {
    new CancipModelEditModal(app, input, resolve).open();
  });
}

class CancipContextEditModal extends Modal {
  private labelEl: HTMLInputElement | null = null;
  private contentElInput: HTMLTextAreaElement | null = null;
  private settled = false;

  constructor(
    app: App,
    private readonly titleText: string,
    private readonly initialLabel: string,
    private readonly initialContent: string,
    private readonly onSubmitValue: (value: { label: string; content: string } | null) => void
  ) {
    super(app);
  }

  onOpen(): void {
    this.containerEl.addClass("obcc-context-edit-modal-container");
    this.modalEl.addClass("obcc-context-edit-modal");
    // Keep the context editor isolated from Cancip's mobile first-touch and
    // button-management listeners. Those listeners belong to the main view,
    // not to a modal that is already handling its own controls.
    const stopOuterTouch = (event: Event) => event.stopPropagation();
    this.modalEl.addEventListener("pointerdown", stopOuterTouch);
    this.modalEl.addEventListener("touchstart", stopOuterTouch);
    this.modalEl.addEventListener("touchmove", stopOuterTouch, { passive: true });
    this.modalEl.addEventListener("keydown", (event) => {
      if (event.key !== "Escape") return;
      event.preventDefault();
      event.stopPropagation();
      this.dismiss();
    });
    this.modalEl.addEventListener("click", (event) => {
      const target = event.target as Element | null;
      if (!target?.closest(".modal-close")) return;
      event.preventDefault();
      event.stopImmediatePropagation();
      this.dismiss();
    }, true);
    this.setTitle(this.titleText);
    new Setting(this.contentEl)
      .setName(this.titleText)
      .addText((text) => {
        this.labelEl = text.inputEl;
        text.setValue(this.initialLabel);
      });
    const body = this.contentEl.createEl("textarea", {
      cls: "obcc-context-edit-textarea",
      attr: { rows: "12" }
    });
    body.value = this.initialContent;
    this.contentElInput = body;
    const actions = this.contentEl.createDiv({ cls: "obcc-context-edit-actions" });
    const cancel = actions.createEl("button", { text: "Cancel", attr: { type: "button" } });
    cancel.addEventListener("click", () => this.dismiss());
    const save = actions.createEl("button", { text: "OK", attr: { type: "button" } });
    save.addClass("mod-cta");
    save.addEventListener("click", () => this.submit());
    window.setTimeout(() => this.contentElInput?.focus(), 20);
  }

  onClose(): void {
    if (!this.settled) this.onSubmitValue(null);
    this.contentEl.empty();
  }

  private dismiss(): void {
    this.close();
  }

  private submit(): void {
    this.settled = true;
    this.onSubmitValue({
      label: this.labelEl?.value.trim() || this.initialLabel,
      content: this.contentElInput?.value ?? ""
    });
    this.close();
  }
}

function editContextModal(app: App, title: string, label: string, content: string): Promise<{ label: string; content: string } | null> {
  return new Promise((resolve) => {
    new CancipContextEditModal(app, title, label, content, resolve).open();
  });
}

