class MarkdownScratchComponent extends Component {}

type EditorAutocompleteSuggestion = {
  from: number;
  suffix: string;
  candidates: string[];
  candidateIndex: number;
  rotationPaused: boolean;
  signature: string;
  prefix: string;
  trailing: string;
  lineFrom: number;
};

type EditorAutocompleteModelTree = {
  candidates: string[];
  branches: Map<string, string[]>;
};

const setEditorAutocompleteSuggestion = StateEffect.define<EditorAutocompleteSuggestion | null>();
const refreshEditorAutocompleteSuggestion = StateEffect.define<null>();
const regenerateEditorAutocompleteSuggestion = StateEffect.define<null>();
const resyncEditorAutocompleteRotation = StateEffect.define<null>();
const prefetchEditorAutocompleteNextBranches = StateEffect.define<null>();

function uniqueEditorAutocompleteCandidates(values: string[], limit = 3): string[] {
  const output: string[] = [];
  const seen = new Set<string>();
  for (const raw of values) {
    const value = raw.replace(/\r\n?/g, "\n");
    if (!value.trim()) continue;
    const key = value.toLocaleLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    output.push(value);
    if (output.length >= limit) break;
  }
  return output;
}

class EditorAutocompleteWidget extends WidgetType {
  constructor(
    private plugin: CancipPlugin,
    private suggestion: EditorAutocompleteSuggestion
  ) {
    super();
  }

  eq(other: EditorAutocompleteWidget): boolean {
    return other.suggestion.from === this.suggestion.from
      && other.suggestion.suffix === this.suggestion.suffix
      && other.suggestion.candidateIndex === this.suggestion.candidateIndex
      && sameStringArray(other.suggestion.candidates, this.suggestion.candidates)
      && other.suggestion.signature === this.suggestion.signature;
  }

  toDOM(view: EditorView): HTMLElement {
    const wrap = createDetachedElement(view.dom.ownerDocument, "span");
    wrap.addClass("obcc-editor-autocomplete-widget");
    const lineCount = Math.max(1, (this.suggestion.suffix.match(/\n/g)?.length ?? 0) + 1);
    wrap.setCssProps({ "--obcc-editor-autocomplete-line-count": String(lineCount) });
    wrap.toggleClass("is-multiline", lineCount > 1);
    const spacer = wrap.createSpan({ cls: "obcc-editor-autocomplete-spacer" });
    spacer.setAttr("aria-hidden", "true");
    spacer.createSpan({ cls: "obcc-editor-autocomplete-ghost", text: this.suggestion.suffix });
    if (this.suggestion.candidates.length > 1) {
      spacer.createSpan({
        cls: "obcc-editor-autocomplete-position",
        text: `${this.suggestion.candidateIndex + 1}/${this.suggestion.candidates.length}`
      });
    }
    const spacerButton = spacer.createSpan({ cls: "obcc-editor-autocomplete-apply" });
    setIcon(spacerButton, "corner-down-left");
    view.requestMeasure({
      read: () => {
        const cursorRect = view.coordsAtPos(this.suggestion.from);
        const lineStartRect = view.coordsAtPos(this.suggestion.lineFrom);
        const widgetRect = wrap.getBoundingClientRect();
        const contentRect = view.contentDOM.getBoundingClientRect();
        if (!cursorRect || !lineStartRect || widgetRect.width < 0) return null;
        const width = Math.max(0, contentRect.right - lineStartRect.left);
        if (width <= 0) return null;
        const firstLineIndent = Math.max(0, Math.min(width, cursorRect.left - lineStartRect.left));
        return { firstLineIndent, width, blockStart: cursorRect.top - widgetRect.top };
      },
      write: (measurement) => {
        if (!measurement || !wrap.isConnected) return;
        wrap.setCssProps({
          "--obcc-editor-autocomplete-inline-start": `${-measurement.firstLineIndent}px`,
          "--obcc-editor-autocomplete-first-line-indent": `${measurement.firstLineIndent}px`,
          "--obcc-editor-autocomplete-overlay-width": `${measurement.width}px`,
          "--obcc-editor-autocomplete-block-start": `${measurement.blockStart}px`
        });
        wrap.addClass("is-positioned");
        view.requestMeasure();
      }
    });
    const overlay = wrap.createSpan({ cls: "obcc-editor-autocomplete-overlay" });
    const ghost = overlay.createSpan({ cls: "obcc-editor-autocomplete-ghost", text: this.suggestion.suffix });
    ghost.setAttr("aria-hidden", "true");
    if (this.suggestion.candidates.length > 1) {
      overlay.createSpan({
        cls: "obcc-editor-autocomplete-position",
        text: `${this.suggestion.candidateIndex + 1}/${this.suggestion.candidates.length}`
      });
    }
    const applyButton = overlay.createEl("button", {
      cls: "obcc-editor-autocomplete-apply",
      attr: {
        type: "button",
        tabindex: "-1",
        title: this.plugin.t("autocompleteApply"),
        "aria-label": this.plugin.t("autocompleteApply")
      }
    });
    setIcon(applyButton, "corner-down-left");
    const win = view.dom.ownerDocument.defaultView;
    let longPressTimer: number | null = null;
    let longPressOpened = false;
    const cancelLongPress = () => {
      if (longPressTimer !== null && win) win.clearTimeout(longPressTimer);
      longPressTimer = null;
    };
    applyButton.addEventListener("pointerdown", (event) => {
      if (event.pointerType === "mouse" && event.button !== 0) return;
      event.preventDefault();
      event.stopPropagation();
      cancelLongPress();
      longPressOpened = false;
      if (win) {
        longPressTimer = win.setTimeout(() => {
          longPressTimer = null;
          longPressOpened = true;
          showEditorAutocompleteMenu(view, applyButton);
        }, 520);
      }
    });
    applyButton.addEventListener("pointerup", cancelLongPress);
    applyButton.addEventListener("pointercancel", cancelLongPress);
    applyButton.addEventListener("pointerleave", cancelLongPress);
    applyButton.addEventListener("contextmenu", (event) => {
      event.preventDefault();
      event.stopPropagation();
      cancelLongPress();
      const alreadyOpened = longPressOpened;
      longPressOpened = true;
      if (!alreadyOpened) showEditorAutocompleteMenu(view, applyButton);
    });
    applyButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (longPressOpened) {
        longPressOpened = false;
        return;
      }
      applyEditorAutocompleteSuggestion(view, "button");
    });
    return wrap;
  }

  ignoreEvent(): boolean {
    return true;
  }
}

const editorAutocompleteState = StateField.define<EditorAutocompleteSuggestion | null>({
  create: () => null,
  update: (value, transaction) => {
    if (transaction.docChanged && value) {
      const source = value;
      const from = transaction.changes.mapPos(source.from, 1);
      const line = transaction.newDoc.lineAt(from);
      const prefix = line.text.slice(0, Math.max(0, from - line.from));
      const trailing = line.text.slice(Math.max(0, from - line.from));
      const remainingCandidates = prefix.startsWith(source.prefix) && trailing === source.trailing
        ? uniqueEditorAutocompleteCandidates(source.candidates
            .map((candidate) => `${source.prefix}${candidate}`)
            .filter((completed) => completed.startsWith(prefix))
            .map((completed) => completed.slice(prefix.length))
            .filter(Boolean), Math.max(1, source.candidates.length))
        : [];
      const selectedCompleted = `${source.prefix}${source.suffix}`;
      const selectedRemaining = selectedCompleted.startsWith(prefix) ? selectedCompleted.slice(prefix.length) : "";
      const selectedIndex = Math.max(0, remainingCandidates.indexOf(selectedRemaining));
      value = remainingCandidates.length && transaction.newSelection.main.empty && transaction.newSelection.main.head === from
        ? {
            ...source,
            from,
            suffix: remainingCandidates[selectedIndex] ?? remainingCandidates[0],
            candidates: remainingCandidates,
            candidateIndex: selectedIndex,
            rotationPaused: false,
            prefix,
            trailing,
            lineFrom: line.from,
            signature: `${transaction.newDoc.length}:${line.from}:${from}:${stableTextHash(`${prefix}\0${trailing}`)}`
          }
        : null;
    }
    for (const effect of transaction.effects) {
      if (effect.is(setEditorAutocompleteSuggestion)) value = effect.value;
    }
    return value;
  },
  provide: (field) => EditorView.decorations.compute([field], (state) => {
    const suggestion = state.field(field);
    if (!suggestion || suggestion.from > state.doc.length) return Decoration.none;
    return Decoration.set([
      Decoration.widget({ widget: new EditorAutocompleteWidget(cancipEditorAutocompletePlugin, suggestion), side: 1 }).range(suggestion.from)
    ]);
  })
});

let cancipEditorAutocompletePlugin: CancipPlugin;

function editorAutocompleteSnapshot(view: EditorView, plugin: CancipPlugin): EditorAutocompleteSuggestion | null {
  if (!plugin.settings.composerAutocompleteEnabled || !plugin.isEditorAutocompleteViewActive(view) || view.composing) return null;
  if (view.state.selection.ranges.length !== 1 || !view.state.selection.main.empty) return null;
  const from = view.state.selection.main.head;
  const line = view.state.doc.lineAt(from);
  const column = Math.max(0, from - line.from);
  const prefix = line.text.slice(0, column);
  const trailing = line.text.slice(column);
  if (trailing && !/^\s/.test(trailing)) return null;
  return {
    from,
    suffix: "",
    signature: `${view.state.doc.length}:${line.from}:${from}:${stableTextHash(`${prefix}\0${trailing}`)}`,
    prefix,
    trailing,
    candidates: [],
    candidateIndex: 0,
    rotationPaused: false,
    lineFrom: line.from
  };
}

function rebaseEditorAutocompleteSuggestion(
  source: EditorAutocompleteSuggestion,
  candidates: string[],
  current: EditorAutocompleteSuggestion | null
): EditorAutocompleteSuggestion | null {
  if (!current || !candidates.length || current.lineFrom !== source.lineFrom) return null;
  if (current.trailing !== source.trailing) return null;
  if (!current.prefix.startsWith(source.prefix)) return null;
  const remaining = uniqueEditorAutocompleteCandidates(candidates
    .map((candidate) => `${source.prefix}${candidate}`)
    .filter((completed) => completed.startsWith(current.prefix))
    .map((completed) => completed.slice(current.prefix.length))
    .filter(Boolean), Math.max(1, candidates.length));
  if (!remaining.length) return null;
  return { ...current, suffix: remaining[0], candidates: remaining, candidateIndex: 0 };
}

function cycleEditorAutocompleteCandidate(view: EditorView, delta: number, manual = true): boolean {
  const suggestion = view.state.field(editorAutocompleteState);
  if (!suggestion || suggestion.candidates.length < 2) return false;
  const count = suggestion.candidates.length;
  const candidateIndex = (suggestion.candidateIndex + delta % count + count) % count;
  view.dispatch({
    effects: setEditorAutocompleteSuggestion.of({
      ...suggestion,
      candidateIndex,
      suffix: suggestion.candidates[candidateIndex],
      rotationPaused: manual || suggestion.rotationPaused
    })
  });
  return true;
}

function editorAutocompleteMenuPosition(button: HTMLElement): { x: number; y: number } {
  const rect = button.getBoundingClientRect();
  return { x: Math.max(8, rect.left), y: Math.max(8, rect.bottom + 4) };
}

function showEditorAutocompleteModelMenu(view: EditorView, position: { x: number; y: number }): void {
  const plugin = cancipEditorAutocompletePlugin;
  const menu = new Menu();
  menu.addItem((item) => item.setTitle(plugin.t("settingsAutocompleteModel")).setIcon("brain-circuit").setIsLabel(true));
  for (const option of plugin.autocompleteModelOptions()) {
    menu.addItem((item) => {
      item
        .setTitle(option.label)
        .setIcon(option.value ? "bot" : "git-branch")
        .setChecked(plugin.settings.composerAutocompleteModel === option.value)
        .onClick(() => void plugin.selectAutocompleteModel(option.value));
    });
  }
  menu.addSeparator();
  menu.addItem((item) => item.setTitle(plugin.t("settingsAutocompleteSource")).setIcon("server").setIsLabel(true));
  for (const option of plugin.autocompleteApiProfileOptions()) {
    menu.addItem((item) => {
      item
        .setTitle(option.label)
        .setIcon(option.value ? "bot" : "git-branch")
        .setChecked(plugin.settings.composerAutocompleteApiProfileId === option.value)
        .onClick(() => void plugin.selectAutocompleteApiProfile(option.value));
    });
  }
  menu.showAtPosition(position, view.dom.ownerDocument);
}

function showEditorAutocompleteMenu(view: EditorView, button: HTMLElement): void {
  const plugin = cancipEditorAutocompletePlugin;
  const suggestion = view.state.field(editorAutocompleteState);
  if (!suggestion) return;
  const position = editorAutocompleteMenuPosition(button);
  const menu = new Menu();
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteCandidatePosition", {
        current: suggestion.candidateIndex + 1,
        total: suggestion.candidates.length
      }))
      .setIcon("text-cursor-input")
      .setIsLabel(true);
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompletePrevious"))
      .setIcon("chevron-left")
      .setDisabled(suggestion.candidates.length < 2)
      .onClick(() => cycleEditorAutocompleteCandidate(view, -1));
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteNext"))
      .setIcon("chevron-right")
      .setDisabled(suggestion.candidates.length < 2)
      .onClick(() => cycleEditorAutocompleteCandidate(view, 1));
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteApply"))
      .setIcon("corner-down-left")
      .onClick(() => applyEditorAutocompleteSuggestion(view, "menu"));
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteRegenerateBatch"))
      .setIcon("refresh-cw")
      .onClick(() => view.dispatch({ effects: regenerateEditorAutocompleteSuggestion.of(null) }));
  });
  menu.addSeparator();
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteSelectModel"))
      .setIcon("brain-circuit")
      .onClick(() => view.dom.ownerDocument.defaultView?.setTimeout(() => showEditorAutocompleteModelMenu(view, position), 0));
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteEditPrompt"))
      .setIcon("message-square-text")
      .onClick(() => void plugin.editEditorAutocompletePrompt());
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteOpenSettings"))
      .setIcon("settings")
      .onClick(() => plugin.openCancipSettings());
  });
  menu.addItem((item) => {
    item
      .setTitle(plugin.t("autocompleteDisable"))
      .setIcon("circle-off")
      .setWarning(true)
      .onClick(() => void plugin.setEditorAutocompleteEnabled(false));
  });
  menu.showAtPosition(position, view.dom.ownerDocument);
}

function editorAutocompleteSuggestionAfterInsertion(
  view: EditorView,
  source: EditorAutocompleteSuggestion,
  inserted: string,
  candidates: string[]
): EditorAutocompleteSuggestion | null {
  const normalizedCandidates = uniqueEditorAutocompleteCandidates(
    candidates,
    cancipEditorAutocompletePlugin.editorAutocompleteCandidateCount()
  );
  if (!normalizedCandidates.length) return null;
  const from = source.from + inserted.length;
  const lastLineBreak = inserted.lastIndexOf("\n");
  const prefix = lastLineBreak >= 0
    ? inserted.slice(lastLineBreak + 1)
    : `${source.prefix}${inserted}`;
  const lineFrom = lastLineBreak >= 0
    ? source.from + lastLineBreak + 1
    : source.lineFrom;
  const trailing = source.trailing;
  return {
    from,
    suffix: normalizedCandidates[0],
    candidates: normalizedCandidates,
    candidateIndex: 0,
    rotationPaused: false,
    signature: `${view.state.doc.length + inserted.length}:${lineFrom}:${from}:${stableTextHash(`${prefix}\0${trailing}`)}`,
    prefix,
    trailing,
    lineFrom
  };
}

function applyEditorAutocompleteSuggestion(view: EditorView, trigger: EditorAutocompleteApplyTrigger = "button"): boolean {
  const suggestion = view.state.field(editorAutocompleteState);
  if (!suggestion || !suggestion.suffix || view.state.selection.main.head !== suggestion.from) return false;
  const plugin = cancipEditorAutocompletePlugin;
  const current = editorAutocompleteSnapshot(view, plugin);
  if (!current || current.signature !== suggestion.signature) return false;
  const path = plugin.app.workspace.getActiveFile()?.path ?? "";
  const completedPrefix = `${suggestion.prefix}${suggestion.suffix}`;
  const prefetched = plugin.editorPrefetchedAutocompleteCandidates(completedPrefix, path);
  const provisionalNext = prefetched.length
    ? editorAutocompleteSuggestionAfterInsertion(view, suggestion, suggestion.suffix, prefetched)
    : null;
  const immediateCandidates = provisionalNext
    ? plugin.rememberEditorAutocompleteCandidateAlias(provisionalNext.prefix, path, provisionalNext.candidates)
    : [];
  const immediateNext = provisionalNext && immediateCandidates.length
    ? { ...provisionalNext, suffix: immediateCandidates[0], candidates: immediateCandidates }
    : null;
  void plugin.recordEditorAutocompleteChoice(suggestion.suffix, {
    prefix: suggestion.prefix,
    index: suggestion.candidateIndex,
    total: suggestion.candidates.length,
    trigger,
    preloadedNextBranch: prefetched.length > 0,
    rotationPaused: suggestion.rotationPaused
  });
  view.dispatch({
    changes: { from: suggestion.from, insert: suggestion.suffix },
    selection: { anchor: suggestion.from + suggestion.suffix.length },
    effects: immediateNext
      ? [
          setEditorAutocompleteSuggestion.of(immediateNext),
          prefetchEditorAutocompleteNextBranches.of(null)
        ]
      : setEditorAutocompleteSuggestion.of(null),
    scrollIntoView: true
  });
  view.focus();
  if (immediateNext) return true;
  const next = editorAutocompleteSnapshot(view, plugin);
  const adoptBranch = (expected: EditorAutocompleteSuggestion, values: string[]): boolean => {
    if (!view.dom.isConnected || plugin.app.workspace.getActiveFile()?.path !== path) return false;
    const live = editorAutocompleteSnapshot(view, plugin);
    if (!live || live.signature !== expected.signature) return false;
    const candidates = plugin.rememberEditorAutocompleteCandidateAlias(live.prefix, path, values);
    if (candidates.length) {
      view.dispatch({
        effects: [
          setEditorAutocompleteSuggestion.of({
            ...live,
            suffix: candidates[0],
            candidates,
            candidateIndex: 0
          }),
          prefetchEditorAutocompleteNextBranches.of(null)
        ]
      });
      return true;
    }
    return false;
  };
  if (next && prefetched.length) {
    adoptBranch(next, prefetched);
  } else if (next && plugin.settings.composerAutocompletePrefetchEnabled) {
    void plugin.awaitEditorAutocompleteBranchPrefetch(completedPrefix, path)
      .then((candidates) => {
        if (candidates.length) adoptBranch(next, candidates);
      })
      .catch(() => undefined);
  }
  return true;
}

function createCancipEditorAutocompleteExtension(plugin: CancipPlugin): Extension {
  cancipEditorAutocompletePlugin = plugin;
  const behavior = ViewPlugin.fromClass(class {
    private timer: number | null = null;
    private candidateRotationTimer: number | null = null;
    private requestId = 0;
    private destroyed = false;
    private inputArmed = false;
    private modelInFlight = false;
    private queuedSnapshot: EditorAutocompleteSuggestion | null = null;
    private queuedForce = false;
    private readonly compositionEnd = () => {
      const win = this.view.dom.ownerDocument.defaultView;
      if (!win || !this.inputArmed) return;
      win.requestAnimationFrame(() => this.schedule());
    };

    constructor(private view: EditorView) {
      this.view.dom.addEventListener("compositionend", this.compositionEnd);
    }

    update(update: ViewUpdate): void {
      const effects = update.transactions.flatMap((transaction) => transaction.effects);
      if (effects.some((effect) => effect.is(setEditorAutocompleteSuggestion))) this.syncCandidateRotation();
      if (effects.some((effect) => effect.is(resyncEditorAutocompleteRotation))) this.syncCandidateRotation();
      if (effects.some((effect) => effect.is(prefetchEditorAutocompleteNextBranches))) {
        const suggestion = this.view.state.field(editorAutocompleteState);
        if (suggestion) {
          const path = plugin.app.workspace.getActiveFile()?.path ?? "";
          this.scheduleBranchPrefetch(suggestion, suggestion.candidates, path);
        }
        return;
      }
      if (effects.some((effect) => effect.is(regenerateEditorAutocompleteSuggestion))) {
        if (this.inputArmed) this.schedule(undefined, { force: true });
        else this.clearInactiveState();
        return;
      }
      if (effects.some((effect) => effect.is(refreshEditorAutocompleteSuggestion))) {
        if (this.inputArmed) this.schedule(undefined, { force: true });
        else this.clearInactiveState();
        return;
      }
      if (update.docChanged) {
        const userChangedDocument = update.transactions.some((transaction) => (
          transaction.isUserEvent("input")
          || transaction.isUserEvent("delete")
          || transaction.isUserEvent("undo")
          || transaction.isUserEvent("redo")
        ));
        const appliedAutocomplete = effects.some((effect) => effect.is(setEditorAutocompleteSuggestion));
        const focusedDocumentEdit = !appliedAutocomplete
          && this.view.hasFocus
          && plugin.isEditorAutocompleteViewActive(this.view);
        if (userChangedDocument || focusedDocumentEdit) {
          this.inputArmed = this.view.state.doc.length > 0;
        }
        if ((userChangedDocument || focusedDocumentEdit || appliedAutocomplete) && this.inputArmed) {
          this.schedule(update.startState.field(editorAutocompleteState));
        } else if (!this.inputArmed) {
          this.clearInactiveState();
        }
        return;
      }
      if (update.focusChanged && !plugin.isEditorAutocompleteViewActive(this.view)) {
        this.inputArmed = false;
        this.clearInactiveState();
        return;
      }
      if ((update.selectionSet || update.focusChanged) && this.inputArmed) this.schedule();
    }

    destroy(): void {
      this.destroyed = true;
      this.requestId += 1;
      this.queuedSnapshot = null;
      this.queuedForce = false;
      this.clearTimer();
      this.clearCandidateRotation();
      this.view.dom.removeEventListener("compositionend", this.compositionEnd);
    }

    private clearTimer(): void {
      const win = this.view.dom.ownerDocument.defaultView;
      if (this.timer !== null && win) win.clearTimeout(this.timer);
      this.timer = null;
    }

    private clearCandidateRotation(): void {
      const win = this.view.dom.ownerDocument.defaultView;
      if (this.candidateRotationTimer !== null && win) win.clearTimeout(this.candidateRotationTimer);
      this.candidateRotationTimer = null;
    }

    private clearInactiveState(): void {
      this.clearTimer();
      this.clearCandidateRotation();
      this.queuedSnapshot = null;
      this.queuedForce = false;
      const requestId = ++this.requestId;
      const win = this.view.dom.ownerDocument.defaultView;
      if (!win) return;
      win.setTimeout(() => {
        if (this.destroyed || requestId !== this.requestId) return;
        if (this.view.state.field(editorAutocompleteState)) {
          this.view.dispatch({ effects: setEditorAutocompleteSuggestion.of(null) });
        }
      }, 0);
    }

    private syncCandidateRotation(): void {
      this.clearCandidateRotation();
      if (this.destroyed) return;
      const suggestion = this.view.state.field(editorAutocompleteState);
      const win = this.view.dom.ownerDocument.defaultView;
      if (!win || !suggestion || suggestion.rotationPaused || suggestion.candidates.length < 2) return;
      this.candidateRotationTimer = win.setTimeout(() => {
        this.candidateRotationTimer = null;
        cycleEditorAutocompleteCandidate(this.view, 1, false);
      }, plugin.editorAutocompleteRotationMs());
    }

    private dispatchSuggestion(snapshot: EditorAutocompleteSuggestion, candidates: string[], candidateIndex = 0, allowReplace = false): void {
      if (this.destroyed || !this.inputArmed) return;
      const existing = this.view.state.field(editorAutocompleteState);
      const normalizedCandidates = uniqueEditorAutocompleteCandidates(candidates, plugin.editorAutocompleteCandidateCount());
      if (!normalizedCandidates.length) {
        if (existing) this.view.dispatch({ effects: setEditorAutocompleteSuggestion.of(null) });
        return;
      }
      const current = editorAutocompleteSnapshot(this.view, plugin);
      if (!current || current.signature !== snapshot.signature) return;
      const sameBatch = existing?.signature === snapshot.signature
        && sameStringArray(existing.candidates, normalizedCandidates);
      if (!allowReplace && existing?.signature === snapshot.signature && existing.candidates.length && !sameBatch) return;
      const requestedIndex = Math.max(0, Math.min(candidateIndex, normalizedCandidates.length - 1));
      const nextIndex = sameBatch
        ? Math.max(0, Math.min(existing.candidateIndex, normalizedCandidates.length - 1))
        : requestedIndex;
      const value = {
        ...snapshot,
        suffix: normalizedCandidates[nextIndex],
        candidates: normalizedCandidates,
        candidateIndex: nextIndex,
        rotationPaused: sameBatch ? existing.rotationPaused : false
      };
      if (existing?.signature === value.signature
        && existing.candidateIndex === value.candidateIndex
        && sameStringArray(existing.candidates, value.candidates)) return;
      this.view.dispatch({ effects: setEditorAutocompleteSuggestion.of(value) });
    }

    private scheduleBranchPrefetch(snapshot: EditorAutocompleteSuggestion, candidates: string[], path: string): void {
      if (!this.inputArmed || !plugin.settings.composerAutocompletePrefetchEnabled || !candidates.length) return;
      const current = editorAutocompleteSnapshot(this.view, plugin);
      if (!current || current.signature !== snapshot.signature) return;
      const contextFrom = Math.max(0, snapshot.from - 1050);
      const contextTo = Math.min(this.view.state.doc.length, snapshot.from + 150);
      const context = `${this.view.state.sliceDoc(contextFrom, snapshot.from)}<CURSOR>${this.view.state.sliceDoc(snapshot.from, contextTo)}`;
      plugin.scheduleEditorAutocompleteBranchPrefetch(snapshot.prefix, context, path, candidates);
    }

    private schedule(previous?: EditorAutocompleteSuggestion | null, options: { force?: boolean } = {}): void {
      this.clearTimer();
      if (!this.inputArmed) {
        this.clearInactiveState();
        return;
      }
      const requestId = ++this.requestId;
      const snapshot = editorAutocompleteSnapshot(this.view, plugin);
      const win = this.view.dom.ownerDocument.defaultView;
      if (!win) return;
      if (!snapshot) {
        this.clearCandidateRotation();
        this.queuedSnapshot = null;
        this.queuedForce = false;
        win.setTimeout(() => {
          if (requestId === this.requestId) this.dispatchSuggestion({ from: 0, suffix: "", candidates: [], candidateIndex: 0, rotationPaused: false, signature: "", prefix: "", trailing: "", lineFrom: 0 }, []);
        }, 0);
        return;
      }
      const carried = previous ? rebaseEditorAutocompleteSuggestion(previous, previous.candidates, snapshot) : null;
      const local = plugin.editorLocalAutocompleteSuffix(snapshot.prefix);
      const path = plugin.app.workspace.getActiveFile()?.path ?? "";
      const prefetched = options.force ? [] : plugin.editorPrefetchedAutocompleteCandidates(snapshot.prefix, path);
      const waitForCompleteModelTree = plugin.editorAutocompleteModelConfigured();
      const displayed = this.view.state.field(editorAutocompleteState);
      const displayedBatchIsStable = !options.force
        && displayed?.signature === snapshot.signature
        && displayed.from === snapshot.from
        && displayed.candidates.length > 0;
      if (displayedBatchIsStable) {
        this.queuedSnapshot = null;
        this.queuedForce = false;
        return;
      }
      const immediateCandidates = uniqueEditorAutocompleteCandidates([
        ...(prefetched ?? []),
        ...(carried?.candidates ?? []),
        ...(waitForCompleteModelTree ? [] : local ? [local] : [])
      ], plugin.editorAutocompleteCandidateCount());
      if (immediateCandidates.length) {
        this.queuedSnapshot = null;
        win.setTimeout(() => {
          if (requestId !== this.requestId) return;
          this.dispatchSuggestion(snapshot, immediateCandidates);
          if (prefetched.length) this.scheduleBranchPrefetch(snapshot, immediateCandidates, path);
        }, 0);
      }
      if (!immediateCandidates.length && (!displayed?.suffix || displayed.from !== snapshot.from)) {
        win.setTimeout(() => {
          if (requestId === this.requestId) this.dispatchSuggestion(snapshot, []);
        }, 0);
      }
      if (!options.force && prefetched.length) return;
      this.timer = win.setTimeout(() => {
        this.timer = null;
        const current = editorAutocompleteSnapshot(this.view, plugin);
        if (requestId !== this.requestId || !current || current.signature !== snapshot.signature) return;
        if (this.modelInFlight) {
          this.queuedSnapshot = current;
          this.queuedForce ||= Boolean(options.force);
          return;
        }
        void this.requestModelSuggestion(current, Boolean(options.force));
      }, options.force || prefetched.length ? 0 : EDITOR_AUTOCOMPLETE_DEBOUNCE_MS);
    }

    private async requestModelSuggestion(snapshot: EditorAutocompleteSuggestion, force = false): Promise<void> {
      const current = editorAutocompleteSnapshot(this.view, plugin);
      if (!this.inputArmed || !current || current.signature !== snapshot.signature || this.destroyed || this.modelInFlight) return;
      const displayedAtStart = this.view.state.field(editorAutocompleteState);
      const contextFrom = Math.max(0, snapshot.from - 1050);
      const contextTo = Math.min(this.view.state.doc.length, snapshot.from + 150);
      const context = `${this.view.state.sliceDoc(contextFrom, snapshot.from)}<CURSOR>${this.view.state.sliceDoc(snapshot.from, contextTo)}`;
      const path = plugin.app.workspace.getActiveFile()?.path ?? "";
      let prefetchedRoots = force ? [] : plugin.editorPrefetchedAutocompleteCandidates(snapshot.prefix, path);
      const finishActivity = plugin.beginEditorAutocompleteActivity();
      this.modelInFlight = true;
      let candidates: string[] = [];
      try {
        if (prefetchedRoots.length) {
          candidates = prefetchedRoots;
        } else {
          const live = editorAutocompleteSnapshot(this.view, plugin);
          if (live?.signature === snapshot.signature) {
            candidates = await plugin.editorAutocompleteCandidates(snapshot.prefix, context, path, {
              force,
              excluded: force ? displayedAtStart?.candidates ?? [] : []
            });
          }
        }
      } finally {
        this.modelInFlight = false;
        finishActivity();
      }
      if (this.destroyed || !this.inputArmed || !plugin.isEditorAutocompleteViewActive(this.view)) return;
      const latest = editorAutocompleteSnapshot(this.view, plugin);
      if (!latest) {
        this.queuedSnapshot = null;
        this.queuedForce = false;
        this.dispatchSuggestion(snapshot, []);
        return;
      }
      const inserted = latest.from >= snapshot.from
        ? this.view.state.sliceDoc(snapshot.from, latest.from)
        : "";
      const accepted = candidates.find((candidate) => inserted === candidate);
      if (accepted) {
        const branches = plugin.editorPrefetchedAutocompleteCandidates(`${snapshot.prefix}${accepted}`, path);
        const adopted = plugin.rememberEditorAutocompleteCandidateAlias(latest.prefix, path, branches);
        if (adopted.length) {
          this.clearTimer();
          this.queuedSnapshot = null;
          this.queuedForce = false;
          this.dispatchSuggestion(latest, adopted);
          this.scheduleBranchPrefetch(latest, adopted, path);
          return;
        }
      }
      const rebased = rebaseEditorAutocompleteSuggestion(snapshot, candidates, latest);
      if (rebased) {
        this.clearTimer();
        this.queuedSnapshot = null;
        this.queuedForce = false;
        this.dispatchSuggestion(rebased, rebased.candidates, rebased.candidateIndex);
        this.scheduleBranchPrefetch(rebased, rebased.candidates, path);
        return;
      }
      const queued = this.queuedSnapshot;
      const queuedForce = this.queuedForce;
      this.queuedSnapshot = null;
      this.queuedForce = false;
      if (latest.signature !== snapshot.signature) {
        this.schedule();
        return;
      }
      if (candidates.length) {
        this.dispatchSuggestion(snapshot, candidates, 0, force);
        this.scheduleBranchPrefetch(snapshot, candidates, path);
      }
      if (queued?.signature === latest.signature && queuedForce) {
        void this.requestModelSuggestion(latest, true);
      }
    }
  });
  return [
    editorAutocompleteState,
    behavior,
    keymap.of([{
      key: "Tab",
      run: (view) => applyEditorAutocompleteSuggestion(view, "tab")
    }])
  ];
}

