function scoreCapabilityRoute(route: CapabilityRoute, query: string): number {
  const normalized = query.toLocaleLowerCase().trim();
  if (!normalized) return route.priority;
  const compact = normalized.replace(/\s+/g, "");
  let score = route.priority;
  if (compact.includes(route.id.replace(/-/g, ""))) score += 120;
  const tokens = uniqueStrings(normalized.split(/[^\p{L}\p{N}_.-]+/u).filter((token) => token.length >= 2));
  const haystack = `${route.id} ${route.title} ${route.purpose} ${route.keywords.join(" ")}`.toLocaleLowerCase();
  for (const token of tokens) {
    if (haystack.includes(token)) score += route.keywords.some((keyword) => keyword.toLocaleLowerCase().includes(token)) ? 12 : 5;
  }
  return score;
}

function uniqueStrings(values: string[]): string[] {
  return [...new Set(values.map((value) => value.trim()).filter(Boolean))];
}

function isSkillFileCandidatePath(path: string): boolean {
  const normalized = normalizePath(path);
  const lower = normalized.toLowerCase();
  const name = lower.split("/").pop() ?? lower;
  if (!isContextTextPath(normalized)) return false;
  if (name === "skill.md" || name.endsWith(".skill.md")) return true;
  if (/(^|\/)(skills?|skillob|技能|能力)(\/|$)/i.test(lower)) return name.endsWith(".md") || name.endsWith(".txt");
  if (isPathInVaultFolder(lower, `${CANCIP_CONFIG_DIR.toLowerCase()}/skills`) || lower.startsWith("ai/cancip/skills/")) return name.endsWith(".md") || name.endsWith(".txt");
  return false;
}

function skillCandidatePriority(path: string, pluginInstallDir: string): number {
  const lower = normalizePath(path).toLowerCase();
  const pluginDir = normalizePath(pluginInstallDir).toLowerCase();
  let score = 0;
  if (lower.startsWith("cancip://builtin/")) score += 30;
  if (lower.endsWith("/skill.md") || lower === "skill.md") score += 100;
  if (lower.endsWith(".skill.md")) score += 90;
  if (isPathInVaultFolder(lower, `${CANCIP_CONFIG_DIR.toLowerCase()}/skills`)) score += 70;
  if (lower.startsWith("ai/cancip/skills/")) score += 64;
  if (lower.includes("/skillob/")) score += 55;
  if (/(^|\/)(skills?|技能|能力)(\/|$)/i.test(lower)) score += 45;
  if (pluginDir && isPathInFolder(lower, pluginDir)) score += 20;
  return score;
}

function filterFreshNewsBriefItems(items: NewsBriefItem[], now: number): { items: NewsBriefItem[]; dropped: number } {
  const currentYear = new Date(now).getFullYear();
  const fresh: NewsBriefItem[] = [];
  const undated: NewsBriefItem[] = [];
  let dropped = 0;
  for (const item of items) {
    if (newsBriefLooksExplicitlyOld(item, currentYear)) {
      dropped += 1;
      continue;
    }
    const publishedAt = Date.parse(item.published || "");
    if (Number.isFinite(publishedAt) && publishedAt > 0) {
      const age = now - publishedAt;
      if (age >= -60 * 60 * 1000 && age <= NEWS_BRIEF_MAX_AGE_MS) fresh.push(item);
      else dropped += 1;
      continue;
    }
    undated.push(item);
  }
  const selectedUndated = undated.slice(0, NEWS_BRIEF_UNDATED_LIMIT);
  dropped += Math.max(0, undated.length - selectedUndated.length);
  return { items: [...fresh, ...selectedUndated], dropped };
}

function newsBriefLooksExplicitlyOld(item: NewsBriefItem, currentYear: number): boolean {
  const text = `${item.title} ${item.summary} ${item.link}`;
  const years = [...text.matchAll(/\b(20\d{2}|19\d{2})\b/g)].map((match) => Number.parseInt(match[1], 10));
  return years.some((year) => Number.isFinite(year) && year <= currentYear - 2);
}

