function isAbortControllerAborted(request: AbortController): boolean {
  return Boolean((request as unknown as { signal?: { aborted?: boolean } }).signal?.aborted);
}

function vaultPathParent(path: string): string {
  const normalized = normalizePath(path.replace(/\\/g, "/"));
  const index = normalized.lastIndexOf("/");
  return index >= 0 ? normalized.slice(0, index) : "";
}

function normalizeFilePinPath(path: string): string {
  const stripped = String(path ?? "").replace(/\\/g, "/").replace(/^\/+|\/+$/g, "");
  if (!stripped) return "";
  return normalizePath(stripped).replace(/^\/+|\/+$/g, "");
}

function normalizeFilePinFolderPath(path: string): string {
  return normalizeFilePinPath(path);
}

function emptyFilePinState(): FilePinState {
  return {
    schemaVersion: CANCIP_FILE_PINS_SCHEMA_VERSION,
    updatedAt: new Date(0).toISOString(),
    folders: {}
  };
}

function cloneFilePinState(state: FilePinState): FilePinState {
  return {
    schemaVersion: CANCIP_FILE_PINS_SCHEMA_VERSION,
    updatedAt: state.updatedAt,
    folders: Object.fromEntries(Object.entries(state.folders).map(([folder, paths]) => [folder, [...paths]]))
  };
}

function normalizeFilePinState(raw: unknown): FilePinState {
  const folders: Record<string, string[]> = {};
  const seen = new Set<string>();
  const rawFolders = isRecord(raw) && isRecord(raw.folders) ? raw.folders : {};
  for (const paths of Object.values(rawFolders)) {
    if (!Array.isArray(paths)) continue;
    for (const value of paths) {
      if (typeof value !== "string") continue;
      const path = normalizeFilePinPath(value);
      if (!path || seen.has(path)) continue;
      seen.add(path);
      const folder = vaultPathParent(path);
      (folders[folder] ??= []).push(path);
    }
  }
  return {
    schemaVersion: CANCIP_FILE_PINS_SCHEMA_VERSION,
    updatedAt: isRecord(raw) && typeof raw.updatedAt === "string" && raw.updatedAt.trim() ? raw.updatedAt : new Date(0).toISOString(),
    folders
  };
}

function removePathFromFilePinFolders(folders: Record<string, string[]>, path: string): void {
  for (const [folder, paths] of Object.entries(folders)) {
    folders[folder] = paths.filter((item) => item !== path);
  }
  removeEmptyFilePinFolders(folders);
}

function removeEmptyFilePinFolders(folders: Record<string, string[]>): void {
  for (const [folder, paths] of Object.entries(folders)) {
    const unique = uniqueStrings(paths.map(normalizeFilePinPath).filter(Boolean));
    if (unique.length) folders[folder] = unique;
    else delete folders[folder];
  }
}

function filePinPathMatchesBase(path: string, basePath: string): boolean {
  return path === basePath || path.startsWith(`${basePath}/`);
}

function migrateFilePinStatePaths(state: FilePinState, oldPath: string, newPath: string): FilePinState {
  const oldNormalized = normalizeFilePinPath(oldPath);
  const newNormalized = normalizeFilePinPath(newPath);
  if (!oldNormalized || !newNormalized || oldNormalized === newNormalized) return state;
  const exactSameFolder = vaultPathParent(oldNormalized) === vaultPathParent(newNormalized)
    && Object.values(state.folders).flat().some((path) => path === oldNormalized)
    && !Object.values(state.folders).flat().some((path) => path.startsWith(`${oldNormalized}/`));
  if (exactSameFolder) {
    for (const [folder, paths] of Object.entries(state.folders)) {
      state.folders[folder] = paths.map((path) => path === oldNormalized ? newNormalized : path);
    }
    return normalizeFilePinState(state);
  }
  const unaffected: string[] = [];
  const affected: string[] = [];
  for (const path of Object.values(state.folders).flat()) {
    if (filePinPathMatchesBase(path, oldNormalized)) {
      affected.push(`${newNormalized}${path.slice(oldNormalized.length)}`);
    } else {
      unaffected.push(path);
    }
  }
  const folders: Record<string, string[]> = {};
  for (const path of [...unaffected, ...affected]) {
    const normalized = normalizeFilePinPath(path);
    if (!normalized) continue;
    const folder = vaultPathParent(normalized);
    const paths = folders[folder] ?? [];
    if (!paths.includes(normalized)) paths.push(normalized);
    folders[folder] = paths;
  }
  return {
    schemaVersion: CANCIP_FILE_PINS_SCHEMA_VERSION,
    updatedAt: state.updatedAt,
    folders
  };
}

function sameStringArray(left: string[], right: string[]): boolean {
  return left.length === right.length && left.every((value, index) => value === right[index]);
}

function stableCacheKey(value: unknown): string {
  return JSON.stringify(canonicalJsonValue(value));
}

function uniqueCancipActions(actions: CancipAction[]): CancipAction[] {
  const seen = new Set<string>();
  return actions.filter((action) => {
    const key = stableCacheKey(action);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function canonicalJsonValue(value: unknown): unknown {
  if (Array.isArray(value)) return value.map((item) => canonicalJsonValue(item));
  if (!isRecord(value)) return value;
  const output: Record<string, unknown> = {};
  for (const key of Object.keys(value).sort()) {
    output[key] = canonicalJsonValue(value[key]);
  }
  return output;
}

function getDefaultApiProfile(): ApiProfile {
  return { ...DEFAULT_SETTINGS.apiProfiles[0] };
}

function normalizeApiProfile(raw: Partial<ApiProfile>, fallback: ApiProfile): ApiProfile {
  const id = typeof raw.id === "string" && raw.id.trim() ? raw.id.trim() : fallback.id;
  const name = typeof raw.name === "string" && raw.name.trim() ? raw.name.trim() : fallback.name;
  const apiMode = isApiMode(raw.apiMode) ? raw.apiMode : fallback.apiMode;
  return {
    id,
    name,
    apiUrl: typeof raw.apiUrl === "string" ? raw.apiUrl.trim() : fallback.apiUrl,
    apiKey: typeof raw.apiKey === "string" ? raw.apiKey.trim() : fallback.apiKey,
    apiMode,
    model: typeof raw.model === "string" && raw.model.trim() ? raw.model.trim() : fallback.model
  };
}

function normalizeApiProfiles(raw: unknown, legacy: ApiProfile): ApiProfile[] {
  if (!Array.isArray(raw) || !raw.length) return mergeApiProfilePresets([legacy]);
  const seen = new Set<string>();
  const profiles: ApiProfile[] = [];
  raw.forEach((item, index) => {
    if (!isRecord(item)) return;
    const fallback = index === 0 ? legacy : { ...legacy, id: `profile-${index + 1}`, name: `Profile ${index + 1}`, apiKey: "" };
    let profile = normalizeApiProfile(item, fallback);
    if (seen.has(profile.id)) {
      profile = { ...profile, id: `${profile.id}-${index + 1}` };
    }
    seen.add(profile.id);
    profiles.push(profile);
  });
  return mergeApiProfilePresets(profiles.length ? profiles : [legacy]);
}

function mergeApiProfilePresets(profiles: ApiProfile[]): ApiProfile[] {
  const configuredByEndpoint = new Map<string, ApiProfile>();
  for (const profile of profiles) {
    const endpoint = apiEndpointIdentity(profile.apiUrl);
    if (endpoint && profile.apiKey.trim() && !configuredByEndpoint.has(endpoint)) configuredByEndpoint.set(endpoint, profile);
  }
  const next = profiles.filter((profile) => {
    const preset = API_PROFILE_PRESETS.find((item) => item.id === profile.id);
    if (!preset || profile.apiKey.trim()) return true;
    const presetEndpoint = apiEndpointIdentity(preset.apiUrl);
    return apiEndpointIdentity(profile.apiUrl) !== presetEndpoint || !configuredByEndpoint.has(presetEndpoint);
  });
  const ids = new Set(next.map((profile) => profile.id));
  for (const preset of API_PROFILE_PRESETS) {
    if (ids.has(preset.id)) continue;
    const endpoint = apiEndpointIdentity(preset.apiUrl);
    if (endpoint && configuredByEndpoint.has(endpoint)) continue;
    ids.add(preset.id);
    next.push({ ...preset });
  }
  return next.slice(0, 40);
}

function apiEndpointIdentity(rawUrl: string): string {
  const trimmed = rawUrl.trim();
  if (!trimmed) return "";
  try {
    const url = new URL(trimmed);
    const pathname = url.pathname.replace(/\/+$/, "") || "/";
    return `${url.protocol.toLowerCase()}//${url.host.toLowerCase()}${pathname.toLowerCase()}`;
  } catch {
    return trimmed.replace(/\/+$/, "").toLowerCase();
  }
}

function resolveApiProfileId(rawId: string, profiles: ApiProfile[]): string {
  const id = rawId.trim();
  if (!id) return "";
  if (profiles.some((profile) => profile.id === id)) return id;
  const lower = id.toLowerCase();
  const sameId = profiles.find((profile) => profile.id.toLowerCase() === lower);
  if (sameId) return sameId.id;
  const sameName = profiles.find((profile) => (profile.name || profile.id).trim().toLowerCase() === lower);
  if (sameName) return sameName.id;
  const preset = API_PROFILE_PRESETS.find((profile) => profile.id.toLowerCase() === id.toLowerCase());
  if (!preset) return id;
  const endpoint = apiEndpointIdentity(preset.apiUrl);
  return profiles.find((profile) => profile.apiKey.trim() && apiEndpointIdentity(profile.apiUrl) === endpoint)?.id ?? preset.id;
}

function apiProfileDisplayLabel(profile: ApiProfile, language: Language): string {
  const name = profile.name || profile.id;
  if (profile.apiKey.trim()) return name;
  return `${name} · ${isChineseLanguage(language) ? "未配置密钥" : "API key missing"}`;
}

function normalizeModelOptions(raw: unknown, activeModel?: string): string[] {
  const values: string[] = [];
  const push = (value: unknown): void => {
    if (typeof value !== "string") return;
    for (const part of value.split(/[\r\n,]+/)) {
      const model = part.trim();
      if (model) values.push(model);
    }
  };
  if (Array.isArray(raw)) {
    for (const item of raw) push(item);
  } else {
    push(raw);
  }
  if (!values.length) values.push(...MODEL_PRESETS);
  const unique = uniqueStrings(values);
  const active = activeModel?.trim();
  if (active && !unique.includes(active)) unique.push(active);
  return unique.slice(0, 80);
}

function defaultModelSourceByModel(models: readonly string[]): Record<string, string> {
  const result: Record<string, string> = {};
  for (const model of models) {
    const normalized = String(model ?? "").trim();
    if (!normalized) continue;
    result[normalized] = defaultModelSourceIdForModel(normalized);
  }
  return result;
}

function defaultModelSourceIdForModel(model: string): string {
  const lower = model.trim().toLowerCase();
  if (!lower) return "default";
  if (lower.startsWith("qwen/") || lower.startsWith("deepseek-ai/") || lower.startsWith("baai/") || lower.startsWith("zai-org/")) return "siliconflow";
  if (lower.includes("/") || lower.startsWith("anthropic/") || lower.startsWith("google/") || lower.startsWith("deepseek/") || lower.startsWith("x-ai/") || lower.startsWith("mistralai/") || lower.startsWith("meta-llama/")) return "openrouter";
  if (/^(gpt-|o\d|chatgpt-|openai-)/.test(lower)) return "default";
  if (lower.startsWith("gemini-")) return "google-gemini";
  if (lower.startsWith("deepseek-")) return "deepseek";
  if (/^(qwen|qwq|wanx|baichuan)/.test(lower)) return "dashscope";
  if (/^(kimi|moonshot)/.test(lower)) return "moonshot";
  if (/^(glm|charglm)/.test(lower)) return "zhipu";
  if (/^(grok|xai)/.test(lower)) return "xai";
  if (/^(mistral|codestral|open-mistral|pixtral)/.test(lower)) return "mistral";
  if (/^(sonar|pplx)/.test(lower)) return "perplexity";
  if (/^(llama|mixtral|meta-llama)/.test(lower)) return "groq";
  return "openrouter";
}

function normalizeModelSourceByModel(raw: unknown, models: string[], profiles: ApiProfile[], activeProfileId: string): Record<string, string> {
  const modelSet = new Set(models);
  const profileIds = new Set(profiles.map((profile) => profile.id));
  const fallbackProfileId = profileIds.has(activeProfileId) ? activeProfileId : profiles[0]?.id ?? "default";
  const result: Record<string, string> = {};
  if (isRecord(raw)) {
    for (const [model, profileId] of Object.entries(raw)) {
      const cleanModel = model.trim();
      const cleanProfileId = typeof profileId === "string" ? resolveApiProfileId(profileId, profiles) : "";
      if (!cleanModel || !modelSet.has(cleanModel) || !profileIds.has(cleanProfileId)) continue;
      result[cleanModel] = cleanProfileId;
    }
  }
  for (const profile of profiles) {
    if (modelSet.has(profile.model) && !result[profile.model]) result[profile.model] = profile.id;
  }
  for (const model of models) {
    if (result[model] && profileIds.has(result[model])) continue;
    const guessed = resolveApiProfileId(defaultModelSourceIdForModel(model), profiles);
    result[model] = profileIds.has(guessed) ? guessed : fallbackProfileId;
  }
  return result;
}

function isCjkChar(char: string): boolean {
  return /[\u3400-\u9fff]/.test(char);
}

function hasCjkText(input: string): boolean {
  return /[\u3400-\u9fff]/.test(input);
}

function looksLikeEnglishTtsText(input: string): boolean {
  const letters = input.match(/[A-Za-z]/g)?.length ?? 0;
  if (!letters) return false;
  const cjk = input.match(/[\u3400-\u9fff]/g)?.length ?? 0;
  return letters >= Math.max(3, cjk * 2);
}

function normalizeSkillRoots(raw: unknown): string[] {
  const values: string[] = [];
  const push = (value: unknown): void => {
    if (typeof value !== "string") return;
    for (const part of value.split(/[\r\n,]+/)) {
      const root = normalizePath(part.trim().replace(/^\/+|\/+$/g, ""));
      if (root && root !== ".") values.push(root);
    }
  };
  if (Array.isArray(raw)) {
    for (const item of raw) push(item);
  } else {
    push(raw);
  }
  if (!values.length) values.push(...DEFAULT_SKILL_ROOTS);
  return uniqueStrings(values).slice(0, 40);
}

function normalizeTagList(raw: unknown): string[] {
  const values = Array.isArray(raw) ? raw : [];
  return uniqueStrings(values
    .filter((item): item is string => typeof item === "string")
    .map((item) => normalizeTagName(item))
    .filter(Boolean))
    .slice(0, 200);
}

function normalizeUiButtonRules(raw: unknown): UiButtonRule[] {
  if (!Array.isArray(raw)) return [];
  const rules = raw
    .filter(isRecord)
    .map((item): UiButtonRule | null => {
      const rawSelector = typeof item.selector === "string" ? item.selector.trim() : "";
      const label = typeof item.label === "string" && item.label.trim() ? item.label.trim() : rawSelector;
      const selector = migrateUiButtonRuleSelector(rawSelector, label);
      if (!selector) return null;
      const scope = item.scope === "active" || item.scope === "cancip" ? item.scope : "global";
      const rawId = typeof item.id === "string" && item.id.trim() ? item.id.trim() : "";
      const order = Number.isFinite(Number(item.order)) ? Math.max(-999, Math.min(999, Math.round(Number(item.order)))) : 0;
      const title = typeof item.title === "string" && item.title.trim() ? item.title.trim() : undefined;
      const icon = typeof item.icon === "string" && item.icon.trim() ? item.icon.trim() : undefined;
      const rawCommandId = typeof item.commandId === "string" && item.commandId.trim() ? item.commandId.trim() : undefined;
      const commandId = rawCommandId?.startsWith("uiclick:")
        ? `uiclick:${migrateUiButtonRuleSelector(rawCommandId.slice("uiclick:".length).trim()) || rawCommandId.slice("uiclick:".length).trim()}`
        : rawCommandId;
      const rawAnchorSelector = typeof item.anchorSelector === "string" && item.anchorSelector.trim() ? item.anchorSelector.trim() : undefined;
      const anchorSelector = rawAnchorSelector ? migrateUiButtonAnchorSelector(rawAnchorSelector) : undefined;
      const looksLikeCustom = item.kind === "custom"
        || rawId.startsWith("custom-")
        || selector.includes("data-cancip-ui-custom-button-id")
        || Boolean(commandId || anchorSelector);
      const kind = item.kind === "custom" || (commandId && anchorSelector) ? "custom" : undefined;
      if (looksLikeCustom && (!commandId || !anchorSelector)) return null;
      const commandName = typeof item.commandName === "string" && item.commandName.trim() ? item.commandName.trim() : undefined;
      const anchorLabel = typeof item.anchorLabel === "string" && item.anchorLabel.trim() ? item.anchorLabel.trim() : undefined;
      const rawFallbackSelector = typeof item.fallbackSelector === "string" && item.fallbackSelector.trim() ? item.fallbackSelector.trim() : undefined;
      const fallbackSelector = rawFallbackSelector ? migrateUiButtonRuleSelector(rawFallbackSelector) : undefined;
      const insertPosition = item.insertPosition === "before" ? "before" : item.insertPosition === "after" ? "after" : undefined;
      const viewType = typeof item.viewType === "string" && item.viewType.trim() ? item.viewType.trim() : undefined;
      const commandGuard = typeof item.commandGuard === "string" && item.commandGuard.trim() ? item.commandGuard.trim() : undefined;
      const iconGuard = typeof item.iconGuard === "string" && item.iconGuard.trim() ? item.iconGuard.trim() : undefined;
      const menuGroupGuard = typeof item.menuGroupGuard === "string" && item.menuGroupGuard.trim() ? item.menuGroupGuard.trim() : undefined;
      const targetKey = typeof item.targetKey === "string" && item.targetKey.trim() ? item.targetKey.trim() : undefined;
      const legacyTargetKey = typeof item.legacyTargetKey === "string" && item.legacyTargetKey.trim() ? item.legacyTargetKey.trim() : undefined;
      const createdAt = typeof item.createdAt === "string" && item.createdAt.trim() ? item.createdAt.trim() : undefined;
      const updatedAt = typeof item.updatedAt === "string" && item.updatedAt.trim() ? item.updatedAt.trim() : undefined;
      const selectorChanged = rawSelector && rawSelector !== selector;
      const id = rawId && (kind === "custom" || !selectorChanged)
        ? rawId
        : stableRuleId(uiButtonRuleStableIdInput(scope, selector, label));
      return { id, selector, label, hidden: Boolean(item.hidden), order, title, icon, scope, kind, anchorSelector, anchorLabel, commandId, commandName, fallbackSelector, insertPosition, viewType, commandGuard, iconGuard, menuGroupGuard, targetKey, legacyTargetKey, createdAt, updatedAt };
    })
    .filter((item): item is UiButtonRule => item !== null);
  return mergeUiButtonRules([], rules).slice(0, 200);
}

function migrateUiButtonRuleSelector(selector: string, label = ""): string {
  const normalized = selector.trim();
  if (!normalized) return "";
  if (isStaleUiButtonMenuSelector(normalized)) return UI_BUTTON_MENU_ITEM_SELECTOR;
  const statusBarSelector = migrateUiButtonStatusBarSelector(normalized);
  if (statusBarSelector) return statusBarSelector;
  const statusLabel = `${normalized} ${label}`;
  if (/^(?:div|button)\[aria-label=/i.test(normalized) && /(?:打开\s*cancip|cancip.*(?:未读|待审核)|审核\s*[·:：-]?.*待审核)/i.test(statusLabel)) {
    return ".status-bar .obcc-statusbar";
  }
  if (isStaleUiButtonViewActionSelector(normalized) && label.trim()) {
    const value = cssEscapeAttr(label.trim());
    return `.view-action[aria-label="${value}"], .view-action[title="${value}"]`;
  }
  return normalized;
}

function migrateUiButtonAnchorSelector(selector: string): string {
  const normalized = selector.trim();
  if (!normalized) return "";
  if (isStaleUiButtonMenuSelector(normalized)) return UI_BUTTON_MENU_ITEM_SELECTOR;
  if (isStaleUiButtonViewActionSelector(normalized)) return UI_BUTTON_ACTIVE_MORE_SELECTOR;
  return normalized;
}

function isStaleUiButtonMenuSelector(selector: string): boolean {
  const normalized = selector.trim();
  if (!/menu(?:-|\.| |>|$)|\[role=['"]?menuitem['"]?\]/i.test(normalized)) return false;
  return /:nth-of-type\(/.test(normalized)
    || /\.obcc-ui-rule-/.test(normalized)
    || /(^|[\s>])div\.menu-item\b/.test(normalized)
    || /(^|[\s>])div\.menu-group\b/.test(normalized);
}

function isStaleUiButtonViewActionSelector(selector: string): boolean {
  const normalized = selector.trim();
  if (!/:nth-of-type\(/.test(normalized) && !/\.obcc-ui-rule-/.test(normalized)) return false;
  return /\.view-action\b/.test(normalized)
    || /\.clickable-icon\b/.test(normalized)
    || /\.view-actions\b/.test(normalized)
    || /\.view-header\b/.test(normalized);
}

function migrateUiButtonStatusBarSelector(selector: string): string {
  const normalized = selector.trim();
  if (!/\.status-bar\b|\.status-bar-item\b|\.obcc-statusbar\b/.test(normalized)) return "";
  if (/\.obcc-statusbar\b|plugin-cancip\b|aria-label=["'][^"']*Cancip/i.test(normalized)) return ".status-bar .obcc-statusbar";
  const pluginMatch = normalized.match(/\.status-bar-item\.plugin-([a-z0-9_-]+)/i);
  if (pluginMatch?.[1]) return `.status-bar .status-bar-item.plugin-${pluginMatch[1]}`;
  if (/\.status-bar-item\b/.test(normalized)) return ".status-bar .status-bar-item";
  if (normalized === ".status-bar" || normalized === "div.status-bar" || /(?:^|[\s>])\.status-bar(?:$|[\s>])/.test(normalized)) return ".status-bar";
  return "";
}

function normalizeUiButtonRuleResetTargets(raw: unknown): UiButtonRuleResetTarget[] {
  const values = Array.isArray(raw) ? raw : raw === undefined || raw === null ? [] : [raw];
  return values
    .map((item): UiButtonRuleResetTarget | null => {
      if (typeof item === "string" && item.trim()) return { selector: item.trim(), id: item.trim() };
      if (!isRecord(item)) return null;
      const id = typeof item.id === "string" && item.id.trim() ? item.id.trim() : undefined;
      const selector = typeof item.selector === "string" && item.selector.trim() ? item.selector.trim() : undefined;
      const label = typeof item.label === "string" && item.label.trim() ? item.label.trim() : undefined;
      const scope = item.scope === "active" || item.scope === "cancip" || item.scope === "global" ? item.scope : undefined;
      if (!id && !selector && !label) return null;
      return { id, selector, label, scope };
    })
    .filter((item): item is UiButtonRuleResetTarget => item !== null)
    .slice(0, 80);
}

function uiButtonRuleMatchesAnyResetTarget(rule: UiButtonRule, targets: UiButtonRuleResetTarget[]): boolean {
  return targets.some((target) => {
    if (target.id && rule.id === target.id) return true;
    if (target.selector && rule.selector === target.selector && (!target.scope || rule.scope === target.scope)) return true;
    if (target.label && normalizeUiButtonLabel(rule.label) === normalizeUiButtonLabel(target.label) && (!target.scope || rule.scope === target.scope)) return true;
    return false;
  });
}

function uiButtonRuleChangeKinds(rule: UiButtonRule): UiButtonRuleChange[] {
  const kinds: UiButtonRuleChange[] = [];
  if (rule.kind === "custom") kinds.push("custom");
  if (rule.hidden) kinds.push("hidden");
  if (Number.isFinite(rule.order) && rule.order !== 0) kinds.push("order");
  if (rule.title?.trim()) kinds.push("title");
  if (rule.icon?.trim()) kinds.push("icon");
  return kinds;
}

function uiButtonRuleHasChanges(rule: UiButtonRule): boolean {
  return uiButtonRuleChangeKinds(rule).length > 0;
}

function uiButtonMutationNodeHasCustomButton(node: Node): boolean {
  if (node.nodeType !== 1) return false;
  const el = node as Element;
  return el.matches("[data-cancip-ui-custom-button]")
    || Boolean(el.querySelector("[data-cancip-ui-custom-button]"));
}

function uiButtonMutationTouchesManagedRule(mutation: MutationRecord): boolean {
  if (mutation.type !== "attributes") return false;
  const name = mutation.attributeName ?? "";
  const oldValue = mutation.oldValue ?? "";
  if (name.startsWith("data-cancip-")) return Boolean(oldValue);
  if (name === "class") return /\bobcc-ui-rule-/.test(oldValue);
  if (name === "style") return /(?:^|;)\s*(?:order|display)\s*:/.test(oldValue);
  return false;
}

function stableRuleId(input: string): string {
  return `rule-${input.toLowerCase().replace(/[^a-z0-9\u4e00-\u9fff]+/gi, "-").replace(/^-+|-+$/g, "").slice(0, 80) || "button"}`;
}

function normalizeTagName(input: string): string {
  return input.trim().replace(/^#+/, "").replace(/\\/g, "/").replace(/\s+/g, "").replace(/^\/+|\/+$/g, "");
}

function personalizationTimeKey(date: Date): string {
  const hour = date.getHours();
  const period = hour < 5 ? "night" : hour < 12 ? "morning" : hour < 18 ? "afternoon" : hour < 23 ? "evening" : "night";
  return `${localDateKey(date)}:${period}`;
}

function isRecentPersonalizationTimestamp(timestamp: number, now = Date.now()): boolean {
  if (!isValidPersonalizationTimestamp(timestamp, now)) return false;
  return now - timestamp <= PERSONALIZATION_RECENT_WINDOW_MS;
}

function isValidPersonalizationTimestamp(timestamp: number, now = Date.now()): boolean {
  return Number.isFinite(timestamp) && timestamp > 0 && timestamp <= now + 5 * 60 * 1000;
}

function personalizationEvidenceTierForTimestamps(timestamps: number[], now = Date.now()): PersonalizationEvidenceTier {
  const ages = timestamps
    .filter((timestamp) => isValidPersonalizationTimestamp(timestamp, now))
    .map((timestamp) => Math.max(0, now - timestamp));
  if (!ages.length) return "none";
  if (ages.some((age) => age <= PERSONALIZATION_RECENT_WINDOW_MS)) return "24h";
  if (ages.some((age) => age <= PERSONALIZATION_THREE_DAY_WINDOW_MS)) return "72h";
  if (ages.some((age) => age <= PERSONALIZATION_WEEK_WINDOW_MS)) return "7d";
  return "latest";
}

function personalizationTimestampMatchesTier(timestamp: number, tier: PersonalizationEvidenceTier, now = Date.now()): boolean {
  if (!isValidPersonalizationTimestamp(timestamp, now) || tier === "none") return false;
  const age = Math.max(0, now - timestamp);
  if (tier === "24h") return age <= PERSONALIZATION_RECENT_WINDOW_MS;
  if (tier === "72h") return age <= PERSONALIZATION_THREE_DAY_WINDOW_MS;
  if (tier === "7d") return age <= PERSONALIZATION_WEEK_WINDOW_MS;
  return true;
}

function personalizationEvidenceWording(tier: PersonalizationEvidenceTier): string {
  if (tier === "24h") return "within 24h; may say just changed/recent";
  if (tier === "72h") return "within 72h; say in the last few days, not just changed";
  if (tier === "7d") return "within 7d; say this week, not recent/new";
  if (tier === "latest") return "older fallback; say last/currently available clue, never recent/new";
  return "no reliable activity evidence; use a natural time greeting only";
}

function personalizationPeriodLabel(date: Date, language: Language): string {
  const hour = date.getHours();
  if (!isChineseLanguage(language)) {
    if (hour < 5 || hour >= 23) return "late night";
    if (hour < 12) return "morning";
    if (hour < 18) return "afternoon";
    return "evening";
  }
  if (hour < 5 || hour >= 23) return "夜里";
  if (hour < 12) return "上午";
  if (hour < 18) return "下午";
  return "晚上";
}

function localPersonalizationCache(
  date: Date,
  sourcePaths: string[],
  language: Language,
  friendlyName = "",
  weather: PersonalizationWeather | null = null,
  inferredWeatherLocation = "",
  evidenceTier: PersonalizationEvidenceTier = sourcePaths.length ? "latest" : "none"
): PersonalizationCache {
  const paths = uniqueStrings(sourcePaths.map((path) => normalizePath(path)).filter(Boolean)).slice(0, PERSONALIZATION_MAX_SOURCE_FILES);
  const names = paths.map((path) => (path.split("/").pop() ?? path).replace(/\.[^.]+$/, "")).filter(Boolean);
  const recentName = names[0] ?? "";
  const chinese = isChineseLanguage(language);
  const period = personalizationPeriodLabel(date, language);
  const evening = date.getHours() >= 18 || date.getHours() < 5;
  const safeName = sanitizePersonalizationName(friendlyName);
  const salutation = safeName ? `${safeName}，` : "";
  const recentShort = trimContext(recentName, chinese ? 28 : 36);
  const secondShort = trimContext(names[1] ?? "", chinese ? 28 : 36);
  const primaryEvidenceText = evidenceTier === "24h"
    ? (chinese
      ? `刚看到「${recentShort}」有更新，这件事看起来还在往前走。要从这里接着吗？`
      : `“${recentShort}” was updated in the last day. Continue from there?`)
    : evidenceTier === "72h"
      ? (chinese
        ? `这几天「${recentShort}」有过更新。要从上次的进度接着吗？`
        : `“${recentShort}” changed in the last few days. Continue from that point?`)
      : evidenceTier === "7d"
        ? (chinese
          ? `这周能接上的一条线索是「${recentShort}」。要继续把它往前推吗？`
          : `One thread available from this week is “${recentShort}”. Continue it?`)
        : (chinese
          ? `目前能接上的最新线索是「${recentShort}」。要从上次的落点继续吗？`
          : `The latest available thread is “${recentShort}”. Continue from the last stopping point?`);
  const specificChoice = (name: string, verb: "continue" | "review" | "connect"): string => {
    const short = trimContext(name, chinese ? 28 : 36);
    if (!short) return "";
    if (!chinese) {
      if (verb === "review") return `Review “${short}” and identify the next step`;
      if (verb === "connect") return `Connect “${short}” with the recent work`;
      return `Continue “${short}” and verify the result`;
    }
    if (verb === "review") return `打开「${short}」梳理下一步`;
    if (verb === "connect") return `把「${short}」和近期工作串起来`;
    return `继续处理「${short}」并核对结果`;
  };
  const greetingCandidates: PersonalizationGreeting[] = [];
  if (recentShort) {
    greetingCandidates.push({
      text: chinese
        ? `${salutation}${period}好。${primaryEvidenceText}`
        : `Good ${period}${safeName ? `, ${safeName}` : ""}. ${primaryEvidenceText}`,
      choices: uniqueStrings([specificChoice(recentName, "continue"), specificChoice(recentName, "review"), specificChoice(names[1] ?? "", "connect")]).filter(Boolean)
    });
  }
  if (weather) {
    greetingCandidates.push({
      text: chinese
        ? `${salutation}${period}好。${weather.location}${weather.summary}。先把手头最明确的一件事推进一点？`
        : `Good ${period}${safeName ? `, ${safeName}` : ""}. It is ${weather.summary} in ${weather.location}. A good moment to move the clearest current task forward.`,
      choices: uniqueStrings([specificChoice(recentName, "continue"), specificChoice(names[1] ?? recentName, "review"), specificChoice(names[2] ?? "", "connect")]).filter(Boolean)
    });
  }
  if (secondShort) {
    greetingCandidates.push({
      text: chinese
        ? evidenceTier === "24h"
          ? `${salutation}${period}好。除了「${recentShort}」，「${secondShort}」今天也有动静。先收住哪一头？`
          : `${salutation}${period}好。「${recentShort}」和「${secondShort}」是目前能接上的两条线。先继续哪一件？`
        : evidenceTier === "24h"
          ? `Good ${period}${safeName ? `, ${safeName}` : ""}. Both “${recentShort}” and “${secondShort}” moved today. Which one should we close out first?`
          : `Good ${period}${safeName ? `, ${safeName}` : ""}. “${recentShort}” and “${secondShort}” are the two available threads. Which should we continue?`,
      choices: uniqueStrings([specificChoice(names[1], "continue"), specificChoice(recentName, "review"), specificChoice(names[2] ?? recentName, "connect")]).filter(Boolean)
    });
  }
  if (names.length > 2) {
    greetingCandidates.push({
      text: chinese
        ? `${salutation}${period}好。手头有几条能继续的线，不急着全铺开，先挑一件做完整。`
        : `Good ${period}${safeName ? `, ${safeName}` : ""}. Several threads are available; finishing one cleanly may be the easiest start.`,
      choices: names.slice(0, 3).map((name, index) => specificChoice(name, index === 0 ? "continue" : index === 1 ? "review" : "connect")).filter(Boolean)
    });
  }
  if (evening) {
    greetingCandidates.push({
      text: chinese
        ? `${salutation}${period}好。今天要是还有点余力，可以补两句日记、收住一个待办；剩下的留到明天，洗漱后早点休息。`
        : `Good ${period}${safeName ? `, ${safeName}` : ""}. If you still have a little energy, add a short diary note or close one todo, then leave the rest for tomorrow and wind down early.`,
      choices: chinese
        ? ["补写今日日记", "收尾一个未完成待办", "整理好后早点休息"]
        : ["Add a short diary entry", "Close one unfinished todo", "Wind down and rest early"]
    });
  }
  if (recentShort && greetingCandidates.length < 4) {
    const alternates = chinese && evidenceTier === "24h"
      ? [
          `${salutation}${period}好。「${recentShort}」还是最近最明确的一条线索。先把最容易确认的一步做掉？`,
          `${salutation}${period}好。上次的落点还在「${recentShort}」。这回不铺开，先做一次完整核对。`,
          `${salutation}${period}好。看得出「${recentShort}」最近动过。要不要顺手把后续和遗漏一起收住？`,
          `${salutation}${period}好。今天先从「${recentShort}」开个小口子，做完一件再看下一件。`
        ]
      : chinese
        ? [
          `${salutation}${period}好。「${recentShort}」是目前最明确的一条线索。先把最容易确认的一步做掉？`,
          `${salutation}${period}好。上次的落点还在「${recentShort}」。这回先做一次完整核对。`,
          `${salutation}${period}好。要不要从「${recentShort}」接上，把后续和遗漏一起收住？`,
          `${salutation}${period}好。今天先从「${recentShort}」开个小口子，做完一件再看下一件。`
        ]
        : [
          `Good ${period}${safeName ? `, ${safeName}` : ""}. “${recentShort}” is the clearest available thread. Start with its easiest verifiable step?`,
          `Good ${period}${safeName ? `, ${safeName}` : ""}. The last clear stopping point is “${recentShort}”. Let us verify it end to end first.`,
          `Good ${period}${safeName ? `, ${safeName}` : ""}. We can continue “${recentShort}” and close its follow-up and omissions together.`,
          `Good ${period}${safeName ? `, ${safeName}` : ""}. A small, complete pass on “${recentShort}” is a practical start.`
        ];
    for (let index = 0; greetingCandidates.length < 4 && index < alternates.length; index += 1) {
      greetingCandidates.push({
        text: alternates[index],
        choices: uniqueStrings([
          specificChoice(recentName, index % 2 === 0 ? "review" : "continue"),
          specificChoice(names[1] ?? recentName, index % 2 === 0 ? "continue" : "connect"),
          specificChoice(names[2] ?? recentName, "connect")
        ]).filter(Boolean)
      });
    }
  }
  if (!greetingCandidates.length) {
    greetingCandidates.push({
      text: chinese ? `${salutation}${period}好。` : `Good ${period}${safeName ? `, ${safeName}` : ""}.`,
      choices: []
    });
  }
  const greetings = greetingCandidates.map((item) => ({
    text: sanitizePersonalizationText(item.text, 180, true),
    choices: uniqueStrings(item.choices.map((choice) => sanitizePersonalizationText(choice, 90, true)).filter(Boolean)).slice(0, 3)
  })).slice(0, 6);
  const greeting = greetings[0]?.text ?? "";
  const autocomplete = paths.slice(0, 4).map((path) => {
    const name = (path.split("/").pop() ?? path).replace(/\.[^.]+$/, "");
    return chinese ? `继续整理「${trimContext(name, 28)}」并核对结果` : `Continue organizing “${trimContext(name, 36)}” and verify the result`;
  });
  return {
    schemaVersion: PERSONALIZATION_SCHEMA_VERSION,
    updatedAt: new Date().toISOString(),
    timeKey: personalizationTimeKey(date),
    greeting,
    greetings,
    friendlyName: safeName,
    weather,
    inferredWeatherLocation: sanitizePersonalizationLocation(inferredWeatherLocation || weather?.location || ""),
    diary: "",
    autocomplete: uniqueStrings(autocomplete).slice(0, 6),
    sourcePaths: paths
  };
}

function normalizePersonalizationCache(raw: unknown): PersonalizationCache | null {
  if (!isRecord(raw)) return null;
  const legacyGreeting = typeof raw.greeting === "string" ? sanitizePersonalizationText(raw.greeting, 180, true) : "";
  const friendlyName = sanitizePersonalizationName(
    typeof raw.friendlyName === "string"
      ? raw.friendlyName
      : Number(raw.schemaVersion) === 1
        ? extractPersonalizationNameFromLegacyGreeting(legacyGreeting)
        : ""
  );
  const greetings = normalizePersonalizationGreetings(raw.greetings, friendlyName);
  if (!greetings.length && legacyGreeting) greetings.push({ text: enforcePersonalizationGreetingIdentity(legacyGreeting, friendlyName), choices: [] });
  const greeting = greetings[0]?.text ?? legacyGreeting;
  if (!greeting) return null;
  const weather = normalizePersonalizationWeather(raw.weather);
  const inferredWeatherLocation = sanitizePersonalizationLocation(
    typeof raw.inferredWeatherLocation === "string" ? raw.inferredWeatherLocation : weather?.location ?? ""
  );
  return {
    schemaVersion: PERSONALIZATION_SCHEMA_VERSION,
    updatedAt: typeof raw.updatedAt === "string" && raw.updatedAt ? raw.updatedAt : new Date().toISOString(),
    timeKey: typeof raw.timeKey === "string" && raw.timeKey ? raw.timeKey : personalizationTimeKey(new Date()),
    greeting,
    greetings: greetings.slice(0, 6),
    friendlyName,
    weather,
    inferredWeatherLocation,
    diary: "",
    autocomplete: uniqueStrings((Array.isArray(raw.autocomplete) ? raw.autocomplete : [])
      .filter((item): item is string => typeof item === "string")
      .map((item) => sanitizePersonalizationText(item, 110, true))
      .filter(Boolean)).slice(0, 6),
    sourcePaths: uniqueStrings((Array.isArray(raw.sourcePaths) ? raw.sourcePaths : [])
      .filter((item): item is string => typeof item === "string")
      .map((item) => normalizePath(item))
      .filter(Boolean)).slice(0, PERSONALIZATION_MAX_SOURCE_FILES)
  };
}

function personalizationCacheFromModel(
  raw: string,
  fallback: PersonalizationCache,
  sourcePaths: string[],
  timeKey: string,
  sourceContext: string
): PersonalizationCache {
  const cleaned = raw.trim().replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/, "");
  let parsed: unknown = null;
  try {
    parsed = JSON.parse(cleaned);
  } catch {
    return fallback;
  }
  if (!isRecord(parsed)) return fallback;
  const proposedName = sanitizePersonalizationName(typeof parsed.friendlyName === "string" ? parsed.friendlyName : "");
  const friendlyName = proposedName && personalizationEvidenceContains(sourceContext, proposedName) ? proposedName : fallback.friendlyName;
  const proposedLocation = sanitizePersonalizationLocation(typeof parsed.weatherLocation === "string" ? parsed.weatherLocation : "");
  const inferredWeatherLocation = proposedLocation && personalizationEvidenceContains(sourceContext, proposedLocation)
    ? proposedLocation
    : fallback.inferredWeatherLocation;
  const blockedName = proposedName && proposedName !== friendlyName ? proposedName : "";
  const blockedLocation = proposedLocation && (proposedLocation !== inferredWeatherLocation || !fallback.weather) ? proposedLocation : "";
  const modelGreetings = normalizePersonalizationGreetings(parsed.greetings, friendlyName).filter((item) => {
    const text = `${item.text}\n${item.choices.join("\n")}`;
    if (blockedName && personalizationEvidenceContains(text, blockedName)) return false;
    if (blockedLocation && personalizationEvidenceContains(text, blockedLocation)) return false;
    if (!fallback.weather && /(?:天气|气温|温度|晴朗|多云|阴天|下雨|降雨|下雪|weather|temperature|sunny|cloudy|rain|snow)/i.test(text)) return false;
    return true;
  });
  let legacyGreeting = typeof parsed.greeting === "string"
    ? enforcePersonalizationGreetingIdentity(sanitizePersonalizationText(parsed.greeting, 180, true), friendlyName)
    : "";
  if ((blockedName && personalizationEvidenceContains(legacyGreeting, blockedName))
    || (blockedLocation && personalizationEvidenceContains(legacyGreeting, blockedLocation))
    || (!fallback.weather && /(?:天气|气温|温度|晴朗|多云|阴天|下雨|降雨|下雪|weather|temperature|sunny|cloudy|rain|snow)/i.test(legacyGreeting))) {
    legacyGreeting = "";
  }
  if (!modelGreetings.length && legacyGreeting) modelGreetings.push({ text: legacyGreeting, choices: [] });
  const greetings = uniquePersonalizationGreetings([...modelGreetings, ...fallback.greetings]).slice(0, 6);
  return normalizePersonalizationCache({
    schemaVersion: PERSONALIZATION_SCHEMA_VERSION,
    updatedAt: new Date().toISOString(),
    timeKey,
    greeting: greetings[0]?.text ?? fallback.greeting,
    greetings,
    friendlyName,
    weather: fallback.weather,
    inferredWeatherLocation,
    diary: "",
    autocomplete: Array.isArray(parsed.autocomplete) ? parsed.autocomplete : fallback.autocomplete,
    sourcePaths
  }) ?? fallback;
}

function personalizationEvidenceContains(source: string, value: string): boolean {
  const needle = value.toLocaleLowerCase().replace(/[\s,，。.!！?？:：;；()（）[\]{}]/g, "");
  if (needle.length < 2) return false;
  const haystack = source.toLocaleLowerCase().replace(/[\s,，。.!！?？:：;；()（）[\]{}]/g, "");
  return haystack.includes(needle);
}

function normalizeEditorAutocompleteModelTree(raw: string, prefix: string, candidateCount = 3): EditorAutocompleteModelTree {
  const limit = Math.max(1, Math.min(EDITOR_AUTOCOMPLETE_CANDIDATE_COUNT_MAX, candidateCount));
  const visible = sanitizeModelVisibleAnswer(raw)
    .replace(/^```(?:json|text|markdown)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
  const parsed = parseFirstJsonObject(visible);
  const branches = new Map<string, string[]>();
  let values: Array<string | Record<string, unknown>> = [];
  if (isRecord(parsed) && Array.isArray(parsed.candidates)) {
    values = parsed.candidates.filter((value): value is string | Record<string, unknown> => typeof value === "string" || isRecord(value));
  } else if (isRecord(parsed) && typeof parsed.suffix === "string") {
    values = [parsed.suffix];
  } else if (/^[{[]/.test(visible)) {
    const recovered: string[] = [];
    for (const match of visible.matchAll(/"text"\s*:\s*("(?:\\.|[^"\\])*")/g)) {
      try {
        const value = JSON.parse(match[1]) as unknown;
        if (typeof value === "string") recovered.push(value);
      } catch {
        // Keep only complete JSON strings from a truncated response.
      }
    }
    values = recovered;
  } else if (visible) {
    let fallback = visible;
    if ((fallback.startsWith('"') && fallback.endsWith('"')) || (fallback.startsWith("'") && fallback.endsWith("'"))) {
      try {
        const decoded = JSON.parse(fallback) as unknown;
        if (typeof decoded === "string") fallback = decoded;
      } catch {
        fallback = fallback.slice(1, -1);
      }
    }
    values = [fallback];
  }
  const candidates: string[] = [];
  for (const item of values) {
    const rawCandidate = typeof item === "string"
      ? item
      : typeof item.text === "string"
        ? item.text
        : typeof item.suffix === "string"
          ? item.suffix
          : typeof item.candidate === "string"
            ? item.candidate
            : "";
    const candidate = normalizeEditorAutocompleteCandidate(rawCandidate, prefix, EDITOR_AUTOCOMPLETE_MAX_CANDIDATE_CHARS);
    if (!candidate || candidates.some((value) => value.toLocaleLowerCase() === candidate.toLocaleLowerCase())) continue;
    candidates.push(candidate);
    if (typeof item !== "string") {
      const rawChildren = Array.isArray(item.next)
        ? item.next
        : Array.isArray(item.children)
          ? item.children
          : [];
      const completedPrefix = `${prefix}${candidate}`;
      const children = uniqueEditorAutocompleteCandidates(rawChildren
        .filter((value): value is string => typeof value === "string")
        .map((value) => normalizeEditorAutocompleteCandidate(value, completedPrefix, EDITOR_AUTOCOMPLETE_MAX_BRANCH_CHARS)), limit);
      if (children.length) branches.set(candidate, children);
    }
    if (candidates.length >= limit) break;
  }
  return { candidates, branches };
}

function normalizeEditorAutocompleteCandidate(raw: string, prefix: string, maxChars = EDITOR_AUTOCOMPLETE_MAX_CANDIDATE_CHARS): string {
  let value = raw
    .replace(/\r\n?/g, "\n")
    .replace(/^(?:补全|后缀|completion|suffix)\s*[:：]\s*/i, "")
    .replace(/[ \t]+$/gm, "")
    .replace(/\n+$/, "");
  if (prefix.trim().length >= 3 && value.toLocaleLowerCase().startsWith(prefix.toLocaleLowerCase())) value = value.slice(prefix.length);
  if (value.length > maxChars) {
    value = value.slice(0, maxChars).replace(/[ \t]+$/gm, "").replace(/\n+$/, "");
  }
  if (!value.trim()) return "";
  if (/[^\s]$/.test(prefix) && /[A-Za-z0-9]/.test(prefix.slice(-1)) && /^[A-Za-z0-9]/.test(value)) return ` ${value}`;
  return value;
}

function sanitizePersonalizationText(input: string, maxChars: number, singleLine: boolean): string {
  let value = redactSensitiveText(input)
    .replace(/<!--[^>]*-->/g, "")
    .replace(/^#{1,6}\s+/gm, "")
    .replace(/\b(?:as an ai|作为(?:一个)?ai)\b/gi, "")
    .trim();
  if (singleLine) value = value.replace(/\s+/g, " ");
  return trimContext(value, maxChars).trim();
}

function sanitizePersonalizationName(input: string): string {
  return trimContext(redactSensitiveText(input).replace(/[\r\n\t<>[\]{}]/g, " ").replace(/\s+/g, " ").trim(), 24)
    .replace(/^[,，。.!！?？:：]+|[,，。.!！?？:：]+$/g, "")
    .trim();
}

function sanitizePersonalizationLocation(input: string): string {
  return trimContext(redactSensitiveText(input).replace(/[\r\n\t<>[\]{}]/g, " ").replace(/\s+/g, " ").trim(), 60)
    .replace(/^[,，。.!！?？:：]+|[,，。.!！?？:：]+$/g, "")
    .trim();
}

function extractPersonalizationNameFromLegacyGreeting(greeting: string): string {
  const match = greeting.match(/^([^，,。.!！?？]{1,16})[，,](?:夜里|上午|下午|晚上|早上|中午|傍晚|Good\b)/i);
  return sanitizePersonalizationName(match?.[1] ?? "");
}

function extractPersonalizationFriendlyName(source: string): string {
  const patterns = [
    /(?:朋友称呼|用户称呼|首选称呼|姓名|名字)\s*[:：]\s*([^\n,，。;；]{1,24})/i,
    /(?:preferred\s+name|user\s+name|name)\s*[:：]\s*([^\n,，。;；]{1,24})/i,
    /(?:User|用户)\s*[:：]\s*([^\n,，。;；]{1,24})/i
  ];
  for (const pattern of patterns) {
    const name = sanitizePersonalizationName(source.match(pattern)?.[1] ?? "");
    if (name && !/^(none|null|unknown|无|未设置)$/i.test(name)) return name;
  }
  return "";
}

function extractPersonalizationWeatherLocation(source: string): string {
  const patterns = [
    /(?:天气地点|常住地|所在地)\s*[:：]\s*([^\n,，。;；]{1,60})/i,
    /(?:weather\s+location|home\s+location|location)\s*[:：]\s*([^\n,，。;；]{1,60})/i
  ];
  for (const pattern of patterns) {
    const location = sanitizePersonalizationLocation(source.match(pattern)?.[1] ?? "");
    if (location && !/^(none|null|unknown|无|未设置)$/i.test(location)) return location;
  }
  return "";
}

function enforcePersonalizationGreetingIdentity(text: string, friendlyName: string): string {
  const value = sanitizePersonalizationText(text, 180, true);
  const leading = value.match(/^([^，,。.!！?？]{1,16})[，,]((?:夜里|上午|下午|晚上|早上|中午|傍晚|Good\b)[\s\S]*)$/i);
  if (!leading) return value;
  const proposed = sanitizePersonalizationName(leading[1]);
  if (friendlyName && proposed === friendlyName) return value;
  return sanitizePersonalizationText(leading[2], 180, true);
}

function normalizePersonalizationGreetings(raw: unknown, friendlyName: string): PersonalizationGreeting[] {
  if (!Array.isArray(raw)) return [];
  const result: PersonalizationGreeting[] = [];
  for (const item of raw) {
    if (!isRecord(item) || typeof item.text !== "string") continue;
    const text = enforcePersonalizationGreetingIdentity(item.text, friendlyName);
    if (!text) continue;
    const choices = uniqueStrings((Array.isArray(item.choices) ? item.choices : [])
      .filter((choice): choice is string => typeof choice === "string")
      .map((choice) => sanitizePersonalizationText(choice, 90, true))
      .filter(Boolean)).slice(0, 3);
    result.push({ text, choices });
  }
  return uniquePersonalizationGreetings(result).slice(0, 6);
}

function uniquePersonalizationGreetings(items: PersonalizationGreeting[]): PersonalizationGreeting[] {
  const unique = new Map<string, PersonalizationGreeting>();
  for (const item of items) {
    const key = item.text.toLocaleLowerCase().replace(/\s+/g, " ").trim();
    if (key && !unique.has(key)) unique.set(key, item);
  }
  return [...unique.values()];
}

function normalizePersonalizationWeather(raw: unknown): PersonalizationWeather | null {
  if (!isRecord(raw)) return null;
  const location = typeof raw.location === "string" ? sanitizePersonalizationLocation(raw.location) : "";
  const summary = typeof raw.summary === "string" ? sanitizePersonalizationText(raw.summary, 80, true) : "";
  const updatedAt = typeof raw.updatedAt === "string" && Number.isFinite(Date.parse(raw.updatedAt)) ? raw.updatedAt : "";
  return location && summary && updatedAt ? { location, summary, updatedAt } : null;
}

function personalizationWeatherCodeLabel(code: number, language: Language): string {
  const chinese = isChineseLanguage(language);
  if (code === 0) return chinese ? "晴" : "clear";
  if (code === 1 || code === 2) return chinese ? "晴间多云" : "partly cloudy";
  if (code === 3) return chinese ? "阴" : "overcast";
  if (code === 45 || code === 48) return chinese ? "有雾" : "foggy";
  if ([51, 53, 55, 56, 57].includes(code)) return chinese ? "有毛毛雨" : "drizzly";
  if ([61, 63, 65, 66, 67, 80, 81, 82].includes(code)) return chinese ? "有雨" : "rainy";
  if ([71, 73, 75, 77, 85, 86].includes(code)) return chinese ? "有雪" : "snowy";
  if ([95, 96, 99].includes(code)) return chinese ? "有雷雨" : "stormy";
  return chinese ? "天气平稳" : "settled weather";
}

function emptyPersonalizationUsageLedger(): PersonalizationUsageLedger {
  return {
    schemaVersion: PERSONALIZATION_USAGE_SCHEMA_VERSION,
    entries: [],
    approvedPriorityKeys: [],
    reviewedPriorityKeys: [],
    autocompleteSelections: [],
    autocompleteUsage: [],
    autocompleteSummary: emptyAutocompletePreferenceSummary()
  };
}

const AUTOCOMPLETE_CONTENT_SIGNAL_RULES: ReadonlyArray<{ key: string; label: string; pattern: RegExp }> = [
  { key: "coding-obsidian", label: "编码、Obsidian与插件", pattern: /代码|源码|编程|插件|obsidian|cancip|typescript|javascript|css|api|接口|构建|编译|github|git|bug|报错|脚本/i },
  { key: "writing-notes", label: "写作、笔记与日记", pattern: /写作|文章|文案|笔记|日记|日志|总结|润色|改写|纪要|记录/i },
  { key: "office-files", label: "办公文件与格式转换", pattern: /docx|pptx|xlsx|pdf|表格|文档|幻灯片|文件|导出|转换|预览/i },
  { key: "search-analysis", label: "搜索、分析与对比", pattern: /搜索|查找|检索|分析|研究|对比|核对资料|提取|阅读|引用/i },
  { key: "automation-workflow", label: "自动化、任务与工作流", pattern: /自动化|定时|通知|任务|skill|子代理|工作流|预加载|后台|整理/i },
  { key: "health-admin", label: "医疗与行政事项", pattern: /医疗|药|症状|检查|医院|复诊|转诊|患者|证书|行政/i },
  { key: "learning-review", label: "学习、复盘与记忆", pattern: /学习|复习|记忆|经验|复盘|回顾|总结|知识/i }
];

const AUTOCOMPLETE_STYLE_SIGNAL_RULES: ReadonlyArray<{ key: string; label: string; pattern: RegExp }> = [
  { key: "concise", label: "偏好精简、少废话", pattern: /精简|简短|扼要|少废话|不废话|省token|省 token|直接说|不要套话/i },
  { key: "verification", label: "偏好执行后核对验证", pattern: /核对|验证|测试|检查|确认|读回|复盘|对齐/i },
  { key: "direct-action", label: "偏好直接执行和修复", pattern: /修复|改成|完成|执行|打开|生成|整理|转换|导出|安装|升级/i },
  { key: "preserve", label: "偏好保持原样、少动正常内容", pattern: /原样|不要动|别动|不影响|保持|保留|不要改|只改|仅改/i },
  { key: "stepwise", label: "偏好分阶段、按步骤推进", pattern: /先|然后|接着|下一步|步骤|流程|依次|逐步|以此类推/i },
  { key: "proactive", label: "偏好主动预判和后台准备", pattern: /自动|后台|预加载|提前|推荐|根据.*习惯|主动|随时/i }
];

function countAutocompletePreferenceSignals(
  events: AutocompleteSelectionEvent[],
  rules: ReadonlyArray<{ key: string; label: string; pattern: RegExp }>,
  limit = 6
): AutocompletePreferenceSignal[] {
  const counts = new Map<string, AutocompletePreferenceSignal>();
  for (const event of events) {
    const source = `${event.prefixHint}\n${event.text}`;
    for (const rule of rules) {
      if (!rule.pattern.test(source)) continue;
      const existing = counts.get(rule.key);
      counts.set(rule.key, existing
        ? { ...existing, count: existing.count + 1 }
        : { key: rule.key, label: rule.label, count: 1 });
    }
  }
  return [...counts.values()]
    .sort((a, b) => b.count - a.count || a.label.localeCompare(b.label))
    .slice(0, limit);
}

function emptyAutocompletePreferenceSummary(): AutocompletePreferenceSummary {
  return {
    schemaVersion: 3,
    updatedAt: "",
    totalSelections: 0,
    totalShown: 0,
    totalUsed: 0,
    usageRate: 0,
    unusedShown: 0,
    pendingShown: 0,
    preferredPosition: 1,
    positionCounts: [],
    triggerCounts: { button: 0, tab: 0, menu: 0 },
    reasonCounts: { "first-visible": 0, "auto-rotated": 0, "manual-navigation": 0 },
    preloadedNextBranchCount: 0,
    contentSignals: [],
    styleSignals: [],
    summary: ""
  };
}

function normalizeAutocompleteUsageEvent(raw: unknown): AutocompleteUsageEvent | null {
  if (!isRecord(raw) || typeof raw.id !== "string") return null;
  const id = raw.id.trim();
  const candidates = uniqueStrings((Array.isArray(raw.candidates) ? raw.candidates : [])
    .filter((candidate): candidate is string => typeof candidate === "string")
    .map((candidate) => sanitizePersonalizationText(candidate, 240, false))
    .filter(Boolean)).slice(0, EDITOR_AUTOCOMPLETE_CANDIDATE_COUNT_MAX);
  if (!id || !candidates.length) return null;
  const used = Boolean(raw.used);
  const selectedText = typeof raw.selectedText === "string"
    ? sanitizePersonalizationText(raw.selectedText, 240, false)
    : "";
  const selectedIndex = typeof raw.selectedIndex === "number"
    ? clampInt(raw.selectedIndex, 0, 0, Math.max(0, candidates.length - 1))
    : undefined;
  const dismissedReason = raw.dismissedReason === "input-changed"
    || raw.dismissedReason === "replaced"
    || raw.dismissedReason === "closed"
    || raw.dismissedReason === "disabled"
    ? raw.dismissedReason
    : undefined;
  return {
    id,
    shownAt: typeof raw.shownAt === "string" && Number.isFinite(Date.parse(raw.shownAt)) ? raw.shownAt : new Date().toISOString(),
    prefixHint: typeof raw.prefixHint === "string" ? sanitizePersonalizationText(raw.prefixHint, 120, false) : "",
    candidates,
    used,
    ...(used && selectedText ? { selectedText } : {}),
    ...(used && selectedIndex !== undefined ? { selectedIndex } : {}),
    ...(typeof raw.selectedAt === "string" && Number.isFinite(Date.parse(raw.selectedAt)) ? { selectedAt: raw.selectedAt } : {}),
    ...(typeof raw.dismissedAt === "string" && Number.isFinite(Date.parse(raw.dismissedAt)) ? { dismissedAt: raw.dismissedAt } : {}),
    ...(dismissedReason ? { dismissedReason } : {})
  };
}

function normalizeAutocompleteSelectionEvent(raw: unknown): AutocompleteSelectionEvent | null {
  if (!isRecord(raw) || typeof raw.text !== "string") return null;
  const text = sanitizePersonalizationText(raw.text, 140, true);
  if (!text) return null;
  const total = clampInt(raw.total, 1, 1, EDITOR_AUTOCOMPLETE_CANDIDATE_COUNT_MAX);
  const index = clampInt(raw.index, 0, 0, total - 1);
  const trigger: EditorAutocompleteApplyTrigger = raw.trigger === "tab" || raw.trigger === "menu" ? raw.trigger : "button";
  const rotationPaused = Boolean(raw.rotationPaused);
  const reason: AutocompleteSelectionEvent["reason"] = raw.reason === "manual-navigation" || raw.reason === "auto-rotated" || raw.reason === "first-visible"
    ? raw.reason
    : rotationPaused
      ? "manual-navigation"
      : index > 0
        ? "auto-rotated"
        : "first-visible";
  return {
    text,
    at: typeof raw.at === "string" && Number.isFinite(Date.parse(raw.at)) ? raw.at : new Date().toISOString(),
    index,
    total,
    trigger,
    preloadedNextBranch: Boolean(raw.preloadedNextBranch),
    rotationPaused,
    reason,
    prefixHint: typeof raw.prefixHint === "string" ? sanitizePersonalizationText(raw.prefixHint, 80, true) : ""
  };
}

function summarizeAutocompletePreference(events: AutocompleteSelectionEvent[], usage: AutocompleteUsageEvent[] = []): AutocompletePreferenceSummary {
  const positionCounts: number[] = [];
  const triggerCounts: Record<EditorAutocompleteApplyTrigger, number> = { button: 0, tab: 0, menu: 0 };
  const reasonCounts: Record<AutocompleteSelectionEvent["reason"], number> = {
    "first-visible": 0,
    "auto-rotated": 0,
    "manual-navigation": 0
  };
  let preloadedNextBranchCount = 0;
  for (const event of events) {
    positionCounts[event.index] = (positionCounts[event.index] ?? 0) + 1;
    triggerCounts[event.trigger] += 1;
    reasonCounts[event.reason] += 1;
    if (event.preloadedNextBranch) preloadedNextBranchCount += 1;
  }
  const totalSelections = events.length;
  const totalShown = usage.length;
  const totalUsed = usage.filter((event) => event.used).length;
  const unusedShown = usage.filter((event) => !event.used && Boolean(event.dismissedAt || event.dismissedReason)).length;
  const pendingShown = Math.max(0, totalShown - totalUsed - unusedShown);
  const decidedShown = totalUsed + unusedShown;
  const usageRate = decidedShown ? Math.round((totalUsed / decidedShown) * 100) : 0;
  let preferredIndex = 0;
  for (let index = 1; index < positionCounts.length; index += 1) {
    if ((positionCounts[index] ?? 0) > (positionCounts[preferredIndex] ?? 0)) preferredIndex = index;
  }
  if (!totalSelections && !totalShown) return emptyAutocompletePreferenceSummary();
  const parts = totalShown
    ? [`推断：展示 ${totalShown} 批，实际采用 ${totalUsed} 批，明确未采用 ${unusedShown} 批，待判定 ${pendingShown} 批，已完成批次采用率 ${usageRate}%`]
    : [`推断：已有历史选择 ${totalSelections} 次，暂无展示批次记录`];
  if (totalSelections) parts.push(`较常接受第 ${preferredIndex + 1} 项`);
  if (unusedShown) parts.push(`${unusedShown} 批展示后未采用`);
  if (reasonCounts["manual-navigation"]) parts.push(`手动切换后接受 ${reasonCounts["manual-navigation"]} 次`);
  if (reasonCounts["auto-rotated"]) parts.push(`自动轮换到后续项接受 ${reasonCounts["auto-rotated"]} 次`);
  if (triggerCounts.tab) parts.push(`Tab 应用 ${triggerCounts.tab} 次`);
  const preloadRate = totalSelections ? Math.round((preloadedNextBranchCount / totalSelections) * 100) : 0;
  if (preloadRate) parts.push(`${preloadRate}% 的选择发生在下一层已预加载时`);
  const contentSignals = countAutocompletePreferenceSignals(events, AUTOCOMPLETE_CONTENT_SIGNAL_RULES);
  const styleSignals = countAutocompletePreferenceSignals(events, AUTOCOMPLETE_STYLE_SIGNAL_RULES);
  const lastUsage = usage[usage.length - 1];
  const lastSelection = events[events.length - 1];
  if (contentSignals.length) parts.push(`内容偏好：${contentSignals.slice(0, 4).map((item) => `${item.label}${item.count}次`).join("、")}`);
  if (styleSignals.length) parts.push(`工作方式：${styleSignals.slice(0, 4).map((item) => `${item.label}${item.count}次`).join("、")}`);
  return {
    schemaVersion: 3,
    updatedAt: lastUsage?.selectedAt ?? lastUsage?.shownAt ?? lastSelection?.at ?? new Date().toISOString(),
    totalSelections,
    totalShown,
    totalUsed,
    usageRate,
    unusedShown,
    pendingShown,
    preferredPosition: preferredIndex + 1,
    positionCounts,
    triggerCounts,
    reasonCounts,
    preloadedNextBranchCount,
    contentSignals,
    styleSignals,
    summary: parts.join("；")
  };
}

function personalizationChoiceKey(text: string): string {
  const normalized = sanitizePersonalizationText(text, 180, true).toLocaleLowerCase();
  return `choice-${stableTextHash(normalized).slice(0, 12)}`;
}

function normalizeComposerWorkflowHint(raw: unknown): ComposerWorkflowHint {
  if (!isRecord(raw)) return { title: "", steps: [] };
  const title = typeof raw.title === "string" ? sanitizePersonalizationText(raw.title, 70, true) : "";
  const steps = uniqueStrings((Array.isArray(raw.steps) ? raw.steps : [])
    .filter((step): step is string => typeof step === "string")
    .map((step) => sanitizePersonalizationText(step, 70, true))
    .filter(Boolean)).slice(0, 6);
  return { title, steps };
}

function normalizePersonalizationUsageLedger(raw: unknown): PersonalizationUsageLedger {
  if (!isRecord(raw)) return emptyPersonalizationUsageLedger();
  const entries: PersonalizationUsageEntry[] = [];
  if (Array.isArray(raw.entries)) {
    for (const item of raw.entries) {
      if (!isRecord(item) || typeof item.text !== "string") continue;
      const text = sanitizePersonalizationText(item.text, 140, true);
      if (!text) continue;
      const key = typeof item.key === "string" && /^choice-[a-z0-9]+$/i.test(item.key) ? item.key : personalizationChoiceKey(text);
      const source = item.source === "composer"
        ? "composer"
        : item.source === "editor-autocomplete"
          ? "editor-autocomplete"
          : "greeting";
      const count = clampInt(item.count, 1, 1, 100000);
      const lastUsedAt = typeof item.lastUsedAt === "string" && Number.isFinite(Date.parse(item.lastUsedAt)) ? item.lastUsedAt : new Date().toISOString();
      const workflowHint = normalizeComposerWorkflowHint(item.workflowHint);
      entries.push({ key, text, source, count, lastUsedAt, ...(workflowHint.steps.length ? { workflowHint } : {}) });
    }
  }
  const autocompleteSelections = Array.isArray(raw.autocompleteSelections)
    ? raw.autocompleteSelections.map(normalizeAutocompleteSelectionEvent).filter((event): event is AutocompleteSelectionEvent => Boolean(event)).slice(-120)
    : [];
  const autocompleteUsage = Array.isArray(raw.autocompleteUsage)
    ? raw.autocompleteUsage.map(normalizeAutocompleteUsageEvent).filter((event): event is AutocompleteUsageEvent => Boolean(event)).slice(-180)
    : [];
  return {
    schemaVersion: PERSONALIZATION_USAGE_SCHEMA_VERSION,
    entries: entries.slice(0, 120),
    approvedPriorityKeys: uniqueStrings((Array.isArray(raw.approvedPriorityKeys) ? raw.approvedPriorityKeys : []).filter((key): key is string => typeof key === "string" && /^choice-[a-z0-9]+$/i.test(key))).slice(0, 120),
    reviewedPriorityKeys: uniqueStrings((Array.isArray(raw.reviewedPriorityKeys) ? raw.reviewedPriorityKeys : []).filter((key): key is string => typeof key === "string" && /^choice-[a-z0-9]+$/i.test(key))).slice(0, 240),
    autocompleteSelections,
    autocompleteUsage,
    autocompleteSummary: summarizeAutocompletePreference(autocompleteSelections, autocompleteUsage)
  };
}

function isPersonalizationSourcePath(path: string, obsidianConfigDir: string): boolean {
  const normalized = normalizePath(path.replace(/\\/g, "/").replace(/^\/+/, ""));
  if (!normalized) return false;
  const lower = normalized.toLowerCase();
  const config = normalizePath(obsidianConfigDir).toLowerCase();
  if (lower === PERSONALIZATION_CACHE_PATH.toLowerCase()) return false;
  if (lower === PERSONALIZATION_USAGE_PATH.toLowerCase() || lower === PERSONALIZATION_PRIORITY_REVIEW_PATH.toLowerCase()) return false;
  if (lower.startsWith(`${CANCIP_CONFIG_DIR.toLowerCase()}/`) || lower.startsWith(`${config}/`)) return false;
  if (lower.startsWith(".trash/") || lower.includes("/archive/") || lower.includes("/归档/")) return false;
  return true;
}

function isPersonalizedDiaryPath(path: string): boolean {
  const normalized = normalizePath(path.replace(/\\/g, "/"));
  const name = normalized.split("/").pop() ?? "";
  return /(?:^|\/)(?:日记|diary|journal)(?:\/|$)/i.test(normalized)
    || /^\d{4}-\d{2}-\d{2}(?:[-_ ].*)?\.md$/i.test(name);
}

function isDiaryWritingRequest(prompt: string, path: string): boolean {
  if (!path || !isPersonalizedDiaryPath(path)) return false;
  const compact = prompt.replace(/\s+/g, "").trim();
  if (!compact) return false;
  return /(?:写|续写|补充|整理|生成|草拟|润色|总结|复盘|记录).{0,8}(?:日记|日志|今[天日]|今日小结)|(?:日记|日志|今[天日]|今日小结).{0,8}(?:写|续写|补充|整理|生成|草拟|润色|总结|复盘|记录)/i.test(compact);
}

function getActiveApiProfile(settings: Settings): ApiProfile {
  const activeApiProfileId = resolveApiProfileId(settings.activeApiProfileId, settings.apiProfiles);
  return settings.apiProfiles.find((profile) => profile.id === activeApiProfileId) ?? settings.apiProfiles[0] ?? getDefaultApiProfile();
}

function hasLegacyApiProfileFields(settings: Partial<Settings>): boolean {
  return settings.apiUrl !== undefined || settings.apiKey !== undefined || settings.apiMode !== undefined || settings.model !== undefined;
}

function migrateVisibleFolderDefaults(settings: Settings): Settings {
  const folder = normalizePath(settings.memoryFolder);
  if (
    folder !== normalizePath(LEGACY_DEFAULT_MEMORY_FOLDER) &&
    folder !== normalizePath(INTERRUPTED_DEFAULT_MEMORY_FOLDER)
  ) {
    return settings;
  }
  return { ...settings, memoryFolder: DEFAULT_MEMORY_FOLDER };
}

function migrateLegacyCancipStoragePath(rawPath: string): string {
  const normalized = normalizePath(rawPath.replace(/\\/g, "/")).replace(/^\/+|\/+$/g, "");
  const legacy = LEGACY_CANCIP_CONFIG_DIR.toLowerCase();
  const lower = normalized.toLowerCase();
  if (lower === legacy) return CANCIP_CONFIG_DIR;
  if (lower.startsWith(`${legacy}/`)) {
    return `${CANCIP_CONFIG_DIR}/${normalized.slice(LEGACY_CANCIP_CONFIG_DIR.length + 1)}`;
  }
  return normalized;
}

function migrateLegacyCancipStorageSettings(settings: Settings): Settings {
  const memoryFolder = migrateLegacyCancipStoragePath(settings.memoryFolder);
  const skillRoots = uniqueStrings(settings.skillRoots.map(migrateLegacyCancipStoragePath));
  if (memoryFolder === settings.memoryFolder && sameStringArray(skillRoots, settings.skillRoots)) return settings;
  return { ...settings, memoryFolder, skillRoots };
}

function migrateDefaultMemorySearchPolicy(settings: Settings): Settings {
  let next = settings;
  if (settings.useVaultSearchByDefault) {
    next = { ...next, useVaultSearchByDefault: false };
  }
  if (settings.codexMemoryAutoSearch) {
    next = { ...next, codexMemoryAutoSearch: false };
  }
  if (!settings.includeCoreMemory) {
    next = { ...next, includeCoreMemory: true };
  }
  if (!settings.memoryFolder.trim()) {
    next = { ...next, memoryFolder: DEFAULT_MEMORY_FOLDER };
  }
  return next;
}

function migrateTokenSavingDefaults(settings: Settings): Settings {
  let next = settings;
  const updateDefault = <K extends keyof Settings>(key: K, oldValue: Settings[K], newValue: Settings[K]): void => {
    if (next[key] === oldValue) next = { ...next, [key]: newValue };
  };
  updateDefault("maxContextFiles", 6, DEFAULT_SETTINGS.maxContextFiles);
  updateDefault("maxRecentTranscriptMessages", 8, DEFAULT_SETTINGS.maxRecentTranscriptMessages);
  updateDefault("maxRecentTranscriptMessages", 4, DEFAULT_SETTINGS.maxRecentTranscriptMessages);
  updateDefault("maxRecentTranscriptMessages", 2, DEFAULT_SETTINGS.maxRecentTranscriptMessages);
  updateDefault("maxHistoryAnchors", 8, DEFAULT_SETTINGS.maxHistoryAnchors);
  updateDefault("maxFileContextChars", 8000, DEFAULT_SETTINGS.maxFileContextChars);
  updateDefault("maxFolderFileContextChars", 2600, DEFAULT_SETTINGS.maxFolderFileContextChars);
  updateDefault("maxSkillContextChars", 12000, DEFAULT_SETTINGS.maxSkillContextChars);
  updateDefault("maxSkillContextChars", 9000, DEFAULT_SETTINGS.maxSkillContextChars);
  updateDefault("maxSkillContextChars", 7000, DEFAULT_SETTINGS.maxSkillContextChars);
  updateDefault("maxAutoSkillContextChars", 6000, DEFAULT_SETTINGS.maxAutoSkillContextChars);
  updateDefault("maxAutoSkillContextChars", 3600, DEFAULT_SETTINGS.maxAutoSkillContextChars);
  updateDefault("maxAutoSkillContextChars", 2400, DEFAULT_SETTINGS.maxAutoSkillContextChars);
  updateDefault("codexMemoryMaxFiles", 6, DEFAULT_SETTINGS.codexMemoryMaxFiles);
  updateDefault("codexMemoryMaxChars", 12000, DEFAULT_SETTINGS.codexMemoryMaxChars);
  updateDefault("composerAutocompleteCandidateCount", 3, DEFAULT_SETTINGS.composerAutocompleteCandidateCount);
  return next;
}

function isTtsOverlayPosition(value: unknown): value is { left: number; top: number } {
  return isRecord(value)
    && typeof value.left === "number"
    && typeof value.top === "number"
    && Number.isFinite(value.left)
    && Number.isFinite(value.top);
}

function normalizeSettings(input: Partial<Settings>): Settings {
  const merged = { ...DEFAULT_SETTINGS, ...input };
  const temperature = Number(merged.temperature);
  const maxOutputTokens = Number.parseInt(String(merged.maxOutputTokens), 10);
  const maxContextFiles = Number.parseInt(String(merged.maxContextFiles), 10);
  const maxCoreMemoryFiles = Number.parseInt(String(merged.maxCoreMemoryFiles), 10);
  const maxRecentTranscriptMessages = Number.parseInt(String(merged.maxRecentTranscriptMessages), 10);
  const maxHistoryAnchors = Number.parseInt(String(merged.maxHistoryAnchors), 10);
  const maxMentionResults = Number.parseInt(String(merged.maxMentionResults), 10);
  const maxMentionFolderFiles = Number.parseInt(String(merged.maxMentionFolderFiles), 10);
  const maxFileContextChars = Number.parseInt(String(merged.maxFileContextChars), 10);
  const maxFolderFileContextChars = Number.parseInt(String(merged.maxFolderFileContextChars), 10);
  const maxAutoSkills = Number.parseInt(String(merged.maxAutoSkills), 10);
  const maxSkillContextChars = Number.parseInt(String(merged.maxSkillContextChars), 10);
  const maxAutoSkillContextChars = Number.parseInt(String(merged.maxAutoSkillContextChars), 10);
  const maxToolIterations = Number.parseInt(String(merged.maxToolIterations), 10);
  const codexMemoryMaxFiles = Number.parseInt(String(merged.codexMemoryMaxFiles), 10);
  const codexMemoryMaxChars = Number.parseInt(String(merged.codexMemoryMaxChars), 10);
  const localVersionHour = Number.parseInt(String(merged.localVersionHour), 10);
  const localVersionMaxFileBytes = Number.parseInt(String(merged.localVersionMaxFileBytes), 10);
  const automationCheckMinutes = Number.parseInt(String(merged.automationCheckMinutes), 10);
  const composerAutocompleteNetworkTimeoutSeconds = Number.parseInt(String(merged.composerAutocompleteNetworkTimeoutSeconds), 10);
  const composerAutocompleteRotationSeconds = Number.parseInt(String(merged.composerAutocompleteRotationSeconds), 10);
  const composerAutocompleteCandidateCount = Number.parseInt(String(merged.composerAutocompleteCandidateCount), 10);
  const ttsRate = Number(merged.ttsRate);
  const ttsPitch = Number(merged.ttsPitch);
  const ttsChunkChars = Number.parseInt(String(merged.ttsChunkChars), 10);
  const legacyProfile = normalizeApiProfile(
    {
      id: "default",
      name: DEFAULT_SETTINGS.apiProfiles[0].name,
      apiUrl: merged.apiUrl,
      apiKey: merged.apiKey,
      apiMode: merged.apiMode,
      model: merged.model
    },
    getDefaultApiProfile()
  );
  const apiProfiles = normalizeApiProfiles(input.apiProfiles, legacyProfile);
  const requestedActiveApiProfileId = typeof merged.activeApiProfileId === "string"
    ? resolveApiProfileId(merged.activeApiProfileId, apiProfiles)
    : "";
  const activeApiProfileId =
    requestedActiveApiProfileId && apiProfiles.some((profile) => profile.id === requestedActiveApiProfileId)
      ? requestedActiveApiProfileId
      : apiProfiles[0].id;
  const requestedAutocompleteApiProfileId = typeof merged.composerAutocompleteApiProfileId === "string"
    ? resolveApiProfileId(merged.composerAutocompleteApiProfileId, apiProfiles)
    : "";
  const composerAutocompleteApiProfileId =
    requestedAutocompleteApiProfileId
      && apiProfiles.some((profile) => profile.id === requestedAutocompleteApiProfileId)
      ? requestedAutocompleteApiProfileId
      : "";
  const activeProfileBase = apiProfiles.find((profile) => profile.id === activeApiProfileId) ?? apiProfiles[0] ?? getDefaultApiProfile();
  const selectedModel = typeof merged.model === "string" && merged.model.trim()
    ? merged.model.trim()
    : activeProfileBase.model;
  const modelOptions = normalizeModelOptions(merged.modelOptions, selectedModel);
  let modelSourceByModel = normalizeModelSourceByModel((merged as Partial<Settings>).modelSourceByModel, modelOptions, apiProfiles, activeApiProfileId);
  const profileIds = new Set(apiProfiles.map((profile) => profile.id));
  const selectedModelSourceId = resolveApiProfileId(modelSourceByModel[selectedModel] || activeApiProfileId, apiProfiles);
  const resolvedActiveApiProfileId = profileIds.has(selectedModelSourceId) ? selectedModelSourceId : activeApiProfileId;
  const apiProfilesWithSelectedModel = apiProfiles.map((profile) =>
    profile.id === resolvedActiveApiProfileId ? normalizeApiProfile({ ...profile, model: selectedModel }, profile) : profile
  );
  modelSourceByModel = normalizeModelSourceByModel(
    { ...modelSourceByModel, [selectedModel]: resolvedActiveApiProfileId },
    modelOptions,
    apiProfilesWithSelectedModel,
    resolvedActiveApiProfileId
  );
  const activeProfile = apiProfilesWithSelectedModel.find((profile) => profile.id === resolvedActiveApiProfileId)
    ?? apiProfilesWithSelectedModel[0]
    ?? getDefaultApiProfile();
  return {
    ...merged,
    language: isLanguageMode(merged.language) ? merged.language : DEFAULT_SETTINGS.language,
    accessMode: isAccessMode(merged.accessMode) ? merged.accessMode : DEFAULT_SETTINGS.accessMode,
    activeApiProfileId: resolvedActiveApiProfileId,
    apiProfiles: apiProfilesWithSelectedModel,
    apiMode: activeProfile.apiMode,
    apiUrl: activeProfile.apiUrl,
    apiKey: activeProfile.apiKey,
    model: selectedModel,
    modelOptions,
    modelSourceByModel,
    temperature: Number.isFinite(temperature) ? Math.max(0, Math.min(2, temperature)) : DEFAULT_SETTINGS.temperature,
    maxOutputTokens: Number.isFinite(maxOutputTokens) ? Math.max(16, Math.min(32000, maxOutputTokens)) : DEFAULT_SETTINGS.maxOutputTokens,
    maxContextFiles: Number.isFinite(maxContextFiles) ? Math.max(1, Math.min(20, maxContextFiles)) : DEFAULT_SETTINGS.maxContextFiles,
    memoryFolder: typeof merged.memoryFolder === "string" ? merged.memoryFolder : DEFAULT_SETTINGS.memoryFolder,
    includeCurrentFile: Boolean(merged.includeCurrentFile),
    includeCoreMemory: Boolean(merged.includeCoreMemory),
    maxCoreMemoryFiles: Number.isFinite(maxCoreMemoryFiles) ? Math.max(0, Math.min(12, maxCoreMemoryFiles)) : DEFAULT_SETTINGS.maxCoreMemoryFiles,
    codexMemoryImportPath: typeof merged.codexMemoryImportPath === "string" ? merged.codexMemoryImportPath : DEFAULT_SETTINGS.codexMemoryImportPath,
    codexMemoryAutoImport: typeof merged.codexMemoryAutoImport === "boolean" ? merged.codexMemoryAutoImport : DEFAULT_SETTINGS.codexMemoryAutoImport,
    codexMemoryAutoSearch: typeof merged.codexMemoryAutoSearch === "boolean" ? merged.codexMemoryAutoSearch : DEFAULT_SETTINGS.codexMemoryAutoSearch,
    codexMemoryMaxFiles: Number.isFinite(codexMemoryMaxFiles) ? Math.max(1, Math.min(12, codexMemoryMaxFiles)) : DEFAULT_SETTINGS.codexMemoryMaxFiles,
    codexMemoryMaxChars: Number.isFinite(codexMemoryMaxChars) ? Math.max(1000, Math.min(60000, codexMemoryMaxChars)) : DEFAULT_SETTINGS.codexMemoryMaxChars,
    useVaultSearchByDefault: Boolean(merged.useVaultSearchByDefault),
    showAttachmentButton: typeof merged.showAttachmentButton === "boolean" ? merged.showAttachmentButton : DEFAULT_SETTINGS.showAttachmentButton,
    compactHeader: typeof merged.compactHeader === "boolean" ? merged.compactHeader : DEFAULT_SETTINGS.compactHeader,
    documentWorkbenchDefaultMode: isDocumentWorkbenchMode(merged.documentWorkbenchDefaultMode) ? merged.documentWorkbenchDefaultMode : DEFAULT_SETTINGS.documentWorkbenchDefaultMode,
    documentWorkbenchCompactHeader: typeof merged.documentWorkbenchCompactHeader === "boolean" ? merged.documentWorkbenchCompactHeader : DEFAULT_SETTINGS.documentWorkbenchCompactHeader,
    documentWorkbenchShowMetadata: typeof merged.documentWorkbenchShowMetadata === "boolean" ? merged.documentWorkbenchShowMetadata : DEFAULT_SETTINGS.documentWorkbenchShowMetadata,
    documentWorkbenchReuseSingleLeaf: typeof merged.documentWorkbenchReuseSingleLeaf === "boolean" ? merged.documentWorkbenchReuseSingleLeaf : DEFAULT_SETTINGS.documentWorkbenchReuseSingleLeaf,
    documentWorkbenchExtensions: normalizeDocumentWorkbenchExtensions(merged.documentWorkbenchExtensions),
    documentWorkbenchWildcardMigrated: typeof merged.documentWorkbenchWildcardMigrated === "boolean" ? merged.documentWorkbenchWildcardMigrated : DEFAULT_SETTINGS.documentWorkbenchWildcardMigrated,
    codeBlockWrap: typeof merged.codeBlockWrap === "boolean" ? merged.codeBlockWrap : DEFAULT_SETTINGS.codeBlockWrap,
    personalizedGreetingEnabled: typeof merged.personalizedGreetingEnabled === "boolean" ? merged.personalizedGreetingEnabled : DEFAULT_SETTINGS.personalizedGreetingEnabled,
    personalizationFriendlyName: typeof merged.personalizationFriendlyName === "string" ? sanitizePersonalizationName(merged.personalizationFriendlyName) : DEFAULT_SETTINGS.personalizationFriendlyName,
    personalizationWeatherLocation: typeof merged.personalizationWeatherLocation === "string" ? sanitizePersonalizationLocation(merged.personalizationWeatherLocation) : DEFAULT_SETTINGS.personalizationWeatherLocation,
    personalizedDiaryEnabled: typeof merged.personalizedDiaryEnabled === "boolean" ? merged.personalizedDiaryEnabled : DEFAULT_SETTINGS.personalizedDiaryEnabled,
    processRecordRuntimeCollapsed: typeof merged.processRecordRuntimeCollapsed === "boolean" ? merged.processRecordRuntimeCollapsed : DEFAULT_SETTINGS.processRecordRuntimeCollapsed,
    composerAutocompleteEnabled: typeof merged.composerAutocompleteEnabled === "boolean" ? merged.composerAutocompleteEnabled : DEFAULT_SETTINGS.composerAutocompleteEnabled,
    composerAutocompletePrefetchEnabled: typeof merged.composerAutocompletePrefetchEnabled === "boolean" ? merged.composerAutocompletePrefetchEnabled : DEFAULT_SETTINGS.composerAutocompletePrefetchEnabled,
    composerAutocompleteNetworkTimeoutSeconds: Number.isFinite(composerAutocompleteNetworkTimeoutSeconds)
      ? Math.max(EDITOR_AUTOCOMPLETE_NETWORK_TIMEOUT_SECONDS_MIN, Math.min(EDITOR_AUTOCOMPLETE_NETWORK_TIMEOUT_SECONDS_MAX, composerAutocompleteNetworkTimeoutSeconds))
      : DEFAULT_SETTINGS.composerAutocompleteNetworkTimeoutSeconds,
    composerAutocompleteRotationSeconds: Number.isFinite(composerAutocompleteRotationSeconds)
      ? Math.max(EDITOR_AUTOCOMPLETE_ROTATION_SECONDS_MIN, Math.min(EDITOR_AUTOCOMPLETE_ROTATION_SECONDS_MAX, composerAutocompleteRotationSeconds))
      : DEFAULT_SETTINGS.composerAutocompleteRotationSeconds,
    composerAutocompleteCandidateCount: Number.isFinite(composerAutocompleteCandidateCount)
      ? Math.max(EDITOR_AUTOCOMPLETE_CANDIDATE_COUNT_MIN, Math.min(EDITOR_AUTOCOMPLETE_CANDIDATE_COUNT_MAX, composerAutocompleteCandidateCount))
      : DEFAULT_SETTINGS.composerAutocompleteCandidateCount,
    composerAutocompleteApiProfileId,
    composerAutocompleteModel: typeof merged.composerAutocompleteModel === "string"
      ? merged.composerAutocompleteModel.trim()
      : DEFAULT_SETTINGS.composerAutocompleteModel,
    composerAutocompletePrompt: typeof merged.composerAutocompletePrompt === "string" ? trimContext(merged.composerAutocompletePrompt.trim(), 240) : DEFAULT_SETTINGS.composerAutocompletePrompt,
    forceStatusBarVisible: typeof merged.forceStatusBarVisible === "boolean" ? merged.forceStatusBarVisible : DEFAULT_SETTINGS.forceStatusBarVisible,
    autoOpenPlanPanel: typeof merged.autoOpenPlanPanel === "boolean" ? merged.autoOpenPlanPanel : DEFAULT_SETTINGS.autoOpenPlanPanel,
    showLiveTodos: typeof merged.showLiveTodos === "boolean" ? merged.showLiveTodos : DEFAULT_SETTINGS.showLiveTodos,
    showManualTodos: typeof merged.showManualTodos === "boolean" ? merged.showManualTodos : DEFAULT_SETTINGS.showManualTodos,
    uiButtonManagementEnabled: typeof merged.uiButtonManagementEnabled === "boolean" ? merged.uiButtonManagementEnabled : DEFAULT_SETTINGS.uiButtonManagementEnabled,
    uiButtonRules: normalizeUiButtonRules(merged.uiButtonRules),
    pinnedTags: normalizeTagList(merged.pinnedTags),
    hideUnpinnedTagsInRightSidebar: typeof merged.hideUnpinnedTagsInRightSidebar === "boolean" ? merged.hideUnpinnedTagsInRightSidebar : DEFAULT_SETTINGS.hideUnpinnedTagsInRightSidebar,
    commandBusEnabled: typeof merged.commandBusEnabled === "boolean" ? merged.commandBusEnabled : DEFAULT_SETTINGS.commandBusEnabled,
    executeObsidianCommands: typeof merged.executeObsidianCommands === "boolean" ? merged.executeObsidianCommands : DEFAULT_SETTINGS.executeObsidianCommands,
    githubCommandsEnabled: typeof merged.githubCommandsEnabled === "boolean" ? merged.githubCommandsEnabled : DEFAULT_SETTINGS.githubCommandsEnabled,
    githubApiBaseUrl: typeof merged.githubApiBaseUrl === "string" ? merged.githubApiBaseUrl : DEFAULT_SETTINGS.githubApiBaseUrl,
    githubDownloadBaseUrl: typeof merged.githubDownloadBaseUrl === "string" ? merged.githubDownloadBaseUrl : DEFAULT_SETTINGS.githubDownloadBaseUrl,
    githubOwner: typeof merged.githubOwner === "string" ? merged.githubOwner : DEFAULT_SETTINGS.githubOwner,
    githubRepo: typeof merged.githubRepo === "string" ? merged.githubRepo : DEFAULT_SETTINGS.githubRepo,
    githubToken: typeof merged.githubToken === "string" ? merged.githubToken : DEFAULT_SETTINGS.githubToken,
    autoContinueAfterTools: typeof merged.autoContinueAfterTools === "boolean" ? merged.autoContinueAfterTools : DEFAULT_SETTINGS.autoContinueAfterTools,
    maxToolIterations: Number.isFinite(maxToolIterations) ? Math.max(0, Math.min(10, maxToolIterations)) : DEFAULT_SETTINGS.maxToolIterations,
    exportMarkdownContextSnapshots: typeof merged.exportMarkdownContextSnapshots === "boolean" ? merged.exportMarkdownContextSnapshots : DEFAULT_SETTINGS.exportMarkdownContextSnapshots,
    exportMarkdownManualTodos: typeof merged.exportMarkdownManualTodos === "boolean" ? merged.exportMarkdownManualTodos : DEFAULT_SETTINGS.exportMarkdownManualTodos,
    maxRecentTranscriptMessages: Number.isFinite(maxRecentTranscriptMessages) ? Math.max(0, Math.min(40, maxRecentTranscriptMessages)) : DEFAULT_SETTINGS.maxRecentTranscriptMessages,
    includeHistoryAnchors: typeof merged.includeHistoryAnchors === "boolean" ? merged.includeHistoryAnchors : DEFAULT_SETTINGS.includeHistoryAnchors,
    maxHistoryAnchors: Number.isFinite(maxHistoryAnchors) ? Math.max(0, Math.min(20, maxHistoryAnchors)) : DEFAULT_SETTINGS.maxHistoryAnchors,
    maxMentionResults: Number.isFinite(maxMentionResults) ? Math.max(4, Math.min(40, maxMentionResults)) : DEFAULT_SETTINGS.maxMentionResults,
    maxMentionFolderFiles: Number.isFinite(maxMentionFolderFiles) ? Math.max(1, Math.min(30, maxMentionFolderFiles)) : DEFAULT_SETTINGS.maxMentionFolderFiles,
    maxFileContextChars: Number.isFinite(maxFileContextChars) ? Math.max(500, Math.min(50000, maxFileContextChars)) : DEFAULT_SETTINGS.maxFileContextChars,
    maxFolderFileContextChars: Number.isFinite(maxFolderFileContextChars) ? Math.max(300, Math.min(20000, maxFolderFileContextChars)) : DEFAULT_SETTINGS.maxFolderFileContextChars,
    skillsEnabled: typeof merged.skillsEnabled === "boolean" ? merged.skillsEnabled : DEFAULT_SETTINGS.skillsEnabled,
    skillRoots: normalizeSkillRoots(merged.skillRoots),
    skillAutoSelect: typeof merged.skillAutoSelect === "boolean" ? merged.skillAutoSelect : DEFAULT_SETTINGS.skillAutoSelect,
    maxAutoSkills: Number.isFinite(maxAutoSkills) ? Math.max(0, Math.min(8, maxAutoSkills)) : DEFAULT_SETTINGS.maxAutoSkills,
    maxSkillContextChars: Number.isFinite(maxSkillContextChars) ? Math.max(1000, Math.min(50000, maxSkillContextChars)) : DEFAULT_SETTINGS.maxSkillContextChars,
    maxAutoSkillContextChars: Number.isFinite(maxAutoSkillContextChars) ? Math.max(500, Math.min(20000, maxAutoSkillContextChars)) : DEFAULT_SETTINGS.maxAutoSkillContextChars,
    skillExperienceHarvestEnabled: typeof merged.skillExperienceHarvestEnabled === "boolean" ? merged.skillExperienceHarvestEnabled : DEFAULT_SETTINGS.skillExperienceHarvestEnabled,
    dailyLocalVersioning: typeof merged.dailyLocalVersioning === "boolean" ? merged.dailyLocalVersioning : DEFAULT_SETTINGS.dailyLocalVersioning,
    localVersionHour: Number.isFinite(localVersionHour) ? Math.max(0, Math.min(23, localVersionHour)) : DEFAULT_SETTINGS.localVersionHour,
    localVersionMaxFileBytes: Number.isFinite(localVersionMaxFileBytes) ? Math.max(1024, Math.min(5242880, localVersionMaxFileBytes)) : DEFAULT_SETTINGS.localVersionMaxFileBytes,
    automationsEnabled: typeof merged.automationsEnabled === "boolean" ? merged.automationsEnabled : DEFAULT_SETTINGS.automationsEnabled,
    automationCheckMinutes: Number.isFinite(automationCheckMinutes) ? Math.max(1, Math.min(1440, automationCheckMinutes)) : DEFAULT_SETTINGS.automationCheckMinutes,
    obsidianNoticesEnabled: typeof merged.obsidianNoticesEnabled === "boolean" ? merged.obsidianNoticesEnabled : DEFAULT_SETTINGS.obsidianNoticesEnabled,
    obsidianNoticeOnSessionComplete: typeof merged.obsidianNoticeOnSessionComplete === "boolean" ? merged.obsidianNoticeOnSessionComplete : DEFAULT_SETTINGS.obsidianNoticeOnSessionComplete,
    obsidianNoticeOnUserAttention: typeof merged.obsidianNoticeOnUserAttention === "boolean" ? merged.obsidianNoticeOnUserAttention : DEFAULT_SETTINGS.obsidianNoticeOnUserAttention,
    ntfyEnabled: typeof merged.ntfyEnabled === "boolean" ? merged.ntfyEnabled : DEFAULT_SETTINGS.ntfyEnabled,
    ntfyServerUrl: typeof merged.ntfyServerUrl === "string" && merged.ntfyServerUrl.trim() ? merged.ntfyServerUrl.trim() : DEFAULT_SETTINGS.ntfyServerUrl,
    ntfyTopic: typeof merged.ntfyTopic === "string" ? merged.ntfyTopic.trim() : DEFAULT_SETTINGS.ntfyTopic,
    ntfyToken: typeof merged.ntfyToken === "string" ? merged.ntfyToken.trim() : DEFAULT_SETTINGS.ntfyToken,
    ntfyOnSessionComplete: typeof merged.ntfyOnSessionComplete === "boolean" ? merged.ntfyOnSessionComplete : DEFAULT_SETTINGS.ntfyOnSessionComplete,
    ntfyOnSessionFail: typeof merged.ntfyOnSessionFail === "boolean" ? merged.ntfyOnSessionFail : DEFAULT_SETTINGS.ntfyOnSessionFail,
    ttsProvider: isTtsProvider(merged.ttsProvider) ? merged.ttsProvider : DEFAULT_SETTINGS.ttsProvider,
    ttsQualityMode: isTtsQualityMode(merged.ttsQualityMode) ? merged.ttsQualityMode : DEFAULT_SETTINGS.ttsQualityMode,
    ttsVoice: typeof merged.ttsVoice === "string" ? merged.ttsVoice : DEFAULT_SETTINGS.ttsVoice,
    ttsRate: Number.isFinite(ttsRate) ? Math.max(0.25, Math.min(4, ttsRate)) : DEFAULT_SETTINGS.ttsRate,
    ttsPitch: Number.isFinite(ttsPitch) ? Math.max(0, Math.min(2, ttsPitch)) : DEFAULT_SETTINGS.ttsPitch,
    ttsChunkChars: Number.isFinite(ttsChunkChars) ? Math.max(120, Math.min(2400, ttsChunkChars)) : DEFAULT_SETTINGS.ttsChunkChars,
    ttsCustomUrl: typeof merged.ttsCustomUrl === "string" ? merged.ttsCustomUrl : DEFAULT_SETTINGS.ttsCustomUrl,
    ttsShowViewActions: typeof merged.ttsShowViewActions === "boolean" ? merged.ttsShowViewActions : DEFAULT_SETTINGS.ttsShowViewActions,
    ttsAutoReadFinalAnswer: typeof merged.ttsAutoReadFinalAnswer === "boolean" ? merged.ttsAutoReadFinalAnswer : DEFAULT_SETTINGS.ttsAutoReadFinalAnswer,
    ttsOverlayCollapsed: typeof merged.ttsOverlayCollapsed === "boolean" ? merged.ttsOverlayCollapsed : DEFAULT_SETTINGS.ttsOverlayCollapsed,
    ttsOverlayPosition: isTtsOverlayPosition(merged.ttsOverlayPosition) ? merged.ttsOverlayPosition : DEFAULT_SETTINGS.ttsOverlayPosition,
    systemPrompt: typeof merged.systemPrompt === "string" ? merged.systemPrompt : DEFAULT_SETTINGS.systemPrompt
  };
}

