function assertCancipConfigWriteShape(config: Record<string, unknown>): void {
  const issues: string[] = [];
  for (const [key, value] of Object.entries(config)) {
    if (value === undefined) continue;
    if (CANCIP_CONFIG_STRING_KEYS.has(key)) {
      if (typeof value !== "string") issues.push(`${key} must be a string`);
      continue;
    }
    if (CANCIP_CONFIG_NUMBER_KEYS.has(key)) {
      if (!isFiniteConfigNumber(value)) issues.push(`${key} must be a finite number`);
      continue;
    }
    if (CANCIP_CONFIG_BOOLEAN_KEYS.has(key)) {
      if (typeof value !== "boolean") issues.push(`${key} must be a boolean`);
      continue;
    }
    if (CANCIP_CONFIG_STRING_ARRAY_KEYS.has(key)) {
      if (!isValidStringArrayConfigValue(value)) issues.push(`${key} must be a string or string[]`);
      continue;
    }
    if (key === "language") {
      if (!isLanguageMode(value)) issues.push("language is unsupported");
      continue;
    }
    if (key === "accessMode") {
      if (!isAccessMode(value)) issues.push("accessMode is unsupported");
      continue;
    }
    if (key === "apiMode") {
      if (!isApiMode(value)) issues.push("apiMode is unsupported");
      continue;
    }
    if (key === "ttsProvider") {
      if (!isTtsProvider(value)) issues.push("ttsProvider is unsupported");
      continue;
    }
    if (key === "ttsQualityMode") {
      if (!isTtsQualityMode(value)) issues.push("ttsQualityMode is unsupported");
      continue;
    }
    if (key === "apiProfiles") {
      if (!isValidApiProfilesConfigValue(value)) issues.push("apiProfiles must be an array of profile objects");
      continue;
    }
    if (key === "modelSourceByModel") {
      if (!isValidModelSourceByModelConfigValue(value)) issues.push("modelSourceByModel must map model IDs to profile IDs");
      continue;
    }
    issues.push(`${key} is not a supported Cancip config key`);
  }
  if (issues.length) {
    throw new Error(`config schema violation in ${CANCIP_CONFIG_PATH}: ${issues.join("; ")}`);
  }
}

function isFiniteConfigNumber(value: unknown): boolean {
  if (typeof value === "number") return Number.isFinite(value);
  if (typeof value !== "string") return false;
  const trimmed = value.trim();
  if (!trimmed) return false;
  return Number.isFinite(Number(trimmed));
}

function isValidStringArrayConfigValue(value: unknown): boolean {
  if (typeof value === "string") return Boolean(value.trim());
  return Array.isArray(value) && value.every((item) => typeof item === "string" && Boolean(item.trim()));
}

function isValidApiProfilesConfigValue(value: unknown): boolean {
  if (!Array.isArray(value)) return false;
  return value.every((item) => {
    if (!isRecord(item)) return false;
    return Object.entries(item).every(([key, field]) => {
      if (["id", "name", "apiUrl", "apiKey", "model"].includes(key)) return typeof field === "string";
      if (key === "apiMode") return isApiMode(field);
      return true;
    });
  });
}

function isValidModelSourceByModelConfigValue(value: unknown): boolean {
  if (!isRecord(value)) return false;
  return Object.entries(value).every(([model, profileId]) => Boolean(model.trim()) && typeof profileId === "string" && Boolean(profileId.trim()));
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function safeParseObject(raw: string, fallback: Record<string, unknown>): Record<string, unknown> {
  try {
    const parsed = JSON.parse(raw) as unknown;
    return isRecord(parsed) ? parsed : fallback;
  } catch {
    return fallback;
  }
}

function noteDrawEncodedDrawingName(path: string): string {
  const encoded = normalizePath(path)
    .replace(/[^a-zA-Z0-9._/-]/g, "_")
    .replace(/\//g, "__");
  return `${encoded || "note"}.json`;
}

function normalizeNoteDrawStrokeForStorage(value: unknown): Record<string, unknown> {
  const raw = isRecord(value) ? value : {};
  const kind = raw.kind === "text" || raw.kind === "embed" ? raw.kind : "";
  const render = raw.render === "markdown" || raw.render === "html" || raw.render === "note" ? raw.render : "plain";
  const points = normalizeAnnotationPoints(raw.points);
  const stroke: Record<string, unknown> = {
    brush: raw.brush === "watercolor" ? "watercolor" : "pen",
    color: normalizeHexColorForAnnotation(typeof raw.color === "string" ? raw.color : "#e53935"),
    width: clampNumber(raw.width, 3, 0.5, 80),
    opacity: clampNumber(raw.opacity, 1, 0, 1),
    count: clampInt(raw.count, 1, 1, 8),
    points
  };
  if (kind) stroke.kind = kind;
  if (kind === "text" || typeof raw.text === "string") {
    stroke.kind = "text";
    stroke.text = typeof raw.text === "string" ? raw.text : "";
    stroke.render = render;
    stroke.fontSize = clampNumber(raw.fontSize, render === "plain" ? 18 : 16, 10, 72);
    stroke.bold = raw.bold === true;
    stroke.code = raw.code === true || render === "html";
    stroke.boxed = raw.boxed === true || render !== "plain";
    stroke.file = raw.file === true || render === "note";
    stroke.previewWidth = clampNumber(raw.previewWidth, render === "note" ? 320 : 300, 80, 900);
    stroke.previewHeight = clampNumber(raw.previewHeight, render === "note" ? 220 : 180, 40, 700);
    stroke.uiRole = typeof raw.uiRole === "string" ? raw.uiRole : "";
    stroke.buttonStyle = typeof raw.buttonStyle === "string" ? raw.buttonStyle : "";
    stroke.snap = raw.snap === true;
    stroke.locked = raw.locked === true;
  }
  return stroke;
}

function pdftionAnnotationKey(path: string): string {
  return encodeURIComponent(normalizePath(path)).replace(/[!'()*]/g, (char) => `%${char.charCodeAt(0).toString(16).toUpperCase()}`);
}

function makeAnnotationElementId(): string {
  return `stroke-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 9)}`;
}

function normalizeHexColorForAnnotation(value: string): string {
  const trimmed = value.trim();
  if (/^#[0-9a-f]{6}$/i.test(trimmed)) return trimmed;
  if (/^#[0-9a-f]{3}$/i.test(trimmed)) return `#${trimmed[1]}${trimmed[1]}${trimmed[2]}${trimmed[2]}${trimmed[3]}${trimmed[3]}`;
  return "#000000";
}

function cloneJsonObject(value: unknown): Record<string, unknown> {
  if (!isRecord(value)) return {};
  return JSON.parse(JSON.stringify(value)) as Record<string, unknown>;
}

function cloneJsonValue(value: unknown): unknown {
  if (value === undefined) return null;
  return JSON.parse(JSON.stringify(value));
}

function deepMergeJsonObject(target: Record<string, unknown>, patch: Record<string, unknown>, changed: Set<string>, prefix = ""): void {
  for (const [key, value] of Object.entries(patch)) {
    if (!key) continue;
    const keyPath = prefix ? `${prefix}.${key}` : key;
    if (isRecord(value) && isRecord(target[key])) {
      const current = target[key];
      deepMergeJsonObject(current, value, changed, keyPath);
      continue;
    }
    target[key] = cloneJsonValue(value);
    changed.add(keyPath);
  }
}

function deleteJsonPath(target: Record<string, unknown>, keyPath: string): boolean {
  const parts = keyPath.split(".").map((part) => part.trim()).filter(Boolean);
  if (!parts.length) return false;
  let cursor: Record<string, unknown> = target;
  for (const part of parts.slice(0, -1)) {
    const next = cursor[part];
    if (!isRecord(next)) return false;
    cursor = next;
  }
  const last = parts[parts.length - 1];
  if (!Object.prototype.hasOwnProperty.call(cursor, last)) return false;
  delete cursor[last];
  return true;
}

function isLanguage(value: unknown): value is Language {
  return typeof value === "string" && (LANGUAGE_VALUES as readonly string[]).includes(value);
}

function isLanguageMode(value: unknown): value is LanguageMode {
  return value === "auto" || isLanguage(value);
}

function isAccessMode(value: unknown): value is AccessMode {
  return value === "ask-for-approval" || value === "full-access";
}

function isSessionStatus(value: unknown): value is NonNullable<SessionHistoryEntry["status"]> {
  return value === "idle" || value === "running" || value === "completed" || value === "failed" || value === "stopped";
}

function sessionSnapshotPersistenceSignature(snapshot: Record<string, unknown>): string {
  const messages = Array.isArray(snapshot.messages)
    ? snapshot.messages.map((message) => {
        if (!isRecord(message) || typeof message.content !== "string") return message;
        if (!/<!--\s*cancip-(?:progress-step|tool-feedback|process-message)/i.test(message.content)) return message;
        return {
          ...message,
          content: message.content.replace(/(耗时|elapsed)(?:[:：]?\s*)\d+(?:\.\d+)?(?:ms|s|m|h)\b/gi, "$1")
        };
      })
    : snapshot.messages;
  const taskControl = isRecord(snapshot.taskControl)
    ? { ...snapshot.taskControl, updatedAt: "" }
    : snapshot.taskControl;
  return stableTextHash(JSON.stringify({
    ...snapshot,
    updatedAt: "",
    metadataUpdatedAt: "",
    lastOpenedAt: "",
    exportedAt: "",
    taskControl,
    messages
  }));
}

function sessionHistoryEntryPersistenceSignature(entry: SessionHistoryEntry): string {
  return stableCacheKey({
    id: entry.id,
    title: entry.title,
    createdAt: entry.createdAt,
    startedAt: entry.startedAt,
    completedAt: entry.completedAt,
    stoppedAt: entry.stoppedAt,
    failedAt: entry.failedAt,
    messageCount: entry.messageCount,
    mode: entry.mode,
    model: entry.model,
    status: entry.status,
    completedNotice: entry.completedNotice,
    unread: entry.unread,
    pinned: entry.pinned,
    archived: entry.archived,
    coldArchived: entry.coldArchived,
    archivedAt: entry.archivedAt,
    manualTitle: entry.manualTitle,
    manualOrder: entry.manualOrder,
    parentSessionId: entry.parentSessionId,
    parentSessionTitle: entry.parentSessionTitle,
    subagentIds: entry.subagentIds,
    subagentRole: entry.subagentRole,
    subagentGoal: entry.subagentGoal,
    subagentProgress: entry.subagentProgress,
    path: entry.path
  });
}

function cancipLatestTimestamp(...values: Array<string | undefined>): string {
  let latest = "";
  let latestTime = Number.NEGATIVE_INFINITY;
  for (const value of values) {
    if (!value) continue;
    const time = Date.parse(value);
    if (!Number.isFinite(time)) continue;
    if (time >= latestTime) {
      latest = value;
      latestTime = time;
    }
  }
  return latest;
}

function cancipSessionTimeline(raw: Partial<SessionTimeline> & { sessionCreatedAt?: string }, fallbackId = ""): SessionTimeline {
  const id = raw.id || fallbackId;
  const createdAt = raw.createdAt || raw.sessionCreatedAt || new Date().toISOString();
  const startedAt = typeof raw.startedAt === "string" ? raw.startedAt : undefined;
  const completedAt = typeof raw.completedAt === "string" ? raw.completedAt : undefined;
  const stoppedAt = typeof raw.stoppedAt === "string" ? raw.stoppedAt : undefined;
  const failedAt = typeof raw.failedAt === "string" ? raw.failedAt : undefined;
  const updatedAt = raw.updatedAt || cancipLatestTimestamp(createdAt, startedAt, completedAt, stoppedAt, failedAt) || createdAt;
  return { id, createdAt, startedAt, updatedAt, completedAt, stoppedAt, failedAt, status: raw.status };
}

function cancipApplySessionStatusTimes(target: Partial<SessionTimeline> & { sessionCreatedAt?: string }, status: NonNullable<SessionHistoryEntry["status"]>, at: string): void {
  const createdAt = target.createdAt || target.sessionCreatedAt || at;
  target.createdAt = createdAt;
  if (status === "running" && !target.startedAt) target.startedAt = at;
  if (status === "completed" && !target.completedAt) target.completedAt = at;
  if (status === "stopped" && !target.stoppedAt) target.stoppedAt = at;
  if (status === "failed" && !target.failedAt) target.failedAt = at;
}

function cancipSessionTimelineRows(raw: Partial<SessionTimeline> & { sessionCreatedAt?: string }, language: Language): Array<[string, string, string]> {
  const timeline = cancipSessionTimeline(raw, raw.id);
  const chinese = isChineseLanguage(language);
  const rows: Array<[string, string, string]> = [];
  const add = (key: keyof SessionTimeline, zh: string, en: string): void => {
    const value = timeline[key];
    if (typeof value !== "string" || !value) return;
    rows.push([chinese ? zh : en, formatSessionHistoryTime(value), value]);
  };
  add("createdAt", "创建", "created");
  add("startedAt", "开始", "started");
  add("updatedAt", "更新", "updated");
  add("completedAt", "完成", "completed");
  add("stoppedAt", "停止", "stopped");
  add("failedAt", "失败", "failed");
  return rows;
}

function cancipSessionTimelineText(raw: Partial<SessionTimeline> & { sessionCreatedAt?: string }, language: Language): string {
  return cancipSessionTimelineRows(raw, language)
    .map(([label, time, iso]) => `${label}: ${time}${iso ? ` (${iso})` : ""}`)
    .join("\n");
}

function normalizeSessionHistoryEntry(item: Record<string, unknown>): SessionHistoryEntry | null {
  const id = typeof item.id === "string" ? item.id : "";
  const path = typeof item.path === "string" ? migrateLegacyCancipStoragePath(item.path) : "";
  if (!id || !path) return null;
  const status = isSessionStatus(item.status) ? item.status : "idle";
  const completedNotice = typeof item.completedNotice === "boolean" ? item.completedNotice : false;
  const unread = typeof item.unread === "boolean"
    ? item.unread
    : completedNotice && (status === "completed" || status === "failed" || status === "stopped");
  return {
    id,
    title: typeof item.title === "string" && item.title.trim() ? item.title.trim() : id,
    createdAt: typeof item.createdAt === "string" ? item.createdAt : "",
    startedAt: typeof item.startedAt === "string" ? item.startedAt : undefined,
    updatedAt: typeof item.updatedAt === "string" ? item.updatedAt : "",
    metadataUpdatedAt: typeof item.metadataUpdatedAt === "string" ? item.metadataUpdatedAt : undefined,
    completedAt: typeof item.completedAt === "string" ? item.completedAt : undefined,
    stoppedAt: typeof item.stoppedAt === "string" ? item.stoppedAt : undefined,
    failedAt: typeof item.failedAt === "string" ? item.failedAt : undefined,
    messageCount: typeof item.messageCount === "number" ? item.messageCount : 0,
    mode: normalizeComposerMode(item.mode) ?? "ask",
    model: typeof item.model === "string" ? item.model : "",
    status,
    completedNotice,
    unread,
    pinned: typeof item.pinned === "boolean" ? item.pinned : false,
    archived: typeof item.archived === "boolean" ? item.archived : false,
    coldArchived: typeof item.coldArchived === "boolean" ? item.coldArchived : false,
    archivedAt: typeof item.archivedAt === "string" ? item.archivedAt : undefined,
    lastOpenedAt: typeof item.lastOpenedAt === "string" ? item.lastOpenedAt : undefined,
    manualTitle: typeof item.manualTitle === "boolean" ? item.manualTitle : false,
    manualOrder: typeof item.manualOrder === "number" && Number.isFinite(item.manualOrder) ? item.manualOrder : undefined,
    parentSessionId: typeof item.parentSessionId === "string" ? item.parentSessionId : undefined,
    parentSessionTitle: typeof item.parentSessionTitle === "string" ? item.parentSessionTitle : undefined,
    subagentIds: Array.isArray(item.subagentIds) ? uniqueStrings(item.subagentIds.filter((value): value is string => typeof value === "string")) : undefined,
    subagentRole: typeof item.subagentRole === "string" ? item.subagentRole : undefined,
    subagentGoal: typeof item.subagentGoal === "string" ? item.subagentGoal : undefined,
    subagentProgress: typeof item.subagentProgress === "string" ? item.subagentProgress : undefined,
    eventOnly: typeof item.eventOnly === "boolean" ? item.eventOnly : false,
    path
  };
}

function sessionHistoryEntryFromSnapshot(raw: unknown, path: string): SessionHistoryEntry | null {
  if (!isRecord(raw)) return null;
  const id = typeof raw.sessionId === "string" && raw.sessionId.trim()
    ? raw.sessionId.trim()
    : reviewFileName(path).replace(/\.json$/i, "");
  if (!id) return null;
  const messages = Array.isArray(raw.messages) ? raw.messages : [];
  const status = isSessionStatus(raw.status) ? raw.status : "idle";
  const apiProfile = isRecord(raw.apiProfile) ? raw.apiProfile : {};
  const updatedAt = typeof raw.updatedAt === "string"
    ? raw.updatedAt
    : typeof raw.exportedAt === "string"
      ? raw.exportedAt
      : "";
  return {
    id,
    title: typeof raw.title === "string" && raw.title.trim() ? raw.title.trim() : id,
    createdAt: typeof raw.sessionCreatedAt === "string" ? raw.sessionCreatedAt : updatedAt,
    startedAt: typeof raw.startedAt === "string" ? raw.startedAt : undefined,
    updatedAt,
    metadataUpdatedAt: typeof raw.metadataUpdatedAt === "string" ? raw.metadataUpdatedAt : undefined,
    completedAt: typeof raw.completedAt === "string" ? raw.completedAt : undefined,
    stoppedAt: typeof raw.stoppedAt === "string" ? raw.stoppedAt : undefined,
    failedAt: typeof raw.failedAt === "string" ? raw.failedAt : undefined,
    messageCount: messages.length,
    mode: normalizeComposerMode(raw.mode) ?? "ask",
    model: typeof apiProfile.model === "string" ? apiProfile.model : "",
    status,
    completedNotice: typeof raw.completedNotice === "boolean" ? raw.completedNotice : false,
    unread: typeof raw.unread === "boolean" ? raw.unread : false,
    pinned: typeof raw.pinned === "boolean" ? raw.pinned : false,
    archived: typeof raw.archived === "boolean" ? raw.archived : false,
    coldArchived: typeof raw.coldArchived === "boolean" ? raw.coldArchived : false,
    archivedAt: typeof raw.archivedAt === "string" ? raw.archivedAt : undefined,
    lastOpenedAt: typeof raw.lastOpenedAt === "string" ? raw.lastOpenedAt : undefined,
    manualTitle: typeof raw.manualTitle === "boolean" ? raw.manualTitle : false,
    manualOrder: typeof raw.manualOrder === "number" && Number.isFinite(raw.manualOrder) ? raw.manualOrder : undefined,
    parentSessionId: typeof raw.parentSessionId === "string" ? raw.parentSessionId : undefined,
    parentSessionTitle: typeof raw.parentSessionTitle === "string" ? raw.parentSessionTitle : undefined,
    subagentIds: Array.isArray(raw.subagentIds) ? uniqueStrings(raw.subagentIds.filter((value): value is string => typeof value === "string")) : undefined,
    subagentRole: typeof raw.subagentRole === "string" ? raw.subagentRole : undefined,
    subagentGoal: typeof raw.subagentGoal === "string" ? raw.subagentGoal : undefined,
    subagentProgress: typeof raw.subagentProgress === "string" ? raw.subagentProgress : undefined,
    path
  };
}

function mergeSessionHistoryEntry(existing: SessionHistoryEntry | undefined, fromFile: SessionHistoryEntry): SessionHistoryEntry {
  if (!existing) return fromFile;
  const existingTime = Date.parse(existing.updatedAt);
  const fileTime = Date.parse(fromFile.updatedAt);
  const fileIsNewer = Number.isFinite(fileTime) && (!Number.isFinite(existingTime) || fileTime >= existingTime);
  const primary = fileIsNewer ? fromFile : existing;
  const secondary = fileIsNewer ? existing : fromFile;
  const existingMetadataTime = Date.parse(existing.metadataUpdatedAt || existing.updatedAt);
  const fileMetadataTime = Date.parse(fromFile.metadataUpdatedAt || fromFile.updatedAt);
  const fileMetadataIsNewer = Number.isFinite(fileMetadataTime)
    && (!Number.isFinite(existingMetadataTime) || fileMetadataTime >= existingMetadataTime);
  const metadata = fileMetadataIsNewer ? fromFile : existing;
  return {
    ...primary,
    title: metadata.manualTitle ? metadata.title : primary.title || secondary.title,
    metadataUpdatedAt: metadata.metadataUpdatedAt,
    pinned: metadata.pinned ?? false,
    archived: metadata.archived ?? false,
    coldArchived: metadata.coldArchived ?? false,
    archivedAt: metadata.archivedAt,
    lastOpenedAt: cancipLatestTimestamp(existing.lastOpenedAt, fromFile.lastOpenedAt) || undefined,
    manualTitle: metadata.manualTitle ?? false,
    manualOrder: metadata.manualOrder,
    unread: metadata.unread ?? false,
    completedNotice: metadata.completedNotice ?? false,
    parentSessionId: primary.parentSessionId || secondary.parentSessionId,
    parentSessionTitle: primary.parentSessionTitle || secondary.parentSessionTitle,
    subagentIds: uniqueStrings([...(primary.subagentIds ?? []), ...(secondary.subagentIds ?? [])]),
    subagentRole: primary.subagentRole || secondary.subagentRole,
    subagentGoal: primary.subagentGoal || secondary.subagentGoal,
    subagentProgress: primary.subagentProgress || secondary.subagentProgress,
    eventOnly: false,
    path: primary.path || secondary.path
  };
}

async function mergeSessionFilesIntoHistoryWithAdapter(
  adapter: DataAdapter,
  entries: SessionHistoryEntry[],
  additionalPaths: string[] = [],
  refreshIndexedFiles = false
): Promise<SessionHistoryEntry[]> {
  const byId = new Map<string, SessionHistoryEntry>();
  for (const entry of entries) byId.set(entry.id, entry);
  const indexedIds = new Set(byId.keys());
  try {
    if (!(await adapter.exists(SESSION_HISTORY_DIR))) {
      return entries.sort(compareSessionHistoryEntries).slice(0, SESSION_HISTORY_LIMIT);
    }
    const listing = await adapter.list(SESSION_HISTORY_DIR);
    const missingFiles = listing.files
      .filter((path) => path.endsWith(".json") && !path.endsWith("/index.json"))
      .sort((a, b) => b.localeCompare(a))
      .filter((path) => !indexedIds.has(reviewFileName(path).replace(/\.json$/i, "")))
      .slice(0, Math.max(8, SESSION_HISTORY_LIMIT - Math.min(entries.length, SESSION_HISTORY_LIMIT)));
    const files = uniqueStrings([
      ...additionalPaths
        .map((path) => normalizePath(path.replace(/\\/g, "/")))
        .filter((path) => path.startsWith(`${SESSION_HISTORY_DIR}/`) && path.endsWith(".json") && path !== SESSION_HISTORY_INDEX_PATH),
      ...(refreshIndexedFiles
        ? entries
            .map((entry) => normalizePath(entry.path || `${SESSION_HISTORY_DIR}/${entry.id}.json`))
            .filter((path) => path.startsWith(`${SESSION_HISTORY_DIR}/`) && path.endsWith(".json") && path !== SESSION_HISTORY_INDEX_PATH)
        : []),
      ...missingFiles
    ]).slice(0, SESSION_HISTORY_LIMIT * 2);
    for (const path of files) {
      try {
        const raw = await adapter.read(path);
        const parsed = JSON.parse(raw) as unknown;
        const entry = sessionHistoryEntryFromSnapshot(parsed, path);
        if (!entry) continue;
        byId.set(entry.id, mergeSessionHistoryEntry(byId.get(entry.id), entry));
      } catch {
        // Ignore one corrupt or half-synced session file; the rest of history should still load.
      }
    }
  } catch (error) {
    console.warn("Cancip session file history merge failed", error);
  }
  return [...byId.values()].sort(compareSessionHistoryEntries).slice(0, SESSION_HISTORY_LIMIT);
}

function shouldShowUnreadSession(entry: SessionHistoryEntry): boolean {
  if (entry.eventOnly) return false;
  if (entry.unread === true) return true;
  return Boolean(entry.completedNotice && (entry.status === "completed" || entry.status === "failed" || entry.status === "stopped"));
}

function compareSessionHistoryEntries(a: SessionHistoryEntry, b: SessionHistoryEntry): number {
  if (Boolean(a.archived) !== Boolean(b.archived)) return a.archived ? 1 : -1;
  const aManualOrder = typeof a.manualOrder === "number" && Number.isFinite(a.manualOrder) ? a.manualOrder : null;
  const bManualOrder = typeof b.manualOrder === "number" && Number.isFinite(b.manualOrder) ? b.manualOrder : null;
  if (aManualOrder !== null && bManualOrder !== null && aManualOrder !== bManualOrder) {
    return aManualOrder - bManualOrder;
  }
  const aLastUsedAt = cancipLatestTimestamp(a.lastOpenedAt, a.updatedAt, a.createdAt);
  const bLastUsedAt = cancipLatestTimestamp(b.lastOpenedAt, b.updatedAt, b.createdAt);
  const byUpdatedAt = bLastUsedAt.localeCompare(aLastUsedAt);
  if (byUpdatedAt) return byUpdatedAt;
  return b.createdAt.localeCompare(a.createdAt) || b.id.localeCompare(a.id);
}

function generateSessionTitleFromPrompt(prompt: string, fallback: string): string {
  const cleaned = removeCancipActionBlocks(prompt)
    .replace(/```[\s\S]*?```/g, " ")
    .replace(/<details\b[^>]*>[\s\S]*?<\/details>/gi, " ")
    .replace(/[#>*_`~[\](){}|]/g, " ")
    .replace(/\b(cancip-action|Raw user prompt|Resolved task goal|Model prompt for this turn)\b/gi, " ")
    .replace(/\s+/g, " ")
    .trim();
  const base = cleaned || fallback;
  return trimContext(base, 38).replace(/\s+/g, " ").trim() || fallback;
}

function redactSessionEvent(event: SessionEvent): SessionEvent {
  return {
    ...event,
    summary: event.summary ? trimContext(redactSensitiveText(event.summary), 400) : undefined,
    detail: event.detail ? trimContext(redactSensitiveText(event.detail), 1600) : undefined
  };
}

async function recordCancipSessionEvent(adapter: DataAdapter, event: SessionEvent): Promise<void> {
  try {
    await ensureFolder(adapter, SESSION_HISTORY_DIR);
    const payload: SessionEvent = {
      ...event,
      at: event.at ?? new Date().toISOString()
    };
    const line = `${JSON.stringify(redactSessionEvent(payload))}\n`;
    if (!(await adapter.exists(SESSION_EVENTS_PATH))) {
      await adapter.write(SESSION_EVENTS_PATH, line);
      return;
    }
    const stat = await adapter.stat(SESSION_EVENTS_PATH);
    if (!stat || stat.size <= SESSION_EVENTS_MAX_BYTES) {
      await adapter.append(SESSION_EVENTS_PATH, line);
      return;
    }
    const existing = await adapter.read(SESSION_EVENTS_PATH);
    const next = `${existing.slice(-Math.floor(SESSION_EVENTS_MAX_BYTES * 0.8))}${line}`;
    await adapter.write(SESSION_EVENTS_PATH, next);
  } catch (error) {
    console.warn("Cancip session event write failed", error);
  }
}

function formatSessionEventLine(event: SessionEventView): string {
  const parts = [
    event.at || "-",
    event.kind,
    event.sessionId ? `session=${event.sessionId}` : "",
    event.status ? `status=${event.status}` : "",
    event.toolStatus ? `tool=${event.toolStatus}` : "",
    event.role ? `role=${event.role}` : "",
    event.summary ? `summary=${trimContext(redactSensitiveText(event.summary).replace(/\r?\n/g, " "), 180)}` : "",
    event.path ? `path=${event.path}` : "",
    event.detail ? `detail=${trimContext(redactSensitiveText(event.detail).replace(/\r?\n/g, " "), 260)}` : ""
  ].filter(Boolean);
  return parts.join(" | ");
}

function sessionEventIcon(kind: SessionEventKind): string {
  if (kind === "plugin.load") return "plug";
  if (kind.startsWith("session.")) return "messages-square";
  if (kind.startsWith("prompt.")) return "send";
  if (kind.startsWith("model.")) return "route";
  if (kind === "message.add") return "message-square";
  if (kind.startsWith("tool.")) return "wrench";
  return "list-checks";
}

function isComposerMode(value: unknown): value is ComposerMode {
  return value === "ask" || value === "search" || value === "plan" || value === "edit";
}

function normalizeComposerMode(value: unknown): ComposerMode | null {
  if (!isComposerMode(value)) return null;
  return value === "plan" ? "ask" : value;
}

function isApiMode(value: unknown): value is ApiMode {
  return value === "auto" || value === "compatible" || value === "responses";
}

function normalizeSessionApiProfile(raw: Record<string, unknown>): ChatMessage["apiProfile"] {
  return {
    id: typeof raw.id === "string" ? raw.id : "",
    name: typeof raw.name === "string" ? raw.name : "",
    apiMode: isApiMode(raw.apiMode) ? raw.apiMode : "auto",
    model: typeof raw.model === "string" ? raw.model : "",
    hasApiUrl: Boolean(raw.hasApiUrl),
    hasApiKey: Boolean(raw.hasApiKey)
  };
}

function normalizeManualTodos(raw: unknown): ManualTodo[] {
  if (!Array.isArray(raw)) return [];
  return dedupeManualTodos(raw
    .filter(isRecord)
    .map((item) => ({
      id: typeof item.id === "string" && item.id ? item.id : crypto.randomUUID(),
      text: typeof item.text === "string" ? item.text.trim() : "",
      done: Boolean(item.done),
      sendToModel: typeof item.sendToModel === "boolean" ? item.sendToModel : true,
      source: item.source === "programmatic" ? "programmatic" as const : "manual" as const,
      createdAt: typeof item.createdAt === "string" ? item.createdAt : new Date().toISOString()
    }))
    .filter((item) => item.text));
}

function dedupeManualTodos(todos: ManualTodo[]): ManualTodo[] {
  const seen = new Set<string>();
  const next: ManualTodo[] = [];
  for (const todo of todos) {
    const text = todo.text.trim();
    if (!text) continue;
    const key = normalizeUiButtonLabel(text);
    if (seen.has(key)) continue;
    seen.add(key);
    next.push({ ...todo, text });
  }
  return next;
}

function isProgrammaticPlanTemplateTodo(todo: ManualTodo): boolean {
  return PROGRAMMATIC_PLAN_TEMPLATE_TEXTS.has(todo.text.trim());
}

function normalizeQueuedPrompts(raw: unknown): QueuedPrompt[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .filter(isRecord)
    .map((item) => ({
      id: typeof item.id === "string" && item.id ? item.id : crypto.randomUUID(),
      prompt: typeof item.prompt === "string" ? item.prompt.trim() : "",
      createdAt: typeof item.createdAt === "number" && Number.isFinite(item.createdAt) ? item.createdAt : Date.now(),
      held: typeof item.held === "boolean" ? item.held : undefined
    }))
    .filter((item) => item.prompt);
}

function markdownFenceLines(content: string, lang = "text", indent = ""): string[] {
  const normalized = content.replace(/\r\n?/g, "\n");
  let maxTicks = 0;
  const tickRuns = normalized.match(/`+/g);
  if (tickRuns) {
    for (const item of tickRuns) maxTicks = Math.max(maxTicks, item.length);
  }
  const fence = "`".repeat(Math.max(3, maxTicks + 1));
  const opening = lang ? `${fence}${lang}` : fence;
  return [
    `${indent}${opening}`,
    ...normalized.split("\n").map((line) => `${indent}${line}`),
    `${indent}${fence}`
  ];
}

function countRegex(text: string, pattern: RegExp): number {
  return text.match(pattern)?.length ?? 0;
}

function retainLatestText(content: string, maxChars: number): string {
  const trimmed = content.trim();
  if (trimmed.length <= maxChars) return trimmed;
  const heading = trimmed.match(/^# .+$/m)?.[0] ?? "# Cancip Memory";
  const marker = "> Older entries omitted after preserving the newest content.";
  const tailBudget = Math.max(1000, maxChars - heading.length - marker.length - 6);
  return [heading, "", marker, "", trimmed.slice(-tailBudget).replace(/^# .+?\r?\n+/, "")].join("\n");
}

function retainLatestDreamEntries(content: string, maxChars: number): string {
  const trimmed = content.trim();
  if (trimmed.length <= maxChars) return trimmed;
  const marker = "> Older dream entries omitted after preserving the newest entries.";
  const tailBudget = Math.max(1000, maxChars - marker.length - 30);
  const tail = trimmed.slice(-tailBudget);
  const entryBoundary = tail.indexOf("\n## ");
  const retained = entryBoundary >= 0 ? tail.slice(entryBoundary + 1) : tail;
  return ["# Cancip Dream Log", "", marker, "", retained].join("\n");
}

function cleanFoldedBlockContent(block: FoldedMessageBlock): string {
  const content = block.content.trim();
  const lines = content.split(/\r?\n/);
  const firstLine = lines[0]?.trim().toLowerCase();
  const title = block.title.trim().toLowerCase();
  const duplicatedTitle = Boolean(firstLine && firstLine === title && lines.length > 1);
  const titleLooksLikeFenceLabel = /^(?:cancip-action|thinking|reasoning|process|details?|json|text|bash|sh|zsh|shell|powershell|ps1|cmd|bat|terminal|console|ts|tsx|js|jsx|html|css|python|py|diff)$/i.test(title);
  if (duplicatedTitle && titleLooksLikeFenceLabel) return lines.slice(1).join("\n").trim();
  return content;
}

function runStatsMarker(text: string): string {
  return `<!-- ${RUN_STATS_MARKER_NAME} ${JSON.stringify({ text })} -->`;
}

function stripProgrammaticRunStats(content: string): { content: string; text: string } {
  let text = "";
  const cleaned = content.replace(/<!--\s*cancip-run-stats\b([\s\S]*?)-->/gi, (_full, rawPayload: string) => {
    const payload = rawPayload.trim();
    if (payload) {
      try {
        const parsed = JSON.parse(payload) as unknown;
        if (isRecord(parsed) && typeof parsed.text === "string") text = parsed.text.trim();
      } catch {
        text = payload.replace(/^[:：-]\s*/, "").trim();
      }
    }
    return "\n\n";
  });
  return { content: cleaned, text };
}

function stripModelRunStatsLines(content: string): string {
  const lines = content.split(/\r?\n/);
  const kept: string[] = [];
  for (const line of lines) {
    if (isModelRunStatsLine(line.trim())) continue;
    kept.push(line);
  }
  return kept.join("\n");
}

function isModelRunStatsLine(trimmed: string): boolean {
  if (!trimmed) return false;
  const line = trimmed
    .replace(/^[-*]\s*/, "")
    .replace(/^>\s*/, "")
    .trim();
  if (!line || line.length > 140) return false;
  if (/^(?:总耗时|耗时|用时|总用时|Elapsed|Total elapsed|Duration)\s*[:：]/i.test(line)) return true;
  if (/^(?:Token|Tokens|token|tokens|字数|字符|chars?|characters?)\s*(?:[:：]|发送|接收|合计|sent|received|in\b|out\b|total\b)/i.test(line)) return true;
  if (/^(?:发送|接收|合计)\s*(?:token|tokens|字数|字符)/i.test(line)) return true;
  return isOnlyRunStatsText(line);
}

function isModelFailureVisibleText(content: string): boolean {
  const text = stripStructuredChoices(stripProgrammaticRunStats(content).content)
    .replace(/\s+/g, " ")
    .trim();
  if (!text) return false;
  if (/^(?:模型调用失败|Model call failed|API 返回了空回复|The API returned an empty response|调用失败|Call failed)(?:\s|[:：.]|$)/i.test(text)) return true;
  return /HTTP\s+\d{3}[\s\S]{0,220}(?:model_not_found|not supported by any configured account|rate_limit|insufficient_quota|timeout|timed out)/i.test(text);
}

function foldStandaloneProcessJsonArtifacts(content: string, hiddenToolBlocks: FoldedMessageBlock[]): string {
  const seen = new Set<string>();
  const candidates: Array<{ raw: string; title: string }> = [];
  const keyRegex = /["'](?:actions|action|type|tool|command|op|args|messages|request|requestBody|response|responseText|responseJson|responseShape|status|result|error)["']\s*:/g;
  let match: RegExpExecArray | null;
  while ((match = keyRegex.exec(content)) !== null) {
    const raw = extractJsonObjectAroundIndex(content, match.index);
    if (!raw || seen.has(raw)) continue;
    const info = processJsonArtifactInfo(raw);
    if (!info) continue;
    seen.add(raw);
    candidates.push({ raw, title: info.title });
  }
  if (!candidates.length) return content;
  let output = content;
  for (const candidate of candidates.sort((a, b) => b.raw.length - a.raw.length)) {
    hiddenToolBlocks.push({ title: candidate.title, content: candidate.raw });
    output = output.split(candidate.raw).join("\n\n");
  }
  return output;
}

function processJsonArtifactInfo(raw: string): { title: string } | null {
  const body = raw.trim();
  if (!body) return null;
  let parsed: unknown;
  try {
    parsed = JSON.parse(body) as unknown;
  } catch {
    return null;
  }
  const actions = extractCancipActionsFromJson(body);
  if (actions.length) {
    const summary = uniqueStrings(actions.slice(0, 3).map((action) => describeActionPlain(action))).join("; ");
    const suffix = actions.length > 3 ? ` +${actions.length - 3}` : "";
    return { title: summary ? `动作 JSON：${summary}${suffix}` : "动作 JSON" };
  }
  const title = processJsonArtifactTitle(parsed);
  return title ? { title } : null;
}

function processJsonArtifactTitle(value: unknown): string {
  if (Array.isArray(value)) {
    const titles = uniqueStrings(value.map((item) => processJsonArtifactTitle(item)).filter(Boolean));
    if (!titles.length) return "";
    return titles.length === 1 ? titles[0] : `过程 JSON：${Math.min(value.length, titles.length)} 项`;
  }
  if (!isRecord(value)) return "";
  const keys = new Set(Object.keys(value).map((key) => key.toLowerCase()));
  const text = JSON.stringify(value);
  const tool = typeof value.tool === "string" ? value.tool.trim() : "";
  if (tool) return `工具调用：${trimContext(tool, 90)}`;
  const command = typeof value.command === "string" ? value.command.trim() : "";
  if (command && (keys.has("args") || keys.has("type") || keys.has("action"))) return `命令调用：${trimContext(command, 90)}`;
  const actionLike = [value.type, value.action]
    .filter((item): item is string => typeof item === "string")
    .map((item) => item.trim())
    .find((item) => /^(?:read|write|append|patch|config|todo|automation|mkdir|rename|move|copy|delete|command|search)$/i.test(item));
  if (actionLike) return `过程动作：${actionLike}`;
  if (Array.isArray(value.actions)) return `动作 JSON：${value.actions.length} 项`;
  if (keys.has("messages") && keys.has("model")) return "模型请求 JSON";
  if ((keys.has("request") || keys.has("requestbody")) && (keys.has("response") || keys.has("responseshape") || keys.has("status"))) return "API 调用审计 JSON";
  if (keys.has("status") && (keys.has("result") || keys.has("error"))) return "工具结果 JSON";
  if (/(?:cancip|obsidian|github|web\.(?:search|fetch)|requestBody|responseText|tool_call|toolCall)/i.test(text)) return "过程 JSON";
  return "";
}

function prepareMessageDisplay(content: string): MessageDisplay {
  const programmaticStats = stripProgrammaticRunStats(content);
  const baseContent = programmaticStats.content;
  const hiddenToolBlocks: FoldedMessageBlock[] = [];
  const explicitlyProcessOnly = isProgressMessage(baseContent)
    || isToolFeedbackMessage(baseContent)
    || baseContent.includes(PROCESS_MESSAGE_MARKER)
    || isLegacyProgressStatusMessage(baseContent);
  let processOnly = explicitlyProcessOnly || isModelFailureVisibleText(baseContent);
  let visibleContent = stripFinalReviewMetadata(stripModelRunStatsLines(baseContent)).replace(/(`{3,})([^\n`]*)\n?([\s\S]*?)\1/g, (full: string, _fence: string, rawLang: string, body: string) => {
    const lang = rawLang.replace(/^`+/, "").trim().toLowerCase();
    const trimmed = body.trim();
    if (trimmed && shouldFoldCodeBlock(lang, trimmed)) {
      hiddenToolBlocks.push({ title: foldedBlockTitle(lang, trimmed), content: lang ? `${lang}\n${trimmed}` : trimmed });
      return "\n\n";
    }
    return full;
  });
  visibleContent = visibleContent.replace(/<cancip-action\b[^>]*>([\s\S]*?)<\/cancip-action>/gi, (_full, body: string) => {
    const trimmed = body.trim();
    if (trimmed) hiddenToolBlocks.push({ title: "cancip-action", content: trimmed });
    return "\n\n";
  });
  visibleContent = visibleContent.replace(/<!--\s*cancip-action\b([\s\S]*?)-->/gi, (_full, body: string) => {
    const trimmed = body.trim();
    if (trimmed) hiddenToolBlocks.push({ title: "cancip-action", content: trimmed });
    return "\n\n";
  });
  visibleContent = visibleContent.replace(/<(think|thinking|reasoning)\b[^>]*>([\s\S]*?)<\/\1>/gi, (_full, tag: string, body: string) => {
    const trimmed = body.trim();
    if (trimmed) hiddenToolBlocks.push({ title: tag, content: `${tag}\n${trimmed}` });
    return "\n\n";
  });
  visibleContent = foldInlineDetails(visibleContent, hiddenToolBlocks);
  visibleContent = foldReasoningSections(visibleContent, hiddenToolBlocks);
  visibleContent = foldModelReasoningArtifacts(visibleContent, hiddenToolBlocks);
  visibleContent = foldProcessAfterConclusion(visibleContent, hiddenToolBlocks);
  visibleContent = foldStandaloneProcessJsonArtifacts(visibleContent, hiddenToolBlocks);

  const visibleLines: string[] = [];
  for (const line of visibleContent.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (trimmed === PROGRESS_STEP_MARKER || trimmed === PROCESS_MESSAGE_MARKER) continue;
    if (trimmed.startsWith(TOOL_FEEDBACK_MARKER_PREFIX)) continue;
    if (isPromptishProgressNoteLine(trimmed) && !isProgrammaticProgressHeadline(trimmed)) continue;
    const rawJson = trimmed.replace(/^(?:代码|code)\s*/i, "");
    if (/^\{\s*"?(?:actions|action|type)"?\s*:/.test(rawJson)) {
      hiddenToolBlocks.push({ title: "action json", content: rawJson });
      continue;
    }
    const jsonInfo = processJsonArtifactInfo(rawJson);
    if (jsonInfo) {
      hiddenToolBlocks.push({ title: jsonInfo.title, content: rawJson });
      continue;
    }
    visibleLines.push(line);
  }

  visibleContent = visibleLines.join("\n").replace(/\n{3,}/g, "\n\n").trim();
  visibleContent = stripTailChoiceSection(visibleContent);
  if (!explicitlyProcessOnly && processOnly && looksLikeUserFacingFinalContent(visibleContent)) processOnly = false;
  if (!visibleContent && hiddenToolBlocks.some(isProcessFoldedBlock)) processOnly = true;
  return { visibleContent, runStatsText: programmaticStats.text, hiddenToolBlocks, hasProcessFold: hiddenToolBlocks.length > 0, processOnly };
}

function looksLikeUserFacingFinalContent(text: string): boolean {
  const visible = stripTailChoiceSection(stripModelRunStatsLines(text)).replace(/\s+/g, " ").trim();
  if (!visible || visible.length < 8 || visible.length > 900) return false;
  if (isPromptishProgressNoteLine(visible)) return false;
  if (isUnreadableProcessHeadlineText(visible)) return false;
  if (/^(?:已执行|执行中|失败|running|executed|failed)\s*[·:：-]/i.test(visible)) return false;
  if (/(?:已完成|已修复|已写入|已创建|已修改|已验证|没完成|未完成|失败|阻塞|等待确认|等待审核|具体阻塞|改动：|验证：|completed|done|fixed|created|changed|verified|failed|blocked|pending approval|pending review)/i.test(visible)) return true;
  return hasFinalConclusion(visible) && !/(?:raw sent|raw received|request body|response json|tool call|cancip-action|工具调用|原始发送|原始接收)/i.test(visible);
}

function isMeaningfulProcessRecord(message: ChatMessage, display: MessageDisplay): boolean {
  if (message.toolRuns?.length) return true;
  if (display.hiddenToolBlocks.length > 0) return true;
  if (isToolFeedbackMessage(message.content)) return true;
  const visible = display.visibleContent.replace(/\s+/g, " ").trim();
  if (isProgressMessage(message.content)) return Boolean(visible);
  if (!visible) return false;
  if (/^(?:完成|done|executed|工具执行完成)[。.!！\s]*$/i.test(visible)) return false;
  return visible.length > 12;
}

function splitFinalAssistantProcessBlocks(display: MessageDisplay): { finalDisplay: MessageDisplay; processDisplay: MessageDisplay } | null {
  if (!display.hiddenToolBlocks.length) return null;
  const processBlocks = display.hiddenToolBlocks.filter(isProcessFoldedBlock);
  if (!processBlocks.length) return null;
  const finalBlocks = display.hiddenToolBlocks.filter((block) => !isProcessFoldedBlock(block));
  return {
    finalDisplay: {
      ...display,
      hiddenToolBlocks: finalBlocks,
      hasProcessFold: finalBlocks.length > 0
    },
    processDisplay: {
      visibleContent: "",
      runStatsText: "",
      hiddenToolBlocks: processBlocks,
      hasProcessFold: true,
      processOnly: true
    }
  };
}

function isProcessFoldedBlock(block: FoldedMessageBlock): boolean {
  const title = block.title.replace(/\s+/g, " ").trim();
  if (!title) return false;
  if (/^(?:cancip-action|action json|process|reasoning|think|thinking)$/i.test(title)) return true;
  if (/(?:过程|思考|推理|命令|执行|工具|动作|调用|模型|请求|响应|日志|详情|收发|审计|原始|trace|audit|exchange|request|response|raw|tool|action|command|process|reasoning|thinking|details?|logs?)/i.test(title)) return true;
  return false;
}

function isTrivialProgressDetail(detail: string): boolean {
  const compact = detail.replace(/\s+/g, "").trim().toLowerCase();
  return !compact || /^(完成|done|executed|success|ok|工具执行完成)$/.test(compact);
}

function isUnreadableProcessHeadlineText(text: string): boolean {
  const trimmed = text.trim();
  if (!trimmed) return false;
  if (looksLikeProcessProtocolLeakText(trimmed) || isProcessProtocolLeakLine(trimmed)) return true;
  if (/^(?:\{[\s\S]*\}|\[[\s\S]*\])$/.test(trimmed)) return true;
  if (/^(?:json|javascript|js|ts|tsx|css|html|xml|yaml|yml)\b/i.test(trimmed) && /[{}\[\]":,]/.test(trimmed)) return true;
  const symbolCount = countRegex(trimmed, /[{}\[\]":,]/g);
  if (symbolCount >= 12 && symbolCount / Math.max(1, trimmed.length) > 0.14) return true;
  return /["'](?:tool|actions|action|type|command|args|requestBody|responseText|responseJson)["']\s*:/.test(trimmed);
}

function stripProcessVisibleProtocolLeaks(text: string): string {
  const trimmed = text.trim();
  if (!trimmed) return "";
  if (looksLikeProcessProtocolLeakText(trimmed)) return "";
  const kept: string[] = [];
  let skippingProtocolParagraph = false;
  for (const line of trimmed.split(/\r?\n/)) {
    const clean = line.trim();
    if (!clean) {
      skippingProtocolParagraph = false;
      if (kept.length && kept[kept.length - 1] !== "") kept.push("");
      continue;
    }
    if (isProcessProtocolLeakLine(clean)) {
      skippingProtocolParagraph = true;
      continue;
    }
    if (skippingProtocolParagraph) {
      if (/^#{1,6}\s+/.test(clean) || isProgrammaticProgressHeadline(clean)) {
        skippingProtocolParagraph = false;
      } else {
        continue;
      }
    }
    kept.push(line);
  }
  const result = kept.join("\n").replace(/\n{3,}/g, "\n\n").trim();
  return looksLikeProcessProtocolLeakText(result) ? "" : result;
}

function looksLikeProcessProtocolLeakText(text: string): boolean {
  const compact = text.replace(/\s+/g, " ").trim();
  if (!compact) return false;
  if (/^(?:工具协议|Tool protocol|动作格式|Tool format)[:：]/i.test(compact)) return true;
  const patterns = [
    /cancip-action\s+JSON\s*块/i,
    /(?:动作|Supported action types?)[:：].*(?:read|search|write|patch|command)/i,
    /(?:路线例|Routes?)[:：].*(?:findTarget|tools\.index|obsidian\.)/i,
    /(?:入口|Entry points?)[:：].*(?:cancip\.|obsidian\.|github\.|web\.)/i,
    /(?:RAW SENT|RAW RECEIVED|SENT system|Actual API call audit|Model exchange raw contents|requestBody|responseJson|responseText)/i,
    /(?:tool_choice|prompt_cache_key|responseShape|input_tokens|output_tokens)/i,
    /(?:Decide and produce the next response now|Original user request|Latest tool results)/i,
    /(?:最终回答不要写|Final answer format|工具细节留在折叠过程|Keep tool details folded)/i
  ];
  return patterns.filter((pattern) => pattern.test(compact)).length >= 2;
}

function isProcessProtocolLeakLine(line: string): boolean {
  if (!line) return false;
  return /^(?:工具协议|Tool protocol|动作格式|Tool format|动作|Supported action types?|精确|路线例|Routes?|入口|Entry points?|Skill\/经验路由|记忆\/规则\/偏好|自我优化|信息顺序|OB 插件能力|Vault 写入权限规则|紧凑路由|Payload policy|Access mode|Final answer format|Decide and produce the next response now|Original user request|Latest tool results|RAW SENT|RAW RECEIVED|SENT system|SENT contextText|SENT turn prompt|SENT actual user inputText|Actual API call audit|Model exchange raw contents|requestBody|responseJson|responseText|responseShape|tool_choice|prompt_cache_key)\b[:：]?/i.test(line)
    || /^[-*]\s+(?:If more work can advance|Keep the final answer|Do not output a plan|For a generic create-file|如果还能继续|只写真实存在|不要列读取文件)/i.test(line);
}

function emptyMessageDisplay(content: string): MessageDisplay {
  return { visibleContent: content, runStatsText: "", hiddenToolBlocks: [], hasProcessFold: false, processOnly: false };
}

function isProgressMessage(content: string): boolean {
  return content.includes(PROGRESS_STEP_MARKER);
}

function isLegacyProgressStatusMessage(content: string): boolean {
  const normalized = content.replace(/<!--[\s\S]*?-->/g, "").replace(/\s+/g, "");
  return normalized.includes("执行中·")
    || normalized.includes("已执行·")
    || normalized.includes("工具反馈：")
    || normalized.includes("工具执行结果：")
    || normalized.includes("正在根据工具结果继续")
    || normalized.includes("模型生成中")
    || normalized.includes("正在准备上下文")
    || (/^(?:执行中|已执行)[：:]/.test(normalized) && /(?:目的[：:]|做法[：:]|改动文件|字数发送|tokens?发送|耗时)/i.test(normalized));
}

function isPromptishProgressNoteLine(line: string): boolean {
  const text = line.replace(/\s+/g, " ").trim();
  if (!text || text.length > 220) return false;
  return /正在准备本轮最小必要上下文|Preparing the smallest useful context|模型正在基于当前证据生成|The model is generating an answer|正在根据最新工具结果继续推进|Continuing from the latest tool result|正在推进当前任务的一个可追溯步骤|Advancing one traceable step|这一步失败了；错误会保留在过程记录里|This step failed; the error is kept in the process record|^(?:过程详情|工具结果|工具反馈|等待工具结果|继续处理|process details?|tool results?|waiting for tool results?)$|^(?:正在)?根据(?:最新)?(?:工具)?结果继续(?:推进|处理)?[。.!！]?$|^(?:当前状态不足以|没有可展示(?:的)?最终回答|任务(?:仍在|正在)后台|后台(?:正在|仍在))/i.test(text);
}

function isToolFeedbackMessage(content: string): boolean {
  return content.includes(TOOL_FEEDBACK_MARKER_PREFIX);
}

function messageOutlineText(content: string): string {
  const display = prepareMessageDisplay(redactSensitiveText(content));
  const text = (display.visibleContent || display.hiddenToolBlocks[0]?.title || content)
    .replace(/<!--[\s\S]*?-->/g, "")
    .replace(/<details>[\s\S]*?<\/details>/gi, " ")
    .replace(/```[\s\S]*?```/g, " ")
    .replace(/[#>*_[\]()`-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  return trimContext(text, 180);
}

function foldedBlockTitle(lang: string, body: string): string {
  if (lang === "cancip-action" || /^\{\s*"actions"\s*:/.test(body)) return "cancip-action";
  if (["bash", "sh", "zsh", "shell", "powershell", "ps1", "cmd", "bat", "terminal", "console"].includes(lang)) return lang || "command";
  if (lang) return lang;
  return body.startsWith("{") ? "json" : "details";
}

function foldInlineDetails(content: string, hiddenToolBlocks: FoldedMessageBlock[]): string {
  return content.replace(/<details>\s*<summary>([\s\S]*?)<\/summary>([\s\S]*?)<\/details>/gi, (_full, summary: string, body: string) => {
    const cleanSummary = summary.replace(/<[^>]+>/g, "").trim() || "details";
    const cleanBody = body.trim();
    if (cleanBody) hiddenToolBlocks.push({ title: cleanSummary, content: cleanBody });
    return "\n\n";
  });
}

function redactSensitiveText(input: string): string {
  if (!input) return input;
  let redacted = input.replace(/sk-[A-Za-z0-9_-]{12,}/g, "sk-***REDACTED***");
  redacted = redacted.replace(/ghp_[A-Za-z0-9_]{12,}/g, "ghp_***REDACTED***");
  redacted = redacted.replace(/github_pat_[A-Za-z0-9_]{12,}/g, "github_pat_***REDACTED***");
  redacted = redacted.replace(/AKIA[0-9A-Z]{16}/g, "AKIA***REDACTED***");
  redacted = redacted.replace(/(["']?(?:apiKey|githubToken|token|accessToken|secret|password)["']?\s*:\s*["'])[^"']+(["'])/gi, "$1***REDACTED***$2");
  redacted = redacted.replace(/(-----BEGIN (?:RSA |EC |OPENSSH )?PRIVATE KEY-----)[\s\S]*?(-----END (?:RSA |EC |OPENSSH )?PRIVATE KEY-----)/gi, "$1\n***REDACTED***\n$2");
  redacted = redacted.replace(/(\b(?:api[_-]?key|github[_-]?token|access[_-]?token|refresh[_-]?token|auth[_-]?token|client[_-]?secret|password|passwd|secret|authorization)\b\s*[:=]\s*["']?)([^\s,"'};]+)/gi, "$1***REDACTED***");
  redacted = redacted.replace(/(\bBearer\s+)[A-Za-z0-9._~+/-]{12,}/gi, "$1***REDACTED***");
  redacted = redacted.replace(/([?&](?:api[_-]?key|token|access[_-]?token|secret|password)=)[^&#\s]+/gi, "$1***REDACTED***");
  return redacted;
}

function cleanTtsText(input: string): string {
  const redacted = redactSensitiveText(input);
  const display = prepareMessageDisplay(redacted);
  const source = display.visibleContent.trim() || redacted;
  return trimContext(
    source
      .replace(/<!--[\s\S]*?-->/g, " ")
      .replace(/```[\s\S]*?```/g, " ")
      .replace(/`([^`]+)`/g, "$1")
      .replace(/<style[\s\S]*?<\/style>/gi, " ")
      .replace(/<script[\s\S]*?<\/script>/gi, " ")
      .replace(/<[^>]+>/g, " ")
      .replace(/!\[[^\]]*]\([^)]+\)/g, " ")
      .replace(/\[([^\]]+)]\([^)]+\)/g, "$1")
      .replace(/\[\[([^\]|]+)(?:\|([^\]]+))?]]/g, (_full, path: string, alias: string | undefined) => alias || path)
    .replace(/^[\s>*#+=[\]_|-]+/gm, "")
      .replace(/[ \t]{2,}/g, " ")
      .replace(/\n{3,}/g, "\n\n")
      .trim(),
    30000
  );
}

function extractVisibleRenderedText(root: HTMLElement): string {
  const ignored = new Set(["SCRIPT", "STYLE", "NOSCRIPT", "SVG", "CANVAS", "BUTTON", "INPUT", "TEXTAREA", "SELECT"]);
  const chunks: string[] = [];
  const view = root.ownerDocument.defaultView ?? activeDocument.defaultView;
  const walk = (node: Node): void => {
    if (node.nodeType === Node.TEXT_NODE) {
      const text = node.textContent?.replace(/\s+/g, " ").trim();
      if (text) chunks.push(text);
      return;
    }
    if (!view || !node.instanceOf(view.HTMLElement)) return;
    if (ignored.has(node.tagName)) return;
    const style = view.getComputedStyle(node);
    if (style.display === "none" || style.visibility === "hidden") return;
    if (node.matches("li.task-list-item, .task-list-item")) {
      chunks.push(`${isRenderedTaskChecked(node) ? "已完成" : "待办"} `);
    }
    for (const child of Array.from(node.childNodes)) walk(child);
    if (["P", "DIV", "LI", "TR", "BLOCKQUOTE", "H1", "H2", "H3", "H4", "H5", "H6", "PRE", "TABLE"].includes(node.tagName)) {
      chunks.push("\n");
    }
  };
  walk(root);
  return chunks
    .join(" ")
    .replace(/[ \t]*\n[ \t]*/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

type TtsViewportReadableItem = {
  element: HTMLElement;
  rect: DOMRect;
  readable: boolean;
  visible: boolean;
  text: string;
};

function markdownViewportReadableItems(root: HTMLElement, viewport = ttsReadableViewport(root)): TtsViewportReadableItem[] {
  const selectors = [
    ".markdown-preview-view h1",
    ".markdown-preview-view h2",
    ".markdown-preview-view h3",
    ".markdown-preview-view h4",
    ".markdown-preview-view h5",
    ".markdown-preview-view h6",
    ".markdown-preview-view p",
    ".markdown-preview-view li",
    ".markdown-preview-view blockquote",
    ".markdown-preview-view pre",
    ".markdown-preview-view table",
    ".markdown-rendered h1",
    ".markdown-rendered h2",
    ".markdown-rendered h3",
    ".markdown-rendered h4",
    ".markdown-rendered h5",
    ".markdown-rendered h6",
    ".markdown-rendered p",
    ".markdown-rendered li",
    ".markdown-rendered blockquote",
    ".markdown-rendered pre",
    ".markdown-rendered table",
    ".cm-line",
    "p",
    "li",
    "blockquote",
    "pre",
    "h1",
    "h2",
    "h3",
    "h4",
    "h5",
    "h6",
    "table",
    "tr"
  ].join(",");
  let items: TtsViewportReadableItem[] = Array.from(root.querySelectorAll<HTMLElement>(selectors))
    .map((element) => {
      const rect = element.getBoundingClientRect();
      const readable = rect.bottom >= viewport.top && rect.height > 0 && rect.width > 0;
      const visible = readable && rect.top <= viewport.bottom && rect.bottom >= viewport.top;
      const text = renderedElementReadableText(element).replace(/\s+/g, " ").trim();
      return { element, rect, readable, visible, text };
    })
    .filter((item) => item.readable && item.text && !item.element.closest(".obcc-tts-floating, .obcc-view-tts-action, script, style, textarea, input, button"))
    .sort((a, b) => a.rect.top - b.rect.top || a.rect.left - b.rect.left);
  return keepTopLevelReadableItems(items);
}

function extractVisibleMarkdownViewportText(root: HTMLElement, maxChars = TTS_CAPTURE_MAX_CHARS): string {
  const viewport = ttsReadableViewport(root);
  let items = markdownViewportReadableItems(root, viewport);
  const startIndex = viewportStartIndex(items, viewport.top);
  if (startIndex > 0) items = items.slice(startIndex);
  const chunks: string[] = [];
  let total = 0;
  let lastNormalized = "";
  for (let index = 0; index < items.length; index += 1) {
    const item = items[index];
    const text = index === 0 ? visibleElementTextFromViewportTop(item.element, viewport.top, item.text) : item.text;
    const normalized = normalizeTtsHighlightText(text);
    if (!normalized || normalized === lastNormalized) continue;
    chunks.push(text);
    lastNormalized = normalized;
    total += text.length;
    if (total >= maxChars) break;
  }
  return chunks
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

function innermostReadableRoots(roots: HTMLElement[]): HTMLElement[] {
  return roots.filter((root) => {
    for (const other of roots) {
      if (other === root) continue;
      if (root.contains(other)) return false;
    }
    return true;
  });
}

function pdfViewportReadableItems(root: HTMLElement, viewport = ttsReadableViewport(root)): TtsViewportReadableItem[] {
  let pdfSpans = Array.from(root.querySelectorAll<HTMLElement>(".textLayer span"));
  if (!pdfSpans.length && root.hasClass("textLayer")) pdfSpans = Array.from(root.querySelectorAll<HTMLElement>("span"));
  if (!pdfSpans.length) pdfSpans = Array.from(root.querySelectorAll<HTMLElement>(".page span, [data-page-number] span, span[role='presentation']"));
  return pdfSpans
    .map((element) => {
      const rect = element.getBoundingClientRect();
      const readable = rect.bottom >= viewport.top && rect.height > 0 && rect.width > 0;
      const visible = readable && rect.top <= viewport.bottom && rect.bottom >= viewport.top;
      const text = (element.innerText || element.textContent || "").replace(/\s+/g, " ").trim();
      return { element, rect, readable, visible, text };
    })
    .filter((item) => item.readable && item.text && !item.element.closest(".obcc-tts-floating, .obcc-view-tts-action, script, style, textarea, input, button"))
    .sort((a, b) => a.rect.top - b.rect.top || a.rect.left - b.rect.left);
}

function extractVisiblePdfViewportText(root: HTMLElement, maxChars = TTS_CAPTURE_MAX_CHARS): string {
  const viewport = ttsReadableViewport(root);
  const spans = pdfViewportReadableItems(root, viewport);
  const startIndex = viewportStartIndex(spans, viewport.top);
  const readableSpans = (startIndex > 0 ? spans.slice(startIndex) : spans).filter((item) => item.rect.bottom >= viewport.top - 2);
  if (readableSpans.length) return trimContext(normalizePdfTtsText(mergePdfTextLayerSpans(readableSpans)), maxChars);
  return extractVisibleMarkdownViewportText(root, maxChars);
}

function ttsReadableViewport(root?: HTMLElement): { top: number; bottom: number } {
  const visual = window.visualViewport;
  const rawTop = Math.max(0, visual?.offsetTop ?? 0);
  const rawBottom = rawTop + Math.max(160, visual?.height ?? window.innerHeight ?? 800);
  const viewContent = ttsReadableScrollContainer(root);
  const viewRect = viewContent?.getBoundingClientRect();
  const top = Math.max(rawTop, viewRect && viewRect.height > 0 ? viewRect.top : rawTop) + 2;
  const bottom = Math.max(top + 120, Math.min(rawBottom, viewRect && viewRect.height > 0 ? viewRect.bottom : rawBottom));
  return { top, bottom };
}

function ttsReadableScrollContainer(root?: HTMLElement): HTMLElement | null {
  const preferred = root?.closest<HTMLElement>(".markdown-preview-view, .cm-scroller, .pdf-container, .pdf-viewer, .pdfViewer, .view-content, .workspace-leaf-content");
  if (preferred && preferred.getBoundingClientRect().height > 120) return preferred;
  let node: HTMLElement | null = root ?? null;
  while (node && node !== (root?.ownerDocument ?? activeDocument).body) {
    const rect = node.getBoundingClientRect();
    const style = window.getComputedStyle(node);
    const scrollable = /(auto|scroll|overlay)/.test(style.overflowY) || node.scrollHeight > node.clientHeight + 8;
    if (scrollable && rect.height > 120) return node;
    node = node.parentElement;
  }
  return root?.closest<HTMLElement>(".view-content, .workspace-leaf-content") ?? null;
}

function viewportStartIndex<T extends { rect: DOMRect; visible?: boolean }>(items: T[], viewportTop = 0): number {
  if (!items.length) return 0;
  const top = Math.max(0, viewportTop);
  const crossingTop = items.findIndex((item) => item.rect.bottom >= top - 2 && item.visible !== false);
  if (crossingTop >= 0) return crossingTop;
  const visibleBelowTop = items.findIndex((item) => item.rect.top >= top - 2 && item.visible !== false);
  if (visibleBelowTop >= 0) return visibleBelowTop;
  return 0;
}

function scrollTtsHighlightIntoView(element: HTMLElement): void {
  const viewport = ttsReadableViewport(element);
  const rect = element.getBoundingClientRect();
  const viewportHeight = Math.max(120, viewport.bottom - viewport.top);
  const viewportCenter = viewport.top + viewportHeight / 2;
  const elementCenter = rect.top + Math.max(1, rect.height) / 2;
  const centerSlack = Math.max(18, Math.min(72, viewportHeight * 0.16));
  const safelyVisible = rect.top >= viewport.top + 10 && rect.bottom <= viewport.bottom - 10;
  if (safelyVisible && Math.abs(elementCenter - viewportCenter) <= centerSlack) return;
  const scrollContainer = ttsReadableScrollContainer(element);
  if (scrollContainer && scrollContainer.scrollHeight > scrollContainer.clientHeight + 4) {
    const maxTop = Math.max(0, scrollContainer.scrollHeight - scrollContainer.clientHeight);
    const targetTop = Math.max(0, Math.min(maxTop, scrollContainer.scrollTop + elementCenter - viewportCenter));
    scrollContainer.scrollTo({ top: targetTop, behavior: "smooth" });
    return;
  }
  element.scrollIntoView({ block: "center", inline: "nearest", behavior: "smooth" });
}

function isProgrammaticProgressHeadline(line: string): boolean {
  const text = line.replace(/\s+/g, " ").trim();
  return /^(?:执行中|已执行|失败|running|executed|failed)\s*[·:：-]/i.test(text)
    && /(?:耗时|elapsed)\s*[^·\s]+/i.test(text);
}

function mergePdfTextLayerSpans(items: Array<{ rect: DOMRect; text: string }>): string {
  const lines: Array<{ top: number; height: number; items: Array<{ rect: DOMRect; text: string }> }> = [];
  for (const item of items) {
    const height = Math.max(1, item.rect.height || 12);
    const tolerance = Math.max(2, Math.min(8, height * 0.45));
    let line = lines.find((candidate) => Math.abs(candidate.top - item.rect.top) <= tolerance);
    if (!line) {
      line = { top: item.rect.top, height, items: [] };
      lines.push(line);
    }
    line.items.push(item);
  }
  lines.sort((a, b) => a.top - b.top);
  const chunks: string[] = [];
  for (const line of lines) {
    line.items.sort((a, b) => a.rect.left - b.rect.left);
    const pieces: string[] = [];
    let previous: { rect: DOMRect; text: string } | null = null;
    for (const item of line.items) {
      if (previous) {
        const gap = item.rect.left - previous.rect.right;
        if (gap > Math.max(2, line.height * 0.35) && shouldInsertTtsSpace(previous.text, item.text)) pieces.push(" ");
      }
      pieces.push(item.text);
      previous = item;
    }
    const text = pieces.join("").replace(/\s{2,}/g, " ").trim();
    if (text) chunks.push(text);
  }
  return chunks.join("\n").replace(/\n{3,}/g, "\n\n").trim();
}

function normalizePdfTtsText(input: string): string {
  const normalized = normalizeExtractedText(input);
  if (!normalized) return "";
  return normalized
    .split(/\n{2,}/)
    .map((paragraph) => normalizePdfTtsParagraph(paragraph))
    .filter(Boolean)
    .join("\n\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function normalizePdfTtsParagraph(paragraph: string): string {
  const lines = paragraph
    .split(/\n+/)
    .map((line) => line.replace(/[ \t]{2,}/g, " ").trim())
    .filter(Boolean);
  const blocks: string[] = [];
  let buffer = "";
  const pushBuffer = () => {
    const text = buffer.trim();
    if (text) blocks.push(text);
    buffer = "";
  };
  for (const line of lines) {
    if (isPdfStandaloneLine(line)) {
      pushBuffer();
      blocks.push(line);
      continue;
    }
    if (!buffer) {
      buffer = line;
      continue;
    }
    if (shouldJoinPdfTtsLine(buffer, line)) {
      buffer = joinPdfTtsLine(buffer, line);
    } else {
      pushBuffer();
      buffer = line;
    }
  }
  pushBuffer();
  return blocks.join("\n").trim();
}

function shouldJoinPdfTtsLine(left: string, right: string): boolean {
  const previous = left.trim();
  const next = right.trim();
  if (!previous || !next) return false;
  if (isPdfStandaloneLine(previous) || isPdfStandaloneLine(next)) return false;
  if (/[。！？!?；;]$/.test(previous)) return false;
  if (/^[）)\]】》」』”’]/.test(next)) return true;
  if (/^[,，.。:：;；!?！？、]/.test(next)) return true;
  if (looksLikePdfTableLine(previous) || looksLikePdfTableLine(next)) return false;
  if (previous.length <= 18 && next.length <= 18 && /^[A-Z0-9]/.test(next) && /[A-Za-z0-9]$/.test(previous)) return false;
  return true;
}

function joinPdfTtsLine(left: string, right: string): string {
  const previous = left.trim();
  const next = right.trim();
  if (/-$/.test(previous) && /^[A-Za-z]/.test(next)) return `${previous.slice(0, -1)}${next}`;
  return shouldInsertTtsSpace(previous, next) ? `${previous} ${next}` : `${previous}${next}`;
}

function isPdfStandaloneLine(line: string): boolean {
  const text = line.trim();
  if (!text) return false;
  if (/^(?:[-*+]|[0-9]+[.)、]|[一二三四五六七八九十]+[、.．])\s+/.test(text)) return true;
  if (/^(?:第[一二三四五六七八九十0-9]+[章节]|Chapter\s+\d+)\b/i.test(text)) return true;
  if (looksLikePdfTableLine(text)) return true;
  return false;
}

function looksLikePdfTableLine(line: string): boolean {
  if (line.includes("|") || line.includes("\t")) return true;
  const digitGroups = line.match(/\b\d+(?:[.,:：/-]\d+)*\b/g)?.length ?? 0;
  const asciiGroups = line.match(/[A-Za-z0-9]{1,16}/g)?.length ?? 0;
  return digitGroups >= 3 && asciiGroups >= 5;
}

function keepTopLevelReadableItems<T extends { element: HTMLElement; text: string }>(items: T[]): T[] {
  return items.filter((item) => {
    const keepParent = item.element.matches("pre, li.task-list-item, .task-list-item");
    if (keepParent) return true;
    const directText = normalizeTtsHighlightText(readableDirectText(item.element));
    for (const other of items) {
      if (other === item) continue;
      if (!other.text) continue;
      if (item.element.contains(other.element) && !directText) return false;
      if (!other.element.contains(item.element)) continue;
      if (other.element.matches("li.task-list-item, .task-list-item")) return false;
    }
    return true;
  });
}

function readableDirectText(element: HTMLElement): string {
  const chunks: string[] = [];
  for (const child of Array.from(element.childNodes)) {
    if (child.nodeType === Node.TEXT_NODE) chunks.push(child.textContent ?? "");
  }
  return chunks.join(" ").replace(/\s+/g, " ").trim();
}

function shouldInsertTtsSpace(left: string, right: string): boolean {
  const a = left.slice(-1);
  const b = right.slice(0, 1);
  if (!a || !b) return false;
  if (/[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}]/u.test(a) || /[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}]/u.test(b)) return false;
  return /[\p{L}\p{N}]/u.test(a) && /[\p{L}\p{N}]/u.test(b);
}

function getWindowSelectionText(): string {
  try {
    const activeSelection = activeDocument.getSelection?.()?.toString().trim() ?? "";
    if (activeSelection) return activeSelection;
    return window.getSelection?.()?.toString().trim() ?? "";
  } catch {
    return "";
  }
}

function normalizeTtsHighlightText(input: string): string {
  return input
    .replace(/\s+/g, "")
    .replace(/[，。！？；：、,.!?;:"'“”‘’（）()[\]【】{}<>《》—_~`|/\\-]/g, "")
    .trim();
}

function findBestNormalizedNeedleMatch(haystack: string, needle: string, preferShortFallback = false, cursor = 0): { needle: string; index: number } | null {
  if (!needle) return null;
  const directIndex = closestStringIndex(haystack, needle, cursor);
  if (directIndex >= 0) return { needle, index: directIndex };
  const candidates: string[] = [];
  const lengths = preferShortFallback ? [96, 64, 40, 24, 16, 8, 4, 3] : [96, 64, 40, 24];
  for (const length of lengths) {
    if (needle.length > length) candidates.push(needle.slice(0, length));
  }
  for (const candidate of candidates) {
    if (candidate.length < 2) continue;
    const index = closestStringIndex(haystack, candidate, cursor);
    if (index >= 0) return { needle: candidate, index };
  }
  return null;
}

function closestStringIndex(haystack: string, needle: string, cursor = 0): number {
  if (!needle) return -1;
  let best = -1;
  let bestDistance = Number.POSITIVE_INFINITY;
  const safeCursor = Math.max(0, Math.min(haystack.length, Number.isFinite(cursor) ? cursor : 0));
  let index = haystack.indexOf(needle);
  while (index >= 0) {
    const distance = Math.abs(index - safeCursor);
    if (distance < bestDistance) {
      best = index;
      bestDistance = distance;
      if (distance === 0) break;
    }
    index = haystack.indexOf(needle, index + Math.max(1, needle.length));
  }
  return best;
}

function renderedElementReadableText(element: HTMLElement): string {
  const raw = element.innerText || element.textContent || "";
  if (element.matches("li.task-list-item, .task-list-item")) {
    return `${isRenderedTaskChecked(element) ? "已完成" : "待办"} ${raw}`;
  }
  return raw;
}

function visibleElementTextFromViewportTop(element: HTMLElement, viewportTop: number, fallbackText = renderedElementReadableText(element)): string {
  const text = fallbackText.trim();
  const offset = elementHiddenPrefixOffset(element, viewportTop, text);
  return offset > 0 ? text.slice(offset).trimStart() : text;
}

function normalizedElementHiddenPrefixLength(element: HTMLElement, viewportTop: number): number {
  const text = renderedElementReadableText(element).trim();
  const offset = elementHiddenPrefixOffset(element, viewportTop, text);
  return normalizeTtsHighlightText(offset > 0 ? text.slice(0, offset) : "").length;
}

function elementHiddenPrefixOffset(element: HTMLElement, viewportTop: number, text = renderedElementReadableText(element).trim()): number {
  if (!text) return 0;
  const rect = element.getBoundingClientRect();
  if (rect.height <= 0 || rect.bottom <= viewportTop || rect.top >= viewportTop) return 0;
  const hiddenRatio = Math.max(0, Math.min(0.95, (viewportTop - rect.top) / rect.height));
  if (hiddenRatio <= 0.03) return 0;
  const lineHeight = readableLineHeight(element);
  const estimatedLines = Math.max(1, Math.round(rect.height / lineHeight));
  const hiddenLines = Math.max(0, Math.floor((viewportTop - rect.top) / lineHeight));
  if (hiddenLines <= 0) return 0;
  const lines = text.split(/\r?\n/);
  if (lines.length > 1 && hiddenLines < lines.length) {
    return lines.slice(0, hiddenLines).join("\n").length + 1;
  }
  return Math.max(0, Math.min(text.length - 1, Math.floor(text.length * Math.min(0.95, hiddenLines / estimatedLines))));
}

function readableLineHeight(element: HTMLElement): number {
  const style = window.getComputedStyle(element);
  const numeric = Number.parseFloat(style.lineHeight);
  if (Number.isFinite(numeric) && numeric > 4) return numeric;
  const fontSize = Number.parseFloat(style.fontSize);
  return Number.isFinite(fontSize) && fontSize > 4 ? fontSize * 1.45 : 20;
}

function isRenderedTaskChecked(element: HTMLElement): boolean {
  return Boolean(element.querySelector<HTMLInputElement>("input[type='checkbox']")?.checked)
    || element.getAttribute("data-task") === "x"
    || element.getAttribute("data-task") === "X"
    || element.hasClass("is-checked")
    || element.hasClass("task-list-item-checkbox-checked");
}

function normalizedTextWithSourceOffsets(input: string): { text: string; offsets: number[] } {
  let text = "";
  const offsets: number[] = [];
  for (let index = 0; index < input.length; index += 1) {
    const normalized = normalizeTtsHighlightText(input[index] ?? "");
    if (!normalized) continue;
    text += normalized;
    offsets.push(index);
  }
  return { text, offsets };
}

function sliceTtsTextFromAnchorToEnd(fullText: string, anchorText: string, maxChars: number, cursor = 0): string {
  const full = fullText.trim();
  const anchor = normalizeTtsHighlightText(anchorText).slice(0, 240);
  if (!full) return trimContext(anchorText, maxChars);
  if (anchor.length >= 3) {
    const normalizedFull = normalizedTextWithSourceOffsets(full);
    const match = findBestNormalizedNeedleMatch(normalizedFull.text, anchor, true, Math.max(0, cursor));
    if (match) {
      const offset = normalizedFull.offsets[match.index] ?? 0;
      return trimContext(full.slice(offset), maxChars);
    }
  }
  return trimContext(anchorText || full, maxChars);
}

function offsetToEditorPosition(source: string, offset: number): { line: number; ch: number } {
  const safeOffset = Math.max(0, Math.min(source.length, offset));
  let line = 0;
  let lineStart = 0;
  for (let index = 0; index < safeOffset; index += 1) {
    if (source.charCodeAt(index) === 10) {
      line += 1;
      lineStart = index + 1;
    }
  }
  return { line, ch: safeOffset - lineStart };
}

function responseHeaderValue(headers: Record<string, string>, name: string): string {
  const lowerName = name.toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (key.toLowerCase() === lowerName) return value.toLowerCase();
  }
  return "";
}

async function blobUrlToArrayBuffer(url: string): Promise<ArrayBuffer> {
  const response = await XMLHttpRequestArrayBuffer(url);
  return response;
}

function XMLHttpRequestArrayBuffer(url: string): Promise<ArrayBuffer> {
  return new Promise((resolve, reject) => {
    const request = new XMLHttpRequest();
    request.open("GET", url);
    request.responseType = "arraybuffer";
    request.onload = () => {
      if (request.status === 0 || (request.status >= 200 && request.status < 300)) {
        resolve(request.response as ArrayBuffer);
      } else {
        reject(new Error(`audio fallback request failed: HTTP ${request.status}`));
      }
    };
    request.onerror = () => reject(new Error("audio fallback request failed"));
    request.send();
  });
}

function splitTtsText(input: string, targetLength = 420, preferSentenceParts = false): string[] {
  const normalized = input.replace(/\s+\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();
  if (!normalized) return [];
  const parts: string[] = [];
  const maxLength = Math.max(120, targetLength);
  const hardLength = Math.max(maxLength + 120, Math.floor(maxLength * 1.8));
  let buffer = "";
  const push = () => {
    const text = buffer.trim();
    if (text) parts.push(text);
    buffer = "";
  };
  for (const segment of splitTtsTextSegments(normalized)) {
    const next = segment.text.trim();
    if (!next) continue;
    if ((preferSentenceParts || segment.forcedBreak) && next.length <= hardLength) {
      push();
      parts.push(next);
      continue;
    }
    if ((buffer + "\n" + next).length > maxLength) push();
    if (next.length > hardLength) {
      push();
      let rest = next;
      while (rest) {
        const take = ttsLongSegmentTakeLength(rest, maxLength, hardLength);
        parts.push(rest.slice(0, take).trim());
        rest = rest.slice(take).trimStart();
      }
      continue;
    }
    buffer = buffer ? `${buffer}\n${next}` : next;
  }
  push();
  return parts.slice(0, 600);
}

function makeTtsPartPlan(input: string, provider: TtsProvider | undefined, targetLength: number, spokenTransform?: (part: string) => string): TtsPartPlan {
  const usePrimeFastPlan = provider === "builtin-prime-tts" || !provider;
  const playTarget = usePrimeFastPlan ? primeTtsFastTargetLength(targetLength) : targetLength;
  const displayTarget = usePrimeFastPlan
    ? Math.max(220, Math.min(640, playTarget * 4))
    : Math.max(260, Math.min(900, targetLength * 3));
  const sourceDisplayParts = usePrimeFastPlan
    ? splitPrimeTtsDisplayText(input)
    : splitTtsText(input, displayTarget, true);
  const displayParts: string[] = [];
  const playParts: string[] = [];
  const displayIndexByPlayIndex: number[] = [];
  const makePlayChunks = (text: string) => usePrimeFastPlan
    ? splitPrimeTtsMicroPlayText(text, playTarget)
    : splitTtsText(text, targetLength, false);
  for (const display of sourceDisplayParts) {
    const spokenDisplay = spokenTransform ? spokenTransform(display) : display;
    const spokenChunks = makePlayChunks(spokenDisplay).filter(Boolean);
    const chunks = spokenChunks.length ? spokenChunks : [spokenDisplay || display];
    const displayIndex = displayParts.length;
    displayParts.push(display);
    for (let chunkIndex = 0; chunkIndex < chunks.length; chunkIndex += 1) {
      playParts.push(chunks[chunkIndex]);
      displayIndexByPlayIndex.push(displayIndex);
      if (playParts.length >= TTS_MAX_PARTS) return { playParts, displayParts, displayIndexByPlayIndex };
    }
  }
  return {
    playParts: playParts.length ? playParts : displayParts,
    displayParts: displayParts.length ? displayParts : playParts,
    displayIndexByPlayIndex: displayIndexByPlayIndex.length ? displayIndexByPlayIndex : playParts.map((_, index) => index)
  };
}

function mapTtsPlayPartsToDisplayParts(playParts: string[], displayParts: string[]): number[] {
  const normalizedDisplays = displayParts.map((part) => normalizeTtsHighlightText(part));
  let cursor = 0;
  return playParts.map((part) => {
    const needle = normalizeTtsHighlightText(part);
    if (!needle) return Math.max(0, Math.min(displayParts.length - 1, cursor));
    for (let attempt = 0; attempt < normalizedDisplays.length; attempt += 1) {
      const index = (cursor + attempt) % normalizedDisplays.length;
      if (normalizedDisplays[index]?.includes(needle) || needle.includes(normalizedDisplays[index] ?? "\u0000")) {
        cursor = index;
        return index;
      }
    }
    return Math.max(0, Math.min(displayParts.length - 1, cursor));
  });
}

function ttsLongSegmentTakeLength(text: string, targetLength: number, hardLength: number): number {
  if (text.length <= hardLength) return text.length;
  const min = Math.max(40, Math.floor(targetLength * 0.7));
  const hard = Math.min(text.length, hardLength);
  for (let index = hard - 1; index >= min; index -= 1) {
    if ("。！？；.!?;".includes(text[index] ?? "")) return index + 1;
  }
  for (let index = hard - 1; index >= min; index -= 1) {
    if ((text[index] ?? "") === "\n") return index + 1;
  }
  for (let index = hard - 1; index >= min; index -= 1) {
    if ("，,、：:".includes(text[index] ?? "")) return index + 1;
  }
  return Math.min(text.length, targetLength);
}

function primeTtsFastTargetLength(configured: number): number {
  const numeric = Number(configured) || 0;
  if (!numeric || numeric >= 500) return PRIME_TTS_FAST_DEFAULT_CHARS;
  return Math.max(64, Math.min(150, Math.floor(numeric)));
}

function splitPrimeTtsDisplayText(input: string): string[] {
  const normalized = normalizeTtsInputText(input);
  if (!normalized) return [];
  const parts: string[] = [];
  for (const segment of splitTtsTextSegments(normalized)) {
    let rest = segment.text.trim();
    while (rest && parts.length < TTS_MAX_PARTS) {
      const take = primeTtsDisplayTakeLength(rest);
      const part = rest.slice(0, take).trim();
      if (part) parts.push(part);
      rest = rest.slice(take).trimStart();
    }
    if (parts.length >= TTS_MAX_PARTS) break;
  }
  return parts.filter(Boolean);
}

function primeTtsDisplayTakeLength(text: string): number {
  if (text.length <= PRIME_TTS_DISPLAY_MAX_CHARS) return text.length;
  const min = Math.max(8, Math.floor(PRIME_TTS_DISPLAY_TARGET_CHARS * 0.55));
  const hard = Math.min(text.length, PRIME_TTS_DISPLAY_MAX_CHARS);
  for (let index = hard - 1; index >= min; index -= 1) {
    const char = text[index] ?? "";
    if ("。！？!?；;".includes(char) && isPrimeTtsStrongBreak(text, index)) return adjustPrimeTtsDisplayBoundary(text, index + 1, min, hard);
  }
  for (let index = hard - 1; index >= min; index -= 1) {
    if ((text[index] ?? "") === "\n") return adjustPrimeTtsDisplayBoundary(text, index + 1, min, hard);
  }
  for (let index = hard - 1; index >= min; index -= 1) {
    const char = text[index] ?? "";
    if ("，,、：:）)]】》」』”’\"'".includes(char) && isPrimeTtsSoftBreak(text, index)) return adjustPrimeTtsDisplayBoundary(text, index + 1, min, hard);
  }
  for (let index = hard - 1; index >= min; index -= 1) {
    if (/\s/.test(text[index] ?? "")) return adjustPrimeTtsDisplayBoundary(text, index + 1, min, hard);
  }
  return adjustPrimeTtsDisplayBoundary(text, Math.min(text.length, PRIME_TTS_DISPLAY_TARGET_CHARS), min, hard);
}

function adjustPrimeTtsDisplayBoundary(text: string, candidate: number, min: number, hard: number): number {
  const adjusted = adjustPrimeTtsTakeBoundary(text, candidate, min, hard);
  if (adjusted >= text.length) return text.length;
  const before = text[adjusted - 1] ?? "";
  const after = text[adjusted] ?? "";
  if (!isCjkChar(before) || !isCjkChar(after)) return adjusted;
  let runStart = adjusted - 1;
  while (runStart > 0 && isCjkChar(text[runStart - 1] ?? "")) runStart -= 1;
  let runEnd = adjusted;
  while (runEnd < text.length && isCjkChar(text[runEnd] ?? "")) runEnd += 1;
  const run = text.slice(runStart, runEnd);
  const tokens = splitPrimeTtsCjkRunTokens(run);
  let cursor = runStart;
  const boundaries: number[] = [];
  for (const token of tokens) {
    cursor += token.length;
    boundaries.push(cursor);
  }
  for (let index = boundaries.length - 1; index >= 0; index -= 1) {
    const boundary = boundaries[index];
    if (boundary <= adjusted && boundary >= min) return boundary;
  }
  for (const boundary of boundaries) {
    if (boundary > adjusted && boundary <= hard) return boundary;
  }
  return adjusted;
}

function splitPrimeTtsMicroPlayText(input: string, targetLength = PRIME_TTS_FAST_DEFAULT_CHARS): string[] {
  void targetLength;
  const text = normalizePrimeTtsMicroText(input);
  if (!text) return [];
  const parts: string[] = [];
  let buffer = "";
  const pushBuffer = (): void => {
    const part = buffer.trim();
    if (part && hasPrimeTtsReadableToken(part)) parts.push(part);
    buffer = "";
  };
  const pushHard = (value: string, maxLength = PRIME_TTS_MICRO_MAX_CHARS): void => {
    let rest = value.trim();
    while (rest) {
      const part = rest.slice(0, maxLength).trim();
      if (part && hasPrimeTtsReadableToken(part)) parts.push(part);
      rest = rest.slice(maxLength).trimStart();
    }
  };
  const appendToken = (token: string, maxLength = PRIME_TTS_MICRO_MAX_CHARS): void => {
    const clean = token.trim();
    if (!clean) return;
    if (clean.length > maxLength) {
      pushBuffer();
      pushHard(clean, maxLength);
      return;
    }
    const joinedLength = buffer.length + clean.length;
    if (!buffer) {
      buffer = clean;
    } else if (joinedLength <= Math.max(PRIME_TTS_MICRO_MAX_CHARS, maxLength) && (buffer.length < PRIME_TTS_MICRO_TARGET_CHARS || clean.length <= 2)) {
      buffer += clean;
    } else {
      pushBuffer();
      buffer = clean;
    }
    if (buffer.length >= PRIME_TTS_MICRO_TARGET_CHARS) pushBuffer();
  };
  const attachPunctuation = (punctuation: string): void => {
    if (!punctuation.trim()) return;
    if (buffer) {
      if (buffer.length + punctuation.length <= PRIME_TTS_MICRO_MAX_CHARS) buffer += punctuation;
      pushBuffer();
      return;
    }
    const lastIndex = parts.length - 1;
    if (lastIndex >= 0 && !/[,.?!;:，。？！；：、…]$/.test(parts[lastIndex] ?? "") && (parts[lastIndex] ?? "").length + punctuation.length <= PRIME_TTS_MICRO_MAX_CHARS) {
      parts[lastIndex] += punctuation;
    }
  };
  let index = 0;
  while (index < text.length && parts.length < TTS_MAX_PARTS) {
    const char = text[index] ?? "";
    if (/\s/.test(char)) {
      pushBuffer();
      index += 1;
      continue;
    }
    if (isPrimeTtsMicroPunctuation(char)) {
      attachPunctuation(normalizePrimeTtsMicroPunctuation(char));
      index += 1;
      continue;
    }
    if (isCjkChar(char)) {
      let end = index + 1;
      while (end < text.length && isCjkChar(text[end] ?? "")) end += 1;
      for (const token of splitPrimeTtsCjkRunTokens(text.slice(index, end))) appendToken(token);
      index = end;
      continue;
    }
    if (/\d/.test(char)) {
      let end = index + 1;
      while (end < text.length && /[\d.]/.test(text[end] ?? "")) end += 1;
      const token = normalizePrimeTtsMicroNumberToken(text.slice(index, end));
      for (const chunk of splitPrimeTtsMicroAsciiToken(token, PRIME_TTS_MICRO_MAX_CHARS)) appendToken(chunk);
      index = end;
      continue;
    }
    if (/[A-Za-z]/.test(char)) {
      let end = index + 1;
      while (end < text.length && /[A-Za-z']/.test(text[end] ?? "")) end += 1;
      const token = text.slice(index, end).replace(/^'+|'+$/g, "");
      pushBuffer();
      appendToken(normalizePrimeTtsEnglishToken(token), PRIME_TTS_LATIN_WORD_MAX_CHARS);
      pushBuffer();
      index = end;
      continue;
    }
    const punctuation = normalizePrimeTtsSpecialSymbolAsPunctuation(char);
    if (punctuation) attachPunctuation(punctuation);
    else pushBuffer();
    index += 1;
  }
  pushBuffer();
  return parts.filter(hasPrimeTtsReadableToken);
}

function splitPrimeTtsCjkRunTokens(run: string): string[] {
  if (!run) return [];
  return Array.from(run);
}

function normalizePrimeTtsMicroText(input: string): string {
  return normalizeTtsInputText(input)
    .replace(/(^|[^\w./\\-])0+(\d+(?:\.\d+)?)(?=$|[^\w./\\-])/g, (_match, prefix: string, number: string) => {
      return `${prefix}${normalizePrimeTtsMicroNumberToken(number)}`;
    });
}

function normalizePrimeTtsMicroNumberToken(token: string): string {
  if (!token) return token;
  if (token.includes(".")) {
    const [integer, fraction = ""] = token.split(".");
    const normalizedInteger = integer.replace(/^0+(?=\d)/, "") || "0";
    return fraction ? `${normalizedInteger}.${fraction}` : normalizedInteger;
  }
  return token.replace(/^0+(?=\d)/, "") || "0";
}

function splitPrimeTtsMicroAsciiToken(token: string, maxLength: number): string[] {
  const clean = token.trim();
  if (!clean) return [];
  if (clean.length <= maxLength) return [clean];
  const parts: string[] = [];
  for (let index = 0; index < clean.length; index += maxLength) {
    parts.push(clean.slice(index, index + maxLength));
  }
  return parts;
}

function normalizePrimeTtsEnglishToken(token: string): string {
  return token.replace(/^'+|'+$/g, "").trim();
}

function splitPrimeTtsMicroLatinToken(token: string): string[] {
  const clean = token.replace(/^'+|'+$/g, "").trim();
  if (!clean) return [];
  if (clean.length <= PRIME_TTS_LATIN_WORD_MAX_CHARS) return [clean];
  const parts: string[] = [];
  let index = 0;
  while (index < clean.length) {
    const hard = Math.min(clean.length, index + PRIME_TTS_LATIN_WORD_MAX_CHARS);
    let take = hard;
    for (let cursor = hard; cursor > index + 1; cursor -= 1) {
      const before = clean[cursor - 1] ?? "";
      const after = clean[cursor] ?? "";
      if (/[aeiouy]/i.test(before) && after && /[bcdfghjklmnpqrstvwxyz]/i.test(after)) {
        take = cursor;
        break;
      }
    }
    const part = clean.slice(index, take);
    if (part) parts.push(part);
    index = take;
  }
  return parts;
}

function isPrimeTtsMicroPunctuation(char: string): boolean {
  return !!normalizePrimeTtsMicroPunctuation(char);
}

function normalizePrimeTtsMicroPunctuation(char: string): string {
  if (!char || isPrimeTtsIgnorableSymbolChar(char)) return "";
  if (char === "…" || char === "⋯" || char === "⋮") return "。";
  if (/[。.!！?？]/.test(char)) return char;
  if (/[，,；;：:、]/.test(char)) return char;
  if (/[\p{P}\p{S}]/u.test(char)) return "，";
  return "";
}

function normalizePrimeTtsSpecialSymbolAsPunctuation(char: string): string {
  const punctuation = normalizePrimeTtsMicroPunctuation(char);
  if (punctuation) return punctuation;
  return "";
}

function hasPrimeTtsReadableToken(input: string): boolean {
  return /[\u3400-\u9fffA-Za-z0-9]/.test(input);
}

function isPrimeTtsIgnorableSymbolChar(char: string): boolean {
  const code = char.codePointAt(0) ?? 0;
  return (code >= 0x200b && code <= 0x200f) || (code >= 0x202a && code <= 0x202e) || (code >= 0x2060 && code <= 0x206f) || (code >= 0xfe00 && code <= 0xfe0f);
}

function isPrimeTtsStrongBreak(text: string, index: number): boolean {
  const char = text[index] ?? "";
  if (char !== ".") return true;
  const before = text[index - 1] ?? "";
  const after = text[index + 1] ?? "";
  return !(/\d/.test(before) && /\d/.test(after));
}

function isPrimeTtsSoftBreak(text: string, index: number): boolean {
  const char = text[index] ?? "";
  const before = text[index - 1] ?? "";
  const after = text[index + 1] ?? "";
  if (char === "," && /\d/.test(before) && /\d/.test(after)) return false;
  if ((char === ":" || char === "：") && /\d/.test(before) && /\d/.test(after)) return false;
  return true;
}

function splitPrimeTtsStallFallbackText(input: string): string[] {
  const text = normalizeTtsInputText(input);
  if (!text) return [];
  if (/[A-Za-z]/.test(text)) {
    const parts: string[] = [];
    let index = 0;
    while (index < text.length && parts.length < TTS_MAX_PARTS) {
      const char = text[index] ?? "";
      if (/\s/.test(char) || isPrimeTtsMicroPunctuation(char) || normalizePrimeTtsSpecialSymbolAsPunctuation(char)) {
        index += 1;
        continue;
      }
      if (/[A-Za-z]/.test(char)) {
        let end = index + 1;
        while (end < text.length && /[A-Za-z']/.test(text[end] ?? "")) end += 1;
        const token = text.slice(index, end).replace(/^'+|'+$/g, "");
        parts.push(...splitPrimeTtsMicroLatinToken(token).filter(Boolean));
        index = end;
        continue;
      }
      if (/\d/.test(char)) {
        parts.push(char);
        index += 1;
        continue;
      }
      if (isCjkChar(char)) {
        parts.push(char);
        index += 1;
        continue;
      }
      index += 1;
    }
    return parts.filter(hasPrimeTtsReadableToken);
  }
  return splitPrimeTtsProgressiveFallbackText(text);
}

function shouldSplitStalledPrimeTtsChunk(chunk: string, normalizedLength: number): boolean {
  const normalized = normalizeTtsHighlightText(chunk);
  const hasLatin = /[A-Za-z]/.test(chunk);
  const hasCjk = hasCjkText(chunk);
  if (hasLatin && !hasCjk) return normalized.length > PRIME_TTS_LATIN_WORD_MAX_CHARS;
  return normalizedLength > PRIME_TTS_MICRO_MAX_CHARS;
}

function splitPrimeTtsProgressiveFallbackText(input: string, maxBudget = PRIME_TTS_MAX_PLAY_CHARS): string[] {
  void maxBudget;
  const text = normalizeTtsInputText(input);
  if (!text) return [];
  const parts: string[] = [];
  let rest = text;
  for (const budget of PRIME_TTS_PROGRESSIVE_FALLBACK_CHARS) {
    if (!rest) break;
    const take = primeTtsProgressiveFallbackTakeLength(rest, budget);
    const part = rest.slice(0, take).trim();
    if (part) parts.push(part);
    rest = rest.slice(take).trimStart();
    if (rest.length <= budget) break;
  }
  if (rest.trim()) parts.push(rest.trim());
  return parts.length > 1 ? parts : [text];
}

function primeTtsProgressiveFallbackTakeLength(text: string, budget: number): number {
  if (text.length <= budget) return text.length;
  let take = Math.min(text.length, Math.max(1, budget));
  take = adjustPrimeTtsTakeBoundary(text, take, 1, Math.min(text.length, Math.max(take + 4, budget + 4)));
  return Math.max(1, Math.min(text.length, take));
}

const CHINESE_TTS_DIGITS = ["零", "一", "二", "三", "四", "五", "六", "七", "八", "九"] as const;

function normalizeChineseNumbersForPrimeTts(input: string, forceFull = false): string {
  if (!/\d/.test(input) || (!forceFull && !hasCjkText(input))) return input;
  const mode = forceFull ? "full" : chineseNumberReadingMode(input);
  if (mode === "none") return input;
  const normalizedPatterns = normalizeChineseDateTimeNumbers(input, mode);
  return normalizedPatterns.replace(/\d+(?:\.\d+)?[%％]?/g, (match, offset: number, full: string) => {
    if (isProtectedNumberToken(full, offset, match.length)) return match;
    if (mode !== "full" && !isChineseNumberContext(full, offset, match.length)) return match;
    const before = full.slice(Math.max(0, offset - 6), offset);
    const after = full.slice(offset + match.length, offset + match.length + 6);
    if (match.endsWith("%") || match.endsWith("％")) return `百分之${numberTokenToChinese(match.slice(0, -1), "value")}`;
    if (/年/.test(after.slice(0, 1)) && /^\d{2,4}$/.test(match)) return digitsToChinese(match);
    if (/[月日号时点分秒]/.test(after.slice(0, 1))) return numberTokenToChinese(match, "value");
    if (/[第]/.test(before.slice(-1)) || /[章节页条项次个]/.test(after.slice(0, 1))) return numberTokenToChinese(match, "value");
    if (/[:：]\s*$/.test(before) || /^\s*[、，,.。)]/.test(after)) return numberTokenToChinese(match, "value");
    return numberTokenToChinese(match, mode === "full" ? "auto" : "value");
  });
}

function normalizeChineseDateTimeNumbers(input: string, mode: "context" | "full"): string {
  const shouldConvert = (full: string, offset: number, length: number): boolean => {
    return mode === "full" || isChineseNumberContext(full, offset, length);
  };
  let output = input.replace(/(^|[^\w./\\-])(\d{4})[/.-](\d{1,2})[/.-](\d{1,2})(?=$|[^\w./\\-])/g, (match, prefix: string, year: string, month: string, day: string, offset: number, full: string) => {
    if (!shouldConvert(full, offset + prefix.length, match.length - prefix.length)) return match;
    return `${prefix}${digitsToChinese(year)}年${numberTokenToChinese(month, "value")}月${numberTokenToChinese(day, "value")}日`;
  });
  output = output.replace(/(^|[^\w./\\-])(\d{1,2})[:：](\d{2})(?:[:：](\d{2}))?(?=$|[^\w./\\-])/g, (match, prefix: string, hour: string, minute: string, second: string | undefined, offset: number, full: string) => {
    if (!shouldConvert(full, offset + prefix.length, match.length - prefix.length)) return match;
    const secondText = second ? `${numberTokenToChinese(second, "value")}秒` : "";
    return `${prefix}${numberTokenToChinese(hour, "value")}点${numberTokenToChinese(minute, "value")}分${secondText}`;
  });
  return output;
}

function chineseNumberReadingMode(input: string): "none" | "context" | "full" {
  const compact = input.replace(/\s+/g, "");
  const cjkCount = (compact.match(/[\u3400-\u9fff]/g) ?? []).length;
  const digitCount = (compact.match(/\d/g) ?? []).length;
  const latinCount = (compact.match(/[A-Za-z]/g) ?? []).length;
  if (!cjkCount || !digitCount) return "none";
  if (cjkCount >= 4 && cjkCount >= latinCount * 2) return "full";
  return "context";
}

function isProtectedNumberToken(text: string, offset: number, length: number): boolean {
  const before = text.slice(Math.max(0, offset - 16), offset);
  const after = text.slice(offset + length, offset + length + 16);
  if (/https?:\/\/\S*$/i.test(before) || /(?:^|[\s([{<])(?:[A-Za-z]:)?(?:[./\\]|[A-Za-z0-9_-]+[./\\])[\w./\\-]*$/i.test(before)) return true;
  if (/^[A-Za-z_./\\-]/.test(after) || /[A-Za-z_./\\-]$/.test(before)) return true;
  if (/\bv(?:ersion)?\.?$/i.test(before) || /^[.-]\d/.test(after)) return true;
  return false;
}

function isChineseNumberContext(text: string, offset: number, length: number): boolean {
  const before = text.slice(Math.max(0, offset - 8), offset);
  const after = text.slice(offset + length, offset + length + 8);
  if (/https?:\/\/|[A-Za-z_./\\-]$/.test(before) || /^[A-Za-z_./\\-]/.test(after)) return false;
  return /[\u3400-\u9fff年月日号点第个条项次章节页岁分秒小时分钟%％：:，,。！？、；;（）()]/.test(before + after);
}

function numberTokenToChinese(token: string, mode: "auto" | "value" | "digits" = "auto"): string {
  if (!token) return "";
  if (mode === "digits") return digitsToChinese(token);
  if (token.includes(".")) {
    const [integer, fraction = ""] = token.split(".");
    return `${integerNumberToChinese(integer)}点${digitsToChinese(fraction)}`;
  }
  if (/^0\d+/.test(token)) return integerNumberToChinese(token.replace(/^0+(?=\d)/, "") || "0");
  if (mode === "auto" && token.length === 4 && /^[12]\d{3}$/.test(token)) return digitsToChinese(token);
  return integerNumberToChinese(token);
}

function digitsToChinese(input: string): string {
  return input.split("").map((char) => CHINESE_TTS_DIGITS[Number(char)] ?? char).join("");
}

function integerNumberToChinese(input: string): string {
  const value = Number.parseInt(input, 10);
  if (!Number.isFinite(value)) return input;
  if (value === 0) return "零";
  if (value < 0 || value > 99999999) return digitsToChinese(input);
  const units = ["", "十", "百", "千"];
  const sectionUnits = ["", "万"];
  const sections: number[] = [];
  let rest = value;
  while (rest > 0) {
    sections.push(rest % 10000);
    rest = Math.floor(rest / 10000);
  }
  let output = "";
  let needZero = false;
  for (let index = sections.length - 1; index >= 0; index -= 1) {
    const section = sections[index];
    if (section === 0) {
      needZero = output.length > 0;
      continue;
    }
    if (needZero || (output && section < 1000)) output += "零";
    output += sectionToChinese(section, units) + sectionUnits[index];
    needZero = section % 10 === 0;
  }
  return output.replace(/^一十/, "十").replace(/零+/g, "零").replace(/零$/g, "");
}

function sectionToChinese(section: number, units: string[]): string {
  let output = "";
  let zero = false;
  for (let index = 3; index >= 0; index -= 1) {
    const unitValue = 10 ** index;
    const digit = Math.floor(section / unitValue) % 10;
    if (digit === 0) {
      if (output) zero = true;
      continue;
    }
    if (zero) {
      output += "零";
      zero = false;
    }
    output += `${CHINESE_TTS_DIGITS[digit]}${units[index]}`;
  }
  return output;
}

function normalizeTtsInputText(input: string): string {
  return input
    .replace(/([\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}])[\t ]+([\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}])/gu, "$1$2")
    .replace(/([\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}])\n(?=[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}])/gu, "$1")
    .replace(/\s+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function adjustPrimeTtsTakeBoundary(text: string, candidate: number, min: number, hard: number): number {
  const cut = Math.max(1, Math.min(text.length, candidate));
  if (cut >= text.length) return text.length;
  const before = text[cut - 1] ?? "";
  const after = text[cut] ?? "";
  if (/\d/.test(before) && /[年月日号时点分秒%％]/.test(after)) {
    let end = cut + 1;
    while (end < text.length && /[年月日号时点分秒%％]/.test(text[end] ?? "")) end += 1;
    if (end <= hard) return end;
  }
  if (!isPrimeTtsInlineTokenChar(before) || !isPrimeTtsInlineTokenChar(after)) return cut;
  let start = cut - 1;
  while (start > 0 && isPrimeTtsInlineTokenChar(text[start - 1] ?? "")) start -= 1;
  let end = cut;
  while (end < text.length && isPrimeTtsInlineTokenChar(text[end] ?? "")) end += 1;
  while (end < text.length && /[年月日号时点分秒%％]/.test(text[end] ?? "")) end += 1;
  if (start >= min) return start;
  if (end <= hard) return end;
  return cut;
}

function isPrimeTtsInlineTokenChar(char: string): boolean {
  return /[A-Za-z0-9_.:%％]/.test(char);
}

function splitTtsTextSegments(input: string): TtsTextSegment[] {
  const segments: TtsTextSegment[] = [];
  let buffer = "";
  let pendingBreak = false;
  const push = (forcedBreak = false) => {
    const text = buffer.trim();
    if (text) segments.push({ text, forcedBreak });
    buffer = "";
    pendingBreak = false;
  };
  for (let index = 0; index < input.length; index += 1) {
    const char = input[index] ?? "";
    buffer += char;
    if (char === "\n") {
      push(true);
      while (input[index + 1] === "\n") index += 1;
      continue;
    }
    if ("。！？；".includes(char)) {
      push(false);
      continue;
    }
    if (".!?;".includes(char)) {
      pendingBreak = true;
      continue;
    }
    if (pendingBreak && /\s/.test(char)) {
      push(false);
      while (/\s/.test(input[index + 1] ?? "") && input[index + 1] !== "\n") index += 1;
    } else if (!/\s/.test(char)) {
      pendingBreak = false;
    }
  }
  push(false);
  return segments;
}

function shouldFoldCodeBlock(lang: string, body: string): boolean {
  if (lang === "cancip-action") return true;
  if (["bash", "sh", "zsh", "shell", "powershell", "ps1", "cmd", "bat", "terminal", "console"].includes(lang)) return true;
  if (["ts", "tsx", "js", "jsx", "json", "html", "css", "python", "py", "diff"].includes(lang)) return true;
  if (looksLikeProcessProtocolLeakText(body)) return true;
  if (lang === "text" && /^#{2,3}\s+(?:api profile|token usage|model exchange raw contents|actual api call audit|input sizes|reply filter|raw sent|raw received|parsed extracted|visible answer|sent system|sent contexttext|sent turn prompt|sent actual user inputtext|original user prompt|previous attempt|summary|routing summary|included sources)\b/im.test(body)) return true;
  if ((lang === "json" || !lang) && /^\{\s*"?(?:actions|type)"?\s*:/.test(body.trim())) return true;
  if (/^(?:\$|>|PS>|powershell|cmd|node|npm|git|gh|python|py|obsidian|cancip)\b/im.test(body.trim())) return true;
  return false;
}

function foldProcessAfterConclusion(content: string, hiddenToolBlocks: FoldedMessageBlock[]): string {
  const lines = content.split(/\r?\n/);
  const cutIndex = findProcessTailCutIndex(lines);
  if (cutIndex < 0) return content;
  const visible = lines.slice(0, cutIndex).join("\n");
  const hidden = lines.slice(cutIndex).join("\n");
  if (!visible.trim() || !hidden.trim()) return content;
  hiddenToolBlocks.push({ title: "process", content: hidden });
  return visible.trimEnd();
}

function findProcessTailCutIndex(lines: string[]): number {
  for (let index = 0; index < lines.length; index += 1) {
    if (index < 2) continue;
    const trimmed = lines[index].trim();
    if (!trimmed) continue;
    if (isProcessSectionLine(trimmed)) return index;
    if (hasConclusionCueBefore(lines, index) && !isInsideFinalAnswerNumberedSection(lines, index) && looksLikeVerboseProcessLine(trimmed)) return index;
  }
  return -1;
}

function hasConclusionCueBefore(lines: string[], index: number): boolean {
  const before = lines.slice(0, index).join("\n").replace(/\s+/g, "");
  return /(?:最终结论|Finalanswer|已完成|没完成|未完成|部分完成|失败|等待确认|下一步)/i.test(before);
}

function isProcessSectionLine(trimmed: string): boolean {
  return /^(?:#{1,6}\s*)?(?:过程|执行过程|操作过程|工具过程|命令过程|过程记录|工具执行结果|执行详情|命令详情|细节|详情|步骤|检查|验证|日志|我做了这些|刚才我做了这些|本次执行|尝试过程|process|details?|steps?|commands?|logs?)[:：]?\s*$/i.test(trimmed);
}

function looksLikeVerboseProcessLine(trimmed: string): boolean {
  return /^(?:刚才我(?:做了|执行了|尝试了)这些|我(?:刚才|已经)?(?:做了|执行了|尝试了)|本次(?:执行|操作|改动|尝试)|尝试(?:修改|读取|执行)|工具执行结果|动作失败|失败步骤|失败原因|patch find text was not found|patch 修改|read |write |patch |command )[:：\s]/i.test(trimmed);
}

function isInsideFinalAnswerNumberedSection(lines: string[], index: number): boolean {
  for (let cursor = index - 1; cursor >= 0; cursor -= 1) {
    const line = lines[cursor].trim();
    if (!line) continue;
    if (isFinalAnswerNumberedSectionLine(line)) return true;
    if (/^(?:#{1,6}\s*)?(?:过程|执行过程|操作过程|工具过程|过程记录|日志|process|logs?)[:：]?\s*$/i.test(line)) return false;
    if (/^\d{1,2}[.)、]\s+/.test(line)) return false;
  }
  return false;
}

function isFinalAnswerNumberedSectionLine(line: string): boolean {
  return /^\d{1,2}[.)、]\s*(?:动作|改动|修改|读取|文件|验证|结果|提醒|阻塞|记忆|规则|总结|Actions?|Changed|Files?|Verification|Result|Reminder|Memory|Rules?)(?:\s|$|[:：/])/i.test(line);
}

function foldReasoningSections(content: string, hiddenToolBlocks: FoldedMessageBlock[]): string {
  const lines = content.split(/\r?\n/);
  const kept: string[] = [];
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    const trimmed = line.trim();
    if (!/^(?:#{1,6}\s*)?(?:思考过程|思考|推理过程|命令|执行命令|thinking|reasoning|commands?)[:：]?\s*$/i.test(trimmed)) {
      kept.push(line);
      continue;
    }

    const section: string[] = [];
    let cursor = index + 1;
    while (cursor < lines.length) {
      const next = lines[cursor];
      const nextTrimmed = next.trim();
      if (!nextTrimmed) break;
      if (/^#{1,6}\s+/.test(nextTrimmed)) break;
      section.push(next);
      cursor += 1;
    }

    if (section.length) {
      hiddenToolBlocks.push({ title: trimmed, content: `${trimmed}\n${section.join("\n").trim()}` });
      index = cursor;
      continue;
    }
    kept.push(line);
  }
  return kept.join("\n");
}

function foldModelReasoningArtifacts(content: string, hiddenToolBlocks: FoldedMessageBlock[]): string {
  const cueFolded = foldBeforeFinalOutputCue(content, hiddenToolBlocks);
  return foldReasoningTailAfterFinalAnswer(cueFolded.content, hiddenToolBlocks, cueFolded.hadCue);
}

function stripModelReasoningArtifacts(content: string): string {
  const hidden: FoldedMessageBlock[] = [];
  let text = content.replace(/<(think|thinking|reasoning)\b[^>]*>[\s\S]*?<\/\1>/gi, "\n\n");
  text = foldReasoningSections(text, hidden);
  return foldModelReasoningArtifacts(text, hidden);
}

function sanitizeModelVisibleAnswer(content: string): string {
  return stripModelReasoningArtifacts(content).replace(/\n{3,}/g, "\n\n").trim();
}

function sanitizeLiveModelProgress(content: string): string {
  let text = content;
  text = removeCancipActionBlocks(text);
  text = stripStructuredChoices(text);
  text = stripModelRunStatsLines(text);
  text = stripModelReasoningArtifacts(text);
  if (/```cancip-action/i.test(text) || /<cancip-action/i.test(text)) {
    const beforeAction = text.split(/```cancip-action|<cancip-action/i)[0]?.trim() ?? "";
    text = beforeAction || "";
  }
  return text.replace(/\n{3,}/g, "\n\n").trim();
}

function foldBeforeFinalOutputCue(content: string, hiddenToolBlocks: FoldedMessageBlock[]): { content: string; hadCue: boolean } {
  const lines = content.split(/\r?\n/);
  for (let index = 0; index < lines.length; index += 1) {
    const match = finalOutputCueMatch(lines[index].trim());
    if (!match) continue;
    const before = lines.slice(0, index).join("\n").trim();
    if (!before || !looksLikeModelReasoningArtifact(before)) return { content, hadCue: true };
    hiddenToolBlocks.push({ title: "reasoning", content: before });
    const tail = [match[1]?.trim() ?? "", ...lines.slice(index + 1)].filter(Boolean).join("\n").trim();
    return { content: tail || content, hadCue: true };
  }
  return { content, hadCue: false };
}

function foldReasoningTailAfterFinalAnswer(content: string, hiddenToolBlocks: FoldedMessageBlock[], hadFinalCue: boolean): string {
  if (!hadFinalCue) return content;
  const lines = content.split(/\r?\n/);
  let meaningfulSeen = 0;
  for (let index = 0; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (!trimmed) continue;
    if (meaningfulSeen > 0 && isReasoningTailMetaLine(trimmed)) {
      const visible = lines.slice(0, index).join("\n").trim();
      const hidden = lines.slice(index).join("\n").trim();
      if (visible && hidden) hiddenToolBlocks.push({ title: "reasoning", content: hidden });
      return visible || content;
    }
    meaningfulSeen += 1;
  }
  return content;
}

function finalOutputCueMatch(trimmed: string): RegExpMatchArray | null {
  return trimmed.match(/^(?:#{1,6}\s*)?(?:最终输出格式|最终输出|最终答案|最终回答|直接输出|Final output|Final answer)\s*[:：]\s*(.*)$/i);
}

function looksLikeModelReasoningArtifact(text: string): boolean {
  const compact = text.replace(/\s+/g, "");
  if (compact.length < 24) return false;
  return /(?:思考|推理|reasoning|think|用户要求|模板|注意|另外注意|需要|我们|数一下|输出格式|最终输出|这里|保持|替换|解释|分析)/i.test(text);
}

function isReasoningTailMetaLine(trimmed: string): boolean {
  return /^(?:另外注意|特别注意|注意(?:顺序|这里|模板|格式)?|用户要求|最终回答直接|直接输出整理|不要解释|不需要解释|我们(?:保持|需要|应该|要)|需要(?:替换|注意|保持|输出)|这里(?:需要|应该|要)|说明[:：]?|解释[:：]?)/i.test(trimmed);
}

function finalChoiceOptions(content: string): ChoiceOption[] {
  const withoutStats = stripProgrammaticRunStats(content).content;
  return choiceOptionsFromTexts(extractStructuredChoiceTexts(withoutStats)).concat(extractChoiceOptions(withoutStats));
}

function stripTailChoiceSection(content: string): string {
  const cleaned = stripStructuredChoices(content);
  const lines = cleaned.split(/\r?\n/);
  let inFence = false;
  let cueIndex = -1;
  for (let index = 0; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (trimmed.startsWith("```")) {
      inFence = !inFence;
      continue;
    }
    if (!inFence && isChoiceCueLine(trimmed)) cueIndex = index;
  }
  if (cueIndex < 0) return cleaned.trim();

  const skip = new Set<number>([cueIndex]);
  const choiceIndexes: number[] = [];
  let lastChoiceIndex = cueIndex;
  for (let index = cueIndex + 1; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (!trimmed) {
      skip.add(index);
      continue;
    }
    const choiceText = listedChoiceText(trimmed);
    if (choiceText && normalizeChoiceText(choiceText)) {
      skip.add(index);
      choiceIndexes.push(index);
      lastChoiceIndex = index;
      continue;
    }
    break;
  }
  if (choiceIndexes.length < 2) return cleaned.trim();

  const remainingAfterChoices = lines
    .slice(lastChoiceIndex + 1)
    .map((line) => line.trim())
    .filter(Boolean);
  if (remainingAfterChoices.length > 2 || remainingAfterChoices.some((line) => !isChoiceSectionTrailingMeta(line))) {
    return cleaned.trim();
  }

  if (!lines[lastChoiceIndex + 1]?.trim()) skip.add(lastChoiceIndex + 1);
  const kept = lines.filter((_line, index) => !skip.has(index)).join("\n");
  return kept.replace(/\n{3,}/g, "\n\n").trim();
}

function stripStructuredChoices(content: string): string {
  return content
    .replace(/<!--\s*cancip-choices\b[\s\S]*?-->/gi, "\n\n")
    .replace(/<cancip-choices\b[^>]*>[\s\S]*?<\/cancip-choices>/gi, "\n\n")
    .replace(/```cancip-choices\s*[\s\S]*?```/gi, "\n\n");
}

function extractChoiceSourceText(content: string): string {
  const blocks: string[] = [];
  for (const match of content.matchAll(/<!--\s*cancip-choices\b[\s\S]*?-->/gi)) blocks.push(match[0]);
  for (const match of content.matchAll(/<cancip-choices\b[^>]*>[\s\S]*?<\/cancip-choices>/gi)) blocks.push(match[0]);
  for (const match of content.matchAll(/```cancip-choices\s*[\s\S]*?```/gi)) blocks.push(match[0]);

  const tail = extractTailChoiceSection(content);
  if (tail) blocks.push(tail);
  return uniqueStrings(blocks.map((block) => block.trim()).filter(Boolean)).join("\n\n");
}

function extractTailChoiceSection(content: string): string {
  const cleaned = stripStructuredChoices(content);
  const lines = cleaned.split(/\r?\n/);
  let inFence = false;
  let cueIndex = -1;
  for (let index = 0; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (trimmed.startsWith("```")) {
      inFence = !inFence;
      continue;
    }
    if (!inFence && isChoiceCueLine(trimmed)) cueIndex = index;
  }
  if (cueIndex < 0) return "";

  const section: string[] = [lines[cueIndex]];
  const choiceLines: string[] = [];
  let lastChoiceIndex = cueIndex;
  for (let index = cueIndex + 1; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (!trimmed) {
      if (choiceLines.length) section.push(lines[index]);
      continue;
    }
    const choiceText = listedChoiceText(trimmed);
    if (choiceText && normalizeChoiceText(choiceText)) {
      section.push(lines[index]);
      choiceLines.push(lines[index]);
      lastChoiceIndex = index;
      continue;
    }
    break;
  }
  if (choiceLines.length < 2) return "";
  const remainingAfterChoices = lines
    .slice(lastChoiceIndex + 1)
    .map((line) => line.trim())
    .filter(Boolean);
  if (remainingAfterChoices.length > 2 || remainingAfterChoices.some((line) => !isChoiceSectionTrailingMeta(line))) return "";
  return section.join("\n").trim();
}

function extractStructuredChoiceTexts(content: string): string[] {
  const blocks: string[] = [];
  const pushMatches = (regex: RegExp, groupIndex: number): void => {
    for (const match of content.matchAll(regex)) {
      const value = match[groupIndex];
      if (value?.trim()) blocks.push(value.trim());
    }
  };
  pushMatches(/<!--\s*cancip-choices\b([\s\S]*?)-->/gi, 1);
  pushMatches(/<cancip-choices\b[^>]*>([\s\S]*?)<\/cancip-choices>/gi, 1);
  pushMatches(/```cancip-choices\s*([\s\S]*?)```/gi, 1);

  const texts: string[] = [];
  for (const block of blocks) {
    const json = extractFirstJsonObject(block) || block;
    try {
      texts.push(...choiceTextsFromParsedJson(JSON.parse(json) as unknown));
      continue;
    } catch {
      // Fall through to line parsing.
    }
    texts.push(...block
      .split(/\r?\n|[，,；;]/)
      .map((line) => line.replace(/^[-*\d.)、\s]+/, "").trim())
      .filter(Boolean));
  }
  return uniqueStrings(texts).slice(0, 6);
}

function visibleAssistantAnswer(answer: string, suppressToolActions = false): string {
  void suppressToolActions;
  const withoutActions = removeCancipActionBlocks(answer);
  const rawVisible = stripFinalReviewMetadata(stripModelReasoningArtifacts(stripModelRunStatsLines(stripTailChoiceSection(withoutActions)))).trim();
  const display = prepareMessageDisplay(rawVisible);
  const visible = display.visibleContent.trim();
  if (display.processOnly) return "";
  return isToolPrefaceOnlyAnswer(visible) ? "" : visible;
}

function finalReviewStatusFromAnswer(answer: string): FinalReviewStatus | "" {
  const markerCount = [...answer.matchAll(/<!--\s*cancip-final\b[\s\S]*?-->|<cancip-final\b[^>]*\/?\s*>/gi)].length;
  if (markerCount !== 1) return "";
  const comment = answer.match(/<!--\s*cancip-final\s+(\{[\s\S]*?\})\s*-->/i);
  if (comment) {
    try {
      const parsed = JSON.parse(comment[1]) as { status?: unknown };
      const status = typeof parsed.status === "string" ? parsed.status.trim().toLowerCase() : "";
      if (status === "complete" || status === "awaiting-approval" || status === "blocked" || status === "failed") return status;
    } catch {
      return "";
    }
  }
  const attribute = answer.match(/<cancip-final\b[^>]*\bstatus=["'](complete|awaiting-approval|blocked|failed)["'][^>]*\/?\s*>/i);
  return attribute?.[1]?.toLowerCase() as FinalReviewStatus | undefined ?? "";
}

function stripFinalReviewMetadata(content: string): string {
  return content
    .replace(/<!--\s*cancip-final\s+\{[\s\S]*?\}\s*-->/gi, "\n\n")
    .replace(/<cancip-final\b[^>]*\/?\s*>/gi, "\n\n");
}

function isToolPrefaceOnlyAnswer(text: string): boolean {
  const visible = stripTailChoiceSection(text).trim();
  if (!visible) return false;
  if (visible.length > 180) return false;
  if (hasFinalConclusion(visible)) return false;
  const compact = visible.replace(/\s+/g, "").toLowerCase();
  if (!compact) return false;
  if (/(已完成|已读取|已读完|已检查|已修改|已写入|已验证|改动的文件|读取的文件|结果和提醒|done|completed|changedfiles|verification|result)/i.test(compact)) return false;
  const hasPrefaceVerb = /(我先|先|接下来|下一步|现在|马上|随后|稍后|将会|我会|我将|先来|先去|i'?ll|iwill|i’mgoingto|goingto|nexti|letme)/i.test(compact);
  const hasToolVerb = /(读取|读一下|查看|看看|检查|检索|搜索|查找|打开|分析|随后|然后|再|写回|修改|美化|排版|read|inspect|check|search|open|analy[sz]e|then|afterthat|writeback|modify|format)/i.test(compact);
  return hasPrefaceVerb && hasToolVerb;
}

function isProseApprovalRequestAnswer(text: string, taskGoal = ""): boolean {
  const visible = stripTailChoiceSection(stripModelRunStatsLines(text)).trim();
  if (!visible) return false;
  if (visible.length > 520) return false;
  if (hasFinalConclusion(visible)) return false;
  const compact = visible.replace(/\s+/g, "").toLowerCase();
  if (!compact) return false;
  if (/(已完成|已执行|已运行|执行成功|运行成功|已打开|已写入|已修改|已验证|done|completed|executed|succeeded)/i.test(compact)) return false;
  const asksForApproval = /(需要(?:执行|运行|调用|打开|写入|修改|移动|删除|配置|批准|确认)|待确认|等待确认|请(?:确认|批准|允许)|是否(?:执行|运行|继续|打开)|要不要(?:执行|运行|继续|打开)|点(?:批准|运行|确认)|tap(?:approve|run)|pendingapproval|approvalrequired|needs(?:to)?(?:run|execute|approval)|requiresapproval)/i.test(compact);
  if (!asksForApproval) return false;
  if (taskGoal && shouldExpectToolActionForPrompt(taskGoal)) return true;
  return /(执行|运行|调用|打开|写入|修改|移动|删除|配置|命令|批准|确认|obsidian|command|tts|readaloud|open|execute|run|write|modify|delete|move|configure|approve)/i.test(compact);
}

function isAvoidableImplementationQuestionAnswer(text: string, taskGoal = ""): boolean {
  if (!taskGoal || classifyPromptIntent(taskGoal) !== "implementation") return false;
  const visible = stripTailChoiceSection(stripModelRunStatsLines(text)).trim();
  if (!visible || visible.length > 520 || hasFinalConclusion(visible)) return false;
  if (isConcreteMissingInputBlocker(visible, taskGoal)) return false;
  const compact = visible.replace(/\s+/g, "").toLowerCase();
  if (/(密码|密钥|token|验证码|账号|真实交易|下单|删除确认|永久删除|不可逆|password|secret|credential|2fa|destructive|irreversible)/i.test(compact)) return false;
  return /(请(?:提供|告诉|补充|指定).{0,40}(?:文件|路径|位置|内容|需求|目标)|需要.{0,30}(?:更多|具体|额外)(?:信息|上下文)|你希望.{0,40}(?:吗|？)|是否(?:需要|要|继续)|要不要|如果你愿意|我可以.{0,40}(?:继续|帮你|执行)|whichfile|provide.{0,20}(?:file|path|details)|wouldyoulikeme|shouldi)/i.test(compact);
}

function isConcreteMissingInputBlocker(text: string, taskGoal = ""): boolean {
  if (!taskGoal || classifyPromptIntent(taskGoal) !== "implementation") return false;
  const visible = stripTailChoiceSection(stripModelRunStatsLines(text)).replace(/\s+/g, " ").trim();
  if (!visible || visible.length < 8 || visible.length > 700) return false;
  const hasMissing = /(?:缺少|未提供|没有提供|未指定|没有指定|还没给|没给|需要提供|需要指定|missing|required|need(?:s)?|provide|specify)/i.test(visible);
  const hasConcreteField = /(?:文件名|保存路径|路径|位置|目录|文件夹|目标文件|目标|内容|正文|选择|权限|能力|命令|filename|file name|path|folder|directory|target|content|permission|capability|command)/i.test(visible);
  const hasBlockerCue = /(?:阻塞|不能|无法|不可|失败|等待|尚未执行|没法|cannot|can't|blocked|failed|unable|waiting|not yet)/i.test(visible);
  if (!(hasMissing && hasConcreteField && hasBlockerCue)) return false;
  if (isBareCreateVaultFilePrompt(taskGoal)) return false;
  return true;
}

function isOnlyRunStatsText(text: string): boolean {
  const compact = stripTailChoiceSection(text)
    .replace(/\s+/g, "")
    .replace(/[·:：/／|｜-]/g, "")
    .toLowerCase();
  if (!compact) return false;
  return /^(耗时|总耗时|elapsed|time|tokens|token|字数|chars|发送|接收|合计|in|out|total|estimated|\d+[a-z秒毫秒分钟小時小时]+)+$/i.test(compact);
}

function buildChoiceSuggestionPrompt(userPrompt: string, currentConclusion: string, previousConclusion: string, chinese: boolean): string {
  const languageRule = chinese ? "Use concise Simplified Chinese." : "Use concise English.";
  return [
    "Generate 1 to 3 next-step button labels for this assistant reply only when there are real concrete choices.",
    languageRule,
    "Rules:",
    "- Each label must be a concrete next action based on the user's actual request and the assistant's actual answer, not a status sentence.",
    "- Prefer domain-specific actions. Example: for an attached PDF, use labels like summarize this PDF / extract PDF content / explain task state; do not use generic continue/add details.",
    "- No numbering, no markdown, no code, no file paths unless the user explicitly asked for a path action.",
    "- Chinese labels should be 2-10 characters when possible and never exceed 16 Chinese characters.",
    "- English labels should be 2-5 words.",
    "- Avoid generic filler such as continue, add details, ask another; infer specific next actions from the actual task/result.",
    '- Return only JSON, using the real count: {"choices":["...","..."]}. If there are no useful choices, return {"choices":[]}.',
    "",
    `User request: ${trimContext(userPrompt.replace(/\s+/g, " "), 500) || "(empty)"}`,
    `Assistant final answer: ${trimContext(currentConclusion.replace(/\s+/g, " "), 900) || "(empty)"}`,
    `Previous assistant conclusion: ${trimContext(previousConclusion.replace(/\s+/g, " "), 420) || "(none)"}`
  ].join("\n");
}

function parseChoiceSuggestionResponse(raw: string): string[] {
  const text = raw.trim();
  if (!text) return [];
  const candidates = uniqueStrings([
    text,
    text.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim(),
    extractFirstJsonObject(text)
  ]);
  for (const candidate of candidates) {
    if (!candidate) continue;
    try {
      const parsed = JSON.parse(candidate) as unknown;
      const values = choiceTextsFromParsedJson(parsed);
      if (values.length) return values;
    } catch {
      // Fall through to line parsing.
    }
  }
  return text
    .split(/\r?\n|[，,；;]/)
    .map((line) => line.replace(/^[-*\d.)、\s]+/, "").trim())
    .filter(Boolean)
    .slice(0, 6);
}

function choiceTextsFromParsedJson(parsed: unknown): string[] {
  if (Array.isArray(parsed)) return parsed.filter((item): item is string => typeof item === "string");
  if (isRecord(parsed)) {
    const choices = parsed.choices;
    if (Array.isArray(choices)) return choices.filter((item): item is string => typeof item === "string");
  }
  return [];
}

function extractFirstJsonObject(text: string): string {
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");
  if (start < 0 || end <= start) return "";
  return text.slice(start, end + 1);
}

function markdownFrontmatterScalarFields(content: string): Map<string, string> {
  const fields = new Map<string, string>();
  const match = content.replace(/^\uFEFF/, "").match(/^---[ \t]*\r?\n([\s\S]*?)\r?\n---[ \t]*(?:\r?\n|$)/);
  if (!match) return fields;
  for (const line of match[1].split(/\r?\n/)) {
    const field = line.match(/^([A-Za-z0-9_.-]+)\s*:\s*(.*?)\s*$/);
    if (!field) continue;
    let value = field[2].trim();
    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    fields.set(field[1].toLocaleLowerCase(), value);
  }
  return fields;
}

function markdownHeadingsAtLevel(content: string, level: number): Array<{ title: string; line: number }> {
  const prefix = "#".repeat(level);
  const headings: Array<{ title: string; line: number }> = [];
  let fenced = false;
  for (const [index, line] of content.split(/\r?\n/).entries()) {
    if (/^\s*(```|~~~)/.test(line)) {
      fenced = !fenced;
      continue;
    }
    if (fenced || !line.startsWith(`${prefix} `) || line.startsWith(`${prefix}#`)) continue;
    const title = line.slice(prefix.length + 1).replace(/\s+#+\s*$/, "").trim();
    if (title) headings.push({ title, line: index + 1 });
  }
  return headings;
}

function duplicateMarkdownHeadings(headings: Array<{ title: string; line: number }>): Array<{ title: string; lines: number[] }> {
  const groups = new Map<string, { title: string; lines: number[] }>();
  for (const heading of headings) {
    const key = heading.title.replace(/\s+/g, " ").trim().toLocaleLowerCase();
    const group = groups.get(key) ?? { title: heading.title, lines: [] };
    group.lines.push(heading.line);
    groups.set(key, group);
  }
  return [...groups.values()].filter((group) => group.lines.length > 1);
}

function parseFirstJsonObject(text: string): unknown {
  const raw = extractFirstJsonObject(text);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as unknown;
  } catch {
    return null;
  }
}

function choiceOptionsFromTexts(texts: string[]): ChoiceOption[] {
  const options = uniqueStrings(texts)
    .map(normalizeChoiceText)
    .filter(Boolean)
    .slice(0, 3);
  return options.map((text, index) => ({ prefix: String(index + 1), text }));
}

function hasSpecificChoiceOptions(options: ChoiceOption[]): boolean {
  return options.filter((option) => choiceSpecificityScore(option.text) >= 4).length >= 2;
}

function choiceSpecificityScore(text: string): number {
  const normalized = normalizeChoiceText(text);
  if (!normalized) return 0;
  let score = 4;
  if (isGenericChoiceText(normalized)) score -= 4;
  if (/(修复|检查|验证|打开|读取|搜索|总结|导出|审核|朗读|重试|对比|应用|同步|发布|测试|优化|核对|进入|运行|Fix|Check|Verify|Open|Read|Search|Summari[sz]e|Export|Review|Retry|Compare|Apply|Sync|Release|Test|Optimize|Inspect|Run)/i.test(normalized)) score += 2;
  if (/(PDF|TTS|GitHub|Obsidian|Cancip|Vault|插件|会话|文件|设置|审核|朗读|附件|模型|token|上下文|记忆)/i.test(normalized)) score += 2;
  if (/[\u3400-\u9fff]/.test(normalized)) {
    if (normalized.length <= 12) score += 1;
    if (normalized.length > 18) score -= 2;
  } else {
    const words = normalized.split(/\s+/).filter(Boolean).length;
    if (words >= 2 && words <= 5) score += 1;
    if (words > 7) score -= 2;
  }
  return score;
}

function isGenericChoiceText(text: string): boolean {
  const compact = text.trim().toLowerCase().replace(/[\s，。！？!?.、~～]+/g, "");
  return /^(继续|继续处理|继续优化|补充要求|换个问题|继续追问|总结要点|搜索相关内容|重新发送问题|continue|continuefixing|continueimproving|adddetails|askanother|askfollowup|summarize|searchrelated|retry)$/.test(compact);
}

function normalizeChoiceOptions(raw: unknown[]): ChoiceOption[] {
  return raw
    .filter(isRecord)
    .map((item, index): ChoiceOption | null => {
      const text = typeof item.text === "string" ? normalizeChoiceText(item.text) : "";
      if (!text) return null;
      const prefix = typeof item.prefix === "string" && item.prefix.trim() ? item.prefix.trim() : String(index + 1);
      return { prefix, text };
    })
    .filter((item): item is ChoiceOption => item !== null)
    .slice(0, 3);
}

function isChoiceOptionsStatus(value: unknown): value is NonNullable<ChatMessage["choiceOptionsStatus"]> {
  return value === "loading" || value === "ready" || value === "failed";
}

function extractChoiceOptions(content: string): ChoiceOption[] {
  const visible = stripStructuredChoices(content);
  const lines = visible.split(/\r?\n/);
  const hasChoiceCue = lines.some((line) => isChoiceCueLine(line.trim()) || /(?:下一步|建议|推荐|你可以|我可以|继续帮你|请选择|next step|recommended|suggest|choose|option|select|pick)/i.test(line));
  if (!hasChoiceCue) return [];

  const choices: ChoiceOption[] = [];
  let inFence = false;
  let inNextStepSection = false;
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith("```")) {
      inFence = !inFence;
      continue;
    }
    if (inFence) continue;
    if (isChoiceCueLine(trimmed)) {
      inNextStepSection = true;
      continue;
    }
    if (inNextStepSection && /^#{1,6}\s+\S/.test(trimmed) && !/(?:下一步|建议|推荐|Next|Suggest|Option)/i.test(trimmed)) break;
    const match = trimmed.match(/^(?:(\d{1,2})[.)、]|([A-Ha-h])[.)]|[-*]\s+)\s*(.{2,140})$/);
    const text = listedChoiceText(trimmed);
    if (!match || !text) continue;
    if (!text || /^(https?:|```|\{|\[)/i.test(text)) continue;
    if (/^[\w.-]+\/[\w./-]+$/.test(text)) continue;
    if (!inNextStepSection && !looksLikeNextStepChoice(text)) continue;
    const normalized = normalizeChoiceText(text);
    if (!normalized) continue;
    const prefix = match[1] ?? match[2]?.toUpperCase() ?? String(choices.length + 1);
    choices.push({ prefix, text: normalized });
  }

  const unique = new Map<string, ChoiceOption>();
  for (const choice of choices) {
    const key = choice.text.toLowerCase();
    if (!unique.has(key)) unique.set(key, choice);
  }
  return [...unique.values()].slice(0, 3);
}

function isChoiceCueLine(trimmed: string): boolean {
  if (!trimmed) return false;
  return /^(?:#{1,6}\s*)?(?:下一步|建议|推荐操作|推荐下一步|可选下一步|你可以|我可以|请选择|Next steps?|Recommended next steps?|Suggestions?|Options?)[:：]?\s*$/i.test(trimmed)
    || /^(?:#{1,6}\s*)?(?:如果你想|如果需要|你要是想|需要的话|想的话|后续我可以|我可以继续|可以继续).{0,34}(?:我可以|继续帮你|继续|帮你|处理|做|看|总结|解释)[^。！？\n]*[：:]?\s*$/i.test(trimmed);
}

function listedChoiceText(trimmed: string): string {
  const match = trimmed.match(/^(?:(?:\d{1,2})[.)、]|(?:[A-Ha-h])[.)]|[-*]\s+)\s*(.{2,140})$/);
  return match ? match[1].trim() : "";
}

function isChoiceSectionTrailingMeta(trimmed: string): boolean {
  return isModelRunStatsLine(trimmed);
}

function looksLikeNextStepChoice(text: string): boolean {
  if (/[`{}[\]]/.test(text)) return false;
  if (looksLikePathQuery(text)) return false;
  if (text.length > 56) return false;
  return /^(?:继续|修复|检查|重试|总结|生成|打开|查看|看看|提取|解释|应用|确认|取消|导出|保存|重新|补充|执行|测试|验证|搜索|追问|提问|分析|优化|整理|对齐|精简|扩展|核对|进入|运行|Continue|Fix|Check|Retry|Summari[sz]e|Generate|Open|Review|Apply|Confirm|Cancel|Export|Save|Run|Test|Verify|Search|Ask|Analyze|Optimize|Organize|Align|Refine|Extract|Explain|Inspect)\b/i.test(text)
    || /(?:继续|修复|检查|重试|总结|生成|打开|查看|看看|提取|解释|应用|确认|取消|导出|保存|重新|补充|执行|测试|验证|搜索|追问|提问|分析|优化|整理|对齐|精简|扩展|核对|进入|运行|下一步)/.test(text);
}

function normalizeChoiceText(text: string): string {
  let cleaned = text
    .replace(/\[[^\]]+\]\([^)]+\)/g, (match) => match.replace(/^\[([^\]]+)\]\([^)]+\)$/, "$1"))
    .replace(/[*_~#>]+/g, "")
    .replace(/^\[[ x-]\]\s*/i, "")
    .replace(/^(?:下一步|建议|推荐|推荐操作|推荐下一步|可选下一步|你可以|请选择|Next steps?|Recommended next steps?|Suggestions?|Options?)[:：]\s*/i, "")
    .replace(/\s+/g, " ")
    .replace(/[。；;,.，]+$/g, "")
    .trim();
  cleaned = shortenChoiceText(cleaned);
  if (!cleaned || cleaned.length < 2) return "";
  if (!isUsefulChoiceText(cleaned)) return "";
  return cleaned;
}

function shortenChoiceText(text: string): string {
  let next = text.trim();
  const colonIndex = next.search(/[：:]/);
  if (colonIndex > 1 && next.length > 28) next = next.slice(0, colonIndex).trim();
  next = next.split(/[。；;]/)[0].trim();
  next = next.replace(/^(?:请|可以|你可以|建议|推荐|Please|You can|Recommended?)\s*/i, "").trim();
  if (/[\u3400-\u9fff]/.test(next) && next.length > 18) {
    const separators = ["，", "、", ",", " - ", " — ", " – "];
    for (const separator of separators) {
      const index = next.indexOf(separator);
      if (index > 3 && index <= 18) return next.slice(0, index).trim();
    }
    return next.length <= 24 ? next : "";
  }
  if (next.length <= 36) return next;
  const separators = ["，", ",", "、", " - ", " — ", " – "];
  for (const separator of separators) {
    const index = next.indexOf(separator);
    if (index > 4 && index <= 36) return next.slice(0, index).trim();
  }
  return next.length <= 42 ? next : "";
}

function isUsefulChoiceText(text: string): boolean {
  if (!text || text.length > 42) return false;
  if (/[`{}[\]]/.test(text)) return false;
  if (looksLikePathQuery(text)) return false;
  if (/^(?:read|write|patch|config|command|todo|automation|npm|git|gh|node|python|powershell|cmd)\b/i.test(text)) return false;
  if (/^(?:https?:\/\/|[\w.-]+\/[\w./-]+$)/i.test(text)) return false;
  if (/^(?:原因|说明|结果|路径|文件|失败原因|失败步骤|总耗时|Total elapsed)\b/i.test(text)) return false;
  return looksLikeNextStepChoice(text) || /(?:下一步|继续|修复|检查|验证|总结|导出|重试|打开|查看|看看|提取|解释|补充|确认|取消|搜索|追问|提问|分析|优化|整理|对齐|精简|扩展|核对|进入|运行|fix|check|verify|retry|continue|summari[sz]e|extract|explain|export|open|review|search|ask|analy[sz]e|optimi[sz]e|organize|align|refine|inspect|run)/i.test(text);
}

function normalizeToolRuns(raw: unknown): ToolRun[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .filter(isRecord)
    .map((item): ToolRun | null => {
      const action = parseCancipAction(item.action);
      if (!action) return null;
      const status = isToolRunStatus(item.status) ? item.status : "pending";
      return {
        id: typeof item.id === "string" && item.id ? item.id : crypto.randomUUID(),
        action,
        summary: typeof item.summary === "string" && item.summary ? item.summary : action.type,
        status,
        createdAt: typeof item.createdAt === "string" ? item.createdAt : new Date().toISOString(),
        startedAt: typeof item.startedAt === "string" ? item.startedAt : undefined,
        executedAt: typeof item.executedAt === "string" ? item.executedAt : undefined,
        result: typeof item.result === "string" ? item.result : undefined,
        error: typeof item.error === "string" ? item.error : undefined,
        cached: typeof item.cached === "boolean" ? item.cached : undefined,
        reviewPath: typeof item.reviewPath === "string" ? item.reviewPath : undefined,
        reviewRequired: typeof item.reviewRequired === "boolean" ? item.reviewRequired : undefined,
        reviewStage: item.reviewStage === "pre-execution" || item.reviewStage === "post-execution" ? item.reviewStage : undefined,
        autoApproved: typeof item.autoApproved === "boolean" ? item.autoApproved : undefined,
        automationTaskId: typeof item.automationTaskId === "string" ? item.automationTaskId : undefined,
        lineDeltas: normalizeToolRunLineDeltas(item.lineDeltas),
        evidencePaths: Array.isArray(item.evidencePaths)
          ? uniqueStrings(item.evidencePaths.filter((path): path is string => typeof path === "string").map((path) => normalizePath(path)).filter(Boolean))
          : undefined
      };
    })
    .filter((item): item is ToolRun => item !== null);
}

function normalizeToolRunLineDeltas(raw: unknown): ToolRunLineDelta[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  const deltas = raw
    .filter(isRecord)
    .map((item): ToolRunLineDelta | null => {
      const path = typeof item.path === "string" ? normalizePath(item.path) : "";
      if (!path) return null;
      const added = Number(item.added);
      const removed = Number(item.removed);
      if (!Number.isFinite(added) || !Number.isFinite(removed)) return null;
      return {
        path,
        added: Math.max(0, Math.trunc(added)),
        removed: Math.max(0, Math.trunc(removed)),
        estimated: typeof item.estimated === "boolean" ? item.estimated : undefined
      };
    })
    .filter((item): item is ToolRunLineDelta => item !== null);
  return deltas.length ? deltas : undefined;
}

function cloneToolRun(run: ToolRun): ToolRun {
  return {
    ...run,
    action: cloneJsonValue(run.action) as CancipAction,
    lineDeltas: run.lineDeltas?.map((item) => ({ ...item })),
    evidencePaths: run.evidencePaths ? [...run.evidencePaths] : undefined
  };
}

function uniqueToolRunsById(runs: ToolRun[]): ToolRun[] {
  const seen = new Set<string>();
  const unique: ToolRun[] = [];
  for (const run of runs) {
    if (seen.has(run.id)) continue;
    seen.add(run.id);
    unique.push(run);
  }
  return unique;
}

function normalizeResumableTask(raw: unknown): ResumableTaskState | null {
  if (!isRecord(raw)) return null;
  const prompt = typeof raw.prompt === "string" ? raw.prompt.trim() : "";
  const reason = raw.reason === "stopped" || raw.reason === "failed" ? raw.reason : null;
  if (!prompt || !reason) return null;
  const at = Number.isFinite(Number(raw.at)) ? Number(raw.at) : Date.now();
  const detail = typeof raw.detail === "string" ? raw.detail : undefined;
  return { prompt, reason, at, detail };
}

function normalizeChatMessage(raw: Record<string, unknown>): ChatMessage | null {
  const role = raw.role;
  if (role !== "system" && role !== "user" && role !== "assistant") return null;
  return {
    id: typeof raw.id === "string" && raw.id ? raw.id : crypto.randomUUID(),
    role,
    content: ensureDisplayText(raw.content),
    createdAt: timestampMs(raw.createdAt),
    toolRuns: normalizeToolRuns(raw.toolRuns),
    changedFileRuns: normalizeToolRuns(raw.changedFileRuns),
    sources: normalizeSearchHits(raw.sources),
    choiceOptions: Array.isArray(raw.choiceOptions) ? normalizeChoiceOptions(raw.choiceOptions) : undefined,
    choiceOptionsStatus: raw.choiceOptionsStatus === "loading" || raw.choiceOptionsStatus === "ready" || raw.choiceOptionsStatus === "failed" ? raw.choiceOptionsStatus : undefined,
    choiceSourceText: typeof raw.choiceSourceText === "string" ? raw.choiceSourceText : undefined,
    workflowHint: normalizeComposerWorkflowHint(raw.workflowHint).steps.length ? normalizeComposerWorkflowHint(raw.workflowHint) : undefined,
    contextText: typeof raw.contextText === "string" ? raw.contextText : undefined,
    systemPrompt: typeof raw.systemPrompt === "string" ? raw.systemPrompt : undefined,
    mode: normalizeComposerMode(raw.mode) ?? undefined,
    accessMode: isAccessMode(raw.accessMode) ? raw.accessMode : undefined,
    processAuditSections: normalizeProcessAuditSections(raw.processAuditSections)
  };
}

function normalizeProcessAuditSections(raw: unknown): ProcessAuditSection[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  const sections = raw
    .filter(isRecord)
    .map((item): ProcessAuditSection | null => {
      const title = typeof item.title === "string" ? item.title : "";
      const content = typeof item.content === "string" ? item.content : "";
      const group = item.group === "sent" || item.group === "received" || item.group === "runtime" || item.group === "other"
        ? item.group
        : "other";
      if (!title || !content) return null;
      return { title, content, group, raw: item.raw === true };
    })
    .filter((item): item is ProcessAuditSection => item !== null);
  return sections.length ? sections : undefined;
}

function normalizeSearchHits(raw: unknown): SearchHit[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  const hits = raw
    .filter(isRecord)
    .map((item): SearchHit | null => {
      const path = typeof item.path === "string" ? item.path : "";
      if (!path) return null;
      return {
        path,
        title: typeof item.title === "string" ? item.title : path,
        excerpt: typeof item.excerpt === "string" ? item.excerpt : "",
        score: typeof item.score === "number" ? item.score : 0
      };
    })
    .filter((item): item is SearchHit => item !== null);
  return hits.length ? hits : undefined;
}

function formatDomActionResult(result: DomActionResult): string {
  return [
    `selector: ${result.selector}`,
    `index: ${result.index}`,
    `tag: ${result.tag}`,
    result.classes ? `classes: ${result.classes}` : "",
    result.text ? `text: ${result.text}` : ""
  ].filter(Boolean).join("\n");
}

function uiElementLabel(el: HTMLElement): string {
  const snapshotLabel = el.dataset.cancipUiRuleLabel;
  if (snapshotLabel) return snapshotLabel;
  const labelEl = el.querySelector<HTMLElement>(".menu-item-title, .view-action-title, .nav-action-title, .setting-item-name, .workspace-tab-header-inner-title");
  return (el.getAttribute("aria-label") || el.getAttribute("title") || labelEl?.textContent || el.innerText || el.textContent || el.className || el.tagName).toString().replace(/\s+/g, " ").trim();
}

function uiElementIconName(el: HTMLElement | null | undefined): string {
  if (!el) return "";
  const direct = el.dataset.cancipUiIcon || el.dataset.icon || el.getAttribute("data-icon") || "";
  if (direct.trim()) return direct.trim();
  const iconRoot = el.querySelector<HTMLElement>(".menu-item-icon, .view-action-icon, .nav-action-button, .clickable-icon, [data-icon], .svg-icon") ?? el;
  const iconAttr = iconRoot.dataset.icon || iconRoot.getAttribute("data-icon") || iconRoot.getAttribute("icon") || "";
  if (iconAttr.trim()) return iconAttr.trim();
  const svg = iconRoot.matches("svg") ? iconRoot : iconRoot.querySelector<SVGElement>("svg");
  const iconClass = Array.from(svg?.classList ?? [])
    .find((item) => item.startsWith("lucide-") && item.length > "lucide-".length);
  if (iconClass) return iconClass.slice("lucide-".length);
  const aria = iconRoot.getAttribute("aria-label") || iconRoot.getAttribute("title") || "";
  const iconLike = aria.trim().toLowerCase().replace(/\s+/g, "-");
  return /^[a-z0-9][a-z0-9-]{1,48}$/.test(iconLike) ? iconLike : "";
}

function normalizeUiButtonLabel(value: string): string {
  return value.replace(/\s+/g, " ").trim().toLowerCase();
}

function uiButtonLabelEquals(a: string, b: string): boolean {
  const left = normalizeUiButtonLabel(a);
  const right = normalizeUiButtonLabel(b);
  return Boolean(left && right && left === right);
}

