function cleanUiButtonCommandLabel(value: string): string {
  return value
    .replace(/^[\s·•\-–—*]+/, "")
    .replace(/\s*(?:Ctrl|Cmd|Meta|Alt|Shift|⌘|⌥|⇧|⌃)(?:\s*[+＋]\s*[\w\u4e00-\u9fff])+\s*$/i, "")
    .replace(/\s*\([^)]{1,30}\)\s*$/g, "")
    .replace(/[.。…]+$/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function uiButtonCommandNameEquals(a: string, b: string): boolean {
  const left = normalizeUiButtonCommandText(a);
  const right = normalizeUiButtonCommandText(b);
  if (!left || !right) return false;
  return left === right || stripUiButtonCommandPrefix(left) === right || left === stripUiButtonCommandPrefix(right);
}

function scoreUiButtonObsidianCommand(entry: ObsidianCommandEntry, label: string): number {
  const cleaned = cleanUiButtonCommandLabel(label);
  if (!cleaned) return 0;
  const labelNorm = normalizeUiButtonCommandText(cleaned);
  const labelCompact = labelNorm.replace(/\s+/g, "");
  const nameNorm = normalizeUiButtonCommandText(entry.name);
  const nameNoPrefix = stripUiButtonCommandPrefix(nameNorm);
  const nameCompact = nameNorm.replace(/\s+/g, "");
  const noPrefixCompact = nameNoPrefix.replace(/\s+/g, "");
  const idNorm = normalizeUiButtonCommandText(entry.id);
  const idCompact = idNorm.replace(/\s+/g, "");
  let score = scoreObsidianCommand(entry, cleaned);
  if (nameNorm === labelNorm) score += 520;
  if (nameNoPrefix === labelNorm) score += 560;
  if (labelCompact.length >= 2 && (nameCompact.includes(labelCompact) || noPrefixCompact.includes(labelCompact))) score += 260 + Math.min(labelCompact.length * 8, 160);
  if (labelCompact.length >= 4 && (isSubsequence(labelCompact, noPrefixCompact) || isSubsequence(labelCompact, nameCompact))) {
    score += 210 + Math.min(labelCompact.length * 6, 120);
  }
  if (labelCompact.length >= 4 && isSubsequence(labelCompact, idCompact)) score += 105;
  if (labelCompact.length >= 3 && idCompact.includes(labelCompact)) score += 90;
  const labelTokens = uiButtonCommandTokens(cleaned);
  const field = `${idNorm} ${nameNorm}`;
  let matched = 0;
  for (const token of labelTokens) {
    const normalized = normalizeUiButtonCommandText(token).replace(/\s+/g, "");
    if (!normalized) continue;
    if (field.replace(/\s+/g, "").includes(normalized)) {
      matched += 1;
      score += normalized.length <= 2 ? 18 : 32;
    }
  }
  if (labelTokens.length && matched === labelTokens.length) score += 110;
  if (labelTokens.length >= 2 && matched < Math.ceil(labelTokens.length * 0.6)) score -= 80;
  return Math.max(0, Math.round(score));
}

function normalizeUiButtonCommandText(value: string): string {
  return normalizeObsidianCommandSearchText(cleanUiButtonCommandLabel(value)).replace(/\b(pdf|tts|ai|ob)\b/g, (match) => match);
}

function stripUiButtonCommandPrefix(value: string): string {
  return value.replace(/^[a-z0-9 _.-]{2,40}\s+/, "").trim();
}

function uiButtonCommandTokens(value: string): string[] {
  return uniqueStrings([
    ...obsidianCommandSearchTokens(value),
    ...cleanUiButtonCommandLabel(value).split(/\s+/),
    ...(cleanUiButtonCommandLabel(value).match(/[\u4e00-\u9fff]{2,}/g) ?? [])
  ])
    .map((item) => item.trim())
    .filter((item) => item && !/^(ob|obsidian|command|命令|按钮|功能)$/.test(item.toLowerCase()));
}

function isSafeUiButtonVisualClass(value: string): boolean {
  return [
    "clickable-icon",
    "view-action",
    "nav-action-button",
    "workspace-ribbon-action",
    "side-dock-ribbon-action",
    "document-search-button",
    "pdf-toolbar-button"
  ].includes(value);
}

function guessUiButtonCommandIcon(id: string, name: string): string {
  const haystack = `${id} ${name}`.toLowerCase();
  if (/(cancip|ai|chat|assistant|bot|问答|聊天|助手)/i.test(haystack)) return "bot";
  if (/(new|create|add|insert|新建|创建|添加|增加|插入)/i.test(haystack)) return "plus";
  if (/(search|find|lookup|查找|搜索|检索)/i.test(haystack)) return "search";
  if (/(history|recent|历史|最近)/i.test(haystack)) return "history";
  if (/(todo|task|plan|待办|计划|任务)/i.test(haystack)) return "list-todo";
  if (/(review|approve|audit|审核|批准)/i.test(haystack)) return "shield-check";
  if (/(translate|translation|language|翻译|译文|语言)/i.test(haystack)) return "languages";
  if (/(speak|tts|voice|read aloud|朗读|语音)/i.test(haystack)) return "volume-2";
  if (/(pause|暂停)/i.test(haystack)) return "pause";
  if (/(play|resume|continue|播放|继续|恢复)/i.test(haystack)) return "play";
  if (/(stop|停止)/i.test(haystack)) return "square";
  if (/(settings|preference|config|设置|配置)/i.test(haystack)) return "settings";
  if (/(calendar|daily|date|日历|日记|日期)/i.test(haystack)) return "calendar-days";
  if (/(folder|目录|文件夹)/i.test(haystack)) return "folder-open";
  if (/(file|note|markdown|笔记|文件)/i.test(haystack)) return "file-text";
  if (/(command|palette|命令)/i.test(haystack)) return "command";
  if (/(terminal|shell|console|终端|控制台)/i.test(haystack)) return "terminal";
  if (/(refresh|reload|rebuild|sync|刷新|重载|同步|重建)/i.test(haystack)) return "refresh-cw";
  if (/(download|export|下载|导出)/i.test(haystack)) return "download";
  if (/(upload|import|上传|导入)/i.test(haystack)) return "upload";
  if (/(attach|attachment|paperclip|附件)/i.test(haystack)) return "paperclip";
  if (/(draw|paint|canvas|sketch|涂鸦|绘图|画)/i.test(haystack)) return "palette";
  if (/(highlight|mark|高亮|标记)/i.test(haystack)) return "highlighter";
  if (/(pin|固定|置顶)/i.test(haystack)) return "pin";
  if (/(star|favorite|收藏)/i.test(haystack)) return "star";
  return "zap";
}

function stableSelectorForElement(el: HTMLElement): string {
  const snapshotSelector = el.dataset.cancipUiRuleSelector;
  if (snapshotSelector) return snapshotSelector;
  const customButtonId = el.dataset.cancipUiCustomButtonId;
  if (customButtonId) return uniqueSelectorForElement(el, `[data-cancip-ui-custom-button-id="${cssEscapeAttr(customButtonId)}"]`);
  if (el.matches(".status-bar")) return ".status-bar";
  if (el.matches(".status-bar-item, .obcc-statusbar") || el.closest(".status-bar")) {
    const statusItem = el.closest<HTMLElement>(".status-bar-item, .obcc-statusbar") ?? el;
    if (statusItem.hasClass("obcc-statusbar") || statusItem.hasClass("plugin-cancip")) return ".status-bar .obcc-statusbar";
    const pluginClass = Array.from(statusItem.classList).find((item) => /^plugin-[a-z0-9_-]+$/i.test(item));
    if (pluginClass) return `.status-bar .status-bar-item.${cssClassEscape(pluginClass)}`;
    const command = statusItem.getAttribute("data-command");
    if (command) return `.status-bar .status-bar-item[data-command="${cssEscapeAttr(command)}"]`;
    return ".status-bar .status-bar-item";
  }
  const menuItem = el.closest<HTMLElement>(".menu-item, [role='menuitem']");
  if (menuItem?.closest(".menu, .menu-group")) {
    return stableMenuItemSelector(menuItem);
  }
  const command = el.getAttribute("data-command");
  if (command) {
    return uniqueSelectorForElement(el, `${el.tagName.toLowerCase()}[data-command="${cssEscapeAttr(command)}"]`);
  }
  const id = el.getAttribute("id");
  if (id) return uniqueSelectorForElement(el, `${el.tagName.toLowerCase()}#${cssClassEscape(id)}`);
  const href = el.getAttribute("href");
  if (href && el.tagName.toLowerCase() === "a") return uniqueSelectorForElement(el, `a[href="${cssEscapeAttr(href)}"]`);
  const aria = el.getAttribute("aria-label");
  if (aria) return `${el.tagName.toLowerCase()}[aria-label="${cssEscapeAttr(aria)}"]`;
  const title = el.getAttribute("title");
  if (title) return `${el.tagName.toLowerCase()}[title="${cssEscapeAttr(title)}"]`;
  const cls = String(el.className || "").split(/\s+/).filter(Boolean).filter((item) => !/^is-|^mod-|^has-/.test(item)).slice(0, 3);
  if (cls.length) return uniqueSelectorForElement(el, `${el.tagName.toLowerCase()}.${cls.map(cssClassEscape).join(".")}`);
  return uniqueSelectorForElement(el, el.tagName.toLowerCase());
}

function looseSelectorForUiButtonRule(el: HTMLElement): string {
  const snapshotSelector = el.dataset.cancipUiRuleSelector;
  if (snapshotSelector) return snapshotSelector;
  const customButtonId = el.dataset.cancipUiCustomButtonId;
  if (customButtonId) return `[data-cancip-ui-custom-button-id="${cssEscapeAttr(customButtonId)}"]`;
  const menuItem = el.closest<HTMLElement>(".menu-item, [role='menuitem']");
  if (menuItem?.closest(".menu, .menu-group")) return stableMenuItemSelector(menuItem);
  return stableSelectorForElement(el);
}

function stableMenuItemSelector(menuItem: HTMLElement): string {
  const ownCommand = menuItem.getAttribute("data-command") || "";
  if (ownCommand) return `.menu .menu-item[data-command="${cssEscapeAttr(ownCommand)}"], .menu-group .menu-item[data-command="${cssEscapeAttr(ownCommand)}"]`;
  const commandChild = menuItem.querySelector<HTMLElement>("[data-command]");
  const childCommand = commandChild?.getAttribute("data-command") || "";
  if (commandChild && childCommand) return `.menu [data-command="${cssEscapeAttr(childCommand)}"], .menu-group [data-command="${cssEscapeAttr(childCommand)}"]`;
  const id = menuItem.getAttribute("id");
  if (id) return `.menu .menu-item#${cssClassEscape(id)}, .menu-group .menu-item#${cssClassEscape(id)}, [role='menuitem']#${cssClassEscape(id)}`;
  const aria = menuItem.getAttribute("aria-label");
  if (aria) return `.menu .menu-item[aria-label="${cssEscapeAttr(aria)}"], .menu-group .menu-item[aria-label="${cssEscapeAttr(aria)}"]`;
  const title = menuItem.getAttribute("title");
  if (title) return `.menu .menu-item[title="${cssEscapeAttr(title)}"], .menu-group .menu-item[title="${cssEscapeAttr(title)}"]`;
  return UI_BUTTON_MENU_ITEM_SELECTOR;
}

function uniqueSelectorForElement(el: HTMLElement, preferred: string): string {
  if (selectorUniquelyMatches(el, preferred)) return preferred;
  return cssPathSelectorForElement(el);
}

function selectorUniquelyMatches(el: HTMLElement, selector: string): boolean {
  try {
    const matches = Array.from(activeDocument.querySelectorAll<HTMLElement>(selector));
    return matches.length === 1 && matches[0] === el;
  } catch {
    return false;
  }
}

function selectorLooksQueryable(selector: string): boolean {
  const trimmed = selector.trim();
  if (!trimmed) return false;
  try {
    createDiv().querySelector(trimmed);
    return true;
  } catch {
    return false;
  }
}

function cssPathSelectorForElement(el: HTMLElement): string {
  const parts: string[] = [];
  let current: HTMLElement | null = el;
  for (let depth = 0; current && depth < 8; depth += 1) {
    const segment = cssPathSegment(current);
    parts.unshift(segment);
    const selector = parts.join(" > ");
    if (selectorUniquelyMatches(el, selector)) return selector;
    current = current.parentElement;
    if (current?.tagName.toLowerCase() === "body") break;
  }
  return parts.join(" > ");
}

function cssPathSegment(el: HTMLElement): string {
  const tag = el.tagName.toLowerCase();
  const id = el.getAttribute("id");
  if (id) return `${tag}#${cssClassEscape(id)}`;
  const command = el.getAttribute("data-command");
  if (command) return `${tag}[data-command="${cssEscapeAttr(command)}"]`;
  const customButtonId = el.dataset.cancipUiCustomButtonId;
  if (customButtonId) return `${tag}[data-cancip-ui-custom-button-id="${cssEscapeAttr(customButtonId)}"]`;
  const cls = String(el.className || "")
    .split(/\s+/)
    .filter(Boolean)
    .filter((item) => !/^is-|^mod-|^has-/.test(item))
    .slice(0, 2);
  const classPart = cls.length ? `.${cls.map(cssClassEscape).join(".")}` : "";
  const parent = el.parentElement;
  if (!parent) return `${tag}${classPart}`;
  const sameTag = Array.from(parent.children).filter((child) => child.tagName === el.tagName);
  const index = Math.max(1, sameTag.indexOf(el) + 1);
  return `${tag}${classPart}:nth-of-type(${index})`;
}

function cssEscapeAttr(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, "\\\"");
}

function cssClassEscape(value: string): string {
  return value.replace(/[^a-zA-Z0-9_-]/g, "\\$&");
}

function mergeUiButtonRules(existing: UiButtonRule[], incoming: UiButtonRule[]): UiButtonRule[] {
  const merged: UiButtonRule[] = [];
  const addRule = (rule: UiButtonRule): void => {
    const sameTargetIndex = merged.findIndex((item) => uiButtonRulesReferToSameTarget(item, rule));
    const nextRule = ensureUniqueUiButtonRuleId(rule, merged, sameTargetIndex);
    if (sameTargetIndex >= 0) merged[sameTargetIndex] = nextRule;
    else merged.push(nextRule);
  };
  for (const rule of existing) addRule(rule);
  for (const rule of incoming) addRule(rule);
  return merged.slice(-200);
}

function ensureUniqueUiButtonRuleId(rule: UiButtonRule, existing: UiButtonRule[], replaceIndex: number): UiButtonRule {
  const conflict = existing.some((item, index) => index !== replaceIndex && item.id === rule.id);
  if (!conflict) return rule;
  const base = stableRuleId([uiButtonRuleStableIdInput(rule.scope, rule.selector, rule.label), rule.targetKey ?? ""].join(":"));
  let id = base;
  let suffix = 2;
  while (existing.some((item, index) => index !== replaceIndex && item.id === id)) {
    id = `${base.slice(0, 72)}-${suffix}`;
    suffix += 1;
  }
  if (rule.kind !== "custom") return { ...rule, id };
  return {
    ...rule,
    id,
    selector: `[data-cancip-ui-custom-button-id="${cssEscapeAttr(id)}"]`
  };
}

function uniqueElements<T extends Element>(values: Array<T | null | undefined>): T[] {
  const seen = new Set<T>();
  const result: T[] = [];
  for (const value of values) {
    if (!value || seen.has(value)) continue;
    seen.add(value);
    result.push(value);
  }
  return result;
}

function uiButtonRuleStableIdInput(scope: UiButtonRule["scope"], selector: string, label: string): string {
  return uiButtonSelectorRequiresLabelGuard(selector)
    ? `${scope}:${selector}:${normalizeUiButtonLabel(label)}`
    : `${scope}:${selector}`;
}

function uiButtonRulesReferToSameTarget(a: UiButtonRule, b: UiButtonRule): boolean {
  if (a.kind === "custom" || b.kind === "custom") {
    if (a.kind !== "custom" || b.kind !== "custom") return false;
    if (a.id && b.id && a.id === b.id) return true;
    return uiButtonCustomRuleIdentity(a) === uiButtonCustomRuleIdentity(b);
  }
  if (a.id && b.id && a.id === b.id) {
    if (a.scope !== b.scope || a.selector !== b.selector) return false;
    const aLabel = normalizeUiButtonLabel(a.label || "");
    const bLabel = normalizeUiButtonLabel(b.label || "");
    const sameLabel = !aLabel || !bLabel || aLabel === bLabel;
    if (!sameLabel) return false;
    if (a.targetKey && b.targetKey) return a.targetKey === b.targetKey || a.targetKey === b.legacyTargetKey || a.legacyTargetKey === b.targetKey;
    return true;
  }
  if (a.targetKey && b.targetKey && a.targetKey !== b.targetKey && a.targetKey !== b.legacyTargetKey && a.legacyTargetKey !== b.targetKey) return false;
  return uiButtonRuleMatchesTarget(a, b.selector, b.scope, b.label);
}

function uiButtonCustomRuleIdentity(rule: UiButtonRule): string {
  return [
    rule.scope,
    rule.commandId?.trim() ?? "",
    rule.anchorSelector?.trim() ?? "",
    normalizeUiButtonLabel(rule.anchorLabel ?? ""),
    rule.insertPosition ?? "after",
    normalizeUiButtonLabel(rule.title || rule.label || rule.commandName || "")
  ].join("\n");
}

function uiButtonRuleMatchesTarget(rule: UiButtonRule, selector: string, scope: UiButtonRule["scope"], label: string): boolean {
  if (rule.kind === "custom") return false;
  if (rule.selector !== selector || rule.scope !== scope) return false;
  if (!uiButtonRuleHasLabelGuard(rule)) return true;
  return uiButtonRuleAllowsLabel(rule, label || selector);
}

function uiButtonSelectorRequiresLabelGuard(selector: string): boolean {
  const normalized = selector.trim();
  return isBroadUiButtonSelector(normalized)
    || /\.menu(?:\s|\.|>|$)/.test(normalized)
    || /\.menu-group\b/.test(normalized)
    || /\.menu-item\b/.test(normalized)
    || /\[role=['"]?menuitem['"]?\]/i.test(normalized)
    || /\[data-command=/.test(normalized)
    || normalized === ".status-bar .status-bar-item"
    || /:nth-of-type\(/.test(normalized);
}

function isBroadUiButtonSelector(selector: string): boolean {
  const normalized = selector.trim();
  return normalized === ".menu .menu-item"
    || normalized === UI_BUTTON_MENU_ITEM_SELECTOR
    || normalized === ".menu-group .menu-item"
    || normalized === ".menu [role='menuitem']"
    || normalized === ".menu-item"
    || normalized === "[role='menuitem']"
    || /^[a-z0-9_-]+$/i.test(normalized);
}

function uiButtonRuleHasLabelGuard(rule: Pick<UiButtonRule, "selector" | "label" | "title" | "commandName">): boolean {
  return uiButtonSelectorRequiresLabelGuard(rule.selector);
}

function uiButtonRuleReferenceLabels(rule: Pick<UiButtonRule, "selector" | "label" | "title" | "commandName">): string[] {
  const selectorLabel = normalizeUiButtonLabel(rule.selector);
  return uniqueStrings([rule.label, rule.title, rule.commandName]
    .map((item) => normalizeUiButtonLabel(item ?? ""))
    .filter((item) => item && item !== selectorLabel));
}

function uiButtonElementMatchesRuleLabel(rule: Pick<UiButtonRule, "selector" | "label" | "title" | "commandName">, el: HTMLElement): boolean {
  return uiButtonRuleAllowsLabel(rule, uiElementLabel(el));
}

function uiButtonRuleAllowsLabel(rule: Pick<UiButtonRule, "selector" | "label" | "title" | "commandName">, label: string): boolean {
  const wanted = uiButtonRuleReferenceLabels(rule);
  if (!wanted.length) return !uiButtonSelectorRequiresLabelGuard(rule.selector);
  const current = normalizeUiButtonLabel(label || "");
  return Boolean(current && wanted.includes(current));
}

function uiButtonRuleLooksMenuOnly(rule: UiButtonRule, selector: string): boolean {
  const selectors = uniqueStrings([
    selector,
    rule.selector,
    rule.fallbackSelector ?? "",
    rule.commandId?.startsWith("uiclick:") ? rule.commandId.slice("uiclick:".length) : ""
  ].map((item) => item.trim()).filter(Boolean));
  return selectors.some(uiButtonSelectorLooksMenuSelector) && uiButtonRuleReferenceLabels(rule).length > 0;
}

function uiButtonSelectorLooksMenuSelector(selector: string): boolean {
  const normalized = selector.trim();
  return /\.menu(?:\s|\.|>|$)/.test(normalized)
    || /\.menu-group\b/.test(normalized)
    || /\.menu-item\b/.test(normalized)
    || /\[role=['"]?menuitem['"]?\]/i.test(normalized);
}

function workspaceLeafArea(leaf: WorkspaceLeaf): WorkspaceTabInfo["area"] {
  const viewContainer = (leaf.view as unknown as { containerEl?: HTMLElement })?.containerEl;
  const leafContainer = (leaf as unknown as { containerEl?: HTMLElement }).containerEl;
  const parentContainer = (leaf.parent as unknown as { containerEl?: HTMLElement }).containerEl;
  const candidates = [viewContainer, leafContainer, parentContainer].filter((item): item is HTMLElement => Boolean(item));
  for (const container of candidates) {
    if (container.closest(".mod-right-split, .workspace-split.mod-right-split, .workspace-drawer.mod-right, .workspace-drawer-right, .workspace-drawer.is-right, .workspace-drawer.mod-sidedock.mod-right")) return "right";
    if (container.closest(".mod-left-split, .workspace-split.mod-left-split, .workspace-drawer.mod-left, .workspace-drawer-left, .workspace-drawer.is-left, .workspace-drawer.mod-sidedock.mod-left")) return "left";
    if (container.closest(".workspace-popout, .mod-popout")) return "floating";
  }
  const haystack = candidates.map((container) => `${container.className ?? ""} ${container.getAttribute("aria-label") ?? ""}`).join(" ").toLowerCase();
  if (/\bright\b|右侧|右側|右边|右邊/.test(haystack)) return "right";
  if (/\bleft\b|左侧|左側|左边|左邊/.test(haystack)) return "left";
  if (candidates.some((container) => container.closest(".workspace-tabs, .workspace-leaf"))) return "root";
  return "unknown";
}

function workspaceLeafPinned(leaf: WorkspaceLeaf): boolean {
  try {
    return leaf.getViewState().pinned === true;
  } catch {
    return false;
  }
}

function workspaceLeafContainer(leaf: WorkspaceLeaf): HTMLElement | null {
  const viewContainer = (leaf.view as unknown as { containerEl?: HTMLElement })?.containerEl;
  const leafContainer = (leaf as unknown as { containerEl?: HTMLElement }).containerEl;
  return leafContainer ?? viewContainer?.closest<HTMLElement>(".workspace-leaf") ?? viewContainer ?? null;
}

function workspaceLeafTabsContainer(leaf: WorkspaceLeaf): HTMLElement | null {
  const parentContainer = (leaf.parent as unknown as { containerEl?: HTMLElement }).containerEl;
  if (parentContainer?.matches(".workspace-tabs")) return parentContainer;
  const leafContainer = workspaceLeafContainer(leaf);
  return leafContainer?.closest<HTMLElement>(".workspace-tabs, .workspace-drawer-tab-container, .workspace-drawer-tabs") ?? parentContainer ?? null;
}

function workspaceLeafIsDomActive(leaf: WorkspaceLeaf): boolean {
  const container = workspaceLeafContainer(leaf);
  if (!container) return false;
  if (container.hasClass("mod-active") || container.hasClass("is-active")) return true;
  const tabs = workspaceLeafTabsContainer(leaf);
  const activeHeader = tabs?.querySelector<HTMLElement>(".workspace-tab-header.is-active, .workspace-tab-header.mod-active");
  if (!activeHeader) return false;
  const index = activeWorkspaceTabHeaderIndex(activeHeader);
  return orderedWorkspaceLeavesFromParent(leaf.parent)[index] === leaf;
}

function activeWorkspaceTabHeaderIndex(headerOrContainer: HTMLElement): number {
  const tabs = headerOrContainer.closest<HTMLElement>(".workspace-tabs");
  if (!tabs) return -1;
  const headerContainer = tabs.querySelector<HTMLElement>(":scope > .workspace-tab-header-container")
    ?? tabs.querySelector<HTMLElement>(".workspace-tab-header-container");
  const headers = headerContainer
    ? Array.from(headerContainer.querySelectorAll<HTMLElement>(".workspace-tab-header"))
    : [];
  if (!headers.length) return -1;
  const activeHeader = headers.find((header) => header.hasClass("is-active") || header.hasClass("mod-active"));
  const fallbackHeader = headerOrContainer.matches(".workspace-tab-header")
    ? headerOrContainer
    : headerOrContainer.querySelector<HTMLElement>(".workspace-tab-header.is-active, .workspace-tab-header.mod-active, .workspace-tab-header");
  const selected = activeHeader ?? fallbackHeader ?? headers[0];
  return selected ? headers.indexOf(selected) : -1;
}

function orderedWorkspaceLeavesFromParent(parent: WorkspaceLeaf["parent"]): WorkspaceLeaf[] {
  const runtime = parent as unknown as {
    children?: unknown[];
    leaves?: unknown[];
    activeTab?: number;
    activeLeaf?: WorkspaceLeaf;
    currentLeaf?: WorkspaceLeaf;
  };
  const candidates = Array.isArray(runtime.children)
    ? runtime.children
    : Array.isArray(runtime.leaves)
      ? runtime.leaves
      : [];
  return candidates.filter((item): item is WorkspaceLeaf => Boolean(item && typeof item === "object" && "getViewState" in item && "detach" in item));
}

function orderedWorkspaceTabInfosFromParent(tabs: WorkspaceTabInfo[]): WorkspaceTabInfo[] {
  if (!tabs.length) return tabs;
  const orderedLeaves = orderedWorkspaceLeavesFromParent(tabs[0].leaf.parent);
  if (!orderedLeaves.length) return tabs;
  const order = new Map<WorkspaceLeaf, number>(orderedLeaves.map((leaf, index) => [leaf, index]));
  return [...tabs].sort((a, b) => (order.get(a.leaf) ?? Number.MAX_SAFE_INTEGER) - (order.get(b.leaf) ?? Number.MAX_SAFE_INTEGER));
}

function activeWorkspaceTabInfoFromParent(tabs: WorkspaceTabInfo[]): WorkspaceTabInfo | null {
  if (!tabs.length) return null;
  const parent = tabs[0].leaf.parent as unknown as {
    activeTab?: number;
    activeLeaf?: WorkspaceLeaf;
    currentLeaf?: WorkspaceLeaf;
  };
  const activeLeaf = parent.activeLeaf ?? parent.currentLeaf;
  if (activeLeaf) {
    const byLeaf = tabs.find((tab) => tab.leaf === activeLeaf);
    if (byLeaf) return byLeaf;
  }
  if (typeof parent.activeTab === "number") {
    const ordered = orderedWorkspaceTabInfosFromParent(tabs);
    return ordered[parent.activeTab] ?? null;
  }
  return null;
}

function allTagsFromCache(cache: { tags?: Array<{ tag?: string }>; frontmatter?: Record<string, unknown> }): string[] {
  const tags = new Set<string>();
  for (const item of cache.tags ?? []) {
    if (typeof item.tag === "string") tags.add(item.tag);
  }
  const frontmatterTags = cache.frontmatter?.tags ?? cache.frontmatter?.tag;
  for (const item of flattenKeywordValue(frontmatterTags)) tags.add(item);
  return [...tags];
}

function removeTagsFromMarkdown(content: string, tags: string[]): { text: string; removed: string[] } {
  const normalized = new Set(tags.map((tag) => normalizeTagName(tag)).filter(Boolean));
  const removed: string[] = [];
  if (!normalized.size) return { text: content, removed };
  let text = content.replace(/(^|\s)#([^\s#`.,;:!?()[\]{}<>，。！？、；：]+)/g, (match, prefix: string, raw: string) => {
    const tag = normalizeTagName(raw);
    if (!normalized.has(tag)) return match;
    removed.push(tag);
    return prefix;
  });
  text = text.replace(/^---\r?\n([\s\S]*?)\r?\n---/, (match, body: string) => {
    const nextBody = body
      .replace(/^tags:\s*\[(.*?)\]\s*$/gm, (line, inner: string) => {
        const kept = inner.split(",").map((item: string) => item.trim().replace(/^["']|["']$/g, "")).filter((tag: string) => {
          const normalizedTag = normalizeTagName(tag);
          if (!normalizedTag || normalized.has(normalizedTag)) {
            if (normalizedTag) removed.push(normalizedTag);
            return false;
          }
          return true;
        });
        return kept.length ? `tags: [${kept.join(", ")}]` : "";
      })
      .replace(/^tags:\s*\r?\n((?:\s*-\s*.*\r?\n?)+)/gm, (block, lines: string) => {
        const kept = lines.split(/\r?\n/).filter(Boolean).filter((line: string) => {
          const value = line.replace(/^\s*-\s*/, "").trim().replace(/^["']|["']$/g, "");
          const normalizedTag = normalizeTagName(value);
          if (!normalizedTag || normalized.has(normalizedTag)) {
            if (normalizedTag) removed.push(normalizedTag);
            return false;
          }
          return true;
        });
        return kept.length ? `tags:\n${kept.join("\n")}` : "";
      });
    return `---\n${nextBody.replace(/\n{3,}/g, "\n\n").trim()}\n---`;
  });
  text = text.replace(/[ \t]{2,}/g, " ").replace(/[ \t]+\n/g, "\n");
  return { text, removed };
}

function isToolRunStatus(value: unknown): value is ToolRunStatus {
  return value === "pending" || value === "executing" || value === "executed" || value === "blocked" || value === "failed" || value === "rejected";
}

function formatSessionHistoryTime(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  const hour = String(date.getHours()).padStart(2, "0");
  const minute = String(date.getMinutes()).padStart(2, "0");
  return `${month}-${day} ${hour}:${minute}`;
}

function extractCancipActions(answer: string): CancipAction[] {
  const actions: CancipAction[] = [];
  const fenceRegex = /```cancip-action[^\r\n]*(?:\r?\n)([\s\S]*?)```/gi;
  let match: RegExpExecArray | null;
  while ((match = fenceRegex.exec(answer)) !== null) {
    actions.push(...extractCancipActionsFromJson(match[1]));
  }
  const inlineFenceRegex = /```cancip-action\b[ \t]+([^\r\n][\s\S]*?)```/gi;
  while ((match = inlineFenceRegex.exec(answer)) !== null) {
    actions.push(...extractCancipActionsFromJson(match[1]));
  }
  const xmlRegex = /<cancip-action\b[^>]*>([\s\S]*?)<\/cancip-action>/gi;
  while ((match = xmlRegex.exec(answer)) !== null) {
    actions.push(...extractCancipActionsFromJson(match[1]));
  }
  const declarativeXmlRegex = /<cancip-action\b([^>]*?)\/\s*>/gi;
  while ((match = declarativeXmlRegex.exec(answer)) !== null) {
    const action = parseCancipAction(xmlActionAttributes(match[1] ?? ""));
    if (action) actions.push(action);
  }
  const commentRegex = /<!--\s*cancip-action\b([\s\S]*?)-->/gi;
  while ((match = commentRegex.exec(answer)) !== null) {
    actions.push(...extractCancipActionsFromJson(match[1]));
  }
  if (!actions.length) {
    actions.push(...extractCancipActionsFromXmlToolCalls(answer));
  }
  if (!actions.length) {
    const genericFenceRegex = /```(?:json|javascript|js)?[^\r\n]*(?:\r?\n)([\s\S]*?)```/gi;
    while ((match = genericFenceRegex.exec(answer)) !== null) {
      if (!/["'](?:actions|action|type|tool|command|cmd|name|function)["']\s*:/.test(match[1])) continue;
      actions.push(...extractCancipActionsFromJson(match[1]));
    }
  }
  if (!actions.length && /cancip-action/i.test(answer)) {
    actions.push(...extractCancipActionsFromLooseText(answer, true));
  }
  if (!actions.length && /["'](?:actions|action|type|tool|command|cmd|name|function)["']\s*:/.test(answer)) {
    actions.push(...extractCancipActionsFromLooseText(answer, false));
  }
  return actions.slice(0, 20);
}

function cancipActionBlockForActions(actions: CancipAction[]): string {
  return `\`\`\`cancip-action\n${JSON.stringify({ actions })}\n\`\`\``;
}

function hasCancipActionMarker(answer: string): boolean {
  return /```cancip-action\b/i.test(answer)
    || /<cancip-action\b/i.test(answer)
    || /<tool_call\b/i.test(answer)
    || /<!--\s*cancip-action\b/i.test(answer)
    || /["']cancip-action["']\s*:/i.test(answer)
    || /["'](?:actions|action|type|tool|command|cmd|name|function)["']\s*:/.test(answer);
}

function extractCancipActionsFromJson(raw: string): CancipAction[] {
  const body = raw.trim();
  if (!body) return [];
  const parsed = parseCancipActionJson(body);
  if (!parsed.ok) return [];
  return cancipActionCandidates(parsed.value)
    .map((candidate) => parseCancipAction(candidate))
    .filter((action): action is CancipAction => action !== null);
}

function parseCancipActionJson(raw: string): { ok: true; value: unknown } | { ok: false; error: string } {
  const body = raw.trim();
  if (!body) return { ok: false, error: "empty action block" };
  const firstValue = extractFirstJsonValue(body);
  const candidates = uniqueStrings([body, firstValue].filter(Boolean));
  let lastError = "invalid JSON";
  for (const candidate of candidates) {
    for (const normalized of uniqueStrings([candidate, removeJsonTrailingCommas(candidate)])) {
      try {
        return { ok: true, value: JSON.parse(normalized) as unknown };
      } catch (error) {
        lastError = error instanceof Error ? error.message : String(error);
      }
    }
  }
  return { ok: false, error: trimContext(lastError.replace(/^JSON\.parse:\s*/i, ""), 180) };
}

function removeJsonTrailingCommas(input: string): string {
  let output = "";
  let inString = false;
  let escaped = false;
  for (let index = 0; index < input.length; index += 1) {
    const char = input[index];
    if (inString) {
      output += char;
      if (escaped) escaped = false;
      else if (char === "\\") escaped = true;
      else if (char === "\"") inString = false;
      continue;
    }
    if (char === "\"") {
      inString = true;
      output += char;
      continue;
    }
    if (char === ",") {
      let next = index + 1;
      while (next < input.length && /\s/.test(input[next])) next += 1;
      if (input[next] === "}" || input[next] === "]") continue;
    }
    output += char;
  }
  return output;
}

function cancipActionCandidates(parsed: unknown): unknown[] {
  if (Array.isArray(parsed)) return parsed;
  if (!isRecord(parsed)) return [parsed];
  for (const key of ["actions", "tool_calls", "toolCalls"]) {
    const value = parsed[key];
    if (Array.isArray(value)) return value;
    if (isRecord(value)) return [value];
  }
  for (const key of ["cancip-action", "cancipAction", "tool_call", "toolCall"]) {
    const value = parsed[key];
    if (Array.isArray(value)) return value;
    if (isRecord(value)) return [value];
  }
  return [parsed];
}

function cancipActionBlockBodies(answer: string): string[] {
  const bodies: string[] = [];
  const patterns = [
    /```cancip-action[^\r\n]*(?:\r?\n)([\s\S]*?)```/gi,
    /```cancip-action\b[ \t]+([^\r\n][\s\S]*?)```/gi,
    /<cancip-action\b[^>]*>([\s\S]*?)<\/cancip-action>/gi,
    /<!--\s*cancip-action\b([\s\S]*?)-->/gi
  ];
  for (const pattern of patterns) {
    let match: RegExpExecArray | null;
    while ((match = pattern.exec(answer)) !== null) {
      const body = match[1]?.trim();
      if (body) bodies.push(body);
    }
  }
  return uniqueStrings(bodies);
}

/**
 * Some compatible OpenAI endpoints return XML-like tool markup instead of the
 * JSON action contract. Convert the small, declarative subset into the same
 * action type so permission checks and verification are never bypassed.
 */
function extractCancipActionsFromXmlToolCalls(answer: string): CancipAction[] {
  const actions: CancipAction[] = [];
  const callRegex = /<tool_call\b[^>]*>([\s\S]*?)(?:<\/tool_call>|(?=<tool_call\b)|$)/gi;
  let match: RegExpExecArray | null;
  while ((match = callRegex.exec(answer)) !== null) {
    const body = match[1] ?? "";
    const name = xmlToolCallValue(body, "tool_name")
      || decodeXmlToolCallText(/<function\s*=\s*([^>\s]+)\s*>/i.exec(body)?.[1] ?? "").trim();
    if (!name) continue;
    const parametersBody = xmlToolCallValue(body, "parameters");
    const parameters = parametersBody
      ? xmlToolCallParameters(parametersBody)
      : xmlAssignedToolCallParameters(body);
    const direct = parseCancipAction({ type: name, ...parameters });
    if (direct) {
      actions.push(direct);
      continue;
    }
    if (isCommandBusToolActionType(name) || isObsidianExecuteCommandAlias(name) || isObsidianEvalCommandAlias(name)) {
      const command = isObsidianExecuteCommandAlias(name)
        ? "obsidian.execute"
        : isObsidianEvalCommandAlias(name)
          ? "obsidian.eval"
          : name;
      actions.push({ type: "command", command, args: parameters });
    }
  }
  return uniqueCancipActions(actions).slice(0, 20);
}

function xmlToolCallValue(body: string, tag: string): string {
  const escaped = escapeRegExp(tag);
  const match = new RegExp(`<${escaped}\\b[^>]*>([\\s\\S]*?)<\\/${escaped}>`, "i").exec(body);
  return decodeXmlToolCallText(match?.[1] ?? "").trim();
}

function xmlActionAttributes(source: string): Record<string, unknown> {
  const attributes: Record<string, unknown> = {};
  const attributeRegex = /([A-Za-z][A-Za-z0-9_-]*)\s*=\s*(?:"([^"]*)"|'([^']*)')/g;
  let match: RegExpExecArray | null;
  while ((match = attributeRegex.exec(source)) !== null) {
    const key = match[1]?.trim();
    if (!key) continue;
    attributes[key] = decodeXmlToolCallText(match[2] ?? match[3] ?? "");
  }
  return attributes;
}

function xmlToolCallParameters(body: string): Record<string, unknown> {
  const text = body.trim();
  if (!text) return {};
  const parsed = parseCancipActionJson(text);
  if (parsed.ok && isRecord(parsed.value)) return parsed.value;
  const parameters: Record<string, unknown> = {};
  const tagRegex = /<([A-Za-z][A-Za-z0-9_-]*)\b[^>]*>([\s\S]*?)<\/\1>/g;
  let match: RegExpExecArray | null;
  while ((match = tagRegex.exec(text)) !== null) {
    const key = match[1]?.trim();
    if (!key || key === "parameters") continue;
    const value = decodeXmlToolCallText(match[2] ?? "").trim();
    if (!value) continue;
    const nested = parseCancipActionJson(value);
    parameters[key] = nested.ok ? nested.value : value;
  }
  return parameters;
}

function xmlAssignedToolCallParameters(body: string): Record<string, unknown> {
  const parameters: Record<string, unknown> = {};
  const parameterRegex = /<parameter\s*=\s*([A-Za-z][A-Za-z0-9_-]*)\s*>([\s\S]*?)<\/parameter>/gi;
  let match: RegExpExecArray | null;
  while ((match = parameterRegex.exec(body)) !== null) {
    const key = match[1]?.trim();
    if (!key) continue;
    const value = decodeXmlToolCallText(match[2] ?? "").trim();
    if (!value) continue;
    const nested = parseCancipActionJson(value);
    parameters[key] = nested.ok ? nested.value : value;
  }
  return parameters;
}

function decodeXmlToolCallText(value: string): string {
  return value
    .replace(/&quot;/gi, '"')
    .replace(/&apos;/gi, "'")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&amp;/gi, "&");
}

function cancipActionProtocolIssue(answer: string): string {
  if (!hasCancipActionMarker(answer) || extractCancipActions(answer).length) return "";
  const bodies = cancipActionBlockBodies(answer);
  if (!bodies.length) return "动作标记存在，但没有完整的动作 JSON 块";
  for (const body of bodies) {
    const parsed = parseCancipActionJson(body);
    if (!parsed.ok) return `动作 JSON 语法错误：${parsed.error}`;
    const candidates = cancipActionCandidates(parsed.value);
    const names = uniqueStrings(candidates.map((candidate) => {
      if (!isRecord(candidate)) return "";
      for (const key of ["type", "action", "tool", "command", "cmd", "name"]) {
        const value = candidate[key];
        if (typeof value === "string" && value.trim()) return value.trim();
      }
      return "";
    }).filter(Boolean));
    if (names.length) return `动作 ${names.join(", ")} 未匹配可执行协议`;
  }
  return "动作 JSON 缺少可执行的 type/command 和必需参数";
}

function invalidCancipActionFailureReason(issue: string, chinese: boolean): string {
  const detail = trimContext(redactSensitiveText(issue.replace(/\s+/g, " ").trim()), 180);
  return chinese
    ? `模型返回了非空内容，但动作格式无效：${detail}`
    : `The model returned non-empty content, but its action format was invalid: ${detail}`;
}

function extractCancipActionsFromLooseText(input: string, includeCommandKey = false): CancipAction[] {
  const actions: CancipAction[] = [];
  const seen = new Set<string>();
  const keyRegex = includeCommandKey
    ? /["'](?:actions|action|type|tool|command|cmd|name|function)["']\s*:/g
    : /["'](?:actions|action|type|tool|cmd|name|function)["']\s*:/g;
  let match: RegExpExecArray | null;
  while ((match = keyRegex.exec(input)) !== null) {
    const candidate = extractJsonObjectAroundIndex(input, match.index);
    if (!candidate || seen.has(candidate)) continue;
    seen.add(candidate);
    actions.push(...extractCancipActionsFromJson(candidate));
  }
  return actions;
}

function removeLooseCancipActionJson(input: string): string {
  let output = input;
  const candidates: string[] = [];
  const keyRegex = /["'](?:actions|action|type|tool|command|cmd|name|function)["']\s*:/g;
  let match: RegExpExecArray | null;
  while ((match = keyRegex.exec(input)) !== null) {
    const candidate = extractJsonObjectAroundIndex(input, match.index);
    if (!candidate || !extractCancipActionsFromJson(candidate).length) continue;
    candidates.push(candidate);
  }
  for (const candidate of uniqueStrings(candidates).sort((a, b) => b.length - a.length)) {
    output = output.split(candidate).join("\n\n");
  }
  return output;
}

function extractJsonObjectAroundIndex(input: string, index: number): string {
  let start = index;
  while (start >= 0 && input[start] !== "{") start -= 1;
  if (start < 0) return "";
  return extractJsonValueAt(input, start);
}

function extractFirstJsonValue(input: string): string {
  const brace = input.indexOf("{");
  const bracket = input.indexOf("[");
  const start = brace < 0 ? bracket : bracket < 0 ? brace : Math.min(brace, bracket);
  if (start < 0) return "";
  return extractJsonValueAt(input, start);
}

function parseUiButtonClipboardPayload(text: string): UiButtonClipboardPayload | null {
  const body = text.trim();
  if (!body) return null;
  const candidates = uniqueStrings([body, extractFirstJsonValue(body)]).filter(Boolean);
  for (const candidate of candidates) {
    let parsed: unknown;
    try {
      parsed = JSON.parse(candidate) as unknown;
    } catch {
      continue;
    }
    if (!isRecord(parsed)) continue;
    if (parsed.schema !== "cancip-ui-button" || parsed.version !== 1) continue;
    const commandId = typeof parsed.commandId === "string" ? parsed.commandId.trim() : "";
    const label = typeof parsed.label === "string" ? parsed.label.trim() : "";
    if (!commandId) continue;
    const insertPosition = parsed.insertPosition === "before" || parsed.insertPosition === "after" ? parsed.insertPosition : undefined;
    return {
      schema: "cancip-ui-button",
      version: 1,
      label: label || commandId,
      title: typeof parsed.title === "string" && parsed.title.trim() ? parsed.title.trim() : undefined,
      icon: typeof parsed.icon === "string" && parsed.icon.trim() ? parsed.icon.trim() : undefined,
      commandId,
      commandName: typeof parsed.commandName === "string" && parsed.commandName.trim() ? parsed.commandName.trim() : undefined,
      fallbackSelector: typeof parsed.fallbackSelector === "string" && parsed.fallbackSelector.trim() ? parsed.fallbackSelector.trim() : undefined,
      insertPosition
    };
  }
  return null;
}

function extractJsonValueAt(input: string, start: number): string {
  if (start < 0 || start >= input.length) return "";
  const opener = input[start];
  if (opener !== "{" && opener !== "[") return "";
  const closer = opener === "{" ? "}" : "]";
  const stack: string[] = [];
  let inString = false;
  let escaped = false;
  for (let index = start; index < input.length; index += 1) {
    const char = input[index];
    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (char === "\\") {
        escaped = true;
      } else if (char === "\"") {
        inString = false;
      }
      continue;
    }
    if (char === "\"") {
      inString = true;
      continue;
    }
    if (char === "{" || char === "[") {
      stack.push(char === "{" ? "}" : "]");
      continue;
    }
    if (char === "}" || char === "]") {
      if (!stack.length || stack[stack.length - 1] !== char) return "";
      stack.pop();
      if (!stack.length) return input.slice(start, index + 1).trim();
    }
  }
  return closer && stack.length ? "" : input.slice(start).trim();
}

function commandArgsFromLooseObsidianAction(input: Record<string, unknown>): Record<string, unknown> {
  const args: Record<string, unknown> = isRecord(input.args) ? { ...input.args } : {};
  for (const key of ["id", "commandId", "command", "name", "query"]) {
    if (typeof args[key] === "string" && String(args[key]).trim()) return args;
    const value = input[key];
    if (typeof value === "string" && value.trim()) {
      args[key] = value.trim();
      return args;
    }
  }
  return args;
}

function commandArgsFromLooseJsAction(input: Record<string, unknown>): Record<string, unknown> {
  const args: Record<string, unknown> = isRecord(input.args) ? { ...input.args } : {};
  for (const key of ["code", "script", "js", "body", "expression", "timeoutMs", "maxChars"]) {
    if (Object.prototype.hasOwnProperty.call(args, key)) continue;
    if (Object.prototype.hasOwnProperty.call(input, key)) args[key] = input[key];
  }
  return args;
}

function commandArgsFromLooseToolAction(input: Record<string, unknown>): Record<string, unknown> | undefined {
  const nestedArgs = normalizeLooseToolArgs(input.args)
    ?? normalizeLooseToolArgs(input.params)
    ?? normalizeLooseToolArgs(input.arguments)
    ?? normalizeLooseFunctionToolArgs(input.function);
  if (nestedArgs) {
    const merged: Record<string, unknown> = { ...nestedArgs };
    for (const [key, value] of Object.entries(input)) {
      if (isLooseToolControlKey(key)) continue;
      if (!Object.prototype.hasOwnProperty.call(merged, key)) merged[key] = value;
    }
    return normalizeCommandArgsSynonyms(merged);
  }
  if (isRecord(input.args)) return input.args;
  const args: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(input)) {
    if (isLooseToolControlKey(key)) continue;
    args[key] = value;
  }
  return Object.keys(args).length ? normalizeCommandArgsSynonyms(args) : undefined;
}

function isLooseToolControlKey(key: string): boolean {
  return /^(?:type|action|tool|command|cmd|name|function|args|params|arguments)$/i.test(key);
}

function normalizeLooseToolArgs(value: unknown): Record<string, unknown> | undefined {
  if (isRecord(value)) return { ...value };
  if (typeof value !== "string" || !value.trim()) return undefined;
  try {
    const parsed = JSON.parse(value) as unknown;
    return isRecord(parsed) ? { ...parsed } : undefined;
  } catch {
    return undefined;
  }
}

function normalizeLooseFunctionToolArgs(value: unknown): Record<string, unknown> | undefined {
  if (!isRecord(value)) return undefined;
  return normalizeLooseToolArgs(value.arguments);
}

function normalizeCommandArgsSynonyms(args: Record<string, unknown>): Record<string, unknown> {
  const next: Record<string, unknown> = { ...args };
  if (!Object.prototype.hasOwnProperty.call(next, "query")) {
    for (const key of ["q", "search", "text", "target", "name", "path"]) {
      const value = next[key];
      if (typeof value === "string" && value.trim()) {
        next.query = value.trim();
        break;
      }
    }
  }
  if (typeof next.kind === "string" && !Object.prototype.hasOwnProperty.call(next, "targetKind")) next.targetKind = next.kind;
  if (typeof next.type === "string" && !Object.prototype.hasOwnProperty.call(next, "targetKind")) next.targetKind = next.type;
  return next;
}

function isCommandBusToolActionType(actionType: string): boolean {
  return /^(?:cancip|obsidian|web|github|js|javascript|browser)\./i.test(actionType.trim());
}

function isLooseDirectActionCommand(actionType: string): boolean {
  return /^(?:read|write|append|patch|config|todo|automation|mkdir|rename|move|copy|delete|remove|search)$/i.test(actionType.trim());
}

function directActionFromCommandAlias(command: string, args?: Record<string, unknown>): CancipAction | null {
  const match = command.trim().match(/^(?:cancip\.)?(read|write|append|patch|config|mkdir|rename|move|copy|delete)$/i);
  if (!match) return null;
  const payload = args && isRecord(args.input) ? args.input : args;
  if (!payload) return null;
  return parseCancipAction({ type: match[1].toLowerCase(), ...payload });
}

const LOOSE_DIRECT_ACTION_ALIASES = new Map<string, string>([
  ["readfile", "read"],
  ["writefile", "write"],
  ["appendfile", "append"],
  ["patchfile", "patch"],
  ["deletefile", "delete"],
  ["removefile", "delete"],
  ["movefile", "move"],
  ["renamefile", "rename"],
  ["copyfile", "copy"],
  ["createfolder", "mkdir"],
  ["makefolder", "mkdir"]
]);

const LOOSE_ACTION_COMMAND_ALIASES = new Map<string, string>([
  ["findtarget", "cancip.findTarget"],
  ["find", "cancip.findTarget"],
  ["openfile", "cancip.openFile"],
  ["openpath", "cancip.openPath"],
  ["searchvault", "cancip.searchVault"],
  ["sessionhistory", "cancip.sessionHistory"],
  ["currentview", "obsidian.currentView"],
  ["listcommands", "obsidian.listCommands"],
  ["resolvecommand", "obsidian.resolveCommand"],
  ["executecommand", "obsidian.execute"],
  ["tools.index", "cancip.tools.index"],
  ["tools.help", "cancip.tools.help"],
  ["plugincapabilities", "cancip.pluginCapabilities"],
  ["pluginroute", "cancip.pluginRoute"],
  ["pluginaction", "cancip.pluginAction"],
  ["outcome.observe", "cancip.outcome.observe"],
  ["outcome.verify", "cancip.outcome.verify"],
  ["outcome.capture", "cancip.outcome.capture"],
  ["outcome.exportpdf", "cancip.outcome.exportPdf"],
  ["skills.list", "cancip.skills.list"],
  ["skills.read", "cancip.skills.read"],
  ["experience.list", "cancip.experience.list"],
  ["experience.harvest", "cancip.experience.harvest"]
]);

function looseActionAliasKey(value: string): string {
  return value.trim().replace(/[\s_-]+/g, "").toLowerCase();
}

function optionalActionNumber(input: Record<string, unknown>, ...keys: string[]): number | undefined {
  for (const key of keys) {
    const value = input[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
    const parsed = Number.parseInt(String(value ?? ""), 10);
    if (Number.isFinite(parsed)) return parsed;
  }
  return undefined;
}

function optionalActionString(input: Record<string, unknown>, ...keys: string[]): string | undefined {
  for (const key of keys) {
    const value = input[key];
    if (typeof value === "string") return value;
  }
  return undefined;
}

function parseCancipAction(input: unknown): CancipAction | null {
  if (!isRecord(input)) {
    return null;
  }
  if (isRecord(input.action)) return parseCancipAction(input.action);
  if (isRecord(input.tool)) return parseCancipAction(input.tool);
  if (isRecord(input.function)) {
    const functionName = typeof input.function.name === "string" ? input.function.name.trim() : "";
    if (functionName) {
      return parseCancipAction({
        type: "command",
        command: functionName,
        args: normalizeLooseFunctionToolArgs(input.function)
      });
    }
  }
  const looseCommand = typeof input.command === "string"
    ? input.command.trim()
    : typeof input.cmd === "string"
      ? input.cmd.trim()
      : typeof input.name === "string" && isCommandBusToolActionType(input.name)
        ? input.name.trim()
        : "";
  const actionType = typeof input.type === "string"
    ? input.type.trim()
    : typeof input.action === "string"
      ? input.action.trim()
      : typeof input.tool === "string"
        ? input.tool.trim()
        : looseCommand
          ? (isLooseDirectActionCommand(looseCommand) ? looseCommand : "command")
          : "";
  if (!actionType) return null;
  const actionKind = actionType.toLowerCase();

  const directPath = typeof input.path === "string"
    ? input.path
    : typeof input.target === "string"
      ? input.target
      : typeof input.file === "string"
        ? input.file
        : "";
  const legacyPatchContent = typeof input.content === "string" ? input.content : undefined;
  const legacyPatchChunks = normalizeStringChunks(input.chunks);
  if (actionKind === "patch" && directPath && (legacyPatchContent !== undefined || legacyPatchChunks)
    && optionalActionString(input, "find", "old", "old_string", "oldValue", "oldText", "old_text", "from", "search") === undefined
    && optionalActionString(input, "replace", "new", "new_string", "newValue", "newText", "new_text", "to", "replacement", "value") === undefined) {
    return {
      type: "write",
      path: directPath,
      content: legacyPatchContent,
      chunks: legacyPatchChunks,
      overwrite: typeof input.overwrite === "boolean" ? input.overwrite : true
    };
  }

  const directAlias = LOOSE_DIRECT_ACTION_ALIASES.get(looseActionAliasKey(actionType));
  if (directAlias) {
    const path = typeof input.path === "string"
      ? input.path
      : typeof input.target === "string"
        ? input.target
        : typeof input.file === "string"
          ? input.file
          : undefined;
    return parseCancipAction({ ...input, type: directAlias, path });
  }

  const commandAlias = LOOSE_ACTION_COMMAND_ALIASES.get(looseActionAliasKey(actionType));
  if (commandAlias) {
    return {
      type: "command",
      command: commandAlias,
      args: commandArgsFromLooseToolAction(input)
    };
  }

  if (actionKind === "command" && looseCommand) {
    const directAction = directActionFromCommandAlias(looseCommand, commandArgsFromLooseToolAction(input));
    if (directAction) return directAction;
  }

  if (isObsidianExecuteCommandAlias(actionType)) {
    const args = commandArgsFromLooseObsidianAction(input);
    return {
      type: "command",
      command: "obsidian.execute",
      args
    };
  }

  if (isObsidianEvalCommandAlias(actionType)) {
    return {
      type: "command",
      command: "obsidian.eval",
      args: commandArgsFromLooseJsAction(input)
    };
  }

  if (isObsidianJsHelpCommandAlias(actionType) || isObsidianJsProbeCommandAlias(actionType)) {
    return {
      type: "command",
      command: actionType,
      args: isRecord(input.args) ? input.args : undefined
    };
  }

  if (isCommandBusToolActionType(actionType)) {
    return {
      type: "command",
      command: actionType,
      args: commandArgsFromLooseToolAction(input)
    };
  }

  if (actionKind === "command" && typeof input.command === "string") {
    return {
      type: "command",
      command: input.command,
      args: commandArgsFromLooseToolAction(input)
    };
  }

  if (actionKind === "command" && looseCommand) {
    return {
      type: "command",
      command: looseCommand,
      args: commandArgsFromLooseToolAction(input)
    };
  }

  if (actionKind === "command") {
    const args = commandArgsFromLooseObsidianAction(input);
    if (Object.keys(args).length) {
      return {
        type: "command",
        command: "obsidian.execute",
        args
      };
    }
  }

  if (actionKind === "search") {
    const query = typeof input.query === "string"
      ? input.query
      : typeof input.content === "string"
        ? input.content
        : typeof input.path === "string"
          ? input.path
          : "";
    if (!query.trim()) return null;
    const args: Record<string, unknown> = { query };
    if (typeof input.limit === "number") args.limit = input.limit;
    else if (Number.isFinite(Number.parseInt(String(input.limit ?? ""), 10))) args.limit = Number.parseInt(String(input.limit), 10);
    if (typeof input.maxChars === "number") args.maxChars = input.maxChars;
    return {
      type: "command",
      command: "cancip.searchVault",
      args
    };
  }

  if (actionKind === "todo" && isTodoActionOperation(input.op)) {
    return {
      type: "todo",
      op: input.op,
      id: typeof input.id === "string" ? input.id : undefined,
      text: typeof input.text === "string" ? input.text : undefined,
      done: typeof input.done === "boolean" ? input.done : undefined,
      sendToModel: typeof input.sendToModel === "boolean" ? input.sendToModel : undefined,
      items: normalizeTodoActionItems(input.items)
    };
  }

  if (actionKind === "automation" && isAutomationActionOperation(input.op)) {
    return {
      type: "automation",
      op: input.op,
      id: typeof input.id === "string" ? input.id : undefined,
      title: typeof input.title === "string" ? input.title : undefined,
      prompt: typeof input.prompt === "string" ? input.prompt : undefined,
      command: typeof input.command === "string" ? input.command : undefined,
      args: isRecord(input.args) ? input.args : undefined,
      apiProfileId: typeof input.apiProfileId === "string" ? input.apiProfileId : undefined,
      model: typeof input.model === "string" ? input.model : undefined,
      schedule: isAutomationSchedule(input.schedule) ? input.schedule : undefined,
      enabled: typeof input.enabled === "boolean" ? input.enabled : undefined,
      intervalMinutes: typeof input.intervalMinutes === "number" ? input.intervalMinutes : Number.isFinite(Number.parseInt(String(input.intervalMinutes ?? ""), 10)) ? Number.parseInt(String(input.intervalMinutes), 10) : undefined,
      hour: typeof input.hour === "number" ? input.hour : Number.isFinite(Number.parseInt(String(input.hour ?? ""), 10)) ? Number.parseInt(String(input.hour), 10) : undefined,
      minute: typeof input.minute === "number" ? input.minute : Number.isFinite(Number.parseInt(String(input.minute ?? ""), 10)) ? Number.parseInt(String(input.minute), 10) : undefined,
      sessionMode: isAutomationSessionMode(input.sessionMode) ? input.sessionMode : undefined,
      sessionId: typeof input.sessionId === "string" ? input.sessionId : undefined,
      condition: typeof input.condition === "string" ? input.condition : undefined,
      watchNewFiles: typeof input.watchNewFiles === "boolean" ? input.watchNewFiles : undefined,
      newFilePattern: typeof input.newFilePattern === "string" ? input.newFilePattern : undefined,
      newFileDebounceSeconds: typeof input.newFileDebounceSeconds === "number"
        ? input.newFileDebounceSeconds
        : Number.isFinite(Number.parseInt(String(input.newFileDebounceSeconds ?? ""), 10))
          ? Number.parseInt(String(input.newFileDebounceSeconds), 10)
          : undefined,
      notifyMode: isAutomationNotifyMode(input.notifyMode) ? input.notifyMode : undefined,
      silent: typeof input.silent === "boolean" ? input.silent : undefined
    };
  }

  if (actionKind === "config") {
    const set = isRecord(input.set) ? input.set : undefined;
    const unset = Array.isArray(input.unset)
      ? input.unset.filter((item): item is string => typeof item === "string" && Boolean(item.trim()))
      : undefined;
    if (!set && !unset?.length) return null;
    return {
      type: "config",
      path: typeof input.path === "string" ? input.path : undefined,
      set,
      unset,
      replace: Boolean(input.replace)
    };
  }

  if (typeof input.path !== "string") {
    return null;
  }

  if (actionKind === "read") {
    return {
      type: "read",
      path: input.path,
      query: typeof input.query === "string" ? input.query : undefined,
      occurrence: optionalActionNumber(input, "occurrence"),
      maxChars: optionalActionNumber(input, "maxChars", "max_chars"),
      startLine: optionalActionNumber(input, "startLine", "start_line"),
      endLine: optionalActionNumber(input, "endLine", "end_line"),
      aroundLine: optionalActionNumber(input, "aroundLine", "around_line")
    };
  }

  if (actionKind === "write") {
    const chunks = normalizeStringChunks(input.chunks);
    if (typeof input.content !== "string" && !chunks) return null;
    return {
      type: "write",
      path: input.path,
      content: typeof input.content === "string" ? input.content : undefined,
      chunks,
      overwrite: typeof input.overwrite === "boolean" ? input.overwrite : undefined
    };
  }

  if (actionKind === "append") {
    const chunks = normalizeStringChunks(input.chunks);
    if (typeof input.content !== "string" && !chunks) return null;
    return { type: "append", path: input.path, content: typeof input.content === "string" ? input.content : undefined, chunks };
  }

  if (actionKind === "patch") {
    const find = optionalActionString(input, "find", "old", "old_string", "oldValue", "oldText", "old_text", "from", "search");
    const replace = optionalActionString(input, "replace", "new", "new_string", "newValue", "newText", "new_text", "to", "replacement", "value");
    if (find === undefined || replace === undefined) return null;
    return {
      type: "patch",
      path: input.path,
      find,
      replace,
      all: Boolean(input.all),
      regex: Boolean(input.regex),
      flags: typeof input.flags === "string" ? input.flags : undefined
    };
  }

  if (actionKind === "mkdir") {
    return { type: "mkdir", path: input.path };
  }

  if (actionKind === "rename" && typeof input.newPath === "string") {
    return { type: "rename", path: input.path, newPath: input.newPath };
  }

  if (actionKind === "move" && typeof input.newPath === "string") {
    return { type: "move", path: input.path, newPath: input.newPath };
  }

  if (actionKind === "copy" && typeof input.newPath === "string") {
    return { type: "copy", path: input.path, newPath: input.newPath };
  }

  if (actionKind === "delete" || actionKind === "remove") {
    return { type: "delete", path: input.path, permanent: Boolean(input.permanent) };
  }

  return null;
}

function isTodoActionOperation(value: unknown): value is TodoActionOperation {
  return value === "set" || value === "add" || value === "update" || value === "remove" || value === "list" || value === "clear";
}

function isAutomationActionOperation(value: unknown): value is AutomationActionOperation {
  return value === "add" || value === "update" || value === "remove" || value === "list" || value === "run";
}

function isAutomationSchedule(value: unknown): value is AutomationSchedule {
  return value === "manual" || value === "hourly" || value === "daily";
}

function isAutomationNotifyMode(value: unknown): value is AutomationNotifyMode {
  return value === "inherit" || value === "always" || value === "failure" || value === "never";
}

function isAutomationRunStatus(value: unknown): value is AutomationRunStatus {
  return value === "ok" || value === "failed" || value === "skipped" || value === "pending";
}

function isAcceptanceUserReportPath(path: string): boolean {
  return isPathInVaultFolder(normalizePath(path.replace(/\\/g, "/")), ACCEPTANCE_USER_REPORT_ROOT);
}

function isAutomationInternalPath(path: string, obsidianConfigDir: string): boolean {
  const normalized = normalizePath(path.replace(/\\/g, "/").replace(/^\/+/, ""));
  return isPathInVaultFolder(normalized, CANCIP_CONFIG_DIR)
    || isPathInVaultFolder(normalized, obsidianConfigDir)
    || isAcceptanceUserReportPath(normalized)
    || isPathInVaultFolder(normalized, ".trash");
}

function automationNewFilePathMatches(task: AutomationTask, path: string): boolean {
  const patterns = (task.newFilePattern || "**/*")
    .split(/[\n,;；]+/)
    .map((item) => item.trim().replace(/\\/g, "/").replace(/^\/+/, ""))
    .filter(Boolean);
  return patterns.some((pattern) => automationGlobMatches(pattern, path));
}

function automationGlobMatches(pattern: string, path: string): boolean {
  const tokenized = pattern
    .replace(/\*\*/g, "\uE000")
    .replace(/\*/g, "\uE001")
    .replace(/\?/g, "\uE002");
  const source = escapeRegExp(tokenized)
    .replace(/\uE000\//g, "(?:.*/)?")
    .replace(/\uE000/g, ".*")
    .replace(/\uE001/g, "[^/]*")
    .replace(/\uE002/g, "[^/]");
  return new RegExp(`^${source}$`, "i").test(normalizePath(path.replace(/\\/g, "/")));
}

function isAutomationSessionMode(value: unknown): value is AutomationSessionMode {
  return value === "current" || value === "new" || value === "session";
}

function normalizeTodoActionItems(raw: unknown): TodoActionItem[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  return raw
    .filter(isRecord)
    .map((item) => ({
      id: typeof item.id === "string" ? item.id : undefined,
      text: typeof item.text === "string" ? item.text : "",
      done: typeof item.done === "boolean" ? item.done : undefined,
      sendToModel: typeof item.sendToModel === "boolean" ? item.sendToModel : undefined
    }))
    .filter((item) => item.text.trim());
}

function normalizeActionPath(rawPath: string): string {
  const original = rawPath;
  const trimmed = rawPath.trim().replace(/\\/g, "/");
  if (!trimmed) throw new Error(`Invalid action path: ${original}`);
  if (trimmed.startsWith("/") || trimmed.startsWith("//")) throw new Error(`Invalid action path: ${original}`);
  if (/^[a-zA-Z]:/.test(trimmed)) throw new Error(`Invalid action path: ${original}`);
  if (/^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(trimmed)) throw new Error(`Invalid action path: ${original}`);

  const normalized = normalizePath(trimmed);
  if (!normalized || normalized === "." || normalized.startsWith("/") || normalized.startsWith("../")) {
    throw new Error(`Invalid action path: ${original}`);
  }
  if (normalized.split("/").includes("..")) throw new Error(`Invalid action path: ${original}`);
  return normalized;
}

function aiMutationCapturePathHints(action: CancipAction): string[] {
  const hints: string[] = [];
  const add = (value: unknown) => {
    if (typeof value !== "string" || !value.trim()) return;
    try {
      hints.push(normalizeActionPath(value));
    } catch {
      // Only valid Vault-relative paths may become capture scope hints.
    }
  };
  if ("path" in action) add(action.path);
  if (action.type === "rename" || action.type === "move" || action.type === "copy") add(action.newPath);
  if (action.type === "config") add(action.path?.trim() || CANCIP_CONFIG_PATH);
  if (action.type === "command") {
    const argsText = JSON.stringify(action.args ?? {}).replace(/\\\\/g, "/");
    const pluginPathPattern = /\.obsidian\/plugins\/[A-Za-z0-9._-]+\/(?:main\.js|manifest\.json|styles\.css|data\.json)/gi;
    for (const match of argsText.match(pluginPathPattern) ?? []) add(match);
  }
  return uniqueStrings(hints);
}

function aiMutationCapturePathInSourceScope(sourceText: string, rawPath: string): boolean {
  const path = normalizePath(rawPath).replace(/^\/+/, "");
  const volatilePluginData = path.match(/^\.obsidian\/plugins\/([^/]+)\/data\.json$/i);
  const source = sourceText.replace(/\\/g, "/").toLowerCase();
  if (/^\.obsidian\/workspace(?:-mobile)?\.json$/i.test(path)) return source.includes(path.toLowerCase());
  if (!volatilePluginData) return true;
  const pluginId = volatilePluginData[1].toLowerCase();
  const lowerPath = path.toLowerCase();
  return source.includes(lowerPath)
    || source.includes(`plugin:${pluginId}`)
    || source.includes(`/plugins/${pluginId}/`);
}

function scoreVaultPathCandidate(target: string, targetWithMd: string, candidate: string): number {
  const lower = target.toLowerCase();
  const lowerWithMd = targetWithMd.toLowerCase();
  const candidateLower = candidate.toLowerCase();
  if (candidateLower === lower || candidateLower === lowerWithMd) return 1000;

  const targetCompact = compactVaultPathForMatch(target);
  const targetWithMdCompact = compactVaultPathForMatch(targetWithMd);
  const candidateCompact = compactVaultPathForMatch(candidate);
  if (candidateCompact === targetCompact || candidateCompact === targetWithMdCompact) return 960;

  const targetBase = target.split("/").pop() ?? target;
  const targetBaseWithMd = targetWithMd.split("/").pop() ?? targetWithMd;
  const candidateBase = candidate.split("/").pop() ?? candidate;
  const targetBaseCompact = compactVaultPathForMatch(targetBase);
  const targetBaseWithMdCompact = compactVaultPathForMatch(targetBaseWithMd);
  const candidateBaseCompact = compactVaultPathForMatch(candidateBase);
  if (candidateBaseCompact === targetBaseCompact || candidateBaseCompact === targetBaseWithMdCompact) return 930;

  const pathScore = Math.round(normalizedSimilarity(targetWithMdCompact || targetCompact, candidateCompact) * 100);
  const baseScore = Math.round(normalizedSimilarity(targetBaseWithMdCompact || targetBaseCompact, candidateBaseCompact) * 100);
  let score = Math.max(pathScore, baseScore);
  if (candidateLower.endsWith(`/${lower}`) || candidateLower.endsWith(`/${lowerWithMd}`)) score = Math.max(score, 92);
  if (targetBaseCompact && candidateBaseCompact && (candidateBaseCompact.includes(targetBaseCompact) || targetBaseCompact.includes(candidateBaseCompact))) {
    score = Math.max(score, Math.min(89, Math.max(targetBaseCompact.length, candidateBaseCompact.length)));
  }
  return score;
}

function compactVaultPathForMatch(path: string): string {
  return normalizePath(path)
    .toLowerCase()
    .normalize("NFKC")
    .replace(/[\\/\s\-_.()[\]{}【】（）《》<>「」『』·,:：，。"'`~!！?？、]+/g, "");
}

function isReviewableVaultContentPath(rawPath: string, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): boolean {
  const normalized = normalizeActionPath(rawPath);
  if (isReviewableInternalAiPath(normalized, obsidianConfigDir, memoryFolder)) return true;
  if (isDotFolderVaultPath(normalized)) return false;
  if (isConfigOrRuntimeVaultPath(normalized, obsidianConfigDir)) return false;
  const name = normalized.split("/").filter(Boolean).pop() ?? "";
  if (!name) return false;
  const dot = name.lastIndexOf(".");
  if (dot < 1) return true;
  return REVIEWABLE_VAULT_EDIT_EXTENSIONS.has(name.slice(dot + 1).toLowerCase());
}

function isReviewableVaultPath(rawPath: string, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): boolean {
  const normalized = normalizeActionPath(rawPath);
  if (isReviewableVaultContentPath(normalized, obsidianConfigDir, memoryFolder)) return true;
  if (isReviewableInternalAiFolderPath(normalized, obsidianConfigDir, memoryFolder)) return true;
  if (isDotFolderVaultPath(normalized) || isConfigOrRuntimeVaultPath(normalized, obsidianConfigDir)) return false;
  return Boolean(normalized);
}

function isReviewableInternalAiPath(rawPath: string, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): boolean {
  const normalized = normalizeActionPath(rawPath);
  if (!normalized || isReviewGateMachineFilePath(normalized)) return false;
  const lower = normalized.toLowerCase();
  const excludedRoots = [
    SESSION_HISTORY_DIR,
    LOCAL_VERSION_DIR,
    CANCIP_MACHINE_INDEX_DIR,
    CANCIP_OUTCOME_EVIDENCE_DIR,
    REVIEW_GATE_HIDDEN_DIR,
    CANCIP_TRASH_DIR,
    CANCIP_ARCHIVE_DIR,
    CANCIP_CONFIG_BACKUP_DIR
  ].map((path) => normalizePath(path).toLowerCase());
  if (excludedRoots.some((root) => lower === root || lower.startsWith(`${root}/`))) return false;
  if (lower === ".trash" || lower.startsWith(".trash/") || lower === ".git" || lower.startsWith(".git/")) return false;
  if (isReviewableOperationalPath(normalized, obsidianConfigDir)) return true;

  const memoryRoots = uniqueStrings([memoryFolder, DEFAULT_MEMORY_FOLDER, DEFAULT_HIDDEN_MEMORY_FOLDER])
    .map((path) => normalizePath(path).replace(/\/+$/, "").toLowerCase())
    .filter(Boolean);
  if (memoryRoots.some((root) => lower === root || lower.startsWith(`${root}/`))) return true;
  if (lower === PERSONALIZATION_PRIORITY_REVIEW_PATH.toLowerCase()) return true;
  if (lower === PROJECT_MEMORY_PATH.toLowerCase() || lower === EXPERIENCE_LOG_PATH.toLowerCase()) return true;
  if (lower === AUTOMATION_DIR.toLowerCase() || lower.startsWith(`${AUTOMATION_DIR.toLowerCase()}/`)) return true;
  if (lower === CANCIP_CONFIG_PATH.toLowerCase() || lower === CANCIP_FILE_PINS_PATH.toLowerCase() || lower === AUTOMATION_STATE_PATH.toLowerCase()) return true;
  if (lower.startsWith(`${CANCIP_CONFIG_DIR.toLowerCase()}/skills/`)) return true;

  const cancipPrefix = `${CANCIP_CONFIG_DIR.toLowerCase()}/`;
  if (!lower.startsWith(cancipPrefix)) return false;
  const relative = lower.slice(cancipPrefix.length);
  if (!relative || relative.includes("/")) return false;
  const dot = relative.lastIndexOf(".");
  return dot > 0 && REVIEWABLE_VAULT_EDIT_EXTENSIONS.has(relative.slice(dot + 1));
}

function isReviewableInternalAiFolderPath(rawPath: string, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): boolean {
  const normalized = normalizeActionPath(rawPath);
  if (!normalized) return false;
  const lower = normalized.toLowerCase();
  if (lower === CANCIP_CONFIG_DIR.toLowerCase()) return true;
  const memoryRoots = uniqueStrings([memoryFolder, DEFAULT_MEMORY_FOLDER, DEFAULT_HIDDEN_MEMORY_FOLDER])
    .map((path) => normalizePath(path).replace(/\/+$/, "").toLowerCase())
    .filter(Boolean);
  if (memoryRoots.some((root) => lower === root || lower.startsWith(`${root}/`) || root.startsWith(`${lower}/`))) return true;
  if (lower === AUTOMATION_DIR.toLowerCase() || lower.startsWith(`${AUTOMATION_DIR.toLowerCase()}/`) || AUTOMATION_DIR.toLowerCase().startsWith(`${lower}/`)) return true;
  if (lower === `${CANCIP_CONFIG_DIR.toLowerCase()}/skills` || lower.startsWith(`${CANCIP_CONFIG_DIR.toLowerCase()}/skills/`)) return true;
  const configDir = normalizePath(obsidianConfigDir).replace(/\/+$/, "").toLowerCase();
  if (!configDir) return false;
  return lower === configDir
    || lower === `${configDir}/plugins`
    || new RegExp(`^${escapeRegExp(configDir)}/plugins/[^/]+$`, "i").test(lower);
}

function isReviewableOperationalPath(rawPath: string, obsidianConfigDir: string): boolean {
  const normalized = normalizeActionPath(rawPath);
  if (!normalized || isReviewGateMachineFilePath(normalized)) return false;
  const lower = normalized.toLowerCase();
  if (lower === CANCIP_CONFIG_PATH.toLowerCase()) return true;
  const configDir = normalizePath(obsidianConfigDir).toLowerCase();
  if (!configDir || !isPathInFolder(lower, configDir)) return false;
  const relative = lower.slice(configDir.length).replace(/^\/+/, "");
  if (!relative) return false;
  if (!relative.includes("/")) return /\.json$/i.test(relative);
  const pluginPrefix = "plugins/";
  if (!relative.startsWith(pluginPrefix)) return false;
  const parts = relative.slice(pluginPrefix.length).split("/").filter(Boolean);
  if (parts.length !== 2) return false;
  return /^(?:main\.js|manifest\.json|styles\.css|data\.json)$/i.test(parts[1] ?? "");
}

function isConfigOrRuntimeVaultPath(path: string, obsidianConfigDir: string): boolean {
  const normalized = normalizePath(path.replace(/\\/g, "/"));
  const lower = normalized.toLowerCase();
  const configDir = normalizePath(obsidianConfigDir).toLowerCase();
  return isCancipStoragePath(normalized)
    || isReviewGateMachineFilePath(normalized)
    || (configDir ? isPathInFolder(lower, configDir) : false)
    || lower === ".trash"
    || lower.startsWith(".trash/")
    || lower === ".git"
    || lower.startsWith(".git/");
}

function isCancipStoragePath(path: string): boolean {
  const normalized = normalizePath(path.replace(/\\/g, "/")).replace(/^\/+|\/+$/g, "");
  return isPathInVaultFolder(normalized, CANCIP_CONFIG_DIR)
    || isPathInVaultFolder(normalized, LEGACY_CANCIP_CONFIG_DIR);
}

async function applyApprovedReviewGateItem(app: App, item: ReviewGateManifestItem, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): Promise<string> {
  const adapter = app.vault.adapter;
  const applied: string[] = [];
  const textPath = normalizeActionPath(item.path);
  const structure = normalizeReviewStructureChanges(item.structure);

  for (const change of structure) {
    const oldPath = normalizeActionPath(change.old_path || textPath);
    const newPath = normalizeActionPath(change.new_path || textPath);
    if (!isReviewableVaultPath(oldPath, obsidianConfigDir, memoryFolder) && !isReviewableVaultPath(newPath, obsidianConfigDir, memoryFolder)) continue;
    if (change.kind === "folder" && oldPath === newPath && !(item.changes ?? []).includes("delete")) {
      if (!(await adapter.exists(newPath))) {
        await ensureFolder(adapter, newPath);
        applied.push(`mkdir: ${newPath}`);
      }
      continue;
    }
    if ((change.kind === "rename" || change.kind === "move") && oldPath !== newPath) {
      if (!(await adapter.exists(oldPath))) {
        if (await adapter.exists(newPath)) {
          const repaired = await repairApprovedMoveLinks(app, oldPath, newPath, collectApprovedMoveLinkSources(app, oldPath));
          applied.push(`${change.kind}: already at ${newPath}${repaired.changedFiles ? `; links updated in ${repaired.changedFiles} file(s)` : ""}`);
          continue;
        }
        throw new Error(`review apply failed: source not found ${oldPath}`);
      }
      await ensureParentFolder(adapter, newPath);
      await renameApprovedPathWithLinks(app, oldPath, newPath);
      await waitForMetadataResolve(app, [newPath]);
      applied.push(`${change.kind}: ${oldPath} -> ${newPath}; links updated by Obsidian`);
    }
    if (change.kind === "copy" && oldPath !== newPath) {
      if (!(await adapter.exists(oldPath))) {
        throw new Error(`review apply failed: source not found ${oldPath}`);
      }
      if (await adapter.exists(newPath)) {
        applied.push(`copy: already at ${newPath}`);
        continue;
      }
      await ensureParentFolder(adapter, newPath);
      await copyApprovedReviewPath(adapter, oldPath, newPath);
      if (!(await adapter.exists(newPath))) {
        throw new Error(`review apply failed: copy verification failed ${newPath}`);
      }
      applied.push(`copy: ${oldPath} -> ${newPath}`);
    }
  }

  const changes = item.changes ?? [];
  if (changes.includes("delete") && isReviewableVaultPath(textPath, obsidianConfigDir, memoryFolder)) {
    if (await adapter.exists(textPath)) {
      await trashApprovedReviewPath(app, textPath);
      applied.push(`delete: ${textPath}`);
    }
    return applied.join("; ") || `delete: ${textPath}`;
  }

  if (item.old_text !== item.new_text && isReviewableVaultContentPath(textPath, obsidianConfigDir, memoryFolder)) {
    await ensureParentFolder(adapter, textPath);
    await adapter.write(textPath, item.new_text ?? "");
    await waitForMetadataResolve(app, [textPath]);
    applied.push(`write: ${textPath}`);
  }

  return applied.join("; ") || "approved";
}

async function renameApprovedPathWithLinks(app: App, oldPath: string, newPath: string): Promise<void> {
  const adapter = app.vault.adapter;
  const file = app.vault.getAbstractFileByPath(oldPath);
  const fallbackSources = collectApprovedMoveLinkSources(app, oldPath);
  if (file) {
    try {
      await app.fileManager.renameFile(file, newPath);
      return;
    } catch (error) {
      console.warn("Cancip approved rename via FileManager failed, falling back to adapter rename", error);
    }
  }
  await adapter.rename(oldPath, newPath);
  await repairApprovedMoveLinks(app, oldPath, newPath, fallbackSources);
}

function collectApprovedMoveLinkSources(app: App, oldPath: string): string[] {
  const oldNorm = normalizePath(oldPath);
  const oldNoExt = oldNorm.replace(/\.md$/i, "");
  const oldBase = oldNoExt.split("/").pop() ?? oldNoExt;
  const sources = new Set<string>();
  for (const [sourcePath, targets] of Object.entries(app.metadataCache.resolvedLinks ?? {})) {
    for (const targetPath of Object.keys(targets ?? {})) {
      const normalizedTarget = normalizePath(targetPath);
      if (normalizedTarget === oldNorm || normalizedTarget.replace(/\.md$/i, "") === oldNoExt) {
        sources.add(normalizePath(sourcePath));
      }
    }
  }
  for (const [sourcePath, targets] of Object.entries(app.metadataCache.unresolvedLinks ?? {})) {
    for (const targetPath of Object.keys(targets ?? {})) {
      if (approvedMoveMetadataTargetMatches(targetPath, oldNorm, oldNoExt, oldBase)) {
        sources.add(normalizePath(sourcePath));
      }
    }
  }
  return Array.from(sources);
}

function approvedMoveMetadataTargetMatches(target: string, oldPath: string, oldNoExt: string, oldBase: string): boolean {
  const normalized = normalizePath(target.trim()).replace(/\.md$/i, "");
  if (!normalized) return false;
  return normalized === oldNoExt || normalized === oldPath.replace(/\.md$/i, "") || normalized === oldBase;
}

async function repairApprovedMoveLinks(app: App, oldPath: string, newPath: string, sourcePaths?: string[]): Promise<{ changedFiles: number; replacements: number }> {
  const oldNorm = normalizePath(oldPath);
  const newNorm = normalizePath(newPath);
  if (!oldNorm || !newNorm || oldNorm === newNorm) return { changedFiles: 0, replacements: 0 };
  const newFile = app.vault.getAbstractFileByPath(newNorm);
  const oldNoExt = oldNorm.replace(/\.md$/i, "");
  const oldBase = oldNoExt.split("/").pop() ?? oldNoExt;
  const sourceSet = sourcePaths?.length ? new Set(sourcePaths.map((path) => normalizePath(path))) : null;
  const markdownFiles = sourceSet
    ? app.vault.getMarkdownFiles().filter((file) => sourceSet.has(normalizePath(file.path)))
    : app.vault.getMarkdownFiles();
  const allowBaseOnlyMatch = !!sourceSet;
  let changedFiles = 0;
  let replacements = 0;
  for (const source of markdownFiles) {
    const oldText = await app.vault.cachedRead(source);
    const newLinkText = newFile instanceof TFile
      ? app.metadataCache.fileToLinktext(newFile, source.path, true)
      : newNorm.replace(/\.md$/i, "");
    const repaired = replaceApprovedMoveLinksInText(oldText, oldNorm, newNorm, oldNoExt, oldBase, newLinkText, allowBaseOnlyMatch);
    if (repaired.text === oldText) continue;
    await app.vault.modify(source, repaired.text);
    changedFiles += 1;
    replacements += repaired.replacements;
  }
  if (changedFiles) await waitForMetadataResolve(app, markdownFiles.map((file) => file.path));
  return { changedFiles, replacements };
}

function replaceApprovedMoveLinksInText(
  text: string,
  oldPath: string,
  newPath: string,
  oldNoExt: string,
  oldBase: string,
  newLinkText: string,
  allowBaseOnlyMatch: boolean
): { text: string; replacements: number } {
  let replacements = 0;
  const next = text
    .replace(/(!?)\[\[([^\]\n]+)\]\]/g, (full, embed: string, body: string) => {
      const replaced = replaceApprovedMoveWikiBody(body, oldPath, oldNoExt, oldBase, newLinkText, allowBaseOnlyMatch);
      if (replaced === body) return full;
      replacements += 1;
      return `${embed}[[${replaced}]]`;
    })
    .replace(/(\[[^\]\n]*\]\()([^)#\n]+)(#[^)\n]*)?(\))/g, (full, prefix: string, rawTarget: string, hash: string | undefined, suffix: string) => {
      const cleanTarget = rawTarget.trim();
      if (!approvedMoveMarkdownTargetMatches(cleanTarget, oldPath, oldNoExt, oldBase, allowBaseOnlyMatch)) return full;
      replacements += 1;
      const encoded = encodeURI(newPath).replace(/[()]/g, (match) => `%${match.charCodeAt(0).toString(16).toUpperCase()}`);
      return `${prefix}${encoded}${hash ?? ""}${suffix}`;
    });
  return { text: next, replacements };
}

function replaceApprovedMoveWikiBody(body: string, oldPath: string, oldNoExt: string, oldBase: string, newLinkText: string, allowBaseOnlyMatch: boolean): string {
  const pipeIndex = body.indexOf("|");
  const linkPart = pipeIndex >= 0 ? body.slice(0, pipeIndex) : body;
  const aliasPart = pipeIndex >= 0 ? body.slice(pipeIndex) : "";
  const hashIndex = linkPart.indexOf("#");
  const target = hashIndex >= 0 ? linkPart.slice(0, hashIndex) : linkPart;
  const subpath = hashIndex >= 0 ? linkPart.slice(hashIndex) : "";
  if (!approvedMoveWikiTargetMatches(target, oldPath, oldNoExt, oldBase, allowBaseOnlyMatch)) return body;
  return `${newLinkText}${subpath}${aliasPart}`;
}

function approvedMoveWikiTargetMatches(target: string, oldPath: string, oldNoExt: string, oldBase: string, allowBaseOnlyMatch: boolean): boolean {
  const normalized = normalizePath(target.trim()).replace(/\.md$/i, "");
  if (!normalized) return false;
  return normalized === oldNoExt || normalized === oldPath.replace(/\.md$/i, "") || (allowBaseOnlyMatch && normalized === oldBase);
}

function approvedMoveMarkdownTargetMatches(target: string, oldPath: string, oldNoExt: string, oldBase: string, allowBaseOnlyMatch: boolean): boolean {
  let decoded = target;
  try {
    decoded = decodeURI(target);
  } catch {
    decoded = target;
  }
  const clean = normalizePath(decoded.replace(/^<|>$/g, "").replace(/^\.\//, "")).replace(/\.md$/i, "");
  return clean === oldNoExt || clean === oldPath.replace(/\.md$/i, "") || (allowBaseOnlyMatch && clean === oldBase);
}

async function waitForMetadataResolve(app: App, paths: string[], timeoutMs = 1200): Promise<void> {
  const wanted = new Set(paths.map((path) => normalizePath(path)).filter(Boolean));
  if (!wanted.size) return;
  await new Promise<void>((resolve) => {
    let done = false;
    const finish = () => {
      if (done) return;
      done = true;
      window.clearTimeout(timer);
      app.metadataCache.offref(refResolved);
      app.metadataCache.offref(refResolve);
      resolve();
    };
    const timer = window.setTimeout(finish, timeoutMs);
    const refResolved = app.metadataCache.on("resolved", finish);
    const refResolve = app.metadataCache.on("resolve", (file: TFile) => {
      if (wanted.has(normalizePath(file.path))) finish();
    });
  });
}

async function revertReviewGateItem(app: App, item: ReviewGateManifestItem, obsidianConfigDir: string, memoryFolder = DEFAULT_MEMORY_FOLDER): Promise<string> {
  const adapter = app.vault.adapter;
  const reverted: string[] = [];
  const textPath = normalizeActionPath(item.path);
  const structure = normalizeReviewStructureChanges(item.structure).slice().reverse();

  for (const change of structure) {
    const oldPath = normalizeActionPath(change.old_path || textPath);
    const newPath = normalizeActionPath(change.new_path || textPath);
    if (!isReviewableVaultContentPath(oldPath, obsidianConfigDir, memoryFolder) && !isReviewableVaultContentPath(newPath, obsidianConfigDir, memoryFolder)) continue;
    if ((change.kind === "rename" || change.kind === "move") && oldPath !== newPath) {
      if (await adapter.exists(newPath)) {
        await ensureParentFolder(adapter, oldPath);
        if (await adapter.exists(oldPath)) await trashApprovedReviewPath(app, oldPath);
        await adapter.rename(newPath, oldPath);
        reverted.push(`${change.kind}: ${newPath} -> ${oldPath}`);
      } else if (!(await adapter.exists(oldPath)) && item.old_text) {
        await ensureParentFolder(adapter, oldPath);
        await adapter.write(oldPath, item.old_text);
        reverted.push(`restore: ${oldPath}`);
      }
    }
    if (change.kind === "copy" && oldPath !== newPath && (await adapter.exists(newPath))) {
      await trashApprovedReviewPath(app, newPath);
      reverted.push(`remove copy: ${newPath}`);
    }
  }

  const changes = item.changes ?? [];
  if (changes.includes("create") && isReviewableVaultContentPath(textPath, obsidianConfigDir, memoryFolder)) {
    if (await adapter.exists(textPath)) {
      await trashApprovedReviewPath(app, textPath);
      reverted.push(`remove created: ${textPath}`);
    }
    return reverted.join("; ") || `remove created: ${textPath}`;
  }
  if ((changes.includes("delete") || item.old_text !== item.new_text) && isReviewableVaultContentPath(textPath, obsidianConfigDir, memoryFolder)) {
    await ensureParentFolder(adapter, textPath);
    await adapter.write(textPath, item.old_text ?? "");
    reverted.push(`restore: ${textPath}`);
  }

  return reverted.join("; ") || "reverted";
}

async function trashApprovedReviewPath(app: App, path: string): Promise<void> {
  const adapter = app.vault.adapter;
  const abstractFile = app.vault.getAbstractFileByPath(path);
  if (abstractFile) {
    try {
      await app.fileManager.trashFile(abstractFile);
      return;
    } catch {
      // Fall through to adapter trash routes.
    }
  }
  try {
    const trashed = await adapter.trashSystem(path);
    if (trashed !== false) return;
  } catch {
    // Fall through to local trash.
  }
  try {
    await adapter.trashLocal(path);
  } catch {
    const stamp = new Date().toISOString().replace(/[:.]/g, "-");
    const target = `${CANCIP_TRASH_DIR}/${stamp}/${path}`;
    await ensureParentFolder(adapter, target);
    await adapter.rename(path, target);
  }
}

async function copyApprovedReviewPath(adapter: DataAdapter, sourcePath: string, newPath: string): Promise<void> {
  const stat = await adapter.stat(sourcePath);
  if (stat?.type === "folder") {
    await ensureFolder(adapter, newPath);
    const entries = await adapter.list(sourcePath);
    for (const folder of entries.folders) {
      const childName = folder.slice(sourcePath.length).replace(/^\/+/, "");
      if (!childName) continue;
      await copyApprovedReviewPath(adapter, folder, `${newPath}/${childName}`);
    }
    for (const file of entries.files) {
      const childName = file.slice(sourcePath.length).replace(/^\/+/, "");
      if (!childName) continue;
      await ensureParentFolder(adapter, `${newPath}/${childName}`);
      await adapter.copy(file, `${newPath}/${childName}`);
    }
    return;
  }
  await adapter.copy(sourcePath, newPath);
}

function buildReviewCorrectionPrompt(item: ReviewGateManifestItem, note: string, reviewFolder: string): string {
  const path = normalizePath(item.path);
  const changeSummary = [
    item.changes?.length ? `changes: ${item.changes.join(", ")}` : "",
    item.structure?.length ? `structure: ${JSON.stringify(item.structure)}` : ""
  ].filter(Boolean).join("\n");
  return [
    "审核面板收到用户指正。请只围绕这一个文件重新修改，不要泛搜全库，不要输出套话。",
    "",
    `目标文件: ${path}`,
    `审核包: ${reviewFolder}`,
    changeSummary,
    "",
    "用户指正:",
    note,
    "",
    "当前旧文:",
    "```markdown",
    trimContext(item.old_text, REVIEW_GATE_MAX_FILE_CHARS),
    "```",
    "",
    "上一版 AI 新文:",
    "```markdown",
    trimContext(item.new_text, REVIEW_GATE_MAX_FILE_CHARS),
    "```",
    "",
    "要求:",
    "- 根据用户指正生成新的完整文件内容或最小 patch。",
    "- 用 cancip-action 写入同一个目标文件；普通 Vault 笔记会再次进入审核面板。",
    "- 不要直接说已通过，必须等工具/审核结果确认。"
  ].filter(Boolean).join("\n");
}

async function ensureParentFolder(adapter: DataAdapter, path: string): Promise<void> {
  const parent = path.split("/").slice(0, -1).join("/");
  if (parent) await ensureFolder(adapter, parent);
}

type CancipStorageMigrationStats = {
  sourceFiles: number;
  sourceFolders: number;
  copiedFiles: number;
  preservedTargetFiles: number;
  targetConflicts: number;
};

async function firstMissingCancipStorageCriticalPath(adapter: DataAdapter): Promise<string | null> {
  for (const relativePath of CANCIP_STORAGE_MIGRATION_CRITICAL_PATHS) {
    const legacyPath = `${LEGACY_CANCIP_CONFIG_DIR}/${relativePath}`;
    if (await adapter.exists(legacyPath) && !(await adapter.exists(`${CANCIP_CONFIG_DIR}/${relativePath}`))) {
      return relativePath;
    }
  }
  return null;
}

async function copyMissingCancipStoragePath(
  adapter: DataAdapter,
  sourcePath: string,
  targetPath: string,
  stats: CancipStorageMigrationStats
): Promise<void> {
  const sourceStat = await adapter.stat(sourcePath);
  if (!sourceStat) return;
  if (sourceStat.type === "file") {
    stats.sourceFiles += 1;
    const targetStat = await adapter.stat(targetPath);
    if (targetStat) {
      if (targetStat.type !== "file") throw new Error(`migration target is not a file: ${targetPath}`);
      stats.preservedTargetFiles += 1;
      if (sourceStat.size !== targetStat.size) stats.targetConflicts += 1;
      return;
    }
    await ensureParentFolder(adapter, targetPath);
    await adapter.copy(sourcePath, targetPath);
    const copiedStat = await adapter.stat(targetPath);
    if (copiedStat?.type !== "file" || copiedStat.size !== sourceStat.size) {
      throw new Error(`migration copy verification failed: ${sourcePath}`);
    }
    stats.copiedFiles += 1;
    return;
  }

  stats.sourceFolders += 1;
  await ensureFolder(adapter, targetPath);
  const listing = await adapter.list(sourcePath);
  for (const folder of listing.folders) {
    const childName = normalizePath(folder).slice(normalizePath(sourcePath).length).replace(/^\/+/, "");
    if (childName) await copyMissingCancipStoragePath(adapter, folder, `${targetPath}/${childName}`, stats);
  }
  for (const file of listing.files) {
    const childName = normalizePath(file).slice(normalizePath(sourcePath).length).replace(/^\/+/, "");
    if (childName) await copyMissingCancipStoragePath(adapter, file, `${targetPath}/${childName}`, stats);
  }
}

async function ensureFolder(adapter: DataAdapter, folderPath: string): Promise<void> {
  const folder = normalizeActionPath(folderPath);
  const parts = folder.split("/").filter(Boolean);
  let current = "";
  for (const part of parts) {
    current = current ? `${current}/${part}` : part;
    const stat = await adapter.stat(current);
    if (stat?.type === "file") throw new Error(`Path is a file: ${current}`);
    if (!stat) await adapter.mkdir(current);
  }
}

async function backupConfigBeforeCancipWrite(
  adapter: DataAdapter,
  path: string,
  nextText: string,
  deferIndexWrite = false
): Promise<ConfigBackupIndex | null> {
  const normalized = normalizeActionPath(path);
  if (!isConfigBackupCandidatePath(normalized)) return null;
  const stat = await adapter.stat(normalized);
  if (!stat || stat.type !== "file") return null;
  const oldText = await readTextWithRetry(adapter, normalized);
  const oldHash = await sha256Text(oldText);
  const nextHash = await sha256Text(nextText);

  const index = await readConfigBackupIndex(adapter);
  const entry = configBackupEntry(index, normalized);
  const backupFolder = `${CANCIP_CONFIG_BACKUP_DIR}/${await safeConfigBackupPathKey(normalized)}`;
  const now = new Date().toISOString();
  const stamp = now.replace(/[:.]/g, "-");
  if (oldHash === nextHash) {
    if (!entry.lastManualBaselineHash) {
      const manualPath = `${backupFolder}/manual-baseline.json`;
      const manualStampedPath = `${backupFolder}/${stamp}-manual-baseline.json`;
      await ensureFolder(adapter, backupFolder);
      await writeTextInChunksIfChanged(adapter, manualPath, oldText);
      await writeTextInChunks(adapter, manualStampedPath, oldText);
      entry.lastManualBaselineHash = oldHash;
      entry.lastManualBaselineAt = now;
      entry.latestManualBaselinePath = manualPath;
      entry.backups.push({ path: manualStampedPath, createdAt: now, hash: oldHash, source: "manual-baseline" });
      entry.backups = entry.backups.slice(-CANCIP_CONFIG_BACKUP_MAX_RECORDS_PER_PATH);
      if (!deferIndexWrite) await writeConfigBackupIndex(adapter, index);
    }
    return index;
  }

  const latestPath = `${backupFolder}/latest-before-cancip.json`;
  const stampedPath = `${backupFolder}/${stamp}-before-cancip.json`;

  await ensureFolder(adapter, backupFolder);
  await writeTextInChunksIfChanged(adapter, latestPath, oldText);
  const reusableBackup = entry.backups.find((backup) => backup.hash === oldHash && backup.source === "before-cancip-write");
  if (!reusableBackup || !(await adapter.exists(reusableBackup.path))) {
    await writeTextInChunks(adapter, stampedPath, oldText);
    entry.backups.push({ path: stampedPath, createdAt: now, hash: oldHash, source: "before-cancip-write" });
  }
  entry.latestBackupPath = latestPath;

  if (oldHash !== entry.lastCancipWriteHash && oldHash !== entry.lastManualBaselineHash) {
    const manualPath = `${backupFolder}/manual-baseline.json`;
    const manualStampedPath = `${backupFolder}/${stamp}-manual-baseline.json`;
    await writeTextInChunksIfChanged(adapter, manualPath, oldText);
    const reusableManual = entry.backups.find((backup) => backup.hash === oldHash && backup.source === "manual-baseline");
    if (!reusableManual || !(await adapter.exists(reusableManual.path))) {
      await writeTextInChunks(adapter, manualStampedPath, oldText);
      entry.backups.push({ path: manualStampedPath, createdAt: now, hash: oldHash, source: "manual-baseline" });
    }
    entry.lastManualBaselineHash = oldHash;
    entry.lastManualBaselineAt = now;
    entry.latestManualBaselinePath = manualPath;
  }

  entry.backups = entry.backups.slice(-CANCIP_CONFIG_BACKUP_MAX_RECORDS_PER_PATH);
  if (!deferIndexWrite) await writeConfigBackupIndex(adapter, index);
  return index;
}

async function recordCancipConfigWrite(
  adapter: DataAdapter,
  path: string,
  content: string,
  pendingIndex: ConfigBackupIndex | null = null
): Promise<void> {
  const normalized = normalizeActionPath(path);
  if (!isConfigBackupCandidatePath(normalized)) return;
  const index = pendingIndex ?? await readConfigBackupIndex(adapter);
  const entry = configBackupEntry(index, normalized);
  entry.lastCancipWriteHash = await sha256Text(content);
  entry.lastCancipWriteAt = new Date().toISOString();
  await writeConfigBackupIndex(adapter, index);
}

function isConfigBackupCandidatePath(path: string): boolean {
  const normalized = normalizePath(path);
  const lower = normalized.toLowerCase();
  if (!lower || lower.startsWith(`${CANCIP_CONFIG_BACKUP_DIR}/`)) return false;
  if (lower === CANCIP_CONFIG_PATH) return true;
  if (!lower.endsWith(".json")) return false;
  if (lower.startsWith(`${SESSION_HISTORY_DIR}/`) || lower.startsWith(`${LOCAL_VERSION_DIR}/`)) return false;
  if (lower === SESSION_HISTORY_INDEX_PATH || lower === SESSION_EVENTS_PATH || lower === LOCAL_VERSION_INDEX_PATH) return false;
  if (lower.includes("/plugins/") && lower.endsWith("/data.json")) return true;
  if (lower.endsWith("config.json") || lower.includes(".config.")) return true;
  return /(^|[/._-])(settings?|preferences?|options?|automations?)([/._-]|$)/i.test(lower);
}

async function safeConfigBackupPathKey(path: string): Promise<string> {
  const normalized = normalizePath(path);
  const slug = normalized.replace(/[^A-Za-z0-9._-]+/g, "_").replace(/^_+|_+$/g, "").slice(0, 96) || "config";
  const hash = (await sha256Text(normalized)).slice(0, 12);
  return `${slug}-${hash}`;
}

async function readConfigBackupIndex(adapter: DataAdapter): Promise<ConfigBackupIndex> {
  try {
    if (!(await adapter.exists(CANCIP_CONFIG_BACKUP_INDEX_PATH))) {
      return { schemaVersion: CANCIP_CONFIG_BACKUP_SCHEMA_VERSION, entries: {} };
    }
    const raw = JSON.parse(await adapter.read(CANCIP_CONFIG_BACKUP_INDEX_PATH)) as unknown;
    return normalizeConfigBackupIndex(raw);
  } catch {
    return { schemaVersion: CANCIP_CONFIG_BACKUP_SCHEMA_VERSION, entries: {} };
  }
}

async function writeConfigBackupIndex(adapter: DataAdapter, index: ConfigBackupIndex): Promise<void> {
  await ensureFolder(adapter, CANCIP_CONFIG_BACKUP_DIR);
  await writeTextInChunksIfChanged(adapter, CANCIP_CONFIG_BACKUP_INDEX_PATH, `${JSON.stringify(normalizeConfigBackupIndex(index))}\n`);
}

function configBackupEntry(index: ConfigBackupIndex, path: string): ConfigBackupEntry {
  const normalized = normalizePath(path);
  const existing = index.entries[normalized];
  if (existing) {
    existing.backups = Array.isArray(existing.backups) ? existing.backups : [];
    return existing;
  }
  const entry: ConfigBackupEntry = { backups: [] };
  index.entries[normalized] = entry;
  return entry;
}

function normalizeConfigBackupIndex(raw: unknown): ConfigBackupIndex {
  const entries: Record<string, ConfigBackupEntry> = {};
  if (isRecord(raw) && isRecord(raw.entries)) {
    for (const [path, value] of Object.entries(raw.entries)) {
      if (!path || !isRecord(value)) continue;
      const backups = Array.isArray(value.backups)
        ? value.backups
            .filter(isRecord)
            .map((item) => ({
              path: typeof item.path === "string" ? migrateLegacyCancipStoragePath(item.path) : "",
              createdAt: typeof item.createdAt === "string" ? item.createdAt : "",
              hash: typeof item.hash === "string" ? item.hash : "",
              source: item.source === "manual-baseline" ? "manual-baseline" as const : "before-cancip-write" as const
            }))
            .filter((item) => item.path && item.createdAt && item.hash)
            .slice(-CANCIP_CONFIG_BACKUP_MAX_RECORDS_PER_PATH)
        : [];
      entries[migrateLegacyCancipStoragePath(path)] = {
        lastCancipWriteHash: typeof value.lastCancipWriteHash === "string" ? value.lastCancipWriteHash : undefined,
        lastCancipWriteAt: typeof value.lastCancipWriteAt === "string" ? value.lastCancipWriteAt : undefined,
        lastManualBaselineHash: typeof value.lastManualBaselineHash === "string" ? value.lastManualBaselineHash : undefined,
        lastManualBaselineAt: typeof value.lastManualBaselineAt === "string" ? value.lastManualBaselineAt : undefined,
        latestBackupPath: typeof value.latestBackupPath === "string" ? migrateLegacyCancipStoragePath(value.latestBackupPath) : undefined,
        latestManualBaselinePath: typeof value.latestManualBaselinePath === "string" ? migrateLegacyCancipStoragePath(value.latestManualBaselinePath) : undefined,
        backups
      };
    }
  }
  return { schemaVersion: CANCIP_CONFIG_BACKUP_SCHEMA_VERSION, entries };
}

async function readTextIfExists(adapter: DataAdapter, path: string, fallback = ""): Promise<string> {
  return await adapter.exists(path) ? await adapter.read(path) : fallback;
}

function normalizeStringChunks(raw: unknown): string[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  const chunks = raw.filter((item): item is string => typeof item === "string");
  return chunks.length === raw.length && chunks.length ? chunks : undefined;
}

function textWriteActionContent(action: Extract<CancipAction, { type: "write" | "append" }>): string {
  if (Array.isArray(action.chunks)) return action.chunks.join("");
  if (typeof action.content === "string") return action.content;
  throw new Error(`${action.type} action requires content or chunks`);
}

function splitTextChunks(content: string, chunkSize: number): string[] {
  if (!content.length) return [""];
  if (content.length <= chunkSize) return [content];
  const chunks: string[] = [];
  for (let index = 0; index < content.length; index += chunkSize) {
    chunks.push(content.slice(index, index + chunkSize));
  }
  return chunks;
}

async function writeTextInChunks(adapter: DataAdapter, path: string, content: string): Promise<number> {
  const chunks = splitTextChunks(content, FILE_WRITE_CHUNK_SIZE);
  await adapter.write(path, chunks[0] ?? "");
  for (const chunk of chunks.slice(1)) {
    await adapter.append(path, chunk);
  }
  return chunks.length;
}

async function writeTextInChunksIfChanged(adapter: DataAdapter, path: string, content: string): Promise<boolean> {
  if (await adapter.exists(path) && await adapter.read(path) === content) return false;
  await writeTextInChunks(adapter, path, content);
  return true;
}

function normalizeTextForVerification(text: string): string {
  return text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
}

function textWriteVerificationMatches(actual: string, expected: string): boolean {
  return actual === expected || normalizeTextForVerification(actual) === normalizeTextForVerification(expected);
}

async function readTextWithRetry(adapter: DataAdapter, path: string, attempts = 4): Promise<string> {
  let lastError: unknown = null;
  for (let index = 0; index < Math.max(1, attempts); index += 1) {
    if (index > 0) await sleep([80, 180, 360, 720][Math.min(index - 1, 3)] ?? 720);
    try {
      return await adapter.read(path);
    } catch (error) {
      lastError = error;
    }
  }
  throw lastError instanceof Error ? lastError : new Error(String(lastError ?? `read failed: ${path}`));
}

async function verifyTextReadback(adapter: DataAdapter, path: string, expected: string): Promise<{ matched: boolean; actual: string }> {
  let actual = "";
  for (let attempt = 0; attempt < 4; attempt += 1) {
    actual = await readTextWithRetry(adapter, path, 2);
    if (textWriteVerificationMatches(actual, expected)) {
      return { matched: true, actual };
    }
    await sleep([80, 180, 360][Math.min(attempt, 2)] ?? 360);
  }
  return { matched: textWriteVerificationMatches(actual, expected), actual };
}

async function textReadbackFailureMessage(mode: "write" | "append" | "patch", path: string, expected: string, actual: string): Promise<string> {
  const normalizedExpected = normalizeTextForVerification(expected);
  const normalizedActual = normalizeTextForVerification(actual);
  const [expectedHash, actualHash] = await Promise.all([sha256Text(normalizedExpected), sha256Text(normalizedActual)]);
  return [
    `${mode} verification failed: ${path}`,
    `expectedChars=${expected.length}, actualChars=${actual.length}`,
    `expectedHash=${expectedHash.slice(0, 12)}, actualHash=${actualHash.slice(0, 12)}`
  ].join("\n");
}

function makeExcerpt(content: string, tokens: string[]): string {
  const normalized = content.replace(/\s+/g, " ").trim();
  const lower = normalized.toLowerCase();
  const firstHit = tokens
    .map((token) => lower.indexOf(token))
    .filter((index) => index >= 0)
    .sort((a, b) => a - b)[0];
  const start = Math.max(0, (firstHit ?? 0) - 80);
  return normalized.slice(start, start + 320);
}

function compactComposerStatusText(content: string): string {
  const normalized = redactSensitiveText(content)
    .replace(/^(?:status|progress|状态|进度|提示)\s*[:：]\s*/i, "")
    .replace(/(?:正在处理工具输出|根据工具结果继续|核对结果并推进)[…\.。\s]*/gi, "")
    .replace(/(?:^|\s)(?:```|~~~)[\s\S]*$/g, "")
    .replace(/\s+/g, " ")
    .trim();
  if (normalized.length <= 84) return normalized;
  return `${normalized.slice(0, 81).trimEnd()}...`;
}

function compactModelStreamRawText(content: string): string {
  const output: string[] = [];
  const seenEmptyEvents = new Set<string>();
  for (const line of content.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed) {
      if (output.length && output[output.length - 1] !== "") output.push("");
      continue;
    }
    if (/^(?:OPENROUTER\s+PROCESSING|: ?keep-?alive)$/i.test(trimmed)) {
      const key = trimmed.toLocaleLowerCase();
      if (seenEmptyEvents.has(key)) continue;
      seenEmptyEvents.add(key);
      output.push(line);
      continue;
    }
    if (trimmed.startsWith("data:")) {
      const payload = trimmed.slice(5).trim();
      if (payload && payload !== "[DONE]") {
        try {
          const parsed = JSON.parse(payload) as unknown;
          const hasDelta = Boolean(extractCompatibleStreamDelta(parsed) || extractResponsesStreamDelta(parsed));
          if (!hasDelta && isRecord(parsed)) {
            const key = stableTextHash(safeJsonishDisplay(parsed));
            if (seenEmptyEvents.has(key)) continue;
            seenEmptyEvents.add(key);
          }
        } catch {
          // Keep non-JSON provider events exactly as received.
        }
      }
    }
    output.push(line);
  }
  while (output[output.length - 1] === "") output.pop();
  return output.join("\n");
}

function trimContext(content: string, maxLength: number): string {
  return trimContextWithRecovery(content, maxLength, "");
}

function trimPromptPayload(content: string, maxLength: number): string {
  const trimmed = content.trim();
  if (trimmed.length <= maxLength) return trimmed;
  const suffix = "\n...[truncated]";
  return `${trimmed.slice(0, Math.max(0, maxLength - suffix.length)).trimEnd()}${suffix}`;
}

function packPromptContext(parts: string[], maxLength: number, prompt = ""): string {
  const separator = "\n\n---\n\n";
  const unique = new Map<string, { text: string; priority: number; order: number }>();
  for (const [order, raw] of parts.entries()) {
    const text = raw.trim();
    if (!text) continue;
    const key = text.replace(/\s+/g, " ").toLowerCase();
    if (unique.has(key)) continue;
    unique.set(key, { text, priority: promptContextSectionPriority(text, prompt), order });
  }
  const sections = [...unique.values()].sort((a, b) => b.priority - a.priority || a.order - b.order);
  if (!sections.length) return "";
  const separatorChars = separator.length * Math.max(0, sections.length - 1);
  const available = Math.max(0, maxLength - separatorChars);
  const base = Math.min(220, Math.max(40, Math.floor(available / sections.length)));
  const budgets = sections.map((section) => Math.min(section.text.length, base));
  let remaining = Math.max(0, available - budgets.reduce((sum, value) => sum + value, 0));
  for (const [index, section] of sections.entries()) {
    if (remaining <= 0) break;
    const preferred = section.priority >= 95 ? 1800 : section.priority >= 80 ? 1100 : section.priority >= 65 ? 760 : 520;
    const extra = Math.min(remaining, Math.max(0, Math.min(section.text.length, preferred) - budgets[index]));
    budgets[index] += extra;
    remaining -= extra;
  }
  const packed = sections.map((section, index) => trimContext(section.text, budgets[index])).join(separator);
  return trimPromptPayload(packed, maxLength);
}

function promptContextSectionPriority(section: string, prompt = ""): number {
  const heading = section.split(/\r?\n/, 1)[0]?.toLowerCase() ?? "";
  let priority = 65;
  if (/^##\s+@/.test(heading)) priority = 110;
  else if (/active skills?|激活.*skill|当前.*skill|经验.*skill/.test(heading)) priority = 105;
  else if (/current file|当前文件|光标|选择内容|selection|cursor/.test(heading)) priority = 100;
  else if (/task experience|任务经验|执行经验|经验/.test(heading)) priority = 90;
  else if (/plugin|obsidian command|插件|命令|detailed.*rules|详细.*规则/.test(heading)) priority = 80;
  else if (/project|codex memory|项目|偏好/.test(heading)) priority = 70;
  else if (/memory router|core memory|记忆.*索引|核心记忆/.test(heading)) priority = 60;

  const query = prompt.toLocaleLowerCase();
  const memoryTask = /(?:我的|关于我|偏好|习惯|记忆|规则|以前|之前|remember|memory|preference|profile|habit)/i.test(query);
  const pluginTask = /(?:obsidian|插件|命令|plugin|command|api|notedraw|pdftion|spaced\s*repetition)/i.test(query);
  const experienceTask = /(?:skill|经验|流程|步骤|成功路线|失败原因|workflow|recipe|experience)/i.test(query);
  const currentFileTask = promptNeedsCurrentFileContext(prompt);
  if (memoryTask && /memory router|core memory|记忆.*索引|核心记忆|project|codex memory|项目|偏好/.test(heading)) priority += 65;
  if (memoryTask && /task experience|任务经验|执行经验/.test(heading) && !experienceTask) priority -= 35;
  if (pluginTask && /plugin|obsidian command|插件|命令|detailed.*rules|详细.*规则/.test(heading)) priority += 45;
  if (experienceTask && /active skills?|skill|task experience|任务经验|执行经验|经验/.test(heading)) priority += 45;
  if (currentFileTask && /current file|当前文件|光标|选择内容|selection|cursor/.test(heading)) priority += 45;
  if (/全局硬搜索结果|universal hard-search results/.test(heading) && /(?:搜索|查找|找出|search|find)/i.test(query)) priority += 35;
  return priority;
}

function clampNumber(value: unknown, fallback: number, min: number, max: number): number {
  const parsed = Number(value);
  const base = Number.isFinite(parsed) ? parsed : fallback;
  return Math.max(min, Math.min(max, base));
}

function normalizeDocumentDrawingAnchor(value: unknown): DocumentDrawingAnchor | undefined {
  if (!isRecord(value) || value.basis !== "note-content-v1") return undefined;
  const line = Number(value.line);
  const lineConfidence = Number(value.lineConfidence);
  return {
    v: 1,
    basis: "note-content-v1",
    x: clampNumber(value.x, 0, -1, 2),
    y: clampNumber(value.y, 0, 0, 1),
    path: typeof value.path === "string" ? normalizePath(value.path) : "",
    line: Number.isFinite(line) && line >= 0 ? line : null,
    lineConfidence: Number.isFinite(lineConfidence) ? clampNumber(lineConfidence, 0, 0, 1) : null
  };
}

function normalizeAnnotationPoints(value: unknown): DocumentDrawingPoint[] {
  const now = Date.now();
  const raw = Array.isArray(value) ? value : [];
  const points = raw
    .filter((point): point is Record<string, unknown> => isRecord(point))
    .map((point, index) => {
      const anchor = normalizeDocumentDrawingAnchor(point.anchor);
      return {
        x: clampNumber(point.x, index === 0 ? 0.15 : 0.85, 0, 1),
        y: clampNumber(point.y, 0.35, 0, 1),
        t: clampNumber(point.t, now + index * 16, 0, Number.MAX_SAFE_INTEGER),
        ...(anchor ? { anchor } : {})
      };
    });
  if (points.length >= 1) {
    if (points.length === 1) {
      const x = Math.min(1, points[0].x + 0.01);
      points.push({
        x,
        y: points[0].y,
        t: points[0].t + 16,
        ...(points[0].anchor ? { anchor: { ...points[0].anchor, x } } : {})
      });
    }
    return points;
  }
  return [
    { x: 0.15, y: 0.35, t: now },
    { x: 0.85, y: 0.35, t: now + 16 }
  ];
}

function trimContextWithRecovery(content: string, maxLength: number, recoveryHint = ""): string {
  const trimmed = content.trim();
  if (trimmed.length <= maxLength) return trimmed;
  const head = trimmed.slice(0, maxLength);
  const suffix = recoveryHint ? `\n${recoveryHint}` : "";
  return `${head}\n\n...[truncated: ${trimmed.length - maxLength} chars omitted]${suffix}`;
}

function readRecoveryHint(path: string, nextLine: number, totalLines: number, maxChars: number): string {
  if (!path || nextLine > totalLines) return "";
  const payload = { type: "read", path: normalizePath(path), startLine: nextLine, maxChars: Math.min(12000, Math.max(4000, maxChars)) };
  return `cancip-recovery-read: ${JSON.stringify(payload)}`;
}

function parseReadRecoveryHint(text: string): Extract<CancipAction, { type: "read" }> | null {
  const match = text.match(/cancip-recovery-read:\s*(\{[^\r\n]+\})/i);
  if (!match) return null;
  try {
    const parsed = parseCancipAction(JSON.parse(match[1]) as unknown);
    return parsed?.type === "read" ? parsed : null;
  } catch {
    return null;
  }
}

function lineRangeFromStart(content: string, maxChars: number): { startLine: number; endLine: number; text: string } {
  const lines = content.split(/\r?\n/);
  let used = 0;
  let endLine = 0;
  const kept: string[] = [];
  const budget = Math.max(200, maxChars - 220);
  for (const line of lines) {
    const next = used + line.length + 1;
    if (kept.length && next > budget) break;
    kept.push(`${kept.length + 1}: ${line}`);
    used = next;
    endLine += 1;
  }
  return { startLine: 1, endLine: Math.max(1, endLine), text: kept.join("\n") };
}

function truncatedReadRecoveryAction(run: ToolRun): CancipAction | null {
  const direct = parseReadRecoveryHint(run.result ?? "");
  if (direct) return direct;
  if (!run.result?.includes("...[truncated")) return null;
  if (run.action.type === "read") {
    const path = normalizeActionPath(run.action.path);
    const match = run.result.match(/^lines:\s*(\d+)-(\d+)\/(\d+)/m);
    if (path && match) {
      const nextLine = Number.parseInt(match[2], 10) + 1;
      const totalLines = Number.parseInt(match[3], 10);
      if (nextLine <= totalLines) return { type: "read", path, startLine: nextLine, maxChars: Math.min(12000, Math.max(4000, clampInt(run.action.maxChars, 2000, 500, 12000))) };
    }
  }
  return null;
}

function uniqueActions(actions: CancipAction[]): CancipAction[] {
  const seen = new Set<string>();
  const output: CancipAction[] = [];
  for (const action of actions) {
    const key = stableCacheKey(canonicalJsonValue(action));
    if (seen.has(key)) continue;
    seen.add(key);
    output.push(action);
  }
  return output;
}


function isTextAttachmentFile(file: File): boolean {
  const type = file.type.toLowerCase();
  if (type.startsWith("text/")) return true;
  if (
    [
      "application/json",
      "application/xml",
      "application/javascript",
      "application/typescript",
      "application/x-javascript",
      "application/x-typescript",
      "application/x-yaml",
      "application/yaml",
      "application/toml",
      "application/x-ndjson"
    ].includes(type)
  ) {
    return true;
  }
  const name = file.name.toLowerCase();
  return /\.(md|markdown|txt|log|json|jsonl|ndjson|csv|tsv|yaml|yml|toml|xml|html?|css|scss|sass|less|js|jsx|ts|tsx|mjs|cjs|py|rb|go|rs|java|kt|kts|c|cc|cpp|h|hpp|cs|php|sh|bash|zsh|ps1|bat|cmd|sql|ini|conf|cfg|env|gitignore|dockerfile)$/i.test(name);
}

function isImageAttachmentFile(file: File): boolean {
  const type = file.type.toLowerCase();
  if (type.startsWith("image/")) return true;
  return /\.(png|jpe?g|webp|gif)$/i.test(file.name);
}

async function parseBinaryAttachment(file: File, maxChars: number): Promise<ParsedAttachmentResult> {
  const name = file.name.toLowerCase();
  const type = file.type.toLowerCase();
  const warnings: string[] = [];
  const safeMax = Math.max(1200, Math.min(30000, maxChars));
  try {
    if (type === "application/pdf" || name.endsWith(".pdf")) {
      return { kind: "pdf/best-effort-text", text: await extractPdfText(file, safeMax, warnings), warnings };
    }
    if (/\.(docx|xlsx|pptx|zip)$/i.test(file.name) || /zip|officedocument|spreadsheet|presentation|wordprocessingml/i.test(type)) {
      const buffer = await file.arrayBuffer();
      const entries = readZipEntries(new Uint8Array(buffer), warnings);
      if (!entries.length) {
        warnings.push("ZIP central directory was not found or no supported entries were present.");
        return { kind: "zip", text: "", warnings };
      }
      if (name.endsWith(".xlsx") || /spreadsheet/i.test(type)) {
        return { kind: "xlsx/xml", text: await extractXlsxText(entries, new Uint8Array(buffer), safeMax, warnings), warnings };
      }
      if (name.endsWith(".docx") || /wordprocessingml/i.test(type)) {
        return { kind: "docx/xml", text: await extractDocxText(entries, new Uint8Array(buffer), safeMax, warnings), warnings };
      }
      if (name.endsWith(".pptx") || /presentationml/i.test(type)) {
        return { kind: "pptx/xml", text: await extractPptxText(entries, new Uint8Array(buffer), safeMax, warnings), warnings };
      }
      return { kind: "zip/xml-text", text: await extractZipText(entries, new Uint8Array(buffer), safeMax, warnings), warnings };
    }
  } catch (error) {
    warnings.push(error instanceof Error ? error.message : String(error));
  }
  return { kind: type || "binary", text: "", warnings };
}

const DOCUMENT_PARSE_MAX_BYTES = 48 * 1024 * 1024;
const DOCUMENT_MARKDOWN_MAX_CHARS = 900000;
const DOCUMENT_RAW_SOURCE_MAX_BYTES = 16 * 1024 * 1024;
const DOCUMENT_HTML_PREVIEW_CHANNEL = "cancip-html-preview-v1";
const DOCUMENT_TEXT_EXTENSIONS = new Set([
  "md", "markdown", "txt", "log", "json", "jsonl", "ndjson", "csv", "tsv", "yaml", "yml", "toml", "xml",
  "html", "htm", "hltm", "mhtml", "mht", "mhtl", "css", "scss", "sass", "less", "js", "jsx", "ts", "tsx", "mjs", "cjs",
  "py", "rb", "go", "rs", "java", "kt", "kts", "c", "cc", "cpp", "h", "hpp", "cs", "php", "sh", "bash",
  "zsh", "ps1", "bat", "cmd", "sql", "ini", "conf", "cfg", "env", "gitignore", "dockerfile", "svg", "base", "canvas"
]);
const DOCUMENT_IMAGE_EXTENSIONS = new Set(["png", "jpg", "jpeg", "webp", "gif", "bmp", "svg", "avif", "heic", "heif"]);
const DOCUMENT_AUDIO_EXTENSIONS = new Set(["mp3", "m4a", "aac", "wav", "ogg", "oga", "flac", "opus"]);
const DOCUMENT_VIDEO_EXTENSIONS = new Set(["mp4", "m4v", "webm", "mov", "ogv", "mkv"]);
function isDocumentWorkbenchMode(value: unknown): value is DocumentWorkbenchMode {
  return value === "preview" || value === "reading" || value === "markdown" || value === "edit";
}

function normalizeDocumentWorkbenchExtension(value: string): string {
  const normalized = value.trim().toLowerCase().replace(/^\.+/, "");
  if (normalized === "*") return normalized;
  if (normalized === "md" || normalized === "markdown") return "";
  return /^[a-z0-9][a-z0-9+_-]{0,31}$/.test(normalized) ? normalized : "";
}

function normalizeDocumentWorkbenchExtensions(value: unknown): string[] {
  const items = Array.isArray(value)
    ? value
    : typeof value === "string"
      ? value.split(/[\s,;，；]+/)
      : null;
  if (!items) return [...DEFAULT_DOCUMENT_WORKBENCH_EXTENSIONS];
  return uniqueStrings(items.flatMap((item) => {
    if (typeof item !== "string") return [];
    const extension = normalizeDocumentWorkbenchExtension(item);
    return extension ? [extension] : [];
  }));
}

function isDocumentSourceEditable(file: TFile): boolean {
  return DOCUMENT_TEXT_EXTENSIONS.has(file.extension.toLowerCase()) || DOCUMENT_TEXT_EXTENSIONS.has(file.name.toLowerCase());
}

type RawDocumentSource = {
  text: string;
  available: boolean;
  editable: boolean;
  textual: boolean;
  encoding: DocumentTextEncoding;
  hasBom: boolean;
};

function decodeDocumentText(bytes: Uint8Array, forceText: boolean): RawDocumentSource {
  const empty: RawDocumentSource = {
    text: "",
    available: bytes.byteLength === 0,
    editable: bytes.byteLength === 0,
    textual: bytes.byteLength === 0,
    encoding: "utf-8",
    hasBom: false
  };
  if (!bytes.byteLength) return empty;
  const bomCandidates: Array<{ encoding: DocumentTextEncoding; bom: number[] }> = [
    { encoding: "utf-8", bom: [0xef, 0xbb, 0xbf] },
    { encoding: "utf-16le", bom: [0xff, 0xfe] },
    { encoding: "utf-16be", bom: [0xfe, 0xff] }
  ];
  for (const candidate of bomCandidates) {
    if (!candidate.bom.every((value, index) => bytes[index] === value)) continue;
    const text = decodeDocumentTextCandidate(bytes.subarray(candidate.bom.length), candidate.encoding, false);
    if (text === null) break;
    return { text, available: true, editable: true, textual: true, encoding: candidate.encoding, hasBom: true };
  }

  const sample = bytes.subarray(0, Math.min(bytes.byteLength, 128 * 1024));
  const nulAtEven = countByteAtParity(sample, 0, 0);
  const nulAtOdd = countByteAtParity(sample, 0, 1);
  const pairCount = Math.max(1, Math.floor(sample.byteLength / 2));
  const utf16LeSignal = nulAtOdd / pairCount > 0.18 && nulAtEven / pairCount < 0.08;
  const utf16BeSignal = nulAtEven / pairCount > 0.18 && nulAtOdd / pairCount < 0.08;
  const binaryByteRatio = unreadableByteRatio(sample, utf16LeSignal || utf16BeSignal);
  const candidates: Array<{ encoding: DocumentTextEncoding; text: string; score: number }> = [];
  const addCandidate = (encoding: DocumentTextEncoding, fatal: boolean, bonus = 0): void => {
    const text = decodeDocumentTextCandidate(bytes, encoding, fatal);
    if (text === null) return;
    let score = documentTextQuality(text) + bonus;
    if ((encoding === "gb18030" || encoding === "big5") && hasCjkText(text)) score += 0.04;
    candidates.push({ encoding, text, score });
  };
  addCandidate("utf-8", true, 0.08);
  if (utf16LeSignal) addCandidate("utf-16le", true, 0.12);
  if (utf16BeSignal) addCandidate("utf-16be", true, 0.12);
  addCandidate("gb18030", true, 0.02);
  addCandidate("big5", true, 0.01);
  addCandidate("windows-1252", false, -0.08);
  candidates.sort((left, right) => right.score - left.score);
  const best = candidates[0];
  if (!best) return empty;
  const textual = forceText || (best.score >= 0.7 && binaryByteRatio < 0.025);
  return {
    text: textual ? best.text : "",
    available: textual,
    editable: textual,
    textual,
    encoding: best.encoding,
    hasBom: false
  };
}

function decodeDocumentTextCandidate(bytes: Uint8Array, encoding: DocumentTextEncoding, fatal: boolean): string | null {
  try {
    return new TextDecoder(encoding, { fatal }).decode(bytes);
  } catch {
    return null;
  }
}

function countByteAtParity(bytes: Uint8Array, value: number, parity: 0 | 1): number {
  let count = 0;
  for (let index = parity; index < bytes.byteLength; index += 2) {
    if (bytes[index] === value) count += 1;
  }
  return count;
}

function unreadableByteRatio(bytes: Uint8Array, allowUtf16Nul: boolean): number {
  if (!bytes.byteLength) return 0;
  let unreadable = 0;
  for (const value of bytes) {
    if ((!allowUtf16Nul && value === 0)
      || (value > 0 && value < 32 && value !== 9 && value !== 10 && value !== 12 && value !== 13)) unreadable += 1;
  }
  return unreadable / bytes.byteLength;
}

function documentTextQuality(text: string): number {
  if (!text) return 1;
  const sample = text.slice(0, 128 * 1024);
  let unreadable = 0;
  let replacement = 0;
  for (const char of sample) {
    const code = char.codePointAt(0) ?? 0;
    if (code === 0xfffd) replacement += 1;
    if (code === 0 || (code < 32 && code !== 9 && code !== 10 && code !== 12 && code !== 13)) unreadable += 1;
  }
  const length = Math.max(1, [...sample].length);
  const mojibake = (sample.match(/(?:\u00c2|\u00c3|\u00e2[\u0080-\u00bf]|\ufffd)/g) ?? []).length;
  return 1 - unreadable / length * 5 - replacement / length * 8 - mojibake / length * 2;
}

function encodeDocumentText(text: string, encoding: DocumentTextEncoding, hasBom: boolean): { bytes: Uint8Array; encoding: DocumentTextEncoding } {
  if (encoding === "utf-16le" || encoding === "utf-16be") {
    const bomSize = hasBom ? 2 : 0;
    const bytes = new Uint8Array(bomSize + text.length * 2);
    if (hasBom) {
      bytes[0] = encoding === "utf-16le" ? 0xff : 0xfe;
      bytes[1] = encoding === "utf-16le" ? 0xfe : 0xff;
    }
    for (let index = 0; index < text.length; index += 1) {
      const code = text.charCodeAt(index);
      const offset = bomSize + index * 2;
      bytes[offset] = encoding === "utf-16le" ? code & 0xff : code >>> 8;
      bytes[offset + 1] = encoding === "utf-16le" ? code >>> 8 : code & 0xff;
    }
    return { bytes, encoding };
  }
  const utf8 = new TextEncoder().encode(text);
  const preserveUtf8Bom = encoding === "utf-8" && hasBom;
  if (!preserveUtf8Bom) return { bytes: utf8, encoding: "utf-8" };
  const bytes = new Uint8Array(utf8.byteLength + 3);
  bytes.set([0xef, 0xbb, 0xbf]);
  bytes.set(utf8, 3);
  return { bytes, encoding: "utf-8" };
}

async function readRawDocumentSource(app: App, file: TFile, forceText = false): Promise<RawDocumentSource> {
  const unavailable: RawDocumentSource = {
    text: "",
    available: false,
    editable: false,
    textual: false,
    encoding: "utf-8",
    hasBom: false
  };
  if (file.stat.size > DOCUMENT_RAW_SOURCE_MAX_BYTES) return unavailable;
  try {
    const buffer = await app.vault.readBinary(file);
    return decodeDocumentText(new Uint8Array(buffer), forceText);
  } catch {
    return unavailable;
  }
}

function documentFormatKind(file: TFile): DocumentFormatKind {
  const extension = file.extension.toLowerCase();
  if (extension === "md" || extension === "markdown") return "markdown";
  if (extension === "json" || extension === "jsonl" || extension === "ndjson" || extension === "canvas" || extension === "base") return "json";
  if (extension === "csv" || extension === "tsv") return "csv";
  if (extension === "html" || extension === "htm" || extension === "hltm") return "html";
  if (extension === "mhtml" || extension === "mht" || extension === "mhtl") return "mhtml";
  if (extension === "pdf") return "pdf";
  if (extension === "docx") return "docx";
  if (extension === "xlsx") return "xlsx";
  if (extension === "pptx") return "pptx";
  if (DOCUMENT_IMAGE_EXTENSIONS.has(extension)) return "image";
  if (DOCUMENT_AUDIO_EXTENSIONS.has(extension)) return "audio";
  if (DOCUMENT_VIDEO_EXTENSIONS.has(extension)) return "video";
  if (DOCUMENT_TEXT_EXTENSIONS.has(extension) || DOCUMENT_TEXT_EXTENSIONS.has(file.name.toLowerCase())) return "text";
  if (["zip", "epub", "odt", "ods", "odp"].includes(extension)) return "archive";
  return "binary";
}

function replaceUniqueDocumentTextValue(source: string, originalText: string, editedText: string, htmlEntities = false): string | null {
  const candidates = htmlEntities
    ? uniqueStrings([originalText, escapeHtml(originalText)]).filter(Boolean)
    : uniqueStrings([
        originalText,
        originalText.replace(/\r?\n/g, "\r\n"),
        originalText.replace(/\r\n/g, "\n")
      ]).filter(Boolean);
  for (const candidate of candidates) {
    const index = source.indexOf(candidate);
    if (index < 0 || source.indexOf(candidate, index + candidate.length) >= 0) continue;
    const replacement = htmlEntities && candidate !== originalText
      ? escapeHtml(editedText)
      : candidate.includes("\r\n")
        ? editedText.replace(/\r?\n/g, "\r\n")
        : editedText.replace(/\r\n/g, "\n");
    return `${source.slice(0, index)}${replacement}${source.slice(index + candidate.length)}`;
  }
  if (!htmlEntities) {
    const normalizedOriginal = originalText.replace(/\s+/g, " ").trim();
    if (normalizedOriginal) {
      const lines = source.split(/(\r?\n)/);
      for (let index = 0, offset = 0; index < lines.length; index += 2) {
        const line = lines[index] ?? "";
        const heading = line.match(/^(#{1,6}\s+)/);
        if (heading && line.slice(heading[0].length).replace(/\s+/g, " ").trim() === normalizedOriginal) {
          return `${source.slice(0, offset)}${heading[1]}${editedText}${source.slice(offset + line.length)}`;
        }
        offset += line.length + (lines[index + 1]?.length ?? 0);
      }
    }
  }
  return null;
}

function normalizedDocumentTextValue(value: string): string {
  return decodeXmlEntities(String(value ?? ""))
    .replace(/<[^>]+>/g, " ")
    .replace(/[*_~`#>|[\](){}]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizedDocumentTextIncludes(source: string, value: string): boolean {
  const normalizedValue = normalizedDocumentTextValue(value);
  return Boolean(normalizedValue && normalizedDocumentTextValue(source).includes(normalizedValue));
}

function escapeOfficeXmlText(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function officeXmlBlockTags(kind: DocumentFormatKind, path: string): string[] {
  if (kind === "docx" && /^word\/(?:document|header\d*|footer\d*|footnotes|endnotes)\.xml$/i.test(path)) return ["p"];
  if (kind === "pptx" && /^ppt\/(?:slides\/slide\d+|notesSlides\/notesSlide\d+)\.xml$/i.test(path)) return ["p"];
  if (kind === "xlsx" && /^xl\/sharedStrings\.xml$/i.test(path)) return ["si"];
  if (kind === "xlsx" && /^xl\/worksheets\/sheet\d+\.xml$/i.test(path)) return ["is"];
  return [];
}

function officeXmlTextBlockReplacement(block: string, originalText: string, editedText: string): string | null {
  const textPattern = /(<(?:(?:[A-Za-z_][\w.-]*):)?t\b[^>]*>)([\s\S]*?)(<\/(?:(?:[A-Za-z_][\w.-]*):)?t\s*>)/gi;
  const parts = [...block.matchAll(textPattern)];
  if (!parts.length) return null;
  const visible = parts.map((match) => decodeXmlEntities(match[2] ?? "")).join("");
  if (normalizedDocumentTextValue(visible) !== normalizedDocumentTextValue(originalText)) return null;
  let next = block;
  for (let index = parts.length - 1; index >= 0; index -= 1) {
    const match = parts[index];
    if (match.index === undefined) continue;
    const open = match[1] ?? "";
    const content = match[2] ?? "";
    const from = match.index + open.length;
    const replacement = index === 0 ? escapeOfficeXmlText(editedText) : "";
    next = `${next.slice(0, from)}${replacement}${next.slice(from + content.length)}`;
  }
  return next;
}

function officeXmlTextReplacements(xml: string, tags: string[], originalText: string, editedText: string): Array<{ start: number; end: number; text: string }> {
  if (!tags.length) return [];
  const names = tags.join("|");
  const blockPattern = new RegExp(`<(?:(?:[A-Za-z_][\\w.-]*):)?(${names})\\b[^>]*>[\\s\\S]*?<\\/(?:(?:[A-Za-z_][\\w.-]*):)?\\1\\s*>`, "gi");
  const replacements: Array<{ start: number; end: number; text: string }> = [];
  for (const match of xml.matchAll(blockPattern)) {
    if (match.index === undefined) continue;
    const text = officeXmlTextBlockReplacement(match[0], originalText, editedText);
    if (text === null) continue;
    replacements.push({ start: match.index, end: match.index + match[0].length, text });
  }
  return replacements;
}

function replaceOfficeArchiveVisibleText(
  archive: Record<string, Uint8Array>,
  kind: DocumentFormatKind,
  originalText: string,
  editedText: string
): { archive: Record<string, Uint8Array>; changed: boolean } {
  const matches: Array<{ path: string; xml: string; replacement: { start: number; end: number; text: string } }> = [];
  for (const [path, bytes] of Object.entries(archive)) {
    const tags = officeXmlBlockTags(kind, path);
    if (!tags.length) continue;
    const xml = strFromU8(bytes);
    for (const replacement of officeXmlTextReplacements(xml, tags, originalText, editedText)) {
      matches.push({ path, xml, replacement });
    }
  }
  if (matches.length !== 1) return { archive, changed: false };
  const match = matches[0];
  const nextXml = `${match.xml.slice(0, match.replacement.start)}${match.replacement.text}${match.xml.slice(match.replacement.end)}`;
  archive[match.path] = strToU8(nextXml);
  return { archive, changed: true };
}

async function buildDocumentSnapshot(app: App, file: TFile): Promise<DocumentSnapshot> {
  let kind = documentFormatKind(file);
  const mimeType = mimeTypeForPath(file.path);
  const warnings: string[] = [];
  const declaredTextSource = isDocumentSourceEditable(file);
  let rawSource = await readRawDocumentSource(app, file, declaredTextSource);
  if (declaredTextSource && !rawSource.available && file.stat.size > DOCUMENT_RAW_SOURCE_MAX_BYTES) {
    const sourceText = await app.vault.read(file);
    rawSource = {
      text: sourceText,
      available: true,
      editable: true,
      textual: true,
      encoding: "utf-8",
      hasBom: false
    };
  }
  if (kind === "binary" && rawSource.textual) kind = "text";
  const editableSource = declaredTextSource || (kind === "text" && rawSource.textual);
  if (editableSource && rawSource.available) {
    const sourceText = rawSource.text;
    if (file.stat.size > 4 * 1024 * 1024) warnings.push(I18N.zh?.documentLargeFile || EN.documentLargeFile);
    const mhtmlHtml = kind === "mhtml" ? extractMhtmlHtml(sourceText, warnings) : "";
    const previewHtml = kind === "html" || kind === "mhtml"
      ? isolatedHtmlPreview(app, file, kind === "mhtml" ? mhtmlHtml : sourceText)
      : "";
    return {
      file,
      sourceMtime: file.stat.mtime,
      sourceSize: file.stat.size,
      kind,
      previewKind: kind === "html" || kind === "mhtml" ? "html" : kind === "image" ? "image" : "markdown",
      mimeType,
      sourceText,
      rawSourceText: sourceText,
      rawSourceAvailable: true,
      rawSourceEditable: true,
      rawSourceEncoding: rawSource.encoding,
      rawSourceHasBom: rawSource.hasBom,
      markdown: trimContext(kind === "image" ? documentEmbedMarkdown(file, kind, mimeType) : markdownFromDocumentText(file, sourceText, kind), DOCUMENT_MARKDOWN_MAX_CHARS),
      previewHtml,
      editableSource,
      warnings
    };
  }

  if (kind === "image" || kind === "audio" || kind === "video") {
    return {
      file,
      sourceMtime: file.stat.mtime,
      sourceSize: file.stat.size,
      kind,
      previewKind: kind,
      mimeType,
      sourceText: "",
      rawSourceText: rawSource.text,
      rawSourceAvailable: rawSource.available,
      rawSourceEditable: rawSource.editable,
      rawSourceEncoding: rawSource.encoding,
      rawSourceHasBom: rawSource.hasBom,
      markdown: documentEmbedMarkdown(file, kind, mimeType),
      previewHtml: "",
      editableSource: false,
      warnings
    };
  }

  if (file.stat.size > DOCUMENT_PARSE_MAX_BYTES) {
    warnings.push(I18N.zh?.documentLargeFile || EN.documentLargeFile);
    return {
      file,
      sourceMtime: file.stat.mtime,
      sourceSize: file.stat.size,
      kind,
      previewKind: kind === "pdf" ? "pdf" : "markdown",
      mimeType,
      sourceText: "",
      rawSourceText: rawSource.text,
      rawSourceAvailable: rawSource.available,
      rawSourceEditable: rawSource.editable,
      rawSourceEncoding: rawSource.encoding,
      rawSourceHasBom: rawSource.hasBom,
      markdown: documentEmbedMarkdown(file, kind, mimeType),
      previewHtml: "",
      editableSource: false,
      warnings
    };
  }

  const buffer = await app.vault.readBinary(file);
  const bytes = new Uint8Array(buffer);
  let markdown = "";
  if (kind === "pdf") {
    const slice = bytes.subarray(0, Math.min(bytes.byteLength, 8 * 1024 * 1024));
    const extracted = extractPdfTextFromBytes(slice, file.name, DOCUMENT_MARKDOWN_MAX_CHARS - 1000, warnings);
    markdown = `${documentEmbedMarkdown(file, kind, mimeType)}${extracted ? `\n\n## 提取文字\n\n${extracted}` : ""}`;
  } else if (kind === "docx" || kind === "xlsx" || kind === "pptx" || kind === "archive") {
    const entries = readZipEntries(bytes, warnings);
    if (!entries.length) {
      warnings.push("ZIP central directory was not found.");
      markdown = documentEmbedMarkdown(file, kind, mimeType);
    } else if (kind === "docx") {
      markdown = await extractDocxMarkdown(entries, bytes, file, warnings);
    } else if (kind === "xlsx") {
      markdown = await extractXlsxMarkdown(entries, bytes, file, warnings);
    } else if (kind === "pptx") {
      markdown = await extractPptxMarkdown(entries, bytes, file, warnings);
    } else {
      const text = await extractZipText(entries, bytes, DOCUMENT_MARKDOWN_MAX_CHARS - 1000, warnings);
      markdown = `${documentMetadataMarkdown(file, kind, mimeType)}${text ? `\n\n${text}` : "\n\n![[" + file.path + "]]"}`;
    }
  } else {
    warnings.push(I18N.zh?.documentUnsupportedBinary || EN.documentUnsupportedBinary);
    markdown = documentEmbedMarkdown(file, kind, mimeType);
  }

  const normalizedMarkdown = trimContext(markdown, DOCUMENT_MARKDOWN_MAX_CHARS);
  const officePreview = kind === "docx" || kind === "xlsx" || kind === "pptx"
    ? documentMarkdownToPreviewHtml(app, file, normalizedMarkdown, file.basename)
    : "";
  return {
    file,
    sourceMtime: file.stat.mtime,
    sourceSize: file.stat.size,
    kind,
    previewKind: officePreview ? "html" : kind === "pdf" ? "pdf" : "markdown",
    mimeType,
    sourceText: "",
    rawSourceText: rawSource.text,
    rawSourceAvailable: rawSource.available,
    rawSourceEditable: rawSource.editable,
    rawSourceEncoding: rawSource.encoding,
    rawSourceHasBom: rawSource.hasBom,
    markdown: normalizedMarkdown,
    previewHtml: officePreview,
    editableSource: false,
    warnings: uniqueStrings(warnings)
  };
}

function markdownFromDocumentText(file: TFile, sourceText: string, kind = documentFormatKind(file)): string {
  if (kind === "markdown") return sourceText;
  if (kind === "html") return htmlToMarkdown(sourceText, file.basename);
  if (kind === "mhtml") return htmlToMarkdown(extractMhtmlHtml(sourceText, []), file.basename);
  if (kind === "csv") return delimitedTextToMarkdown(sourceText, file.extension.toLowerCase() === "tsv" ? "\t" : ",", file.basename);
  if (kind === "json") {
    let formatted = sourceText;
    try {
      formatted = JSON.stringify(JSON.parse(sourceText), null, 2);
    } catch {
      // Keep JSONL and partially edited JSON readable without blocking the editor.
    }
    return `# ${file.basename}\n\n\`\`\`json\n${formatted.trim()}\n\`\`\``;
  }
  const extension = file.extension.toLowerCase();
  if (extension === "txt" || extension === "log" || !extension) return `# ${file.basename}\n\n${sourceText.trim()}`;
  return `# ${file.basename}\n\n\`\`\`${documentCodeLanguage(extension)}\n${sourceText.trim()}\n\`\`\``;
}

function documentEmbedMarkdown(file: TFile, kind: DocumentFormatKind, mimeType: string): string {
  return `${documentMetadataMarkdown(file, kind, mimeType)}\n\n![[${file.path}]]`;
}

function documentMetadataMarkdown(file: TFile, kind: DocumentFormatKind, mimeType: string): string {
  const modified = new Date(file.stat.mtime).toISOString();
  return [
    `# ${escapeMarkdownText(file.basename)}`,
    "",
    `- **文件**：[[${file.path}]]`,
    `- **格式**：${kind.toUpperCase()}${mimeType ? ` (${mimeType})` : ""}`,
    `- **大小**：${formatFileSize(file.stat.size)}`,
    `- **修改**：${modified}`
  ].join("\n");
}

function documentCodeLanguage(extension: string): string {
  const aliases: Record<string, string> = {
    yml: "yaml", htm: "html", mjs: "javascript", cjs: "javascript", js: "javascript", jsx: "jsx", ts: "typescript",
    tsx: "tsx", py: "python", rb: "ruby", sh: "bash", zsh: "bash", ps1: "powershell", bat: "batch", cmd: "batch"
  };
  return aliases[extension] ?? extension.replace(/[^a-z0-9_+-]/gi, "");
}

function delimitedTextToMarkdown(source: string, delimiter: string, title: string): string {
  const rows = parseDelimitedRows(source, delimiter).slice(0, 500);
  if (!rows.length) return `# ${escapeMarkdownText(title)}`;
  const width = Math.min(80, Math.max(...rows.map((row) => row.length)));
  const normalized = rows.map((row) => Array.from({ length: width }, (_unused, index) => row[index] ?? ""));
  const header = normalized[0].map((cell, index) => cell.trim() || spreadsheetColumnName(index));
  const body = normalized.slice(1);
  return `# ${escapeMarkdownText(title)}\n\n${markdownTable(header, body)}`;
}

function parseDelimitedRows(source: string, delimiter: string): string[][] {
  const rows: string[][] = [];
  let row: string[] = [];
  let value = "";
  let quoted = false;
  for (let index = 0; index < source.length; index += 1) {
    const char = source[index];
    if (char === '"') {
      if (quoted && source[index + 1] === '"') {
        value += '"';
        index += 1;
      } else {
        quoted = !quoted;
      }
    } else if (char === delimiter && !quoted) {
      row.push(value);
      value = "";
    } else if ((char === "\n" || char === "\r") && !quoted) {
      if (char === "\r" && source[index + 1] === "\n") index += 1;
      row.push(value);
      if (row.some((cell) => cell.length)) rows.push(row);
      row = [];
      value = "";
    } else {
      value += char;
    }
  }
  row.push(value);
  if (row.some((cell) => cell.length)) rows.push(row);
  return rows;
}

function markdownTable(header: string[], rows: string[][]): string {
  const safeHeader = header.map(markdownTableCell);
  const lines = [
    `| ${safeHeader.join(" | ")} |`,
    `| ${safeHeader.map(() => "---").join(" | ")} |`
  ];
  for (const row of rows) {
    lines.push(`| ${safeHeader.map((_unused, index) => markdownTableCell(row[index] ?? "")).join(" | ")} |`);
  }
  return lines.join("\n");
}

function markdownTableCell(value: string): string {
  return normalizeExtractedText(String(value)).replace(/\|/g, "\\|").replace(/\r?\n/g, "<br>");
}

function spreadsheetColumnName(index: number): string {
  let value = index + 1;
  let name = "";
  while (value > 0) {
    value -= 1;
    name = String.fromCharCode(65 + value % 26) + name;
    value = Math.floor(value / 26);
  }
  return name;
}

function spreadsheetColumnIndex(reference: string): number {
  const letters = reference.match(/^[A-Z]+/i)?.[0]?.toUpperCase() ?? "A";
  let value = 0;
  for (const letter of letters) value = value * 26 + letter.charCodeAt(0) - 64;
  return Math.max(0, value - 1);
}

function documentMarkdownToPreviewHtml(app: App, file: TFile, markdown: string, title: string): string {
  const lines = markdown.split(/\r?\n/);
  const output: string[] = [`<article class="cancip-office-preview"><h1>${escapeHtml(title)}</h1>`];
  let index = 0;
  while (index < lines.length) {
    const line = lines[index].trim();
    if (!line) {
      index += 1;
      continue;
    }
    const fence = line.match(/^```(.*)$/);
    if (fence) {
      const code: string[] = [];
      index += 1;
      while (index < lines.length && !/^```\s*$/.test(lines[index].trim())) {
        code.push(lines[index]);
        index += 1;
      }
      output.push(`<pre><code>${escapeHtml(code.join("\n"))}</code></pre>`);
      index += 1;
      continue;
    }
    if (/^\|/.test(line) && index + 1 < lines.length && /^\|?\s*:?-{2,}/.test(lines[index + 1].trim())) {
      const rows: string[][] = [];
      while (index < lines.length && /^\|/.test(lines[index].trim())) {
        const row = lines[index].trim().replace(/^\|/, "").replace(/\|$/, "").split("|").map((cell) => cell.trim().replace(/\\\|/g, "|"));
        if (!row.every((cell) => /^:?-{2,}:?$/.test(cell))) rows.push(row);
        index += 1;
      }
      if (rows.length) {
        const width = Math.max(...rows.map((row) => row.length));
        output.push(`<table><thead><tr>${Array.from({ length: width }, (_unused, cellIndex) => `<th>${renderDocumentMarkdownInline(rows[0][cellIndex] ?? "")}</th>`).join("")}</tr></thead><tbody>${rows.slice(1).map((row) => `<tr>${Array.from({ length: width }, (_unused, cellIndex) => `<td>${renderDocumentMarkdownInline(row[cellIndex] ?? "")}</td>`).join("")}</tr>`).join("")}</tbody></table>`);
      }
      continue;
    }
    const heading = line.match(/^(#{1,6})\s+(.+)$/);
    if (heading) {
      const level = Math.min(6, heading[1].length);
      output.push(`<h${level}>${renderDocumentMarkdownInline(heading[2])}</h${level}>`);
      index += 1;
      continue;
    }
    if (/^[-*+]\s+/.test(line) || /^\d+[.)]\s+/.test(line)) {
      const ordered = /^\d+[.)]\s+/.test(line);
      const items: string[] = [];
      while (index < lines.length) {
        const current = lines[index].trim();
        const match = ordered ? current.match(/^\d+[.)]\s+(.+)$/) : current.match(/^[-*+]\s+(.+)$/);
        if (!match) break;
        items.push(`<li>${renderDocumentMarkdownInline(match[1])}</li>`);
        index += 1;
      }
      output.push(`<${ordered ? "ol" : "ul"}>${items.join("")}</${ordered ? "ol" : "ul"}>`);
      continue;
    }
    if (/^>\s?/.test(line)) {
      const quote: string[] = [];
      while (index < lines.length && /^>\s?/.test(lines[index].trim())) {
        quote.push(lines[index].trim().replace(/^>\s?/, ""));
        index += 1;
      }
      output.push(`<blockquote>${quote.map(renderDocumentMarkdownInline).join("<br>")}</blockquote>`);
      continue;
    }
    if (/^---+$/.test(line)) {
      output.push("<hr>");
      index += 1;
      continue;
    }
    const paragraph: string[] = [line];
    index += 1;
    while (index < lines.length && lines[index].trim() && !/^(?:#{1,6}\s|```|\||[-*+]\s+|\d+[.)]\s+|>\s?|---+$)/.test(lines[index].trim())) {
      paragraph.push(lines[index].trim());
      index += 1;
    }
    output.push(`<p>${paragraph.map(renderDocumentMarkdownInline).join("<br>")}</p>`);
  }
  output.push("</article>");
  return isolatedHtmlPreview(app, file, output.join("\n"));
}

function renderDocumentMarkdownInline(value: string): string {
  const escaped = escapeHtml(value)
    .replace(/!\[\[([^\]]+)\]\]/g, "<span class=\"cancip-file-embed\">$1</span>")
    .replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_full, target: string, alias?: string) => `<span class="cancip-file-link">${escapeHtml(alias || target)}</span>`)
    .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
    .replace(/__(.+?)__/g, "<strong>$1</strong>")
    .replace(/~~(.+?)~~/g, "<del>$1</del>")
    .replace(/`([^`]+)`/g, "<code>$1</code>")
    .replace(/\*([^*]+)\*/g, "<em>$1</em>")
    .replace(/_([^_]+)_/g, "<em>$1</em>");
  return escaped;
}

function decodeUriComponentSafely(value: string): string {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
}

function normalizeHtmlPreviewVaultPath(path: string): string {
  const segments: string[] = [];
  for (const segment of path.replace(/\\/g, "/").split("/")) {
    if (!segment || segment === ".") continue;
    if (segment === "..") {
      segments.pop();
      continue;
    }
    segments.push(segment);
  }
  return normalizePath(segments.join("/"));
}

function resolveHtmlPreviewVaultPath(sourcePath: string, href: string): string {
  const rawPath = href.trim().split(/[?#]/, 1)[0] ?? "";
  if (!rawPath || /^[a-z][a-z0-9+.-]*:/i.test(rawPath)) return "";
  const decoded = decodeUriComponentSafely(rawPath).replace(/\\/g, "/");
  const combined = decoded.startsWith("/")
    ? decoded.slice(1)
    : `${vaultPathParent(sourcePath)}/${decoded}`;
  return normalizeHtmlPreviewVaultPath(combined);
}

function obsidianOpenUriFilePath(href: string): string {
  try {
    const url = new URL(href);
    const path = url.searchParams.get("file") || url.searchParams.get("path") || "";
    return path ? normalizeHtmlPreviewVaultPath(decodeUriComponentSafely(path).replace(/^\/+/, "")) : "";
  } catch {
    return "";
  }
}

function resolveHtmlPreviewAssetUrl(app: App, file: TFile, value: string, baseHref = ""): string {
  const raw = value.trim();
  if (!raw || raw.startsWith("#")) return raw;
  if (/^(?:javascript:|file:|data:text\/html)/i.test(raw)) return "";
  if (/^[a-z][a-z0-9+.-]*:/i.test(raw) || raw.startsWith("//")) return raw;
  if (/^(?:https?:)?\/\//i.test(baseHref)) {
    try {
      return new URL(raw, baseHref.startsWith("//") ? `https:${baseHref}` : baseHref).href;
    } catch {
      // Fall back to a Vault-relative resource below.
    }
  }
  const match = raw.match(/^([^?#]*)([?#].*)?$/);
  let path = "";
  const localBase = baseHref.trim().split(/[?#]/, 1)[0] ?? "";
  if (localBase && !/^[a-z][a-z0-9+.-]*:/i.test(localBase) && !localBase.startsWith("//")) {
    const basePath = resolveHtmlPreviewVaultPath(file.path, localBase);
    const baseFolder = localBase.endsWith("/") ? basePath : vaultPathParent(basePath);
    const relativePath = decodeUriComponentSafely(match?.[1] ?? raw).replace(/\\/g, "/");
    path = relativePath.startsWith("/")
      ? normalizeHtmlPreviewVaultPath(relativePath.slice(1))
      : normalizeHtmlPreviewVaultPath(`${baseFolder}/${relativePath}`);
  }
  if (!path) path = resolveHtmlPreviewVaultPath(file.path, match?.[1] ?? raw);
  const target = path ? app.vault.getAbstractFileByPath(path) : null;
  return target instanceof TFile ? `${app.vault.getResourcePath(target)}${match?.[2] ?? ""}` : raw;
}

function rewriteHtmlPreviewCssUrls(app: App, file: TFile, css: string, baseHref = ""): string {
  return css.replace(/url\(\s*(["']?)([^"')]+)\1\s*\)/gi, (full, _quote: string, value: string) => {
    const resolved = resolveHtmlPreviewAssetUrl(app, file, value, baseHref);
    return resolved ? `url("${resolved.replace(/"/g, "%22")}")` : full;
  });
}

function rewriteHtmlPreviewResources(app: App, file: TFile, parsed: Document, baseHref = ""): void {
  const resourceAttributes: Array<[string, string]> = [
    ["script[src]", "src"],
    ["link[href]", "href"],
    ["img[src]", "src"],
    ["source[src]", "src"],
    ["video[src]", "src"],
    ["video[poster]", "poster"],
    ["audio[src]", "src"],
    ["track[src]", "src"],
    ["iframe[src]", "src"],
    ["object[data]", "data"],
    ["embed[src]", "src"],
    ["input[src]", "src"]
  ];
  for (const [selector, attribute] of resourceAttributes) {
    parsed.querySelectorAll<HTMLElement>(selector).forEach((element) => {
      const original = element.getAttribute(attribute) ?? "";
      const resolved = resolveHtmlPreviewAssetUrl(app, file, original, baseHref);
      if (resolved) element.setAttribute(attribute, resolved);
      else element.removeAttribute(attribute);
    });
  }
  parsed.querySelectorAll<HTMLElement>("[srcset]").forEach((element) => {
    const source = element.getAttribute("srcset") ?? "";
    if (!source || /data:/i.test(source)) return;
    const resolved = source.split(",").map((candidate) => {
      const parts = candidate.trim().split(/\s+/);
      const url = parts.shift() ?? "";
      return [resolveHtmlPreviewAssetUrl(app, file, url, baseHref), ...parts].filter(Boolean).join(" ");
    }).filter(Boolean).join(", ");
    if (resolved) element.setAttribute("srcset", resolved);
  });
  parsed.querySelectorAll<HTMLElement>("[style]").forEach((element) => {
    element.setAttribute("style", rewriteHtmlPreviewCssUrls(app, file, element.getAttribute("style") ?? "", baseHref));
  });
  parsed.querySelectorAll("style").forEach((element) => {
    element.textContent = rewriteHtmlPreviewCssUrls(app, file, element.textContent ?? "", baseHref);
  });
  if (/^https?:/i.test(baseHref)) {
    parsed.querySelectorAll<HTMLAnchorElement>("a[href]").forEach((anchor) => {
      const href = anchor.getAttribute("href") ?? "";
      if (!href || href.startsWith("#") || /^[a-z][a-z0-9+.-]*:/i.test(href)) return;
      try {
        anchor.setAttribute("href", new URL(href, baseHref).href);
      } catch {
        // The parent bridge reports malformed links only when the user clicks them.
      }
    });
  }
}

function htmlPreviewAttributes(element: Element, excluded: string[] = []): string {
  const blocked = new Set(excluded.map((name) => name.toLowerCase()));
  return Array.from(element.attributes)
    .filter((attribute) => !blocked.has(attribute.name.toLowerCase()))
    .map((attribute) => ` ${attribute.name}="${escapeHtmlAttribute(attribute.value)}"`)
    .join("");
}

function isolatedHtmlPreview(app: App, file: TFile, source: string): string {
  const parsed = new DOMParser().parseFromString(source || "<p></p>", "text/html");
  const baseHref = parsed.querySelector("base[href]")?.getAttribute("href")?.trim() ?? "";
  parsed.querySelectorAll("noscript,base,applet,meta[http-equiv],meta[name='viewport']").forEach((node) => node.remove());
  parsed.querySelectorAll("*").forEach((element) => {
    for (const attribute of Array.from(element.attributes)) {
      if (["href", "src", "poster", "data", "action", "formaction"].includes(attribute.name.toLowerCase())
        && /^\s*(?:file:|javascript:|data:text\/html)/i.test(attribute.value)) {
        element.removeAttribute(attribute.name);
      }
    }
  });
  rewriteHtmlPreviewResources(app, file, parsed, baseHref);
  const htmlAttributes = htmlPreviewAttributes(parsed.documentElement);
  const headAttributes = htmlPreviewAttributes(parsed.head);
  const bodyAttributes = htmlPreviewAttributes(parsed.body);
  const doctype = source.match(/^\s*(<!doctype[^>]*>)/i)?.[1] ?? "<!doctype html>";
  const csp = [
    "default-src 'none'",
    "script-src 'unsafe-inline' 'unsafe-eval' 'wasm-unsafe-eval' * data: blob: app: capacitor:",
    "style-src 'unsafe-inline' * data: blob: app: capacitor:",
    "img-src * data: blob: app: capacitor:",
    "media-src * data: blob: app: capacitor:",
    "font-src * data: blob: app: capacitor:",
    "connect-src * data: blob: ws: wss: app: capacitor:",
    "frame-src * data: blob: app: capacitor:",
    "worker-src * data: blob: app: capacitor:",
    "child-src * data: blob: app: capacitor:",
    "object-src * data: blob: app: capacitor:",
    "base-uri 'none'",
    "form-action *"
  ].join("; ");
  const responsiveStyle = `<style data-cancip-workbench>html{color-scheme:light dark;width:100%!important;max-width:100%!important;min-width:0!important}body{box-sizing:border-box;max-width:100%!important;min-width:0!important;overflow-wrap:anywhere}*,*::before,*::after{box-sizing:border-box}body>*,main,header,footer,nav,section,article,aside{max-width:100%}img,picture,video,audio,canvas,svg,iframe,object,embed{max-width:100%;height:auto}iframe,object,embed{width:100%}table,pre{max-width:100%;overflow:auto}input,textarea,select,button{max-width:100%;font:inherit}button,input,select,textarea,[role="button"]{min-height:40px}article{margin-inline:auto}.cancip-office-preview h1{font-size:1.35em}.cancip-file-embed,.cancip-file-link{color:GrayText;font-family:ui-monospace,monospace}[contenteditable="true"],[contenteditable="plaintext-only"]{outline:2px solid Highlight;outline-offset:2px}@media(max-width:600px){body{width:100%!important;margin-inline:0!important;padding-inline:min(4vw,18px)!important}body>*,main,header,footer,nav,section,article,aside{min-width:0!important;max-width:100%!important}table{display:block;overflow-x:auto;-webkit-overflow-scrolling:touch}}</style>`;
  return `${doctype}<html${htmlAttributes}><head${headAttributes}><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"><meta http-equiv="Content-Security-Policy" content="${escapeHtmlAttribute(csp)}">${documentHtmlPreviewBootstrapScript()}${parsed.head.innerHTML}${responsiveStyle}</head><body${bodyAttributes}>${parsed.body.innerHTML}${documentHtmlPreviewBridgeScript()}</body></html>`;
}

function normalizeHtmlPreviewEditText(value: string): string {
  return value.replace(/\u00a0/g, " ").replace(/\s+/g, " ").trim();
}

function documentHtmlPreviewBootstrapScript(): string {
  const channel = JSON.stringify(DOCUMENT_HTML_PREVIEW_CHANNEL);
  return `<script data-cancip-bootstrap>(()=>{
    const channel=${channel};
    const post=(action,data={})=>{parent.postMessage({channel,type:"action",action,...data},"*");return true};
    const storage=()=>{const values=new Map();return{get length(){return values.size},clear(){values.clear()},getItem(key){key=String(key);return values.has(key)?values.get(key):null},key(index){return Array.from(values.keys())[Number(index)]??null},removeItem(key){values.delete(String(key))},setItem(key,value){values.set(String(key),String(value))}}};
    for(const name of ["localStorage","sessionStorage"]){try{window[name].length}catch{try{Object.defineProperty(window,name,{configurable:true,value:storage()})}catch{}}}
    const api={
      sendToCancip(prompt=""){const value=String(prompt??"").trim();return value?post("ask",{prompt:value}):post("send-to-cancip")},
      ask(prompt){return post("ask",{prompt:String(prompt??"").trim()})},
      editSource(){return post("edit-source")},
      preview(){return post("preview")},
      save(){return post("save")},
      open(href){return post("open",{href:String(href??"").trim()})},
      runCommand(command){return post("command",{command:String(command??"").trim()})}
    };
    window.Cancip=Object.assign(window.Cancip||{},api);
  })()</script>`;
}

function documentHtmlPreviewBridgeScript(): string {
  const channel = JSON.stringify(DOCUMENT_HTML_PREVIEW_CHANNEL);
  return `<script data-cancip-bridge>(()=>{
    const channel=${channel};
    const editableSelector="p,h1,h2,h3,h4,h5,h6,li,td,th,blockquote,pre,code,figcaption,label,summary,span,strong,em,b,i,u,s,mark,small,a,div,section,article";
    let active=null;let originalText="";let editMode=false;let heightFrame=0;
    const post=(type,data={})=>parent.postMessage({channel,type,...data},"*");
    const sendHeight=()=>{if(heightFrame)return;heightFrame=requestAnimationFrame(()=>{heightFrame=0;const root=document.documentElement;const body=document.body;const height=Math.max(root.scrollHeight,root.offsetHeight,body?body.scrollHeight:0,body?body.offsetHeight:0);post("height",{height})})};
    const sendEditMode=()=>post("edit-mode",{enabled:editMode});
    const selectorFor=element=>{const parts=[];let current=element;while(current&&current!==document.body){const tag=current.tagName.toLowerCase();let index=1;for(let sibling=current.previousElementSibling;sibling;sibling=sibling.previousElementSibling)if(sibling.tagName===current.tagName)index+=1;parts.unshift(tag+":nth-of-type("+index+")");current=current.parentElement}return parts.length?"body>"+parts.join(">") :""};
    const finish=commit=>{if(!active)return;const element=active;const before=originalText;const after=element.innerText||element.textContent||"";const selector=selectorFor(element);active=null;originalText="";element.removeAttribute("contenteditable");element.removeAttribute("spellcheck");if(commit&&before!==after)post("commit",{selector,originalText:before,editedText:after});sendHeight()};
    const editableAt=(x,y)=>{const target=document.elementFromPoint(x,y);if(!target||target.closest("script,style,noscript,svg,canvas,img,video,audio,input,textarea,select,button"))return null;return target.closest(editableSelector)};
    const begin=(element,x,y)=>{if(!element)return;finish(true);const text=element.innerText||element.textContent||"";if(!text.trim())return;active=element;originalText=text;element.setAttribute("contenteditable","plaintext-only");element.setAttribute("spellcheck","true");element.focus({preventScroll:true});const selection=getSelection();const range=document.caretRangeFromPoint?document.caretRangeFromPoint(x,y):null;if(selection&&range){selection.removeAllRanges();selection.addRange(range)}};
    const promptFor=element=>{const literal=element.getAttribute("data-cancip-prompt");if(literal!==null)return literal;const selector=element.getAttribute("data-cancip-prompt-from");if(selector){try{const field=document.querySelector(selector);if(field&&"value" in field)return String(field.value??"")}catch{}}const form=element.closest("form");const field=form?.querySelector('textarea[name="prompt"],input[name="prompt"],textarea[name="message"],input[name="message"],textarea[name="query"],input[name="query"],textarea,input[type="text"]');return field&&"value" in field?String(field.value??""):""};
    const actionFor=element=>{const command=element.getAttribute("data-cancip-command")||element.getAttribute("data-obsidian-command")||element.getAttribute("data-plugin-command")||"";const href=element.getAttribute("data-cancip-href")||element.getAttribute("href")||"";const prompt=promptFor(element);let action=element.getAttribute("data-cancip-action")||"";if(!action&&command)action="command";if(!action&&element.hasAttribute("data-cancip-prompt"))action="ask";return action?{action,prompt,command,href}:null};
    addEventListener("message",event=>{if(event.source!==parent||!event.data||event.data.channel!==channel)return;if(event.data.action==="edit-on"){editMode=true;sendEditMode();return}if(event.data.action==="edit-off"){editMode=false;finish(true);sendEditMode();return}if(event.data.action==="find"){const query=String(event.data.query||"");if(!query){getSelection()?.removeAllRanges();return}const found=window.find?.(query,false,event.data.backwards===true,true,false,false,false)??false;const node=getSelection()?.focusNode?.parentElement;if(found&&node)node.scrollIntoView({block:"center",inline:"nearest"});post("find-result",{found});return}if(event.data.action!=="edit-at")return;begin(editableAt(Number(event.data.x)||0,Number(event.data.y)||0),Number(event.data.x)||0,Number(event.data.y)||0)});
    addEventListener("click",event=>{const target=event.target instanceof Element?event.target:null;if(!target)return;const actionElement=target.closest("[data-cancip-action],[data-cancip-prompt],[data-cancip-command],[data-obsidian-command],[data-plugin-command]");const action=actionElement?actionFor(actionElement):null;if(action){event.preventDefault();event.stopPropagation();post("action",action);return}if(event.defaultPrevented||event.button!==0)return;const anchor=target.closest("a[href]");if(!anchor)return;const href=anchor.getAttribute("href")?.trim()||"";if(!href||href.startsWith("#")||anchor.hasAttribute("download"))return;event.preventDefault();post("link",{href})},true);
    addEventListener("submit",event=>{const form=event.target instanceof HTMLFormElement?event.target:null;if(!form)return;const actionElement=form.matches("[data-cancip-action],[data-cancip-prompt],[data-cancip-command],[data-obsidian-command],[data-plugin-command]")?form:form.querySelector("[data-cancip-action],[data-cancip-prompt],[data-cancip-command],[data-obsidian-command],[data-plugin-command]");const action=actionElement?actionFor(actionElement):null;if(action){event.preventDefault();post("action",action);return}if(event.defaultPrevented||String(form.method).toLowerCase()==="dialog")return;const href=form.getAttribute("action")?.trim()||"";if(!href||href.startsWith("#")){event.preventDefault();return}if(String(form.method).toLowerCase()==="get"){event.preventDefault();try{const url=new URL(href,location.href);for(const [key,value] of new FormData(form))url.searchParams.append(key,typeof value==="string"?value:value.name);post("link",{href:url.href})}catch{post("link",{href})}return}if(/^https?:/i.test(href)){form.target="_blank";return}event.preventDefault();post("link",{href})});
    addEventListener("pointerdown",event=>{if(!editMode||active?.contains(event.target))return;const element=event.target?.closest?.(editableSelector);if(!element||element.closest("script,style,noscript,svg,canvas,img,video,audio,input,textarea,select,button"))return;event.preventDefault();event.stopPropagation();begin(element,event.clientX,event.clientY)},true);
    addEventListener("keydown",event=>{if(!active)return;if(event.key==="Escape"){event.preventDefault();active.innerText=originalText;finish(false)}else if(event.key==="Enter"&&(event.ctrlKey||event.metaKey)){event.preventDefault();finish(true)}});
    addEventListener("focusout",()=>setTimeout(()=>{if(active&&!active.contains(document.activeElement))finish(true)},0),true);
    addEventListener("load",()=>{sendHeight();sendEditMode()});addEventListener("resize",sendHeight);
    new MutationObserver(sendHeight).observe(document.documentElement,{subtree:true,childList:true,characterData:true});if(typeof ResizeObserver==="function")new ResizeObserver(sendHeight).observe(document.documentElement);
    sendHeight();sendEditMode();
  })()</script>`;
}

function htmlToMarkdown(source: string, fallbackTitle: string): string {
  const parsed = new DOMParser().parseFromString(source || "", "text/html");
  parsed.querySelectorAll("script,style,noscript,svg,canvas,form,button,input,textarea,select").forEach((node) => node.remove());
  const title = normalizeExtractedText(parsed.querySelector("title")?.textContent || fallbackTitle);
  const blocks = Array.from(parsed.body.childNodes).map((node) => htmlNodeToMarkdown(node, 0)).filter(Boolean).join("\n\n");
  const normalized = normalizeMarkdownDocument(blocks);
  return normalized.startsWith("# ") ? normalized : `# ${escapeMarkdownText(title || fallbackTitle)}${normalized ? `\n\n${normalized}` : ""}`;
}

function htmlNodeToMarkdown(node: Node, listDepth: number): string {
  if (node.nodeType === Node.TEXT_NODE) return (node.textContent ?? "").replace(/\s+/g, " ");
  if (!node.instanceOf(Element)) return "";
  const tag = node.tagName.toLowerCase();
  if (/^h[1-6]$/.test(tag)) return `${"#".repeat(Number(tag.slice(1)))} ${inlineHtmlChildren(node, listDepth).trim()}`;
  if (tag === "p" || tag === "div" || tag === "section" || tag === "article" || tag === "header" || tag === "footer") {
    return inlineHtmlChildren(node, listDepth).trim();
  }
  if (tag === "br") return "\n";
  if (tag === "hr") return "---";
  if (tag === "strong" || tag === "b") return `**${inlineHtmlChildren(node, listDepth).trim()}**`;
  if (tag === "em" || tag === "i") return `*${inlineHtmlChildren(node, listDepth).trim()}*`;
  if (tag === "del" || tag === "s") return `~~${inlineHtmlChildren(node, listDepth).trim()}~~`;
  if (tag === "code" && node.parentElement?.tagName.toLowerCase() !== "pre") return `\`${(node.textContent ?? "").replace(/`/g, "\\`")}\``;
  if (tag === "pre") return `\`\`\`\n${(node.textContent ?? "").trim()}\n\`\`\``;
  if (tag === "blockquote") return inlineHtmlChildren(node, listDepth).trim().split(/\r?\n/).map((line) => `> ${line}`).join("\n");
  if (tag === "a") {
    const text = inlineHtmlChildren(node, listDepth).trim() || node.getAttribute("href") || "link";
    const href = node.getAttribute("href") || "";
    return href && !/^javascript:/i.test(href) ? `[${text}](${href})` : text;
  }
  if (tag === "img") {
    const alt = node.getAttribute("alt") || "image";
    const src = node.getAttribute("src") || "";
    return src && !/^javascript:/i.test(src) ? `![${alt}](${src})` : alt;
  }
  if (tag === "ul" || tag === "ol") {
    const ordered = tag === "ol";
    return Array.from(node.children).filter((child) => child.tagName.toLowerCase() === "li").map((child, index) => {
      const prefix = ordered ? `${index + 1}.` : "-";
      const text = inlineHtmlChildren(child, listDepth + 1).trim().replace(/\n{2,}/g, "\n");
      return `${"  ".repeat(listDepth)}${prefix} ${text}`;
    }).join("\n");
  }
  if (tag === "table") return htmlTableToMarkdown(node);
  return inlineHtmlChildren(node, listDepth).trim();
}

function inlineHtmlChildren(element: Element, listDepth: number): string {
  return Array.from(element.childNodes).map((child) => htmlNodeToMarkdown(child, listDepth)).join("");
}

function htmlTableToMarkdown(table: Element): string {
  const rows = Array.from(table.querySelectorAll("tr")).map((row) => Array.from(row.querySelectorAll(":scope > th, :scope > td")).map((cell) => normalizeExtractedText(cell.textContent ?? "")));
  if (!rows.length) return "";
  const width = Math.max(...rows.map((row) => row.length));
  const normalized = rows.map((row) => Array.from({ length: width }, (_unused, index) => row[index] ?? ""));
  return markdownTable(normalized[0], normalized.slice(1));
}

function normalizeMarkdownDocument(source: string): string {
  return source
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n[ \t]+/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function extractMhtmlHtml(source: string, warnings: string[]): string {
  const headerEnd = source.search(/\r?\n\r?\n/);
  const topHeaders = parseMimeHeaders(headerEnd >= 0 ? source.slice(0, headerEnd) : source);
  const boundaryMatch = topHeaders["content-type"]?.match(/boundary\s*=\s*(?:"([^"]+)"|([^;\s]+))/i);
  const boundary = boundaryMatch?.[1] || boundaryMatch?.[2] || "";
  if (!boundary) {
    warnings.push("MHTML boundary was not found; using the visible HTML body only.");
    const htmlIndex = source.search(/<(?:!doctype\s+html|html|body)\b/i);
    return htmlIndex >= 0 ? source.slice(htmlIndex) : source;
  }
  const assets = new Map<string, string>();
  let html = "";
  for (const rawPart of source.split(`--${boundary}`)) {
    const split = rawPart.search(/\r?\n\r?\n/);
    if (split < 0) continue;
    const headers = parseMimeHeaders(rawPart.slice(0, split));
    const body = rawPart.slice(split).replace(/^\r?\n\r?\n/, "").replace(/\r?\n$/, "");
    const contentType = headers["content-type"] || "text/plain";
    const encoding = headers["content-transfer-encoding"] || "";
    const location = headers["content-location"] || "";
    const contentId = (headers["content-id"] || "").replace(/[<>]/g, "");
    if (/text\/html/i.test(contentType) && !html) {
      html = decodeMimeTextBody(body, encoding, contentType);
      continue;
    }
    if (/^(?:image|audio|video)\//i.test(contentType)) {
      const mime = contentType.split(";")[0].trim();
      const base64 = encoding.toLowerCase().includes("base64")
        ? body.replace(/\s+/g, "")
        : bytesToBase64(quotedPrintableBytes(body));
      const dataUrl = `data:${mime};base64,${base64}`;
      if (location) assets.set(location, dataUrl);
      if (contentId) assets.set(`cid:${contentId}`, dataUrl);
    }
  }
  if (!html) {
    warnings.push("MHTML did not contain a text/html part.");
    return "";
  }
  for (const [sourceUrl, dataUrl] of assets) html = html.split(sourceUrl).join(dataUrl);
  return html;
}

function parseMimeHeaders(source: string): Record<string, string> {
  const unfolded = source.replace(/\r?\n[ \t]+/g, " ");
  const headers: Record<string, string> = {};
  for (const line of unfolded.split(/\r?\n/)) {
    const separator = line.indexOf(":");
    if (separator <= 0) continue;
    headers[line.slice(0, separator).trim().toLowerCase()] = line.slice(separator + 1).trim();
  }
  return headers;
}

function decodeMimeTextBody(body: string, encoding: string, contentType: string): string {
  const charset = contentType.match(/charset\s*=\s*(?:"([^"]+)"|([^;\s]+))/i)?.slice(1).find(Boolean) || "utf-8";
  try {
    if (/base64/i.test(encoding)) return new TextDecoder(charset).decode(base64ToBytes(body.replace(/\s+/g, "")));
    if (/quoted-printable/i.test(encoding)) return new TextDecoder(charset).decode(quotedPrintableBytes(body));
  } catch {
    // Fall through to the raw body when a WebView lacks the declared charset.
  }
  return body;
}

function quotedPrintableBytes(source: string): Uint8Array {
  const unfolded = source.replace(/=\r?\n/g, "");
  const bytes: number[] = [];
  for (let index = 0; index < unfolded.length; index += 1) {
    if (unfolded[index] === "=" && /^[0-9a-f]{2}$/i.test(unfolded.slice(index + 1, index + 3))) {
      bytes.push(parseInt(unfolded.slice(index + 1, index + 3), 16));
      index += 2;
    } else {
      const encoded = new TextEncoder().encode(unfolded[index]);
      bytes.push(...encoded);
    }
  }
  return new Uint8Array(bytes);
}

function base64ToBytes(source: string): Uint8Array {
  const binary = atob(source);
  return Uint8Array.from(binary, (char) => char.charCodeAt(0));
}

function bytesToBase64(bytes: Uint8Array): string {
  let binary = "";
  const chunk = 0x8000;
  for (let index = 0; index < bytes.length; index += chunk) binary += String.fromCharCode(...bytes.subarray(index, index + chunk));
  return btoa(binary);
}

async function extractDocxMarkdown(entries: ZipEntry[], bytes: Uint8Array, file: TFile, warnings: string[]): Promise<string> {
  const documentEntry = entries.find((entry) => entry.name === "word/document.xml");
  if (!documentEntry) return documentEmbedMarkdown(file, "docx", mimeTypeForPath(file.path));
  const xml = await extractZipEntryText(documentEntry, bytes, warnings);
  const parsed = parseOfficeXml(xml, warnings, documentEntry.name);
  const body = firstDescendantByLocalName(parsed, "body");
  const blocks: string[] = [];
  for (const child of Array.from(body?.children ?? [])) {
    if (child.localName === "p") {
      const paragraph = docxParagraphMarkdown(child);
      if (paragraph) blocks.push(paragraph);
    } else if (child.localName === "tbl") {
      const table = docxTableMarkdown(child);
      if (table) blocks.push(table);
    }
  }
  const supplements: string[] = [];
  for (const entry of entries.filter((candidate) => /^word\/(?:header|footer|footnotes|endnotes)\d*\.xml$/i.test(candidate.name))) {
    const content = extractXmlTextRuns(await extractZipEntryText(entry, bytes, warnings));
    if (content) supplements.push(`### ${officePartLabel(entry.name)}\n\n${content}`);
  }
  return trimContext(`# ${escapeMarkdownText(file.basename)}\n\n${blocks.join("\n\n")}${supplements.length ? `\n\n## 附加内容\n\n${supplements.join("\n\n")}` : ""}`, DOCUMENT_MARKDOWN_MAX_CHARS);
}

function docxParagraphMarkdown(paragraph: Element): string {
  const runs = descendantsByLocalName(paragraph, "r");
  let text = runs.map((run) => {
    let value = descendantsByLocalName(run, "t").map((node) => node.textContent ?? "").join("");
    if (descendantsByLocalName(run, "tab").length) value += "\t";
    if (descendantsByLocalName(run, "br").length) value += "\n";
    if (!value) return "";
    const properties = firstDescendantByLocalName(run, "rPr");
    if (properties && firstDescendantByLocalName(properties, "b")) value = `**${value}**`;
    if (properties && firstDescendantByLocalName(properties, "i")) value = `*${value}*`;
    if (properties && firstDescendantByLocalName(properties, "strike")) value = `~~${value}~~`;
    return value;
  }).join("");
  text = normalizeExtractedText(text || descendantsByLocalName(paragraph, "t").map((node) => node.textContent ?? "").join(""));
  if (!text) return "";
  const style = firstDescendantByLocalName(paragraph, "pStyle");
  const styleName = officeAttribute(style, "val");
  const heading = styleName.match(/(?:heading|标题)\s*([1-6])/i)?.[1];
  if (heading) return `${"#".repeat(Number(heading) + 1)} ${text}`;
  if (/title|标题/i.test(styleName)) return `## ${text}`;
  if (firstDescendantByLocalName(paragraph, "numPr")) return `- ${text}`;
  return text;
}

function docxTableMarkdown(table: Element): string {
  const rows = childElementsByLocalName(table, "tr").map((row) => childElementsByLocalName(row, "tc").map((cell) => {
    return childElementsByLocalName(cell, "p").map(docxParagraphMarkdown).filter(Boolean).join("<br>").replace(/^[-#]+\s*/, "");
  }));
  if (!rows.length) return "";
  const width = Math.max(...rows.map((row) => row.length));
  const normalized = rows.map((row) => Array.from({ length: width }, (_unused, index) => row[index] ?? ""));
  const header = normalized[0].map((cell, index) => cell || spreadsheetColumnName(index));
  return markdownTable(header, normalized.slice(1));
}

async function extractPptxMarkdown(entries: ZipEntry[], bytes: Uint8Array, file: TFile, warnings: string[]): Promise<string> {
  const slideEntries = entries.filter((entry) => /^ppt\/slides\/slide\d+\.xml$/i.test(entry.name)).sort((a, b) => naturalNameNumber(a.name) - naturalNameNumber(b.name));
  const blocks = [`# ${escapeMarkdownText(file.basename)}`];
  for (const entry of slideEntries) {
    const parsed = parseOfficeXml(await extractZipEntryText(entry, bytes, warnings), warnings, entry.name);
    const slideNumber = naturalNameNumber(entry.name);
    const shapes = descendantsByLocalName(parsed, "sp");
    const titleShape = shapes.find((shape) => {
      const placeholder = firstDescendantByLocalName(shape, "ph");
      return /^(?:title|ctrTitle)$/i.test(officeAttribute(placeholder, "type"));
    });
    const title = titleShape ? officeShapeText(titleShape)[0] : "";
    const lines: string[] = [];
    for (const shape of shapes) {
      if (shape === titleShape) continue;
      lines.push(...officeShapeText(shape));
    }
    blocks.push(`## 幻灯片 ${slideNumber}${title ? `：${title}` : ""}${lines.length ? `\n\n${lines.map((line) => `- ${line}`).join("\n")}` : ""}`);
    const notesEntry = entries.find((candidate) => candidate.name === `ppt/notesSlides/notesSlide${slideNumber}.xml`);
    if (notesEntry) {
      const notes = extractXmlTextRuns(await extractZipEntryText(notesEntry, bytes, warnings));
      if (notes) blocks.push(`> 备注：${notes}`);
    }
  }
  return trimContext(blocks.join("\n\n"), DOCUMENT_MARKDOWN_MAX_CHARS);
}

function officeShapeText(shape: Element): string[] {
  return descendantsByLocalName(shape, "p").map((paragraph) => normalizeExtractedText(descendantsByLocalName(paragraph, "t").map((text) => text.textContent ?? "").join(""))).filter(Boolean);
}

async function extractXlsxMarkdown(entries: ZipEntry[], bytes: Uint8Array, file: TFile, warnings: string[]): Promise<string> {
  const sharedStrings = await readXlsxSharedStrings(entries, bytes, warnings);
  const descriptors = await readXlsxSheetDescriptors(entries, bytes, warnings);
  const fallbackEntries = xlsxWorksheetEntries(entries);
  const sheets = descriptors.length ? descriptors : fallbackEntries.map((entry, index) => ({ name: `Sheet ${index + 1}`, path: entry.name }));
  const blocks = [`# ${escapeMarkdownText(file.basename)}`];
  for (const [index, sheet] of sheets.entries()) {
    const entry = xlsxWorksheetEntry(entries, sheet.path, index);
    if (!entry) continue;
    const xml = await extractZipEntryText(entry, bytes, warnings);
    const rows = extractXlsxGrid(xml, sharedStrings, 300, 80);
    if (!rows.length) continue;
    const width = Math.max(...rows.map((row) => row.length));
    const normalized = rows.map((row) => Array.from({ length: width }, (_unused, index) => row[index] ?? ""));
    const header = normalized[0].map((cell, index) => cell || spreadsheetColumnName(index));
    blocks.push(`## ${escapeMarkdownText(sheet.name)}\n\n${markdownTable(header, normalized.slice(1))}`);
  }
  return trimContext(blocks.join("\n\n"), DOCUMENT_MARKDOWN_MAX_CHARS);
}

async function readXlsxSheetDescriptors(entries: ZipEntry[], bytes: Uint8Array, warnings: string[]): Promise<Array<{ name: string; path: string }>> {
  const workbook = findZipEntry(entries, "xl/workbook.xml");
  const relations = findZipEntry(entries, "xl/_rels/workbook.xml.rels");
  if (!workbook || !relations) return [];
  const workbookXml = await extractZipEntryText(workbook, bytes, warnings);
  const relationsXml = await extractZipEntryText(relations, bytes, warnings);
  const relationPaths = new Map<string, string>();
  for (const match of relationsXml.matchAll(/<Relationship\b([^>]*)\/?\s*>/gi)) {
    const id = match[1].match(/\bId="([^"]+)"/i)?.[1] ?? "";
    const target = match[1].match(/\bTarget="([^"]+)"/i)?.[1] ?? "";
    if (!id || !target) continue;
    const path = resolveZipTarget("xl/workbook.xml", target);
    relationPaths.set(id, path);
  }
  const output: Array<{ name: string; path: string }> = [];
  for (const match of workbookXml.matchAll(/<sheet\b([^>]*)\/?\s*>/gi)) {
    const name = decodeXmlEntities(match[1].match(/\bname="([^"]+)"/i)?.[1] ?? "");
    const relationId = match[1].match(/\br:id="([^"]+)"/i)?.[1] ?? "";
    const path = relationPaths.get(relationId) ?? "";
    if (name && path) output.push({ name, path });
  }
  return output;
}

function extractXlsxGrid(xml: string, sharedStrings: string[], maxRows: number, maxColumns: number): string[][] {
  const rows: string[][] = [];
  for (const rowMatch of xml.matchAll(/<row\b[\s\S]*?<\/row>/gi)) {
    const row: string[] = [];
    for (const cellMatch of rowMatch[0].matchAll(/<c\b([^>]*)>([\s\S]*?)<\/c>/gi)) {
      const attrs = cellMatch[1];
      const body = cellMatch[2];
      const column = Math.min(maxColumns - 1, spreadsheetColumnIndex(attrs.match(/\br="([A-Z]+\d+)"/i)?.[1] ?? "A1"));
      const type = attrs.match(/\bt="([^"]+)"/i)?.[1] ?? "";
      const inline = body.match(/<is\b[\s\S]*?<\/is>/i)?.[0] ?? "";
      const formula = decodeXmlEntities(body.match(/<f[^>]*>([\s\S]*?)<\/f>/i)?.[1] ?? "");
      const rawValue = decodeXmlEntities(body.match(/<v[^>]*>([\s\S]*?)<\/v>/i)?.[1] ?? "");
      let value = rawValue;
      if (type === "s") value = sharedStrings[Number(rawValue)] ?? rawValue;
      else if (type === "inlineStr") value = extractXmlTextRuns(inline);
      else if (type === "b") value = rawValue === "1" ? "TRUE" : "FALSE";
      if (!value && formula) value = `=${formula}`;
      while (row.length <= column) row.push("");
      row[column] = normalizeExtractedText(value);
    }
    if (row.some(Boolean)) rows.push(row.slice(0, maxColumns));
    if (rows.length >= maxRows) break;
  }
  return rows;
}

function parseOfficeXml(xml: string, warnings: string[], name: string): XMLDocument {
  const parsed = new DOMParser().parseFromString(xml, "application/xml");
  const error = parsed.querySelector("parsererror")?.textContent?.trim();
  if (error) warnings.push(`${name}: XML parse warning`);
  return parsed;
}

function descendantsByLocalName(parent: ParentNode, localName: string): Element[] {
  const withNamespaces = "getElementsByTagNameNS" in parent
    ? Array.from((parent as Document | Element).getElementsByTagNameNS("*", localName))
    : [];
  if (withNamespaces.length) return withNamespaces;
  return Array.from(parent.querySelectorAll("*")).filter((element) => element.localName === localName);
}

function firstDescendantByLocalName(parent: ParentNode | null, localName: string): Element | null {
  return parent ? descendantsByLocalName(parent, localName)[0] ?? null : null;
}

function childElementsByLocalName(parent: Element, localName: string): Element[] {
  return Array.from(parent.children).filter((element) => element.localName === localName);
}

function officeAttribute(element: Element | null, localName: string): string {
  if (!element) return "";
  return Array.from(element.attributes).find((attribute) => attribute.localName === localName)?.value ?? "";
}

function officePartLabel(path: string): string {
  if (/header/i.test(path)) return "页眉";
  if (/footer/i.test(path)) return "页脚";
  if (/footnotes/i.test(path)) return "脚注";
  if (/endnotes/i.test(path)) return "尾注";
  return path;
}

function escapeMarkdownText(value: string): string {
  return value.replace(/([\\`*_{}[\]()#+.!|>-])/g, "\\$1");
}

function escapeHtml(value: string): string {
  return value.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

function escapeHtmlAttribute(value: string): string {
  return escapeHtml(value).replace(/`/g, "&#96;");
}

function ensureTrailingNewline(value: string): string {
  return value.endsWith("\n") ? value : `${value}\n`;
}

async function extractPdfText(file: File, maxChars: number, warnings: string[]): Promise<string> {
  const maxBytes = Math.min(file.size, 5 * 1024 * 1024);
  const bytes = new Uint8Array(await file.slice(0, maxBytes).arrayBuffer());
  const text = extractPdfTextFromBytes(bytes, file.name, maxChars, warnings);
  if (file.size > maxBytes) warnings.push(`Only scanned first ${formatFileSize(maxBytes)} of ${formatFileSize(file.size)}.`);
  return text;
}

function extractPdfTextFromBytes(bytes: Uint8Array, name: string, maxChars: number, warnings: string[]): string {
  const raw = latin1Decode(bytes);
  const chunks: string[] = [];
  const textObjectRegex = /BT([\s\S]*?)ET/g;
  for (const match of raw.matchAll(textObjectRegex)) {
    chunks.push(...extractPdfTextFragments(match[1]));
    if (chunks.join("\n").length >= maxChars) break;
  }
  if (!chunks.length) chunks.push(...extractPdfTextFragments(raw));
  const text = normalizePdfTtsText(chunks.join("\n"));
  if (!text || !looksLikeReadableExtractedText(text)) {
    warnings.push(`No readable uncompressed PDF text operators were found in ${name}. This may be scanned/OCR-only, encrypted, compressed, or requires a PDF text layer/OCR parser.`);
    return "";
  }
  return trimContext(text, maxChars);
}

function extractPdfTextFragments(raw: string): string[] {
  const fragments: string[] = [];
  for (const match of raw.matchAll(/\((?:\\.|[^\\)]){1,500}\)\s*(?:Tj|'|"|TJ)?/g)) {
    const body = match[0].replace(/\)\s*(?:Tj|'|"|TJ)?\s*$/g, "").slice(1);
    const text = decodePdfLiteral(body);
    if (looksLikeReadableText(text)) fragments.push(text);
  }
  for (const match of raw.matchAll(/<([0-9A-Fa-f\s]{4,2000})>\s*(?:Tj|'|"|TJ)?/g)) {
    const text = decodePdfHexText(match[1]);
    if (looksLikeReadableText(text)) fragments.push(text);
  }
  return fragments;
}

function decodePdfLiteral(input: string): string {
  return input
    .replace(/\\([nrtbf()\\])/g, (_full, code: string) => {
      if (code === "n" || code === "r") return "\n";
      if (code === "t") return "\t";
      if (code === "b" || code === "f") return " ";
      return code;
    })
    .replace(/\\([0-7]{1,3})/g, (_full, octal: string) => String.fromCharCode(parseInt(octal, 8)));
}

function decodePdfHexText(hex: string): string {
  const clean = hex.replace(/\s+/g, "");
  if (/^feff/i.test(clean) && clean.length % 4 === 0) return decodeUtf16BeHex(clean.slice(4));
  const bytes: number[] = [];
  for (let index = 0; index + 1 < clean.length; index += 2) bytes.push(parseInt(clean.slice(index, index + 2), 16));
  const byteArray = new Uint8Array(bytes.filter((byte) => Number.isFinite(byte)));
  if (byteArray.length >= 3 && byteArray[0] === 0xef && byteArray[1] === 0xbb && byteArray[2] === 0xbf) return utf8Decode(byteArray.subarray(3));
  const utf8Text = utf8Decode(byteArray);
  if (looksLikeReadableText(utf8Text)) return utf8Text;
  if (clean.length % 4 === 0) {
    const utf16Text = decodeUtf16BeHex(clean);
    if (looksLikeReadableText(utf16Text)) return utf16Text;
  }
  return latin1Decode(byteArray);
}

function decodeUtf16BeHex(hex: string): string {
  const chars: string[] = [];
  for (let index = 0; index + 3 < hex.length; index += 4) {
    const code = parseInt(hex.slice(index, index + 4), 16);
    if (Number.isFinite(code) && code > 0) chars.push(String.fromCharCode(code));
  }
  return chars.join("");
}

function readZipEntries(bytes: Uint8Array, warnings: string[]): ZipEntry[] {
  const view = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
  const entries: ZipEntry[] = [];
  const start = Math.max(0, bytes.length - 66000);
  let eocd = -1;
  for (let index = bytes.length - 22; index >= start; index -= 1) {
    if (readUint32(view, index) === 0x06054b50) {
      eocd = index;
      break;
    }
  }
  if (eocd < 0) return entries;
  const totalEntries = readUint16(view, eocd + 10);
  const directoryOffset = readUint32(view, eocd + 16);
  let cursor = directoryOffset;
  for (let index = 0; index < totalEntries && cursor + 46 <= bytes.length; index += 1) {
    if (readUint32(view, cursor) !== 0x02014b50) break;
    const compression = readUint16(view, cursor + 10);
    const compressedSize = readUint32(view, cursor + 20);
    const uncompressedSize = readUint32(view, cursor + 24);
    const nameLength = readUint16(view, cursor + 28);
    const extraLength = readUint16(view, cursor + 30);
    const commentLength = readUint16(view, cursor + 32);
    const localOffset = readUint32(view, cursor + 42);
    const name = utf8Decode(bytes.subarray(cursor + 46, cursor + 46 + nameLength));
    const localNameLength = readUint16(view, localOffset + 26);
    const localExtraLength = readUint16(view, localOffset + 28);
    const dataOffset = localOffset + 30 + localNameLength + localExtraLength;
    if (name && !name.endsWith("/")) entries.push({ name, compression, compressedSize, uncompressedSize, dataOffset });
    cursor += 46 + nameLength + extraLength + commentLength;
  }
  const unsupported = entries.filter((entry) => entry.compression !== 0 && entry.compression !== 8).length;
  if (unsupported) warnings.push(`${unsupported} ZIP entries use unsupported compression methods.`);
  return entries;
}

async function extractZipEntryText(entry: ZipEntry, bytes: Uint8Array, warnings: string[]): Promise<string> {
  return utf8Decode(await extractZipEntryBytes(entry, bytes, warnings));
}

async function extractZipEntryBytes(entry: ZipEntry, bytes: Uint8Array, warnings: string[]): Promise<Uint8Array> {
  const compressed = bytes.subarray(entry.dataOffset, entry.dataOffset + entry.compressedSize);
  if (entry.compression === 0) return compressed;
  if (entry.compression === 8) {
    try {
      return await inflateRawBytes(compressed, entry.uncompressedSize);
    } catch (error) {
      warnings.push(`${entry.name}: inflate failed (${error instanceof Error ? error.message : String(error)})`);
      return new Uint8Array();
    }
  }
  warnings.push(`${entry.name}: unsupported ZIP compression method ${entry.compression}`);
  return new Uint8Array();
}

function normalizePrimeTtsZipEntry(name: string): string | null {
  const normalized = normalizePath(name.replace(/\\/g, "/").replace(/^\/+/, ""));
  if (!normalized || normalized.includes("..") || /^[a-zA-Z]:/.test(normalized)) return null;
  const parts = normalized.split("/").filter(Boolean);
  if (!parts.length) return null;
  const allowed = new Set<string>([...PRIME_TTS_REQUIRED_RELATIVES, ...PRIME_TTS_OPTIONAL_RELATIVES]);
  const candidates = [
    parts.join("/"),
    parts.slice(1).join("/")
  ].filter(Boolean);
  for (const relative of candidates) {
    if (allowed.has(relative)) return relative;
  }
  return null;
}

function primeTtsRequiredAssets(basePath: string): Array<{ relative: string; path: string }> {
  return PRIME_TTS_REQUIRED_RELATIVES.map((relative) => ({ relative, path: `${basePath}/${relative}` }));
}

function primeTtsOptionalAssets(basePath: string): Array<{ relative: string; path: string }> {
  return PRIME_TTS_OPTIONAL_RELATIVES.map((relative) => ({ relative, path: `${basePath}/${relative}` }));
}

function primeTtsAssetPaths(basePath: string): { encoder: string; decoder: string; vocoder: string; meta: string; symbols: string; ortWasm: string; ortMjs: string } {
  return {
    encoder: `${basePath}/acoustic_encoder.onnx`,
    decoder: `${basePath}/acoustic_decoder.onnx`,
    vocoder: `${basePath}/vocoder.onnx`,
    meta: `${basePath}/meta.json`,
    symbols: `${basePath}/symbol_table.json`,
    ortWasm: `${basePath}/ort/ort-wasm-simd-threaded.wasm`,
    ortMjs: `${basePath}/ort/ort-wasm-simd-threaded.mjs`
  };
}

function primeTtsPackageSupportsLanguage(pkg: PrimeTtsPackageDefinition, languageCode: string): boolean {
  const normalized = languageCode.toLowerCase();
  const base = normalized.split("-")[0];
  return pkg.languages.some((language) => {
    const candidate = language.toLowerCase();
    return candidate === normalized || candidate === base || candidate.split("-")[0] === base;
  });
}

function inferPrimeTtsPackageLanguages(basePath: string): string[] {
  const name = basePath.split("/").pop()?.toLowerCase() ?? "";
  const inferred = LANGUAGE_VALUES
    .filter((language) => name.includes(language.toLowerCase()))
    .map((language) => defaultLocaleForLanguage(language));
  return inferred.length ? inferred : ["zh-CN", "en-US"];
}

function defaultLocaleForLanguage(language: Language): string {
  const map: Record<Language, string> = {
    zh: "zh-CN",
    "zh-TW": "zh-TW",
    en: "en-US",
    ug: "ug-CN",
    tr: "tr-TR",
    ru: "ru-RU",
    ja: "ja-JP",
    ko: "ko-KR",
    es: "es-ES",
    fr: "fr-FR",
    de: "de-DE",
    ar: "ar-SA"
  };
  return map[language];
}

async function extractDocxText(entries: ZipEntry[], bytes: Uint8Array, maxChars: number, warnings: string[]): Promise<string> {
  const names = ["word/document.xml", ...entries.map((entry) => entry.name).filter((name) => /^word\/(?:header|footer|footnotes|endnotes)\d*\.xml$/i.test(name))];
  const parts: string[] = [];
  for (const name of uniqueStrings(names)) {
    const entry = entries.find((item) => item.name === name);
    if (!entry) continue;
    const xml = await extractZipEntryText(entry, bytes, warnings);
    if (!xml) continue;
    const text = extractXmlTextRuns(xml);
    if (text) parts.push(`## ${name}\n${text}`);
    if (parts.join("\n\n").length >= maxChars) break;
  }
  return trimContext(normalizeExtractedText(parts.join("\n\n")), maxChars);
}

async function extractPptxText(entries: ZipEntry[], bytes: Uint8Array, maxChars: number, warnings: string[]): Promise<string> {
  const slideEntries = entries
    .filter((entry) => /^ppt\/slides\/slide\d+\.xml$/i.test(entry.name))
    .sort((a, b) => naturalNameNumber(a.name) - naturalNameNumber(b.name));
  const parts: string[] = [];
  for (const entry of slideEntries) {
    const xml = await extractZipEntryText(entry, bytes, warnings);
    const text = extractXmlTextRuns(xml);
    if (text) parts.push(`## ${entry.name}\n${text}`);
    if (parts.join("\n\n").length >= maxChars) break;
  }
  return trimContext(normalizeExtractedText(parts.join("\n\n")), maxChars);
}

function normalizeZipPath(path: string): string {
  const parts: string[] = [];
  for (const part of path.replace(/\\/g, "/").split("/")) {
    if (!part || part === ".") continue;
    if (part === "..") {
      parts.pop();
      continue;
    }
    parts.push(part);
  }
  return parts.join("/");
}

function findZipEntry(entries: ZipEntry[], path: string): ZipEntry | undefined {
  const normalized = normalizeZipPath(path).toLocaleLowerCase();
  return entries.find((entry) => normalizeZipPath(entry.name).toLocaleLowerCase() === normalized);
}

function resolveZipTarget(sourcePath: string, target: string): string {
  const normalizedTarget = target.trim().replace(/\\/g, "/");
  if (!normalizedTarget) return "";
  if (normalizedTarget.startsWith("/")) return normalizeZipPath(normalizedTarget.slice(1));
  const sourceParts = normalizeZipPath(sourcePath).split("/");
  sourceParts.pop();
  return normalizeZipPath([...sourceParts, normalizedTarget].join("/"));
}

function xlsxWorksheetEntries(entries: ZipEntry[]): ZipEntry[] {
  return entries
    .filter((entry) => /^xl\/worksheets\/sheet\d+\.xml$/i.test(normalizeZipPath(entry.name)))
    .sort((a, b) => naturalNameNumber(a.name) - naturalNameNumber(b.name));
}

function xlsxWorksheetEntry(entries: ZipEntry[], path: string, index: number): ZipEntry | undefined {
  return findZipEntry(entries, path) ?? xlsxWorksheetEntries(entries)[index];
}

async function extractXlsxText(entries: ZipEntry[], bytes: Uint8Array, maxChars: number, warnings: string[]): Promise<string> {
  const sharedStrings = await readXlsxSharedStrings(entries, bytes, warnings);
  const descriptors = await readXlsxSheetDescriptors(entries, bytes, warnings);
  const sheetEntries = xlsxWorksheetEntries(entries);
  const sheets = descriptors.length
    ? descriptors
    : sheetEntries.map((entry, index) => ({ name: `Sheet ${index + 1}`, path: entry.name }));
  const parts: string[] = [];
  for (const [index, sheet] of sheets.entries()) {
    const entry = xlsxWorksheetEntry(entries, sheet.path, index);
    if (!entry) continue;
    const xml = await extractZipEntryText(entry, bytes, warnings);
    const title = sheet.name || entry.name;
    const rows = extractXlsxRows(xml, sharedStrings).slice(0, 80);
    if (rows.length) parts.push(`## ${title}\n${rows.map((row) => row.join(" | ")).join("\n")}`);
    if (parts.join("\n\n").length >= maxChars) break;
  }
  return trimContext(normalizeExtractedText(parts.join("\n\n")), maxChars);
}

async function extractZipText(entries: ZipEntry[], bytes: Uint8Array, maxChars: number, warnings: string[]): Promise<string> {
  const parts: string[] = [];
  for (const entry of entries) {
    if (!/\.(xml|txt|md|csv|json|html?)$/i.test(entry.name)) continue;
    const text = entry.name.endsWith(".xml")
      ? extractXmlTextRuns(await extractZipEntryText(entry, bytes, warnings))
      : await extractZipEntryText(entry, bytes, warnings);
    if (text) parts.push(`## ${entry.name}\n${trimContext(text, 4000)}`);
    if (parts.join("\n\n").length >= maxChars) break;
  }
  return trimContext(normalizeExtractedText(parts.join("\n\n")), maxChars);
}

async function readXlsxSharedStrings(entries: ZipEntry[], bytes: Uint8Array, warnings: string[]): Promise<string[]> {
  const entry = findZipEntry(entries, "xl/sharedStrings.xml");
  if (!entry) return [];
  const xml = await extractZipEntryText(entry, bytes, warnings);
  return [...xml.matchAll(/<si\b[\s\S]*?<\/si>/gi)].map((match) => extractXmlTextRuns(match[0]));
}

function extractXlsxRows(xml: string, sharedStrings: string[]): string[][] {
  const rows: string[][] = [];
  for (const rowMatch of xml.matchAll(/<row\b[\s\S]*?<\/row>/gi)) {
    const cells: string[] = [];
    for (const cellMatch of rowMatch[0].matchAll(/<c\b([^>]*)>([\s\S]*?)<\/c>/gi)) {
      const attrs = cellMatch[1];
      const body = cellMatch[2];
      const type = attrs.match(/\bt="([^"]+)"/i)?.[1] ?? "";
      const inline = body.match(/<is\b[\s\S]*?<\/is>/i)?.[0];
      const value = body.match(/<v[^>]*>([\s\S]*?)<\/v>/i)?.[1] ?? "";
      if (type === "s") {
        cells.push(sharedStrings[Number(value)] ?? value);
      } else if (type === "inlineStr" && inline) {
        cells.push(extractXmlTextRuns(inline));
      } else {
        cells.push(decodeXmlEntities(value));
      }
    }
    const cleaned = cells.map((cell) => normalizeExtractedText(cell)).filter(Boolean);
    if (cleaned.length) rows.push(cleaned);
  }
  return rows;
}

function extractXmlTextRuns(xml: string): string {
  const runs = [...xml.matchAll(/<(?:\w+:)?t\b[^>]*>([\s\S]*?)<\/(?:\w+:)?t>/gi)].map((match) => decodeXmlEntities(stripXmlTags(match[1])));
  if (runs.length) return normalizeExtractedText(runs.join(" "));
  return normalizeExtractedText(decodeXmlEntities(stripXmlTags(xml)));
}

function stripXmlTags(input: string): string {
  return input.replace(/<[^>]+>/g, " ");
}

function decodeXmlEntities(input: string): string {
  return input
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, "\"")
    .replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_full, code: string) => String.fromCharCode(Number(code)))
    .replace(/&#x([0-9a-f]+);/gi, (_full, code: string) => String.fromCharCode(parseInt(code, 16)));
}

function normalizeExtractedText(input: string): string {
  return input
    .split(String.fromCharCode(0)).join("")
    .replace(/[ \t]{2,}/g, " ")
    .replace(/\s+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function looksLikeReadableText(input: string): boolean {
  const text = input.trim();
  if (text.length < 2) return false;
  const readable = text.replace(/[^\p{L}\p{N}\p{Script=Han}\s.,;:!?，。！？、（）()_/-]/gu, "");
  return readable.length / Math.max(1, text.length) > 0.45;
}

function looksLikeReadableExtractedText(input: string): boolean {
  const text = input.replace(/\s+/g, "");
  if (text.length < 2) return false;
  const controls = [...text].filter(isUnreadableControlChar).length;
  if (controls / Math.max(1, text.length) > 0.02) return false;
  const readable = text.replace(/[^\p{L}\p{N}\p{Script=Han}.,;:!?，。！？、（）()_/-]/gu, "");
  return readable.length / Math.max(1, text.length) > 0.55;
}

function isUnreadableControlChar(char: string): boolean {
  const code = char.codePointAt(0) ?? 0;
  return code === 0xfffd || (code >= 0 && code <= 8) || code === 11 || code === 12 || (code >= 14 && code <= 31);
}

function utf8Decode(bytes: Uint8Array): string {
  try {
    return new TextDecoder("utf-8").decode(bytes);
  } catch {
    return latin1Decode(bytes);
  }
}

function latin1Decode(bytes: Uint8Array): string {
  let output = "";
  const chunkSize = 0x8000;
  for (let index = 0; index < bytes.length; index += chunkSize) {
    output += String.fromCharCode(...bytes.subarray(index, index + chunkSize));
  }
  return output;
}

function readUint16(view: DataView, offset: number): number {
  return offset >= 0 && offset + 2 <= view.byteLength ? view.getUint16(offset, true) : 0;
}

function readUint32(view: DataView, offset: number): number {
  return offset >= 0 && offset + 4 <= view.byteLength ? view.getUint32(offset, true) : 0;
}

function naturalNameNumber(name: string): number {
  const match = name.match(/(\d+)(?!.*\d)/);
  return match ? Number(match[1]) : 0;
}

async function inflateRawBytes(bytes: Uint8Array, expectedSize: number): Promise<Uint8Array> {
  const decompression = (window as unknown as { DecompressionStream?: new (format: string) => DecompressionStream }).DecompressionStream;
  if (decompression) {
    const stream = new Blob([uint8ArrayToArrayBuffer(bytes)]).stream().pipeThrough(new decompression("deflate-raw"));
    const buffer = await new Response(stream).arrayBuffer();
    const output = new Uint8Array(buffer);
    if (expectedSize > 0 && output.byteLength !== expectedSize) {
      // Some ZIP writers report approximate sizes; keep extracted text if decoding succeeded.
    }
    return output;
  }
  const zlibLike = (window as unknown as { require?: (name: string) => unknown }).require?.("zlib") as
    | { inflateRawSync?: (input: Uint8Array) => Uint8Array | ArrayBuffer }
    | undefined;
  if (!zlibLike?.inflateRawSync) {
    throw new Error("deflate decompression bridge unavailable in this runtime");
  }
  const inflated = zlibLike.inflateRawSync(bytes);
  const output = inflated instanceof Uint8Array ? inflated : new Uint8Array(inflated);
  if (expectedSize > 0 && output.byteLength !== expectedSize) {
    // Some ZIP writers report approximate sizes; warn by letting caller keep extracted text.
  }
  return output;
}

function uint8ArrayToArrayBuffer(bytes: Uint8Array): ArrayBuffer {
  const output = new ArrayBuffer(bytes.byteLength);
  new Uint8Array(output).set(bytes);
  return output;
}

async function fileToDataUrl(file: File): Promise<string> {
  const buffer = await file.arrayBuffer();
  return arrayBufferToDataUrl(buffer, file.type || "application/octet-stream");
}

function arrayBufferToDataUrl(buffer: ArrayBuffer, mimeType = "application/octet-stream"): string {
  const bytes = new Uint8Array(buffer);
  const chunkSize = 0x8000;
  let binary = "";
  for (let index = 0; index < bytes.length; index += chunkSize) {
    const chunk = bytes.subarray(index, index + chunkSize);
    binary += String.fromCharCode(...chunk);
  }
  return `data:${mimeType};base64,${btoa(binary)}`;
}

function summarizeModelRequestBody(value: unknown): unknown {
  if (!isRecord(value)) {
    return typeof value === "string"
      ? { type: "string", chars: value.length }
      : { type: typeof value };
  }
  const summary: Record<string, unknown> = {
    model: typeof value.model === "string" ? value.model : undefined,
    temperature: typeof value.temperature === "number" ? value.temperature : undefined,
    max_tokens: typeof value.max_tokens === "number" ? value.max_tokens : undefined,
    max_output_tokens: typeof value.max_output_tokens === "number" ? value.max_output_tokens : undefined,
    has_previous_response_id: typeof value.previous_response_id === "string" && value.previous_response_id.length > 0
  };
  if (typeof value.instructions === "string") {
    summary.instructions_chars = value.instructions.length;
  }
  if (Array.isArray(value.messages)) {
    const messages = value.messages.map((message) => {
      if (!isRecord(message)) return { type: typeof message };
      return {
        role: typeof message.role === "string" ? message.role : "",
        content: summarizeRequestContent(message.content)
      };
    });
    summary.messages = messages;
    summary.input_chars = messages.reduce((total, message) => total + requestContentCharCount(message.content), 0);
  }
  if ("input" in value) {
    const input = summarizeRequestContent(value.input);
    summary.input = input;
    summary.input_chars = requestContentCharCount(input);
  }
  return Object.fromEntries(Object.entries(summary).filter(([, item]) => item !== undefined));
}

function summarizeRequestContent(value: unknown): unknown {
  if (typeof value === "string") return { type: "text", chars: value.length };
  if (Array.isArray(value)) {
    const summaries = value.map((item) => summarizeRequestContent(item));
    return {
      type: "array",
      items: value.length,
      chars: summaries.reduce((total: number, item) => total + requestContentCharCount(item), 0),
      images: summaries.reduce((total: number, item) => total + requestContentImageCount(item), 0)
    };
  }
  if (!isRecord(value)) return { type: typeof value };
  if (typeof value.text === "string") return { type: String(value.type ?? "text"), chars: value.text.length };
  if (typeof value.image_url === "string" || isRecord(value.image_url)) return { type: String(value.type ?? "image"), images: 1 };
  if (typeof value.content === "string" || Array.isArray(value.content)) {
    const content = summarizeRequestContent(value.content);
    return { type: String(value.type ?? "message"), content, chars: requestContentCharCount(content), images: requestContentImageCount(content) };
  }
  return { type: String(value.type ?? "object"), keys: Object.keys(value).slice(0, 8) };
}

function requestContentCharCount(summary: unknown): number {
  if (!isRecord(summary)) return 0;
  const chars = typeof summary.chars === "number" ? summary.chars : 0;
  const content = requestContentCharCount(summary.content);
  return chars + content;
}

function requestContentImageCount(summary: unknown): number {
  if (!isRecord(summary)) return 0;
  const images = typeof summary.images === "number" ? summary.images : 0;
  const content = requestContentImageCount(summary.content);
  return images + content;
}

function formatFileSize(bytes: number): string {
  if (!Number.isFinite(bytes) || bytes <= 0) return "0 B";
  const units = ["B", "KB", "MB", "GB"];
  let value = bytes;
  let index = 0;
  while (value >= 1024 && index < units.length - 1) {
    value /= 1024;
    index += 1;
  }
  const precision = value >= 10 || index === 0 ? 0 : 1;
  return `${value.toFixed(precision)} ${units[index]}`;
}

function stringOccurrences(content: string, query: string): number[] {
  const indexes: number[] = [];
  if (!query) return indexes;
  let cursor = 0;
  while (cursor <= content.length) {
    const index = content.indexOf(query, cursor);
    if (index < 0) break;
    indexes.push(index);
    cursor = index + Math.max(1, query.length);
  }
  return indexes;
}

function snippetAroundIndex(content: string, index: number, maxLength: number): string {
  const safeMax = Math.max(200, maxLength);
  const start = Math.max(0, index - Math.floor(safeMax / 2));
  const end = Math.min(content.length, start + safeMax);
  const prefix = start > 0 ? `...[start ${start}]\n` : "";
  const suffix = end < content.length ? `\n...[end ${end}]` : "";
  return `${prefix}${content.slice(start, end)}${suffix}`;
}

function numberLines(content: string, startLine: number, endLine: number): string {
  const lines = content.split(/\r?\n/);
  const total = Math.max(1, lines.length);
  const safeStart = Math.max(1, Math.min(startLine, total));
  const safeEnd = Math.max(safeStart, Math.min(endLine, total));
  return lines
    .slice(safeStart - 1, safeEnd)
    .map((line, index) => `${safeStart + index}: ${line}`)
    .join("\n");
}

function lineRangeAroundLine(content: string, line: number, maxLength: number): { startLine: number; endLine: number; text: string } {
  const lines = content.split(/\r?\n/);
  const total = Math.max(1, lines.length);
  const safeLine = Math.max(1, Math.min(line, total));
  const radius = Math.max(8, Math.floor(Math.max(500, maxLength) / 220));
  const startLine = Math.max(1, safeLine - radius);
  const endLine = Math.min(total, safeLine + radius);
  return { startLine, endLine, text: numberLines(content, startLine, endLine) };
}

function lineRangeAroundIndex(content: string, index: number, maxLength: number): { startLine: number; endLine: number; text: string } {
  const before = content.slice(0, Math.max(0, Math.min(index, content.length)));
  const hitLine = before.split(/\r?\n/).length;
  return lineRangeAroundLine(content, hitLine, maxLength);
}

function compactReadResultForPrompt(result: string, maxChars: number): string {
  const lines = usefulResultLines(result);
  const header = lines
    .filter((line) => /^(file|read|query|match|lines?|chars?|folder|folders:|files:)/i.test(line.trim()))
    .slice(0, 12);
  const numbered = lines.filter((line) => /^\d+:\s/.test(line.trim())).slice(0, 80);
  const entries = lines.filter((line) => /^\[(file|folder)\]\s+/i.test(line.trim())).slice(0, 80);
  const bodyLines = lines
    .filter((line) =>
      !/^(file|read|query|match|lines?|chars?|folder|folders:|files:)/i.test(line.trim())
      && !/^\[(file|folder)\]\s+/i.test(line.trim())
    )
    .slice(0, 80);
  const body = [...header, ...numbered, ...entries, ...bodyLines].join("\n") || lines.slice(0, 60).join("\n");
  const hint = parseReadRecoveryHint(result);
  return trimContextWithRecovery(redactSensitiveText(body), maxChars, hint ? readRecoveryHint(hint.path, hint.startLine ?? 1, Number.MAX_SAFE_INTEGER, maxChars) : "");
}

function normalizePatchRegexFlags(rawFlags: string | undefined, all: boolean): string {
  const allowed = new Set(["i", "m", "s", "u"]);
  const flags: string[] = [];
  for (const flag of String(rawFlags ?? "")) {
    if (flag === "g") continue;
    if (allowed.has(flag) && !flags.includes(flag)) flags.push(flag);
  }
  if (all) flags.push("g");
  return flags.join("");
}

function formatPatchFindFailure(path: string, current: string, find: string, regex: boolean): string {
  const hint = patchFailureHint(current, find);
  return [
    `patch ${regex ? "regex" : "find text"} was not found in ${path}.`,
    "Do not retry the same patch. First read the current file with a focused query, or use a smaller anchored patch.",
    `Suggested read action: {"type":"read","path":"${path}","query":"<short current anchor>","maxChars":8000}`,
    `file length: ${current.length}`,
    `missing ${regex ? "regex" : "find"}: ${trimContext(redactSensitiveText(find), 500)}`,
    hint ? `closest current snippet:\n${trimContext(redactSensitiveText(hint), 1200)}` : ""
  ].filter(Boolean).join("\n\n");
}

function patchFailureHint(current: string, find: string): string {
  const candidates = patchFindCandidates(find);
  for (const candidate of candidates) {
    const index = current.indexOf(candidate);
    if (index >= 0) return snippetAroundIndex(current, index, 1200);
  }
  return "";
}

function patchFindCandidates(find: string): string[] {
  const normalized = find.replace(/\s+/g, " ").trim();
  const candidates: string[] = [];
  const push = (value: string) => {
    const trimmed = value.trim();
    if (trimmed.length >= 12 && !candidates.includes(trimmed)) candidates.push(trimmed);
  };
  push(normalized.slice(0, 160));
  if (normalized.length > 220) {
    push(normalized.slice(Math.max(0, Math.floor(normalized.length / 2) - 80), Math.floor(normalized.length / 2) + 80));
    push(normalized.slice(-160));
  }
  const tokenPattern = /[A-Za-z_$][A-Za-z0-9_$]{8,}|[\u4e00-\u9fff]{4,}/g;
  let match: RegExpExecArray | null;
  while ((match = tokenPattern.exec(find)) !== null) {
    push(match[0]);
    if (candidates.length >= 8) break;
  }
  return candidates;
}

function patchRecoveryQuery(find: string): string | undefined {
  const cleaned = find
    .replace(/\\s[+*?]?/g, " ")
    .replace(/\\([/\\.^$*+?()[\]{}|])/g, "$1")
    .replace(/\(\?:/g, "(")
    .replace(/\s+/g, " ");
  const stopWords = new Set([
    "function", "return", "const", "let", "var", "this", "type", "path",
    "patch", "regex", "replace", "find", "true", "false", "string",
    "number", "object", "undefined", "null"
  ]);
  const tokenPattern = /[.#]?[A-Za-z_$][A-Za-z0-9_$-]{5,}|[\u4e00-\u9fff]{3,}/g;
  let match: RegExpExecArray | null;
  while ((match = tokenPattern.exec(cleaned)) !== null) {
    const token = match[0].trim();
    const normalized = token.replace(/^[.#]/, "").toLowerCase();
    if (stopWords.has(normalized)) continue;
    return token.slice(0, 80);
  }
  return patchFindCandidates(cleaned)[0]?.slice(0, 80);
}

function escapeRegExp(input: string): string {
  return input.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function clampInt(value: unknown, fallback: number, min: number, max: number): number {
  const parsed = typeof value === "number" ? value : Number.parseInt(String(value ?? ""), 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
}

function parseGithubState(value: unknown): string {
  const state = typeof value === "string" ? value.trim().toLowerCase() : "";
  return state === "closed" || state === "all" ? state : "open";
}

function encodePathParts(path: string): string {
  return path
    .split("/")
    .filter(Boolean)
    .map((part) => encodeURIComponent(part))
    .join("/");
}

function parseJsonFallback(text: string): unknown {
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
}

function formatGithubRepo(json: unknown): string {
  if (!isRecord(json)) return ensureDisplayText(json);
  const lines = [
    `${String(json.full_name ?? json.name ?? "repository")}`,
    `default_branch: ${String(json.default_branch ?? "")}`,
    `visibility: ${String(json.visibility ?? "")}`,
    `open_issues: ${String(json.open_issues_count ?? "")}`,
    `pushed_at: ${String(json.pushed_at ?? "")}`,
    `url: ${String(json.html_url ?? "")}`
  ];
  return lines.filter((line) => !line.endsWith(": ")).join("\n");
}

function formatGithubRateLimit(json: unknown): string {
  const resources = isRecord(json) && isRecord(json.resources) ? json.resources : {};
  const core = isRecord(resources.core) ? resources.core : isRecord(json) && isRecord(json.rate) ? json.rate : {};
  const remaining = String(core.remaining ?? "");
  const limit = String(core.limit ?? "");
  const reset = typeof core.reset === "number" ? new Date(core.reset * 1000).toISOString() : String(core.reset ?? "");
  return [`limit: ${limit}`, `remaining: ${remaining}`, `reset: ${reset}`].filter((line) => !line.endsWith(": ")).join("\n");
}

function formatGithubCommits(json: unknown): string {
  if (!Array.isArray(json)) return ensureDisplayText(json);
  if (!json.length) return "No commits.";
  return json
    .filter(isRecord)
    .map((item) => {
      const commit = isRecord(item.commit) ? item.commit : {};
      const author = isRecord(commit.author) ? commit.author : {};
      const message = String(commit.message ?? "").split(/\r?\n/, 1)[0];
      const sha = String(item.sha ?? "").slice(0, 12);
      const date = String(author.date ?? "");
      const url = String(item.html_url ?? "");
      return `- ${sha}${date ? ` ${date}` : ""}${message ? ` ${message}` : ""}${url ? `\n  ${url}` : ""}`.trim();
    })
    .join("\n");
}

function formatGithubItems(json: unknown, kind: "issue" | "pull" | "release" | "branch"): string {
  if (!Array.isArray(json)) return ensureDisplayText(json);
  if (!json.length) return "No GitHub items.";
  return json
    .filter(isRecord)
    .map((item) => {
      if (kind === "branch") {
        const commit = isRecord(item.commit) ? String(item.commit.sha ?? "").slice(0, 12) : "";
        return `- ${String(item.name ?? "")}${commit ? ` (${commit})` : ""}`;
      }
      const number = item.number !== undefined ? `#${String(item.number)}` : "";
      const tag = typeof item.tag_name === "string" ? item.tag_name : "";
      const title = String(item.title ?? item.name ?? tag);
      const state = String(item.state ?? item.draft ?? "");
      const url = String(item.html_url ?? "");
      const assets = kind === "release" && Array.isArray(item.assets)
        ? item.assets.filter(isRecord).map((asset) => String(asset.name ?? "")).filter(Boolean)
        : [];
      return [
        `- ${number || tag} ${title}${state ? ` [${state}]` : ""}`.trim(),
        assets.length ? `  assets: ${assets.join(", ")}` : "",
        url ? `  ${url}` : ""
      ].filter(Boolean).join("\n");
    })
    .join("\n");
}

function formatSearchHitsForCommand(hits: SearchHit[]): string {
  if (!hits.length) return "No Vault Search hits.";
  return hits
    .map((hit, index) => {
      const excerpt = hit.excerpt.trim();
      const score = Number.isFinite(hit.score) ? ` score=${hit.score}` : "";
      return excerpt
        ? `${index + 1}. ${hit.path}${score}\n${excerpt}`
        : `${index + 1}. ${hit.path}${score}`;
    })
    .join("\n\n");
}

function formatUniversalSearchContext(hits: SearchHit[]): string {
  return hits
    .map((hit, index) => {
      const excerpt = trimContext(redactSensitiveText(hit.excerpt), 440).trim();
      return `${index + 1}. ${hit.path}${excerpt ? `\n${excerpt}` : ""}`;
    })
    .join("\n\n");
}

function formatTargetCandidatesForCommand(candidates: TargetCandidate[], query: string): string {
  const visibleCandidates = looksLikeExplicitVaultFileQuery(query)
    ? candidates.filter((candidate, index) => isCredibleVaultTargetCandidate(query, candidate, candidates[index + 1]))
    : candidates;
  if (!visibleCandidates.length) {
    if (looksLikeExplicitVaultFileQuery(query)) {
      return [
        `Exact file target not found: ${query}`,
        "No credible filename/path match exists. Do not open or read another file unless the user explicitly requests fuzzy search."
      ].join("\n");
    }
    return [
      `No target candidates for: ${query}`,
      "Try broader terms, cancip.searchVault for content-only search, obsidian.listCommands for command inventory, or cancip.attachment.help for PDF/image parsing routes."
    ].join("\n");
  }
  const lines = [
    `Target discovery for: ${query}`,
    "Candidates combine weak filename/path/folder inference, text and attachment-content matches, attachment metadata, folder relations, and Obsidian command fuzzy matches.",
    ""
  ];
  for (const [index, candidate] of visibleCandidates.entries()) {
    lines.push(`${index + 1}. [${candidate.kind}] ${candidate.path} — ${candidate.title} [score ${Math.round(candidate.score)}]`);
    lines.push(`   reason: ${candidate.reason}`);
    if (candidate.detail?.trim()) {
      for (const line of trimContext(candidate.detail, 420).split(/\r?\n/)) lines.push(`   ${line}`);
    }
    if (candidate.next) lines.push(`   next: ${candidate.next}`);
  }
  return lines.join("\n");
}

function formatGithubWorkflowRuns(json: unknown): string {
  const runs = isRecord(json) && Array.isArray(json.workflow_runs) ? json.workflow_runs : [];
  if (!runs.length) return "No workflow runs.";
  return runs
    .filter(isRecord)
    .map((run) => {
      const status = [run.status, run.conclusion].filter((item) => typeof item === "string" && item).join("/");
      return `- ${String(run.name ?? run.display_title ?? "workflow")} ${status ? `[${status}]` : ""}\n  ${String(run.html_url ?? "")}`.trim();
    })
    .join("\n");
}

function formatGithubFile(json: unknown): string {
  if (Array.isArray(json)) {
    return json
      .filter(isRecord)
      .map((item) => `- ${String(item.type ?? "file")} ${String(item.path ?? item.name ?? "")}`)
      .join("\n") || "Empty directory.";
  }
  if (!isRecord(json)) return ensureDisplayText(json);
  const path = String(json.path ?? json.name ?? "");
  const size = String(json.size ?? "");
  const encoding = String(json.encoding ?? "");
  const content = typeof json.content === "string" && encoding === "base64" ? decodeBase64Text(json.content) : "";
  const header = `${path}${size ? ` (${size} bytes)` : ""}`;
  return content ? `${header}\n\n${trimContext(content, 6000)}` : `${header}\n${String(json.html_url ?? "")}`.trim();
}

function formatGithubCreatedIssue(json: unknown): string {
  if (!isRecord(json)) return ensureDisplayText(json);
  return `Created issue #${String(json.number ?? "")}: ${String(json.title ?? "")}\n${String(json.html_url ?? "")}`.trim();
}

function decodeBase64Text(input: string): string {
  const compact = input.replace(/\s+/g, "");
  try {
    if (typeof window !== "undefined" && typeof window.atob === "function") {
      return decodeURIComponent(
        Array.from(window.atob(compact))
          .map((char) => `%${char.charCodeAt(0).toString(16).padStart(2, "0")}`)
          .join("")
      );
    }
  } catch {
    return "";
  }
  return "";
}

function normalizeApiUrl(rawUrl: string): { chatUrl: string; responsesUrl: string; explicit: ApiMode | null } {
  const trimmed = rawUrl.trim().replace(/\/+$/, "");
  if (trimmed.endsWith("/chat/completions")) {
    return {
      chatUrl: trimmed,
      responsesUrl: trimmed.replace(/\/chat\/completions$/, "/responses"),
      explicit: "compatible"
    };
  }
  if (trimmed.endsWith("/responses")) {
    return {
      chatUrl: trimmed.replace(/\/responses$/, "/chat/completions"),
      responsesUrl: trimmed,
      explicit: "responses"
    };
  }
  return {
    chatUrl: `${trimmed}/chat/completions`,
    responsesUrl: `${trimmed}/responses`,
    explicit: null
  };
}

function supportsPreviousResponseId(rawUrl: string): boolean {
  try {
    const host = new URL(normalizeApiUrl(rawUrl).responsesUrl).hostname.toLowerCase();
    return host === "api.openai.com";
  } catch {
    return false;
  }
}

function resolveApiMode(setting: ApiMode, endpoint: { explicit: ApiMode | null }): ApiMode {
  if (setting !== "auto") return setting;
  return endpoint.explicit ?? "auto";
}

function estimateTokenCountFromChars(chars: number): number {
  if (!Number.isFinite(chars) || chars <= 0) return 0;
  return Math.max(1, Math.ceil(chars / 3));
}

function estimateRequestTokens(system: string, inputText: string): number {
  return estimateTextTokens(`${system}\n\n${inputText}`);
}

function estimateTextTokens(text: string): number {
  const normalized = String(text ?? "");
  if (!normalized) return 0;
  const cjk = (normalized.match(/[\u3400-\u9fff]/g) ?? []).length;
  const whitespace = (normalized.match(/\s/g) ?? []).length;
  const other = Math.max(0, normalized.length - cjk - whitespace);
  return Math.max(1, Math.ceil(cjk * 0.8 + other / 4));
}

function tokenNumber(value: unknown): number | undefined {
  if (typeof value === "number" && Number.isFinite(value)) return Math.max(0, Math.round(value));
  if (typeof value === "string") {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return Math.max(0, Math.round(parsed));
  }
  return undefined;
}

function usageValue(usage: Record<string, unknown>, keys: string[]): number | undefined {
  for (const key of keys) {
    const value = tokenNumber(usage[key]);
    if (value !== undefined) return value;
  }
  return undefined;
}

function extractTokenUsage(json: unknown, fallbackInput: number, fallbackOutputText: string): TokenUsage {
  const usage = isRecord(json) && isRecord(json.usage) ? json.usage : {};
  const input = usageValue(usage, ["input_tokens", "prompt_tokens", "inputTokens", "promptTokens"]);
  const output = usageValue(usage, ["output_tokens", "completion_tokens", "outputTokens", "completionTokens"]);
  const total = usageValue(usage, ["total_tokens", "totalTokens"]);
  const hasRealUsage = input !== undefined || output !== undefined || total !== undefined;
  const estimatedOutput = estimateTextTokens(fallbackOutputText);

  if (!hasRealUsage) {
    return {
      inputTokens: fallbackInput,
      outputTokens: estimatedOutput,
      totalTokens: fallbackInput + estimatedOutput,
      estimated: true
    };
  }

  const inputTokens = input ?? (total !== undefined && output !== undefined ? Math.max(0, total - output) : fallbackInput);
  const outputTokens = output ?? (total !== undefined ? Math.max(0, total - inputTokens) : estimatedOutput);
  return {
    inputTokens,
    outputTokens,
    totalTokens: total ?? inputTokens + outputTokens,
    estimated: input === undefined || output === undefined || total === undefined
  };
}

function extractResponseText(json: unknown): string {
  if (!isRecord(json)) return extractTextFragment(json);

  const outputText = extractTextFragment(json.output_text);
  if (outputText) return outputText;

  const choicesText = extractChoicesText(json.choices);
  if (choicesText) return choicesText;

  const responsesText = extractResponsesOutputText(json.output);
  if (responsesText) return responsesText;

  const directText = extractTextFragment(json.text);
  if (directText) return directText;

  return extractTextFragment(json.content);
}

function extractResponseId(json: unknown): string {
  if (!isRecord(json)) return "";
  return typeof json.id === "string" ? json.id : "";
}

function modelReplyTruncationReason(json: unknown, text: string): string {
  const records: Record<string, unknown>[] = [];
  const collect = (value: unknown): void => {
    if (!isRecord(value) || records.includes(value)) return;
    records.push(value);
    for (const key of ["response", "incomplete_details", "details"]) collect(value[key]);
    if (Array.isArray(value.choices)) {
      for (const choice of value.choices) collect(choice);
    }
  };
  collect(json);
  for (const record of records) {
    const status = typeof record.status === "string" ? record.status.toLowerCase() : "";
    const type = typeof record.type === "string" ? record.type.toLowerCase() : "";
    const finishReason = typeof record.finish_reason === "string" ? record.finish_reason.toLowerCase() : "";
    const stopReason = typeof record.stop_reason === "string" ? record.stop_reason.toLowerCase() : "";
    const reason = typeof record.reason === "string" ? record.reason.toLowerCase() : "";
    if (status === "incomplete" || type.includes("response.incomplete")) return reason || status || type;
    if (/length|max[_-]?(?:output[_-]?)?tokens?|token[_-]?limit/.test(`${finishReason} ${stopReason} ${reason}`)) {
      return finishReason || stopReason || reason;
    }
  }
  return looksStronglyTruncatedModelText(text) ? "unfinished text structure" : "";
}

function looksStronglyTruncatedModelText(raw: string): boolean {
  const text = stripStructuredChoices(removeCancipActionBlocks(raw)).trim();
  if (text.length < 8) return false;
  const fences = text.match(/^\s*`{3,}/gm) ?? [];
  if (fences.length % 2 === 1) return true;
  const boldMarkers = text.match(/\*\*/g) ?? [];
  if (boldMarkers.length % 2 === 1) return true;
  const tail = text.slice(-500);
  const opens = (tail.match(/[（(【[]/g) ?? []).length;
  const closes = (tail.match(/[）)】\]]/g) ?? []).length;
  const lastLine = tail.split(/\r?\n/).filter((line) => line.trim()).pop()?.trim() ?? "";
  if (opens > closes && !/[。！？.!?；;：:]$/.test(lastLine)) return true;
  if (/^(?:#{1,6}\s+|\*\*\s*)?\d+[.)、]\s*[^。！？.!?；;：:]{0,80}$/.test(lastLine) && !/\*\*$/.test(lastLine)) return true;
  return /(?:建议是|包括|如下|例如|分别是|以及|或者|并且|因此需要|下一步是|the following|including|such as|because|and|or)\s*[:：,，、-]?$/i.test(lastLine);
}

function mergeModelContinuation(base: string, continuation: string): string {
  const left = base.trimEnd();
  const right = continuation.trimStart();
  if (!left) return right;
  if (!right) return left;
  if (right.startsWith(left)) return right;
  if (left.endsWith(right)) return left;
  const maxOverlap = Math.min(600, left.length, right.length);
  for (let size = maxOverlap; size >= 12; size -= 1) {
    if (left.slice(-size) === right.slice(0, size)) return `${left}${right.slice(size)}`;
  }
  const separator = /\s$/.test(base) || /^\s/.test(continuation) ? "" : "\n";
  return `${left}${separator}${right}`;
}

function extractNonJsonText(text: string): string {
  const trimmed = text.trim();
  if (!trimmed) return "";
  if (trimmed.startsWith("{") || trimmed.startsWith("[")) return "";
  return trimmed;
}

function describeResponseShape(json: unknown): string {
  if (!isRecord(json)) return `type=${typeof json}`;
  const fields: string[] = [];
  if (typeof json.status === "string") fields.push(`status=${json.status}`);
  if (typeof json.model === "string") fields.push(`model=${json.model}`);
  if (Array.isArray(json.output)) fields.push(`output=${json.output.length}`);
  if (Array.isArray(json.choices)) fields.push(`choices=${json.choices.length}`);
  if (typeof json.output_text === "string") fields.push(`output_text=${json.output_text.length}`);
  if (isRecord(json.usage)) fields.push("usage=present");
  const keys = Object.keys(json).slice(0, 8).join(",");
  fields.push(`keys=${keys || "none"}`);
  return fields.join(", ");
}

async function readClipboardText(): Promise<string> {
  try {
    if (navigator.clipboard?.readText) return await navigator.clipboard.readText();
  } catch {
    // Some mobile WebViews require a user paste gesture; callers provide a manual paste modal.
  }
  return "";
}

async function copyTextToClipboard(text: string, status: string, t: (key: I18nKey, vars?: Record<string, string | number>) => string): Promise<boolean> {
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
    } else if (!copyTextWithHiddenTextarea(text)) {
      throw new Error("Clipboard API unavailable");
    }
    new Notice(status);
    return true;
  } catch (error) {
    if (copyTextWithHiddenTextarea(text)) {
      new Notice(status);
      return true;
    }
    const reason = error instanceof Error ? error.message : String(error);
    new Notice(t("copyFailed", { reason }));
    return false;
  }
}

function copyTextWithHiddenTextarea(text: string): boolean {
  void text;
  return false;
}

function extractCompatibleStreamDelta(json: unknown): string {
  if (!isRecord(json) || !Array.isArray(json.choices)) return "";
  return json.choices
    .map((choice) => {
      if (!isRecord(choice)) return "";
      const delta = isRecord(choice.delta) ? choice.delta : {};
      if (isReasoningResponseFragment(delta)) return "";
      return (
        extractTextFragment(delta.content) ||
        extractTextFragment(delta.text) ||
        extractTextFragment(choice.text) ||
        ""
      );
    })
    .filter(Boolean)
    .join("");
}

function extractResponsesStreamDelta(json: unknown): string {
  if (!isRecord(json)) return "";
  const type = typeof json.type === "string" ? json.type.toLowerCase() : "";
  if (/(?:reasoning|thinking|thought|analysis)/i.test(type)) return "";
  if (type && !/(?:output_text\.delta|message\.delta|content\.delta|text\.delta|delta)/i.test(type)) return "";
  return (
    extractTextFragment(json.delta) ||
    extractTextFragment(json.text) ||
    extractTextFragment(json.output_text) ||
    extractCompatibleStreamDelta(json)
  );
}

function extractChoicesText(choices: unknown): string {
  if (!Array.isArray(choices)) return "";
  return choices
    .map((choice) => {
      if (!isRecord(choice)) return extractTextFragment(choice);
      if (isRecord(choice.message)) {
        return extractTextFragment(choice.message.content) || extractTextFragment(choice.message.text);
      }
      return extractTextFragment(choice.text) || extractTextFragment(choice.content) || extractTextFragment(choice.delta);
    })
    .filter(Boolean)
    .join("\n");
}

function extractResponsesOutputText(output: unknown): string {
  if (!Array.isArray(output)) return extractTextFragment(output);
  return output
    .map((item) => {
      if (!isRecord(item)) return extractTextFragment(item);
      return (
        extractTextFragment(item.content) ||
        extractTextFragment(item.text) ||
        extractTextFragment(item.message)
      );
    })
    .filter(Boolean)
    .join("\n");
}

function extractModelReasoningSummary(value: unknown): string {
  const summaries: string[] = [];
  const seen = new Set<unknown>();
  const collect = (entry: unknown, reasoningScope = false, depth = 0): void => {
    if (depth > 10 || entry === null || entry === undefined || seen.has(entry)) return;
    if (typeof entry === "string") {
      if (reasoningScope && entry.trim()) summaries.push(entry.trim());
      return;
    }
    if (Array.isArray(entry)) {
      seen.add(entry);
      for (const item of entry) collect(item, reasoningScope, depth + 1);
      return;
    }
    if (!isRecord(entry)) return;
    seen.add(entry);
    const marker = [entry.type, entry.kind, entry.name, entry.category]
      .filter((item): item is string => typeof item === "string")
      .join(" ")
      .toLowerCase();
    const explicitSummary = /reasoning|thinking|thought|analysis/.test(marker)
      && /summary/.test(marker);
    for (const [key, child] of Object.entries(entry)) {
      const normalized = key.toLowerCase();
      const summaryKey = /^(?:reasoning[_-]?summary|thinking[_-]?summary|summary_text)$/.test(normalized);
      const nestedSummary = normalized === "summary" && (/reasoning|thinking|thought|analysis/.test(marker) || reasoningScope);
      const summaryTextChild = reasoningScope && /^(?:text|content|value|parts|delta|output_text)$/.test(normalized);
      collect(child, summaryKey || nestedSummary || explicitSummary || summaryTextChild, depth + 1);
    }
  };
  collect(value);
  return uniqueStrings(summaries).join("\n\n");
}

function extractTextFragment(value: unknown, depth = 0): string {
  if (depth > 8 || value === null || value === undefined) return "";
  if (typeof value === "string") return value;
  if (typeof value === "number" || typeof value === "boolean") return "";
  if (Array.isArray(value)) {
    return value
      .map((item) => extractTextFragment(item, depth + 1))
      .filter(Boolean)
      .join("\n");
  }
  if (!isRecord(value)) return "";
  if (isReasoningResponseFragment(value)) return "";

  return (
    extractTextFragment(value.text, depth + 1) ||
    extractTextFragment(value.output_text, depth + 1) ||
    extractTextFragment(value.content, depth + 1) ||
    extractTextFragment(value.parts, depth + 1) ||
    extractTextFragment(value.message, depth + 1) ||
    extractTextFragment(value.delta, depth + 1) ||
    extractTextFragment(value.value, depth + 1)
  );
}

function isReasoningResponseFragment(value: Record<string, unknown>): boolean {
  const marker = ["type", "kind", "name", "category"]
    .map((key) => {
      const raw = value[key];
      return typeof raw === "string" ? raw.toLowerCase() : "";
    })
    .filter(Boolean)
    .join(" ");
  if (!marker) return false;
  if (/(?:reasoning|thinking|thought|analysis|chain[_\s-]?of[_\s-]?thought|\bcot\b)/i.test(marker)) {
    return !/(?:output[_\s-]?text|message|assistant|final|answer)/i.test(marker);
  }
  return false;
}

function ensureDisplayText(value: unknown): string {
  const text = extractTextFragment(value);
  if (text) return text;
  if (typeof value === "string") return value;
  try {
    const json = JSON.stringify(value, null, 2);
    if (json) return json;
  } catch {
    // Fall through to String().
  }
  return String(value ?? "");
}

function preferredAutomaticApiMode(rawUrl: string): Exclude<ApiMode, "auto"> {
  try {
    const host = new URL(normalizeApiUrl(rawUrl).responsesUrl).hostname.toLowerCase();
    return host === "api.openai.com" ? "responses" : "compatible";
  } catch {
    return "compatible";
  }
}

function shouldDisableOptionalReasoning(rawUrl: string, maxOutputTokens: number): boolean {
  if (maxOutputTokens > 768) return false;
  try {
    const host = new URL(normalizeApiUrl(rawUrl).chatUrl).hostname.toLowerCase();
    return host === "openrouter.ai" || host.endsWith(".openrouter.ai");
  } catch {
    return false;
  }
}

function isStreamingUnavailableError(reason: string): boolean {
  return /(?:failed to fetch|streaming fetch unavailable|stream response body unavailable|networkerror|load failed|http\s+(?:401|403|405|406|415)\b)/i.test(reason);
}

function modelRequestBodyText(value: unknown): string {
  try {
    return JSON.stringify(value) ?? "";
  } catch {
    return "";
  }
}

function safeJsonishDisplay(value: unknown): string {
  if (typeof value === "string") return value;
  if (value === undefined) return "undefined";
  const seen = new WeakSet<object>();
  const win = activeDocument.defaultView;
  try {
    const json = JSON.stringify(value, (_key, item: unknown) => {
      if (typeof item === "function") return `[Function ${item.name || "anonymous"}]`;
      if (typeof item === "object" && item !== null) {
        if (seen.has(item)) return "[Circular]";
        seen.add(item);
        if (item instanceof TFile) return { type: "TFile", path: item.path, basename: item.basename, extension: item.extension };
        if (item instanceof TFolder) return { type: "TFolder", path: item.path, children: item.children.length };
        if (item instanceof Error) return { name: item.name, message: item.message, stack: item.stack };
        const element = item as HTMLElement;
        if (win && element.instanceOf(win.HTMLElement)) {
          return {
            type: "HTMLElement",
            tag: element.tagName.toLowerCase(),
            text: trimContext((element.innerText || element.textContent || "").replace(/\s+/g, " ").trim(), 160),
            classes: String(element.className || "").trim()
          };
        }
      }
      return item;
    }, 2);
    if (json) return json;
  } catch {
    // Fall through to display text.
  }
  return ensureDisplayText(value);
}
